// 全球能源项目世界地图 —— 2026-06 全大区深度补充批次（第十三轮）
// 按 中国/东亚→东南亚→南亚→中亚→中东→欧洲→北美→南美→非洲→大洋洲 顺序，逐区深度调研补充的新增项目。
// id 段 4600–6049；每区一段（东亚4600 东南亚4750 南亚4900 中亚5050 中东5150 欧洲5300 北美5450 南美5600 非洲5750 大洋洲5900）。
// 含内联 descEn/detailEn（保持英文 100% 覆盖）与 progress。concat 进 ENERGY_EXTRA；
// index.html 在 data-clients2.js 之后、progress.js 之前加载。
window.ENERGY_EXTRA = (window.ENERGY_EXTRA || []).concat([
  // ===== 东亚（4600-4633）=====
  {"id":4600,"name":"中海油海南CZ7海上风电示范项目","en":"CNOOC Hainan CZ7 Offshore Wind Demonstration Project","country":"中国","region":"东亚","cat":"renewable","coord":[108.65,19.1],"cap":"1500 MW（CZ7-1 600MW + CZ7-2 900MW）","inv":25.6,"invText":"约182亿元","status":"在建","year":2026,"updated":"2026-06","owner":"中国海洋石油集团","flagship":true,"desc":"中海油首个大型海上风电，位于海南东方西部海域，深水示范。","detail":"项目位于海南省东方市西侧海域，规划装机1500MW，分两期建设；CZ7-1（600MW，水深11–44m）计划2025年9月开工、2026年10月具备并网条件，CZ7-2（900MW，水深26–49m）随后推进。总投资约182亿元，单位千瓦造价约12100元，是中海油进军海上风电的标志性工程。","descEn":"CNOOC's first large-scale offshore wind project in Dongfang, Hainan — a deep-water demonstration with 1.5 GW capacity.","detailEn":"Located west of Dongfang City, Hainan Province, the 1,500 MW project is split into CZ7-1 (600 MW, 11–44 m depth) and CZ7-2 (900 MW, 26–49 m depth). Phase 1 broke ground in September 2025 with grid connection targeted for October 2026. Total investment is ~RMB 18.2 billion. This is CNOOC's flagship entry into utility-scale offshore wind.","progress":"一期陆上集控中心2025年9月30日前开工，2026年10月前具备倒送电条件。"},
  {"id":4601,"name":"中广核阳江三山岛五海上风电","en":"CGN Yangjiang Sansandao No.5 Offshore Wind Farm","country":"中国","region":"东亚","cat":"renewable","coord":[111.45,21.3],"cap":"500 MW","inv":7.2,"invText":"约51亿元","status":"在建","year":2026,"updated":"2026-06","owner":"中国广核集团","flagship":false,"desc":"广东阳江深远海500MW，2025年开工、2026年底投产。","detail":"项目位于广东省阳江市南侧海域，装机50万千瓦，总投资约51亿元，计划2025年9月开工，2026年12月投产。与华电三山岛六、集中送出工程共用一座1000MW海上升压站和一座1000MW海上中间补偿站，共享500kV交流海缆送出。","descEn":"CGN's 500 MW offshore wind farm at Yangjiang's Sansandao site, to be commissioned by end-2026.","detailEn":"Located in the Sansandao sea area south of Yangjiang, Guangdong, this 500 MW project has a total investment of ~RMB 5.1 billion. Construction began September 2025 with completion planned December 2026. It shares offshore substation and 500 kV cable facilities with Huadian's adjacent No.6 farm, reducing per-unit transmission costs."},
  {"id":4602,"name":"华电阳江三山岛六海上风电","en":"Huadian Yangjiang Sansandao No.6 Offshore Wind Farm","country":"中国","region":"东亚","cat":"renewable","coord":[111.5,21.25],"cap":"500 MW（31台×16.2MW）","inv":7.25,"invText":"约51.5亿元","status":"在建","year":2026,"updated":"2026-06","owner":"华电新能源集团","flagship":false,"desc":"华电阳江三山岛六500MW深远海项目，2026年底投产。","detail":"项目位于广东省阳江市南侧海域，拟布置31台16.2MW机组，总装机500MW，项目总投资约51.5亿元，EPC由华电科工牵头签约。该项目与中广核三山岛五联合送出，共建海上升压站，计划2026年12月并网。","descEn":"Huadian's 500 MW deep-sea wind farm at Sansandao, Yangjiang, with 31×16.2 MW turbines, due December 2026.","detailEn":"Huadian's Sansandao No.6 project deploys 31 units of 16.2 MW turbines off Yangjiang, Guangdong. Total investment is ~RMB 5.15 billion. EPC contract (RMB 1.96 billion) was awarded to Huadian Science & Technology. It shares a 1,000 MW offshore booster station and 500 kV submarine cables with the adjacent CGN No.5 farm, targeting December 2026 commissioning."},
  {"id":4603,"name":"三峡库布其沙漠中北部12GW新能源大基地","en":"Three Gorges Kubuqi Desert Central-North 12 GW Renewable Energy Base","country":"中国","region":"东亚","cat":"renewable","coord":[110.2,40.3],"cap":"光伏8GW + 风电4GW + 光热200MW / 配储5GWh","inv":139,"invText":"约988亿元","status":"在建","year":2027,"updated":"2026-06","owner":"三峡集团、内蒙古能源集团","flagship":true,"desc":"内蒙古首个千万千瓦级沙戈荒风光大基地，2025年9月全面开工。","detail":"项目位于内蒙古鄂尔多斯市达拉特旗库布其沙漠，规划光伏800万千瓦、风电400万千瓦、光热20万千瓦，配套煤电400万千瓦及500万千瓦时储能，总投资988亿元。外送通道±800kV特高压（699公里，800万千瓦）北起达拉特旗、南至河北沧州，2025年9月29日全面开工，计划2027年底全容量投运。","descEn":"China's first GW-scale desert wind-solar base in Kubuqi, Inner Mongolia — 8 GW solar + 4 GW wind, ¥98.8 billion investment.","detailEn":"Developed by Three Gorges Group and Inner Mongolia Energy Group at the Kubuqi Desert in Dalat Banner, Ordos, this 12 GW base (8 GW PV + 4 GW wind + 200 MW CSP) is backed by a ±800 kV UHV DC line delivering 8 GW to Cangzhou, Hebei. Total investment RMB 98.8 billion. Full-scale construction started September 29, 2025; full commissioning targeted end-2027.","progress":"2025年9月29日全面开工，配套±800kV特高压外送通道同步建设，预计2027年底全容量投运。","route":[[110.2,40.3],[111.5,39.5],[112.8,38.8],[114,38.2],[116.8,38.35]]},
  {"id":4604,"name":"远景赤峰零碳绿色氢氨一体化工程（三期全量）","en":"Envision Chifeng Zero-Carbon Green Hydrogen-Ammonia Integrated Project","country":"中国","region":"东亚","cat":"renewable","coord":[118.9,42.27],"cap":"1430MW风光 / 年产152万吨绿氨","inv":56,"invText":"总投资约400亿元","status":"在建","year":2028,"updated":"2026-06","owner":"远景能源","flagship":true,"desc":"全球最大绿色氢氨项目，赤峰一期32万吨已于2025年7月投产。","detail":"项目位于内蒙古赤峰市，三期规划总产能152万吨/年绿氨，配套1430MW风电光伏及680MWh储能。一期（32万吨/年）于2025年7月8日正式投产，采用完全离网可再生能源电解水制氢-合成氨工艺，是全球最大离网绿色氢氨工厂。总投资约400亿元，三期全部投运预计2028年。","descEn":"World's largest off-grid green hydrogen-ammonia plant in Chifeng, Inner Mongolia — Phase 1 (320 kt/yr) commissioned July 2025.","detailEn":"Developed by Envision Energy in Chifeng, Inner Mongolia, this project will ultimately produce 1.52 million tonnes/yr of green ammonia from 1.43 GW of off-grid wind and solar. Phase 1 (320 kt/yr) commissioned on 8 July 2025, making it the world's largest off-grid green hydrogen facility. Total investment ~RMB 40 billion across three phases, with full completion by 2028.","progress":"一期（32万吨/年绿氨）已于2025年7月正式投产，为全球最大离网绿色氢氨工厂。"},
  {"id":4605,"name":"华电英德扬潮抽水蓄能电站","en":"Huadian Yingde Yangchao Pumped-Storage Power Station","country":"中国","region":"东亚","cat":"storage","coord":[113.35,24.18],"cap":"2400 MW（8×300MW）","inv":32,"invText":"约228亿元","status":"在建","year":2030,"updated":"2026-06","owner":"华电集团","flagship":false,"desc":"广东英德大型抽水蓄能，装机240万千瓦，2025年开工。","detail":"项目位于广东省英德市，总装机240万千瓦（8台×30万千瓦），总投资约228亿元，2025年核准开工，设计年发电量44.4亿千瓦时。项目地处粤港澳大湾区负荷中心，建成后将有效缓解广东调峰压力，是十五五重点储能工程。","descEn":"240 MW pumped-storage station in Yingde, Guangdong, approved and started construction in 2025.","detailEn":"Located in Yingde, Guangdong, this 2,400 MW (8×300 MW) pumped-storage station has a total investment of ~RMB 22.8 billion. Construction was approved and commenced in 2025. Annual output target is 4.44 billion kWh. Located near the Pearl River Delta load centre, the project will address Guangdong's growing peak-shaving needs under China's 15th Five-Year Plan."},
  {"id":4606,"name":"云南文山丘北200MW构网型锂钠混合储能电站","en":"Yunnan Wenshan Qiubei 200MW Grid-Forming Li-Na Hybrid BESS","country":"中国","region":"东亚","cat":"storage","coord":[104.18,24.04],"cap":"200 MW / 400 MWh","inv":0.65,"invText":"总投资4.6亿元","status":"投运","year":2025,"updated":"2026-06","owner":"南网储能（云南储能有限公司）","flagship":false,"desc":"全国最大构网型锂钠混合储能，云南文山2025年3月投运。","detail":"项目位于云南省文山州丘北县工业园区，装机200MW/400MWh，整站采用构网型储能技术，是全国最大的构网型锂钠混合路线电池储能电站。投资4.6亿元，2024年10月开工，2025年3月全容量并网，5月完成检测投产，也是南方电网网外首个百兆瓦时级黑启动成功验证项目。","descEn":"China's largest grid-forming lithium-sodium hybrid BESS (200 MW/400 MWh) in Wenshan, Yunnan — commissioned March 2025.","detailEn":"Located in Qiubei County, Wenshan, Yunnan, this 200 MW/400 MWh grid-forming BESS uses both lithium-ion and sodium-ion cells — a world first at this scale. Invested by China Southern Grid's storage subsidiary (RMB 460 million), it broke ground in October 2024 and achieved full-capacity grid connection in March 2025, followed by formal commissioning in May 2025.","progress":"2025年5月完成全部检测试验正式投产，为南网首个成功验证黑启动的百兆瓦时级储能站。"},
  {"id":4607,"name":"广西白龙核电一期（白龙1号华龙一号）","en":"Guangxi Bailong Nuclear Power Plant Phase 1 (Hualong One)","country":"中国","region":"东亚","cat":"nuclear","coord":[108.28,21.38],"cap":"2×1200 MW（华龙一号）","inv":51,"invText":"约2×180亿元","status":"在建","year":2030,"updated":"2026-06","owner":"中国核工业集团（中核集团）","flagship":false,"desc":"广西首个核电站，白龙1号2025年底正式开工，华龙一号技术。","detail":"白龙核电位于广西防城港市，白龙1号机组于2025年12月开工（FCD），采用中国自主三代核电技术华龙一号，与中广核防城港三期形成广西核电集群。单机组投资约180亿元，设计年利用小时约7500小时，建成后将大幅提升广西清洁电力比重。","descEn":"Guangxi's first nuclear plant — Bailong Unit 1 (Hualong One, 1,200 MW) broke ground in December 2025.","detailEn":"Bailong NPP is located in Fangchenggang, Guangxi. Unit 1 poured first concrete in December 2025, adopting China's indigenous Generation III pressurized water reactor technology 'Hualong One.' With an investment of ~RMB 18 billion per unit and designed capacity factor of ~87.5%, the plant will significantly boost Guangxi's clean energy share alongside CGN's Fangchenggang Phase 3.","progress":"白龙1号于2025年12月正式开工建设（核岛浇筑第一罐混凝土）。"},
  {"id":4608,"name":"山东金七门核电一期（1、2号华龙一号）","en":"Shandong Jinqimen Nuclear Power Plant Phase 1 (Hualong One)","country":"中国","region":"东亚","cat":"nuclear","coord":[121.55,37.52],"cap":"2×1200 MW（华龙一号）","inv":51,"invText":"约360亿元","status":"在建","year":2031,"updated":"2026-06","owner":"中核集团、山东能源","flagship":false,"desc":"山东金七门核电1号机组2025年开工，烟台华龙一号新基地。","detail":"金七门核电厂址位于山东省烟台市，1号机组于2025年8月开工（FCD），采用华龙一号技术，总投资约360亿元（两台机组）。是山东布局核电的重大举措，与海阳核电、招远核电共同构筑鲁东清洁能源带，预计2031年前后首台机组投运。","descEn":"Jinqimen Nuclear Power Unit 1 (Hualong One) broke ground in Yantai, Shandong in August 2025.","detailEn":"Located in Yantai, Shandong, the Jinqimen NPP Unit 1 poured first concrete in August 2025 using the Hualong One design. Total investment for two units is ~RMB 36 billion. The station forms part of eastern Shandong's clean energy cluster alongside Haiyang and Zhaoyuan NPPs. Unit 1 is expected to enter commercial operation around 2031.","progress":"金七门1号机组已于2025年8月正式开工（核岛浇筑第一罐混凝土）。"},
  {"id":4609,"name":"福建宁德核电6号机组（华龙一号）","en":"Fujian Ningde Nuclear Power Unit 6 (Hualong One)","country":"中国","region":"东亚","cat":"nuclear","coord":[119.76,26.84],"cap":"1×1200 MW（华龙一号）","inv":25,"invText":"约180亿元","status":"在建","year":2030,"updated":"2026-06","owner":"中国广核集团","flagship":false,"desc":"中广核宁德核电6号机组2025年12月开工，扩容至六台机组。","detail":"宁德核电6号机组位于福建省宁德市，采用华龙一号技术，于2025年12月16日完成核岛第一罐混凝土浇筑，标志着宁德核电站扩展至六台机组；投资约180亿元。宁德核电1–4号机组已全部投运，5、6号机组为扩容项目，建成后宁德核电总装机将达约720万千瓦，是福建最大核电基地。","descEn":"CGN Ningde NPP Unit 6 (Hualong One) poured first concrete in December 2025, expanding the site to 6 units.","detailEn":"Unit 6 at CGN's Ningde Nuclear Power Station in Fujian Province poured its first nuclear island concrete on 16 December 2025. Using Hualong One technology, the ~RMB 18 billion unit will expand Ningde NPP to six units totalling ~7,200 MW — making it Fujian's largest nuclear base. Units 1–4 are already in operation; Unit 5 is currently under construction.","progress":"2025年12月16日核岛第一罐混凝土浇筑完成，正式开工建设。"},
  {"id":4610,"name":"广东惠州核电3号机组（华龙一号）","en":"Guangdong Huizhou Nuclear Power Unit 3 (Hualong One)","country":"中国","region":"东亚","cat":"nuclear","coord":[114.73,22.73],"cap":"1×1200 MW（华龙一号）","inv":25,"invText":"约180亿元","status":"在建","year":2030,"updated":"2026-06","owner":"中国广核集团","flagship":false,"desc":"惠州核电3号机组2025年开工，粤港澳大湾区清洁电力新支柱。","detail":"惠州核电3号机组位于广东省惠州市，2025年开工（FCD），采用华龙一号技术，投资约180亿元。惠州核电是粤港澳大湾区电力的重要支撑，建成后将与大亚湾、岭澳核电形成南方核电集群，预计2030年前后投运。粤港澳大湾区首台华龙一号机组（太平岭1号）已于2026年4月投产。","descEn":"Huizhou NPP Unit 3 (Hualong One) started construction in 2025 to support GBA power demand.","detailEn":"Unit 3 at the Huizhou NPP site, Guangdong, broke ground in 2025 using Hualong One technology (investment ~RMB 18 billion). It forms part of a cluster with Daya Bay and Ling'ao NPPs. The Greater Bay Area's first Hualong One unit (Taipingling Unit 1) entered commercial operation in April 2026, underlining the technology's maturity.","progress":"惠州3号机组2025年正式开工建设；粤港澳首台华龙一号（太平岭1号）已于2026年4月投产。"},
  {"id":4611,"name":"长江存储武汉三期（3D NAND超级厂）","en":"YMTC Wuhan Phase 3 3D NAND Mega-Fab","country":"中国","region":"东亚","cat":"ci","coord":[114.05,30.46],"cap":"月产能扩至30万片（12英寸）","inv":280,"invText":"约2000亿元（累计）","status":"在建","year":2027,"updated":"2026-06","owner":"长江存储","flagship":true,"desc":"长江存储武汉三期扩产，力争月产能30万片，三期总投约2000亿元。","detail":"长江存储三期工程位于武汉光谷，是继一、二期之后的再度大规模扩产，规划将武汉基地月产能提升至约30万片12英寸晶圆，主攻232层以上3D NAND闪存。三期累计投资约2000亿元，是中国最大的NAND存储半导体建设项目，亦是武汉半导体自主化的核心支柱，预计2027年前后满产。","descEn":"YMTC's Wuhan Phase 3 fab targets 300K wafers/month of 3D NAND flash, with ¥200 billion cumulative investment.","detailEn":"YMTC's third expansion at Wuhan Optics Valley pushes the site's monthly capacity to ~300,000 12-inch wafers focused on 232+ layer 3D NAND. Cumulative investment across all phases reaches ~RMB 200 billion, making it China's largest NAND semiconductor project and a linchpin of domestic storage chip independence. Full production is targeted for around 2027.","progress":"三期扩产建设持续推进，主攻232层以上3D NAND技术节点，目标月产30万片。"},
  {"id":4612,"name":"宁德时代罗源钠离子/锂电大型储能电芯基地","en":"CATL Luoyuan Sodium-Ion & Lithium Battery Gigafactory","country":"中国","region":"东亚","cat":"ci","coord":[119.55,26.48],"cap":"年产能超100 GWh","inv":100,"invText":"约700亿元","status":"在建","year":2027,"updated":"2026-06","owner":"宁德时代","flagship":true,"desc":"宁德时代罗源基地，全球最大钠离子与储能电芯超级工厂。","detail":"基地位于福建省福州市罗源县，宁德时代规划建设全球最大储能电芯生产基地，重点布局钠离子电池和大容量储能锂电，年产能规划超100GWh，总投资约700亿元。该基地是宁德时代落实十五五储能出海战略的核心产能，将显著拉动罗源及宁德地区产业链配套。","descEn":"CATL's Luoyuan mega-factory for sodium-ion and large-format storage cells, targeting >100 GWh/yr annual capacity.","detailEn":"Located in Luoyuan County, Fuzhou, Fujian, this CATL gigafactory is designed to be the world's largest storage cell production base, focusing on sodium-ion batteries and large-format lithium storage cells. Target annual capacity exceeds 100 GWh with total investment ~RMB 70 billion. It underpins CATL's 15th Five-Year Plan strategy for overseas energy storage markets.","progress":"基地建设持续推进，首期产线预计2026–2027年陆续投产，重点布局钠离子与大容量储能电芯。"},
  {"id":4613,"name":"中芯东方临港12英寸逻辑晶圆厂二期","en":"SMIC East Lingang Phase 2 12-inch Logic Foundry","country":"中国","region":"东亚","cat":"ci","coord":[121.88,30.89],"cap":"月产10万片（12英寸）","inv":83,"invText":"约590亿元","status":"在建","year":2027,"updated":"2026-06","owner":"中芯国际","flagship":true,"desc":"中芯临港二期扩产，月产10万片逻辑芯片，上海半导体产能新里程。","detail":"项目位于上海市临港新片区，中芯国际将临港厂区月产能扩至10万片12英寸逻辑晶圆，主攻28nm及以下成熟工艺，总投资约590亿元。二期于2025年陆续安装设备，与一期合计构成上海最大逻辑芯片产地，支撑国内消费电子、工业控制、汽车电子芯片自主化。","descEn":"SMIC Lingang Phase 2 expands to 100K wafers/month (28nm and below) at Shanghai's Lingang Special Economic Zone.","detailEn":"SMIC's Lingang Phase 2 expansion in Shanghai's Lingang Free Trade Zone brings the site's total monthly capacity to 100,000 12-inch wafers (28 nm and below logic). Total investment is ~RMB 59 billion. Equipment installation was ongoing through 2025, with full capacity expected around 2027. The fab supports domestic demand for consumer electronics, industrial, and automotive chips.","progress":"2025年持续推进设备安装与调试，与一期合计产能进入规模化爬坡阶段。"},
  {"id":4614,"name":"协鑫汇东江苏如东LNG接收站","en":"GCL-Huidong Jiangsu Rudong LNG Receiving Terminal","country":"中国","region":"东亚","cat":"petro","coord":[121.38,32.32],"cap":"年周转350万吨LNG","inv":25,"invText":"约175亿元","status":"在建","year":2025,"updated":"2026-06","owner":"协鑫集团、汇东能源","flagship":false,"desc":"协鑫汇东如东LNG接收站，年周转350万吨，2025年三季度投产。","detail":"项目位于江苏省南通市如东县洋口港，由协鑫集团与汇东能源合资建设，年LNG周转能力350万吨，设计气化外输能力约1700万立方米/天。建设进度截至2025年中总体完成约98%，计划2025年三季度投产运营，是华东地区天然气供应保障的重要增量。","descEn":"GCL-Huidong's LNG receiving terminal in Rudong, Jiangsu — 3.5 Mt/yr capacity, commissioned Q3 2025.","detailEn":"Located at Yankou Port, Rudong County, Jiangsu, this 3.5 million-tonne/year LNG terminal is a joint venture of GCL Group and Huidong Energy. As of mid-2025, overall construction was ~98% complete with commissioning targeted for Q3 2025, adding 17 million m³/day of regasification capacity to East China's gas grid.","progress":"2025年中整体进度完成约98%，计划第三季度投产运营。"},
  {"id":4615,"name":"如东国信LNG接收站（四储罐）","en":"Rudong Guoxin LNG Receiving Terminal (4-Tank)","country":"中国","region":"东亚","cat":"petro","coord":[121.35,32.28],"cap":"年接卸能力约500万吨，4座储罐","inv":35,"invText":"约250亿元（综合）","status":"在建","year":2026,"updated":"2026-06","owner":"国信集团","flagship":false,"desc":"国信如东LNG四储罐扩容，2026年3月底具备首船接卸，规模领先华东。","detail":"项目位于江苏如东洋口港，国信LNG接收站4号储罐外罐工程全部完工，码头工程已架设钢栈桥500米，水上沉桩完成403根，计划确保2025年底建成、2026年3月底具备首船接卸条件。四座储罐齐备后成为华东最大规模LNG接收站之一，每年可增供天然气数十亿立方米。","descEn":"Guoxin Rudong LNG terminal expands to 4 storage tanks, targeting first cargo by March 2026.","detailEn":"The fourth storage tank at Guoxin's LNG terminal in Rudong, Jiangsu completed its outer-tank structure. Offshore construction includes 500 m of steel trestle bridge and 403 steel piles driven. The terminal is scheduled to be fully built by end-2025 and ready to unload its first LNG cargo by March 2026, significantly boosting East China gas supply security.","progress":"4号储罐外罐全部完工，计划2025年底建成，2026年3月底首船接卸。"},
  {"id":4616,"name":"内蒙古和林格尔新一期万卡绿色算力基地","en":"Inner Mongolia Holingor New-Phase 10K-GPU Green AI Computing Hub","country":"中国","region":"东亚","cat":"datacenter","coord":[111.82,40.38],"cap":"万卡GPU集群（>10000张AI加速卡）","inv":30,"invText":"约200亿元（阶段投资）","status":"在建","year":2026,"updated":"2026-06","owner":"字节跳动、中国移动、火山引擎","flagship":false,"desc":"和林格尔绿色算力新批次，字节、移动、火山引擎多家万卡集群落地。","detail":"内蒙古和林格尔数据中心集群是东数西算首批枢纽之一，2025–2026年新增字节跳动火山引擎内蒙古算力中心一期（万卡集群）、中国移动智算中心二期等项目，区域绿电占比超70%。新批次合计服务器机架规模超10万架，算力规模居全国前列。","descEn":"New-phase 10K-GPU green AI computing clusters (ByteDance, China Mobile, Volcano Engine) launched at Holingor, Inner Mongolia.","detailEn":"Holingor in Inner Mongolia hosts China's largest cross-enterprise AI computing cluster hub, with new 2025–2026 phases adding Volcano Engine (ByteDance) Phase 1 and China Mobile's second smart computing centre — each targeting 10,000+ GPU arrays. Green electricity share exceeds 70%. Cumulative rack count in the cluster area now surpasses 100,000.","progress":"火山引擎内蒙古和林格尔算力中心一期（万卡）2025年开工，2026年交付。"},
  {"id":4617,"name":"日本五岛市漂浮式海上风电（商业第一期）","en":"Goto Floating Offshore Wind Farm — Japan's First Commercial Floating Wind","country":"日本","region":"东亚","cat":"renewable","coord":[128.8,32.63],"cap":"16.8 MW（8×2.1MW 混合Spar浮式）","inv":1.2,"invText":"约170亿日元","status":"投运","year":2026,"updated":"2026-06","owner":"戸田建設、ENEOS、中部電力、INPEX、大阪ガス、関西電力","flagship":true,"desc":"日本首个商业漂浮式海上风电，长崎五岛市2026年1月正式投运。","detail":"项目位于长崎县五岛市福江岛冲约7公里处，装机16.8MW（8台×2.1MW），采用钢上-混凝土下混合Spar型浮式基础，系全球首次商用。2026年1月5日正式进入商业运营，并在日本《海洋再生能源利用促进法》框架下获得国土交通省与经济产业省双部门认证，具有重要示范意义。","descEn":"Japan's first commercial floating offshore wind (16.8 MW) off Goto, Nagasaki — entered commercial operation 5 January 2026.","detailEn":"Located 7 km offshore Fukue Island, Goto City, Nagasaki Prefecture, the 16.8 MW farm (8×2.1 MW) uses a hybrid steel-concrete Spar floater designed by Toda Corporation — a world first for commercial floating wind. The consortium (Toda, ENEOS, Chubu Electric, INPEX, Osaka Gas, Kansai Electric) received joint certification from METI and MLIT on 5 January 2026, when commercial operations commenced.","progress":"2026年1月5日正式商业运营，成为日本首个通过海洋可再生能源法认证的漂浮式风电项目。"},
  {"id":4618,"name":"青森津軽沖 615MW 海上风电（JERA领衔）","en":"Aomori Tsugaru Offshore Wind 615 MW (JERA-led Consortium)","country":"日本","region":"东亚","cat":"renewable","coord":[140.48,41.1],"cap":"615 MW（41台×15MW SG-DD236）","inv":40,"invText":"约5000–6000亿日元（预估）","status":"规划","year":2030,"updated":"2026-06","owner":"JERA Nex、Green Power Investment、東北電力","flagship":false,"desc":"日本最大单体海上风电之一，青森津轻冲615MW，计划2030年运营。","detail":"项目位于青森县津轻地区日本海侧，由JERA Nex领衔的津轻沖能源社区联合体于2024年底获得开发权，计划安装41台西门子歌美飒SG-DD 236型15MW机组，总装机615MW，预计2030年6月商业运营。JERA已公开表态将坚持推进，以证明海上风电在日本可行，并将利用能代港作为建设运维基地。","descEn":"JERA-led 615 MW offshore wind project off Aomori (Tsugaru Sea of Japan side), awarded December 2024, targeting June 2030 operations.","detailEn":"Tsugaru Offshore Energy Community (JERA Nex, Green Power Investment, Tohoku Electric) won the seabed lease in December 2024 for a 615 MW farm featuring 41 SG-DD236 15 MW turbines off Aomori Prefecture's Sea of Japan coast. Despite rising costs, JERA reaffirmed its commitment in February 2026, calling the project a proof point for offshore wind viability in Japan. Commercial operations targeted June 2030.","progress":"2024年底获开发权，JERA 2026年2月重申推进决心，组织设计和许可工作进行中。"},
  {"id":4619,"name":"台积电熊本第二工厂（JASM Fab 2）","en":"TSMC Kumamoto Second Fab (JASM Fab 2, 6nm/3nm)","country":"日本","region":"东亚","cat":"ci","coord":[130.75,32.82],"cap":"月产约5万片（6nm→3nm升级讨论中）","inv":138,"invText":"约139亿美元","status":"在建","year":2027,"updated":"2026-06","owner":"台积电（TSMC）、日本政府（METI补贴）","flagship":true,"desc":"台积电熊本二厂2025年10月开工，139亿美元，探讨升级至3nm节点。","detail":"台积电熊本第二工厂（JASM Fab 2）位于熊本县菊阳町，2025年10月28日正式开工，初期规划生产6–12nm芯片，总投资约139亿美元，日本政府将提供补贴。2025年底至2026年初报道指台积电与METI讨论将工艺升级至3–4nm，适应汽车和AI芯片需求；目前重型施工机械已撤场，预计2026年全年不采购设备，2027年后恢复建设节奏。","descEn":"TSMC's second Kumamoto fab (JASM Fab 2) broke ground October 2025 with $13.9B investment; node upgrade to 3nm under discussion.","detailEn":"JASM Fab 2 in Kikuyo, Kumamoto broke ground on 28 October 2025 with a total investment of USD 13.9 billion. Originally targeting 6–7 nm chips, TSMC and the Japanese government are actively discussing an upgrade to 3 nm to better serve automotive and AI customers. Heavy machinery was removed in late 2025, suggesting a timing adjustment, with mass production still targeted around 2027.","progress":"2025年10月底正式动工，总投资约139亿美元，规划6nm制程（业界传闻拟跃升至2nm），目标2027年底投产。"},
  {"id":4620,"name":"Rapidus千岁IIM-1 2nm先进晶圆厂","en":"Rapidus Chitose IIM-1 2nm GAA Advanced Foundry","country":"日本","region":"东亚","cat":"ci","coord":[141.63,42.82],"cap":"2nm GAA试产→量产（2027目标）","inv":76,"invText":"政府补贴约8000亿日元+私人融资","status":"在建","year":2027,"updated":"2026-06","owner":"Rapidus（丰田、索尼、NTT等8社出资）","flagship":true,"desc":"Rapidus千岁2nm晶圆厂，2025年7月首次成功生产2nm GAA晶体管。","detail":"Rapidus IIM-1位于北海道千岁市，2023年9月破土动工，2025年中洁净室启动，ASML EUV极紫外曝光机安装完成。2025年7月首次制备出2nm GAA（环栅）晶体管并展出300mm样品晶圆，实现日本半导体界重大里程碑。日本政府累计已拨付或追加约8000亿日元补贴；2026年2月又获私人股权融资约2670亿日元，目标2027年量产。","descEn":"Rapidus IIM-1 in Chitose, Hokkaido achieved first 2nm GAA transistors in July 2025 — Japan's biggest semiconductor comeback milestone.","detailEn":"Rapidus' IIM-1 fab in Chitose, Hokkaido transitioned from construction to pilot production in mid-2025 after activating its cleanroom and installing ASML EUV tools. In July 2025, it successfully fabricated 2nm gate-all-around (GAA) transistors and displayed a 300 mm prototype wafer — a historic milestone for Japan's chip industry. Government subsidies total ~¥800 billion; a private funding round of ¥267.6 billion closed in February 2026. Mass production is targeted for 2027.","progress":"2025年7月实现2nm GAA晶体管首次制备，洁净室已启动，EUV机台安装完成，试产进行中。"},
  {"id":4621,"name":"松下-斯巴鲁群马EV电池超级工厂","en":"Panasonic Energy – Subaru Gunma EV Battery Gigafactory","country":"日本","region":"东亚","cat":"ci","coord":[139.32,36.39],"cap":"16 GWh/年（2030年产能目标）","inv":32,"invText":"约4630亿日元（约32亿美元）","status":"规划","year":2028,"updated":"2026-06","owner":"松下能源、斯巴鲁","flagship":false,"desc":"松下-斯巴鲁联合在群马大泉建全球领先次世代圆柱电池工厂，2028年量产。","detail":"松下能源与斯巴鲁2024年9月宣布在日本群马县大泉町联合建设动力电池工厂，生产松下新一代4680圆柱锂电池，规划产能2030年达16GWh/年，供应斯巴鲁BEV车型，量产计划从2028财年（2028年4月起）开始。总投资约4630亿日元（约32亿美元），日本政府另提供约350亿日元补贴。","descEn":"Panasonic Energy and Subaru to co-build a 16 GWh/yr 4680-cell EV battery gigafactory in Oizumi, Gunma, starting mass production FY2028.","detailEn":"Announced in September 2024, the Panasonic Energy–Subaru joint gigafactory in Oizumi, Gunma will produce next-generation 4680 cylindrical lithium-ion cells with a target capacity of 16 GWh/yr by 2030. Investment is approximately ¥463 billion (~USD 3.2 billion) with government subsidies of ~¥35 billion. Mass production is scheduled from FY2028 (April 2028) to supply Subaru's upcoming BEV lineup.","progress":"2024年9月签署合作协议，群马大泉工厂选址确定，规划建设期2025–2028年，2028财年量产。"},
  {"id":4622,"name":"微软日本AI数据中心10亿美元及后续扩展","en":"Microsoft Japan AI Data Center — $2.9B then $10B Expansion","country":"日本","region":"东亚","cat":"datacenter","coord":[139.69,35.68],"cap":"Azure Japan East/West GPU扩容，面向AI主权云","inv":129,"invText":"2024年$29亿+2026年$100亿（累计约$129亿）","status":"在建","year":2026,"updated":"2026-06","owner":"微软（Microsoft）","flagship":true,"desc":"微软日本AI算力基础设施，2024年$29亿，2026年追加$100亿，日本最大云投资。","detail":"微软2024年4月宣布在日本投资29亿美元（2年期），用于在东京（Azure Japan East）和大阪（Azure Japan West）两大数据中心部署最新AI GPU，并在东京开设首个Microsoft Research Asia实验室。2026年4月追加宣布100亿美元投资计划，聚焦主权AI云、网络安全与人才培训，成为日本有史以来最大的单笔云/AI基础设施投资承诺。","descEn":"Microsoft commits $2.9B (2024) + $10B (2026) to AI cloud infrastructure in Japan — the country's largest-ever tech investment.","detailEn":"Microsoft invested USD 2.9 billion in Japan in April 2024 (two-year programme) to upgrade Azure Japan East (Tokyo) and Azure Japan West (Osaka) with the latest AI GPUs, and opened Microsoft Research Asia Tokyo focused on embodied AI and robotics. In April 2026, Microsoft deepened its commitment with an additional USD 10 billion pledge for sovereign AI cloud, cybersecurity infrastructure and workforce development — the largest single tech investment in Japan's history.","progress":"2024年$29亿已执行，GPU部署推进中；2026年4月宣布追加$100亿，建设周期延续至2030年代。"},
  {"id":4623,"name":"韩国蔚山漂浮式海上风电集群（Haewoori 1.5GW）","en":"Korea Ulsan Floating Offshore Wind Cluster — Haewoori 1.5 GW (CIP)","country":"韩国","region":"东亚","cat":"renewable","coord":[129.8,35.1],"cap":"1500 MW（漂浮式，蔚山近海约80km）","inv":265,"invText":"约$265亿（预估）","status":"规划","year":2028,"updated":"2026-06","owner":"Copenhagen Infrastructure Partners (CIP)、Copenhagen Offshore Partners","flagship":true,"desc":"韩国蔚山漂浮式1.5GW风电，2025年11月获海上交通安全评估批准，开发推进中。","detail":"Haewoori海上风电项目位于蔚山海岸约80公里处，装机1500MW，由哥本哈根基础设施合伙人（CIP）通过其旗舰基金开发，与Copenhagen Offshore Partners合作。2025年11月获韩国海洋水产部《海上交通安全评估》批准，是全球最大规划中漂浮式海上风电之一。蔚山漂浮式集群总容量约6.2GW，分4个独立项目推进，预计2028年商业运营。投资规模估计超265亿美元。","descEn":"Haewoori 1.5 GW floating offshore wind off Ulsan, South Korea — MTSA approved November 2025, part of the 6.2 GW Ulsan cluster.","detailEn":"Haewoori Offshore Wind (1,500 MW floating) is located ~80 km off Ulsan, developed by CIP's Flagship Fund with Copenhagen Offshore Partners. In November 2025, it secured South Korea's Marine Traffic Safety Assessment approval from the Ministry of Oceans and Fisheries — a major regulatory milestone. Part of the broader 6.2 GW Ulsan floating wind cluster, phased construction is planned from 2025 with full commercial operation in 2028. Estimated investment exceeds USD 26.5 billion across the cluster.","progress":"2025年11月获《海上交通安全评估》批准，FEED合同已授予Principle Power和Aker Solutions。"},
  {"id":4624,"name":"韩国全罗南道全南1号（Jeonnam 1）96MW海上风电","en":"South Korea Jeonnam 1 Offshore Wind Farm (96 MW)","country":"韩国","region":"东亚","cat":"renewable","coord":[125.78,34.9],"cap":"96 MW（10台×Siemens Gamesa SG 10.0-193）","inv":6,"invText":"约6–7亿美元","status":"投运","year":2025,"updated":"2026-06","owner":"SK Innovation E&S、Copenhagen Infrastructure Partners","flagship":false,"desc":"韩国最大民营主导海上风电，全罗南道96MW，2025年5月全容量投运。","detail":"项目位于全罗南道新安郡在元岛附近9公里海域，装机96MW（10台西门子歌美飒SG 10.0-193型机组），由SK Innovation E&S与哥本哈根基础设施合伙人联合开发，建设起于2023年初，2025年5月完成全容量投运。预计年发电量3.01亿千瓦时，供应约9万韩国家庭用电，是韩国首个采用无追索权项目融资的大型海上风电项目。","descEn":"South Korea's largest private-sector offshore wind (96 MW, Sinan, Jeonnam) entered full commercial operation in May 2025.","detailEn":"Located 9 km from Jaeundo Island, Sinan County, Jeonnam, the 96 MW Jeonnam 1 project is a JV between SK Innovation E&S and Copenhagen Infrastructure Partners. Construction began early 2023, all 10 Siemens Gamesa SG 10.0-193 DD turbines were installed by December 2024, and full commercial operation was achieved in May 2025. Expected annual output: 301 million kWh (90,000 households). It pioneered non-recourse project financing for Korean offshore wind.","progress":"2025年5月全容量并网商业运营，是韩国迄今最大民营主导海上风电项目。"},
  {"id":4625,"name":"SK海力士龙仁半导体集群一号厂（M16X系列）","en":"SK Hynix Yongin Semiconductor Cluster Fab 1 (M16X)","country":"韩国","region":"东亚","cat":"ci","coord":[127.2,37.24],"cap":"HBM4 / 1c DRAM / 先进存储（月产约10万片）","inv":215,"invText":"一号厂约310亿韩元→约215亿美元","status":"在建","year":2027,"updated":"2026-06","owner":"SK海力士","flagship":true,"desc":"SK海力士龙仁全球最大半导体集群一号厂2025年2月破土，2027年投产。","detail":"SK海力士龙仁半导体集群位于京畿道龙仁市元三面，规划建设4座尖端晶圆厂（总产值超600万亿韩元），2025年2月25日一号厂正式破土动工。一号厂投资约31万亿韩元（约215亿美元），主攻HBM4和1c DRAM制程，洁净室开放时间从2027年5月提前至2月，2030年达满产。2026年2月SK海力士追加批准本期21.6万亿韩元设备投资，总计约150亿美元。","descEn":"SK Hynix broke ground on Yongin Cluster Fab 1 (Feb 2025) — world's largest semiconductor campus targeting HBM4 and 1c DRAM by 2027.","detailEn":"SK Hynix's Yongin Semiconductor Cluster in Wonsam-myeon, Yongin, Gyeonggi Province will house four state-of-the-art fabs on a 4.15 million m² site. Fab 1 broke ground on 25 February 2025 with a total investment of ~KRW 31 trillion (~USD 21.5 billion). Targeting HBM4 and 1c DRAM, cleanroom opening was advanced from May to February 2027. In February 2026, SK Hynix's board approved an additional KRW 21.6 trillion in equipment investment for Fab 1.","progress":"2025年2月25日正式破土，洁净室开放提前至2027年2月，2026年2月追加设备投资审批。"},
  {"id":4626,"name":"三星平泽P5存储超级工厂（HBM4 / 1c DRAM）","en":"Samsung Pyeongtaek P5 Memory Mega-Fab (HBM4 / 1c DRAM)","country":"韩国","region":"东亚","cat":"ci","coord":[127.04,37],"cap":"3层×6间洁净室（1c DRAM + HBM4 旗舰产线）","inv":760,"invText":"P5+P5-2合计约160万亿韩元（≈$1080亿）","status":"在建","year":2028,"updated":"2026-06","owner":"三星电子","flagship":true,"desc":"三星P5超级工厂2025年重启建设并提速，160万亿韩元投资，2028年HBM4量产。","detail":"三星电子平泽P5工厂（第二园区）规模达650m×195m、三层共6间洁净室，计划2028年开始HBM4和1c DRAM量产；P5与双生的P5-2合计投资160万亿韩元（约1080亿美元），是三星史上最大单一厂区投资。2025年底至2026年初三星加速清洁室建设，将HBM4量产节奏提前约6个月。","descEn":"Samsung's Pyeongtaek P5 — a ₩160T HBM4/1c DRAM mega-fab — accelerated by 6 months, targeting 2028 mass production.","detailEn":"Samsung's P5 fab at Pyeongtaek Campus 2 spans 650 m × 195 m with three floors and six cleanrooms, targeting HBM4 and 1c DRAM production starting 2028. Together with the identical P5-2 twin facility, total investment is KRW 160 trillion (~USD 108 billion), the largest single-site semiconductor investment globally. In late 2025 to early 2026, Samsung accelerated cleanroom shell construction, advancing HBM4 mass production by ~6 months to stay competitive with SK Hynix.","progress":"2025年底加速清洁室建设，HBM4量产节点提前6个月，2026年3月进一步扩大施工规模。"},
  {"id":4627,"name":"奥尤陶勒盖地下矿Panel 0+Panel 2量产爬坡","en":"Oyu Tolgoi Underground Mine — Panel 0 & Panel 2 Production Ramp-Up","country":"蒙古","region":"东亚","cat":"mining","coord":[106.85,42.66],"cap":"目标2028–2036年均50万吨/年铜","inv":70,"invText":"地下矿累计投资逾$70亿","status":"在建","year":2028,"updated":"2026-06","owner":"Rio Tinto（51%）、Turquoise Hill→蒙古国Erdenes OT（49%）","flagship":true,"desc":"奥尤陶勒盖地下矿Panel 0&2进入量产爬坡，2026年铜产量80–87万吨。","detail":"奥尤陶勒盖矿山位于蒙古国南戈壁省，由力拓（Rio Tinto）与蒙古国政府合营，是全球最大在建铜矿之一。Panel 0已于2023年正式开采，Panel 2 South（在Entrée合资区外）从2025年起加速开发；Panel 1（Entrée合资区）因许可证转让问题暂停，资源重新部署至Panel 2 South。力拓2025年铜产量目标780–850万吨（含矿山整体），2026年目标800–870万吨。地下矿累计投资超70亿美元，2028年后可达50万吨/年铜峰值产量。","descEn":"Oyu Tolgoi underground (Panel 0 & 2) ramps toward 500 kt/yr peak copper by 2028; Panel 2 South accelerated after Entree JV pause.","detailEn":"Located in South Gobi, Mongolia, the Oyu Tolgoi underground mine (Rio Tinto 51%, Mongolian state 49%) is one of the world's largest copper-gold deposits. Panel 0 is in full production; Panel 2 South is being accelerated following a pause in Panel 1 work due to licence transfer issues with Entrée Resources. Cumulative underground investment exceeds USD 7 billion. Rio Tinto targets 800–870 kt of copper output in 2026 (mine-wide), with underground capacity reaching ~500 kt/yr from 2028 to 2036.","progress":"2025年5月刷新月度产量纪录，Panel 2 South加速开发以弥补Panel 1暂停影响，2026年铜产量目标800–870万吨。"},
  {"id":4628,"name":"塔本陶勒盖博尔泰格焦煤区块国际开发招标","en":"Tavan Tolgoi Borteeg Coking Coal Block International Development Tender","country":"蒙古","region":"东亚","cat":"mining","coord":[105.63,43.73],"cap":"最低年产1500万吨焦煤，储量4.24亿吨","inv":60,"invText":"投资者首付≥$5亿，预计总投资$50–70亿","status":"规划","year":2028,"updated":"2026-06","owner":"蒙古国国家能源控股（Erdenes Tavan Tolgoi）","flagship":false,"desc":"蒙古塔本陶勒盖博尔泰格区块1500万吨焦煤项目，2025年底启动国际招标。","detail":"博尔泰格区块是塔万陶勒盖煤矿的核心储量区，焦煤资源储量4.24亿吨，蒙古国计划以国际公开招标方式引进战略投资者（要求首付款不低于5亿美元）。2025年底更新了综合可行性研究，要求开采综合体最低年产能1500万吨，已于2025–2026年启动正式国际招标程序，建设期预计2–3年，意向投资方包括中、澳、欧多方财团。","descEn":"Mongolia's Tavan Tolgoi Borteeg 424 Mt coking coal block invites international tender (≥$500M upfront, 15 Mt/yr) — opened 2025–2026.","detailEn":"The Borteeg block at Tavan Tolgoi holds 424 million tonnes of premium coking coal reserves. Erdenes Tavan Tolgoi updated the integrated feasibility study in late 2025 and launched an international tender requiring at least USD 500 million upfront and a minimum 15 million tonne/year mining capacity. Bidders include consortia from China, Australia and Europe. Development timeline: 2–3 years to first coal, targeting commissioning around 2028.","progress":"2025年底完成可行性研究更新，2026年推进国际招标；蒙古国月度煤炭销售量已达140万吨创纪录水平。"},
  {"id":4629,"name":"中国石油江苏LNG接收站四期扩建","en":"CNPC Jiangsu LNG Terminal Phase 4 Expansion","country":"中国","region":"东亚","cat":"petro","coord":[121.18,31.75],"cap":"新增年接卸325万吨，新增气化外输1750万方/天","inv":20,"invText":"约140亿元","status":"在建","year":2027,"updated":"2026-06","owner":"中石油（PetroChina）","flagship":false,"desc":"中石油江苏LNG四期扩建，新增325万吨年接卸能力和20万方储罐。","detail":"中石油江苏如东LNG接收站四期扩建项目已于2025年正式启动，规划新增年接卸能力325万吨，新增储罐容积20万立方米，新增气化外输能力1750万立方米/天，投资约140亿元。四期建成后，该接收站将成为华东地区储气规模最大的LNG接收站之一，进一步增强华东天然气安全保障。","descEn":"CNPC's Phase 4 expansion of Jiangsu LNG terminal adds 3.25 Mt/yr capacity and 200,000 m³ storage — started 2025.","detailEn":"PetroChina's Jiangsu LNG receiving terminal Phase 4 expansion, launched in 2025, adds 3.25 million tonnes/year of LNG unloading capacity and 200,000 m³ of additional tank storage, boosting daily regasification by 17.5 million m³. Investment is ~RMB 14 billion. Once complete, the station becomes one of East China's largest LNG hubs, significantly bolstering regional gas supply security.","progress":"四期扩建项目2025年正式启动建设，预计2027年建成投产。"},
  {"id":4630,"name":"山东海阳核电三期（7、8号机组）","en":"Shandong Haiyang Nuclear Power Plant Phase 3 (Units 7 & 8)","country":"中国","region":"东亚","cat":"nuclear","coord":[121.18,36.68],"cap":"2×1250 MW（国和一号CAP1400）","inv":99,"invText":"约350亿元/台，两台合计约700亿元","status":"规划","year":2032,"updated":"2026-06","owner":"国家电投集团","flagship":false,"desc":"海阳核电三期采用CAP1400国和一号，山东2026年计划开工。","detail":"海阳核电三期（7、8号机组）由国家电投集团开发，位于山东省烟台市海阳市，采用中国自主研发的CAP1400（国和一号）大型压水堆技术。山东省2026年政府工作报告明确计划开工建设海阳核电三期，两台机组投资合计约700亿元，预计2032年前后投运，将成为山东省最大核电基地，也是国和一号在国内规模化应用的重要示范。","descEn":"Shandong Haiyang NPP Phase 3 (2×CAP1400 'Guohe One') planned to break ground in 2026, ~RMB 70 billion investment.","detailEn":"Haiyang NPP Phase 3 (Units 7 & 8) will deploy two CAP1400 ('Guohe One') reactors in Haiyang, Shandong, developed by State Power Investment Corporation. Shandong's 2026 government work report listed it as a planned construction start, with ~RMB 70 billion in combined investment. Estimated commercial operation around 2032, it will become Shandong's largest nuclear base and a key showcase for the domestic CAP1400 technology.","progress":"列入山东省2026年政府工作报告，计划2026年开工建设。"},
  {"id":4631,"name":"华电兴安盟风电制绿色甲醇项目（金风-华电）","en":"Huadian Xing'an League Wind-to-Green Methanol Project","country":"中国","region":"东亚","cat":"renewable","coord":[122.05,46.08],"cap":"725MW风电 / 年产绿色甲醇72.5万吨","inv":50,"invText":"约360亿元","status":"在建","year":2026,"updated":"2026-06","owner":"金风绿能化工（兴安盟）有限公司（金风科技+华电）","flagship":false,"desc":"内蒙古兴安盟风电-绿色甲醇一体化，2026年72.5万吨产能建成。","detail":"项目由金风科技与华电集团联合投资，位于内蒙古兴安盟，规划风电装机725MW，配套电解水制氢及绿色甲醇合成装置，2026年建成72.5万吨/年绿色甲醇产能，2027年底达145万吨/年满产。总投资约360亿元，所产绿甲醇可用于船舶航运燃料及化工原料替代，是内蒙古新能源制绿色燃料的龙头示范工程。","descEn":"Goldwind-Huadian wind-to-green-methanol project in Xing'an League, Inner Mongolia — 72.5 kt/yr methanol by 2026, 145 kt/yr by 2027.","detailEn":"Located in Xing'an League, Inner Mongolia, this project combines 725 MW of wind power with green hydrogen electrolysis and methanol synthesis. Developed by Goldwind Green Energy Chemical (Inner Mongolia) — a JV of Goldwind and Huadian — it targets 72.5 kt/yr of green methanol by 2026 and 145 kt/yr by end-2027. Total investment ~RMB 36 billion. The green methanol is targeted at marine fuel and chemical feedstock markets.","progress":"在建中，2026年完成一期72.5万吨产能建设，2027年底全量145万吨/年投产。"},
  {"id":4632,"name":"新疆哈密1350MW光伏+150MW光热一体化储能项目","en":"Xinjiang Hami 1350 MW PV + 150 MW CSP Integrated Storage Project","country":"中国","region":"东亚","cat":"renewable","coord":[93.4,42.8],"cap":"1350 MW光伏 + 150 MW塔式光热","inv":9,"invText":"总投资约65亿元（6.5亿美元）","status":"在建","year":2027,"updated":"2026-06","owner":"中国能源建设集团等","flagship":false,"desc":"哈密光热光伏储能一体化，全球最大单期光热光伏储能集成项目。","detail":"项目位于新疆哈密市，2026年4月开工，总装机光伏1350MW、塔式光热150MW，配套储能，总投资约65亿元。该项目被规划方称为全球最大单期光热光伏储能一体化项目。光热部分采用定日镜+熔盐储热技术，可实现光热电站连续发电，配合光伏提供高质量稳定电力，有效解决哈密新能源外送波动问题。","descEn":"Xinjiang Hami 1,350 MW PV + 150 MW tower CSP integrated storage project broke ground April 2026 — claimed world's largest single-phase PV-CSP combo.","detailEn":"Located in Hami, Xinjiang, this project combines 1,350 MW of photovoltaic with a 150 MW molten-salt tower CSP plant and integrated storage system. Groundbreaking was held in April 2026 with a total investment of ~RMB 6.5 billion. Developers describe it as the world's largest single-phase PV-CSP-storage integrated project. The CSP component enables dispatchable generation, addressing the transmission stability challenge for Xinjiang's massive renewable export.","progress":"2026年4月正式开工，建设期约2年，预计2027–2028年建成投产。"},
  {"id":4633,"name":"AWS日本AI数据中心$152亿投资计划","en":"AWS Japan $15.2 Billion AI Data Center Investment","country":"日本","region":"东亚","cat":"datacenter","coord":[135.5,34.68],"cap":"AWS日本多区域AI/云算力基础设施扩容","inv":152,"invText":"约$152亿（至2027年）","status":"在建","year":2027,"updated":"2026-06","owner":"亚马逊（Amazon Web Services）","flagship":true,"desc":"AWS承诺在日本投资$152亿，打造最大AI云基础设施，聚焦大阪/东京。","detail":"亚马逊网络服务（AWS）宣布在日本（主要包括大阪和东京两大区域）投资约152亿美元，用于AI和云基础设施建设，是日本有史以来规模最大的外资科技投资之一。投资周期至2027年，涵盖新建数据中心园区、AI GPU集群部署、主权云能力建设，以及与NTT等本地合作伙伴的Oracle Alloy部署。","descEn":"AWS commits $15.2 billion to AI and cloud data centers in Japan (Osaka + Tokyo) through 2027 — Japan's largest-ever foreign tech investment.","detailEn":"Amazon Web Services committed USD 15.24 billion to Japan through 2027, primarily expanding its Osaka (AP-Northeast-3) and Tokyo (AP-Northeast-1) regions with new AI GPU deployments, data center campuses and sovereign cloud capabilities. This is Japan's largest-ever single foreign tech infrastructure commitment, supporting Japan's national AI strategy and digital economy growth.","progress":"2024年宣布$152亿投资计划，大阪和东京两大区域建设全面推进，涵盖AI GPU集群部署。"},

  // ===== 东南亚（4750-4786）=====
  {"id":4750,"name":"仁川3&4号LNG气电联合项目（越南）","en":"Nhon Trach 3 & 4 LNG-to-Power Plant","country":"越南","region":"东南亚","cat":"petro","coord":[106.9,10.85],"cap":"1,624 MW","inv":14,"invText":"约14亿美元","status":"投运","year":2025,"updated":"2026-06","owner":"越南石油天然气集团（PV Power）","flagship":true,"desc":"越南首座LNG气电联合电站，2025年底投入商业运营","detail":"位于越南同奈省大福公社翁桥工业园区，总装机1,624 MW，采用GE 9HA.02高效燃气轮机，总投资约14亿美元。由越南石油天然气集团旗下PV Power建设，2025年12月14日由总理范明政出席竣工典礼。3号机组2025年2月并网，4号机组2025年6月并网，是越南PDP8清洁能源战略的首个LNG里程碑项目。","descEn":"Vietnam's first LNG-to-power plant complex, commercially operational by end-2025.","detailEn":"Located in Ong Keo Industrial Park, Dong Nai Province, the twin-unit complex has a combined capacity of 1,624 MW using GE 9HA.02 gas turbines with 62–64% efficiency. Developed by PV Power (Petrovietnam subsidiary) at a total investment of ~$1.4 billion. Unit 3 was grid-connected on February 5, 2025, and Unit 4 on June 27, 2025; the inauguration ceremony was held on December 14, 2025. It is Vietnam's first LNG-fired power project and a flagship milestone under the revised PDP8.","progress":"2025年12月14日正式投产，年发电量超90亿千瓦时"},
  {"id":4751,"name":"印尼坦古UCC天然气与碳封存项目","en":"Tangguh Ubadari CCUS & Compression (UCC) Project","country":"印度尼西亚","region":"东南亚","cat":"petro","coord":[133.5,-2.3],"cap":"约300亿标准立方英尺额外气产能 / 封存15MtCO₂","inv":70,"invText":"约70亿美元","status":"在建","year":2028,"updated":"2026-06","owner":"BP（运营商）、三菱商事、Inpex、中海油、MI Berau B.V.","flagship":true,"desc":"印尼首个大规模CCUS项目，BP主导，投资70亿美元","detail":"位于巴布亚省宾图尼湾，是坦古LNG设施的扩建工程，涵盖乌巴达里新气田开发、在线压缩和CO₂捕集封存（CCUS），解锁约3万亿标立英尺额外储量并可封存初期约1,500万吨CO₂。BP于2024年11月获最终投资决定（FID），总投资约70亿美元，首阶段预计2028年投产，是东南亚规模最大的CCUS项目。","descEn":"Indonesia's first utility-scale CCUS project, part of the Tangguh LNG expansion in Papua Barat, sanctioned by BP in November 2024.","detailEn":"Located in Bintuni Bay, Papua Barat, this $7 billion project covers development of the Ubadari gas field, enhanced gas recovery via CCUS, and onshore compression to extend field life. It will sequester ~15 million tonnes of CO₂ in Phase 1 and unlock ~3 tcf of additional reserves. Partners include BP (operator), Mitsubishi Corporation, Inpex, CNOOC, and MI Berau B.V. FID was taken in November 2024; first production is targeted for 2028.","progress":"2024年11月FID，工程设计阶段进行中，2028年投产"},
  {"id":4752,"name":"印尼茂力卡电池HPAL镍湿法冶炼厂（SLNC）","en":"Sulawesi Nickel Cobalt (SLNC) HPAL Plant – Merdeka Battery / IMIP Morowali","country":"印度尼西亚","region":"东南亚","cat":"mining","coord":[121.65,-2.05],"cap":"年产90,000吨含镍MHP","inv":18,"invText":"约18亿美元","status":"在建","year":2026,"updated":"2026-06","owner":"Merdeka Battery Materials（MBMA）、PT Sulawesi Nickel Cobalt（SLNC）","flagship":false,"desc":"印尼茂物工业园最新HPAL镍厂，18亿美元，2025年开工","detail":"位于苏拉威西省摩罗瓦利工业园（IMIP），紧邻现有华越镍钴HPAL厂，规划年产9万吨镍当量MHP（混合氢氧化物沉淀物）。Merdeka Battery Materials旗下SLNC公司于2025年2月完成14亿美元融资并开工，总投资约18亿美元，预计18个月内完成调试，是印尼第六座HPAL工厂，进一步巩固其在全球EV电池镍供应链的地位。","descEn":"A new 90,000 t/yr MHP HPAL plant at Indonesia's Morowali Industrial Park, financed by Merdeka Battery Materials at $1.8 billion, construction started January 2025.","detailEn":"Located within IMIP, Morowali, Central Sulawesi, adjacent to the existing HNC HPAL plant. PT Sulawesi Nickel Cobalt (SLNC), majority-owned by Merdeka Battery Materials (MBMA), secured $1.4 billion in non-recourse financing from six Indonesian and Thai banks in February 2025 and commenced construction. Target capacity is 90,000 tonnes of nickel-in-MHP per annum; commissioning is expected within 18 months of start, making it Indonesia's sixth HPAL plant.","progress":"2025年1月开工，2026年中预计进入调试阶段"},
  {"id":4753,"name":"印尼芝拉塔漂浮光伏二期扩建","en":"Cirata Floating Solar PV Phase 2 Expansion","country":"印度尼西亚","region":"东南亚","cat":"renewable","coord":[107.35,-6.72],"cap":"扩建至500 MW（现有145 MWac基础上新增约355 MW）","inv":5,"invText":"约5亿美元（估算）","status":"规划","year":2027,"updated":"2026-06","owner":"Masdar（阿联酋）、PT PLN NP（国家电力公司）","flagship":false,"desc":"东南亚最大漂浮光伏扩建至500MW，利用芝拉塔水库","detail":"位于西爪哇省芝拉塔水库，一期145 MWac（192 MWp）已于2023年11月投运并成为东南亚最大漂浮光伏。2023年9月Masdar与PLN签署谅解备忘录，计划将装机扩至500 MW，利用印尼公共工程部将水面覆盖率上限提至20%的新政策，水库理论最大潜力达1.2 GW峰值。扩建二期具体建设时间仍在推进中。","descEn":"Expansion of Southeast Asia's largest floating solar plant on the Cirata Reservoir in West Java, from 145 MWac to 500 MW, under a Masdar–PLN partnership.","detailEn":"The original 145 MWac (192 MWp) Cirata FPV plant was inaugurated in November 2023 as SEA's largest floating solar site. In September 2023, Masdar and PLN NP signed an MOU to develop Phase 2, tripling capacity to ~500 MW. A 2023 regulatory change allows up to 20% water coverage for renewables, unlocking up to 1.2 GW theoretical potential on the reservoir. Detailed engineering and permitting for Phase 2 are in progress.","progress":"2023年MOU签署，印尼公共工程部新规为扩建解除政策障碍"},
  {"id":4754,"name":"印尼PLN阳光努山塔拉1.2GW太阳能招标（Mentari Nusantara I）","en":"PLN Mentari Nusantara I – 1.225 GW Solar Bundle Tender","country":"印度尼西亚","region":"东南亚","cat":"renewable","coord":[116.5,-2.5],"cap":"1,225 MW（多省分布）","inv":12,"invText":"约12亿美元（估算）","status":"规划","year":2029,"updated":"2026-06","owner":"PT PLN（印尼国家电力公司）","flagship":false,"desc":"印尼最大单次太阳能招标，1.2GW分布于爪哇等多省","detail":"印尼国家电力公司于2026年4月30日启动『Mentari Nusantara I』招标，采用GIGA ONE整合采购模式，一次性捆绑1,225 MW太阳能项目，覆盖爪哇（600 MW）、加里曼丹（340 MW）、东部地区马鲁古与巴布亚（120 MW）、西努沙登加拉（80 MW）、苏拉威西（50 MW）和苏门答腊（35 MW），目标2029年全部投运，是印尼落实百吉瓦太阳能计划的重要举措。","descEn":"Indonesia's largest single solar procurement program, bundling 1,225 MW across six regions under the PLN 'GIGA ONE' model, launched April 2026 with all projects targeting COD by 2029.","detailEn":"PLN launched the Mentari Nusantara I tender on April 30, 2026 using the GIGA ONE integrated procurement framework. Capacity is distributed across Java (600 MW), Kalimantan (340 MW), eastern regions including Maluku and Papua (120 MW), West Nusa Tenggara (80 MW), Sulawesi (50 MW), and Sumatra (35 MW). All projects must reach commercial operation by 2029. The program aims to strengthen Indonesia's domestic clean energy supply chain and advance the government's 100 GW solar target.","progress":"2026年4月30日正式招标，计划2029年全部并网"},
  {"id":4755,"name":"印尼努山塔拉新首都50MW太阳能+储能项目","en":"Nusantara New Capital City Solar + BESS Power Project","country":"印度尼西亚","region":"东南亚","cat":"renewable","coord":[117.1,-0.85],"cap":"50 MW / 14.2 MWh","inv":1,"invText":"约1亿美元（估算）","status":"投运","year":2025,"updated":"2026-06","owner":"PT PLN NP、Sembcorp Industries","flagship":false,"desc":"印尼新首都努山塔拉专用光储项目，东南亚首个可独立供电的新城绿电工程","detail":"位于东加里曼丹省努山塔拉新首都，87公顷场地，装机50 MW太阳能+14.2 MWh电池储能，年发电量约92.8 GWh，是印尼史上首个光储一体化大型项目。由PLN NP与新加坡淡马锡旗下胜科工业合作开发，2025年由普拉博沃总统出席竣工典礼，是努山塔拉100%可再生能源法定目标的标志性工程。","descEn":"A 50 MW solar plus 14.2 MWh BESS project to supply Indonesia's new capital city Nusantara in East Kalimantan, inaugurated in 2025 by President Prabowo.","detailEn":"Located on 87 hectares in the Nusantara Capital Authority zone, East Kalimantan, this co-located solar PV and BESS project is Indonesia's first utility-scale co-located solar-plus-storage system. Developed by PLN NP in partnership with Sembcorp Industries (Temasek-linked), it produces ~92.8 GWh of renewable energy annually. Inaugurated in 2025, it supports the legal mandate for Nusantara to run on 100% renewable electricity and achieve net zero by 2045.","progress":"2025年由普拉博沃总统出席竣工投运"},
  {"id":4756,"name":"印尼卢穆巴莱2号地热机组（PGE）","en":"Lumut Balai Unit 2 Geothermal Power Plant (PGE)","country":"印度尼西亚","region":"东南亚","cat":"renewable","coord":[103.6,-4.15],"cap":"55 MW（累计110 MW）","inv":2,"invText":"约2亿美元（含JICA贷款1.55亿美元）","status":"投运","year":2025,"updated":"2026-06","owner":"PT Pertamina Geothermal Energy（PGE）","flagship":false,"desc":"苏门答腊南部地热新机组55MW，2025年6月投运","detail":"位于苏门答腊南部穆阿拉埃尼姆县，是卢穆巴莱地热区2号机组，装机55 MW，使PGE在该区域累计装机达110 MW，全公司地热总装机提升至727.5 MW。由三菱集团、PT维嘉建设和SEPCO III电力建设公司联合EPC实施，获日本国际协力机构JICA资助1.55亿美元，2025年6月29日完成满负荷72小时试运行并正式投运。","descEn":"A new 55 MW geothermal unit at the Lumut Balai site in South Sumatra, commissioned June 29, 2025, bringing PGE's total installed geothermal capacity to 727.5 MW.","detailEn":"Located ~290 km southwest of Palembang at ~1,000 m elevation in Muara Enim and Ogan Komering Ulu regencies, South Sumatra. The EPCC consortium of Mitsubishi Corporation, PT Wijaya Karya, and SEPCO III delivered this unit at a total cost of ~$200 million, partly funded by a $155 million JICA loan. Following 72 consecutive hours of full-load testing, it received its operational eligibility certificate on June 29, 2025.","progress":"2025年6月29日满负荷72小时试运完成，正式投运"},
  {"id":4757,"name":"印尼穆阿拉拉伯2号地热扩建（Supreme Energy）","en":"Muara Laboh Geothermal Unit 2 – Supreme Energy Expansion","country":"印度尼西亚","region":"东南亚","cat":"renewable","coord":[100.85,-1.5],"cap":"80 MW（合计165 MW）","inv":4.9,"invText":"约4.9亿美元","status":"在建","year":2027,"updated":"2026-06","owner":"Supreme Energy Muara Laboh（Supreme Energy+住友商事+Inpex）","flagship":false,"desc":"西苏门答腊地热扩建80MW，4.9亿美元，2027年投运","detail":"位于西苏门答腊省穆阿拉拉伯地热区，在一期85 MW机组基础上扩建80 MW二期，投产后总装机达165 MW，总投资4.9亿美元。项目由Supreme Energy、住友商事和Inpex合资的Supreme Energy Muara Laboh（SEML）开发，2025年1月与包括日本国际协力银行（JBIC）在内的银行团签署贷款协议，已启动6—8口生产及注入井钻探，计划2027年竣工。","descEn":"An 80 MW expansion of the Muara Laboh geothermal facility in West Sumatra, backed by a $490 million investment and JBIC-led financing, under construction since 2025 with 2027 target.","detailEn":"Supreme Energy Muara Laboh (SEML), a JV of Supreme Energy, Sumitomo Corporation, and Inpex, is investing $490 million to add an 80 MW Unit 2 at the Muara Laboh site in West Sumatra, bringing total site capacity to 165 MW. A loan agreement with a bank syndicate led by JBIC was signed on January 10, 2025; a six-to-eight well drilling campaign commenced shortly after. Commercial operation is targeted for 2027.","progress":"2025年1月融资完成，钻井作业启动，2027年预期投产"},
  {"id":4758,"name":"印尼门塔朗印杜克水电站（Mentarang Induk）","en":"Mentarang Induk Hydroelectric Power Plant (MIHEP)","country":"印度尼西亚","region":"东南亚","cat":"renewable","coord":[115.8,3.2],"cap":"1,375 MW","inv":27,"invText":"约27亿美元","status":"规划","year":2030,"updated":"2026-06","owner":"PT Kayan Hydropower Nusantara（AlamTri Resources 50% + Sarawak Energy 25% + PT KPP 25%）","flagship":true,"desc":"北加里曼丹1375MW绿色水电，为铝冶炼产业园供清洁电","detail":"位于北加里曼丹马利瑙县芒塔朗河，装机1,375 MW，大坝坝高235米，水库面积约200平方公里，年发电量约9 TWh，总投资约27亿美元。由AlamTri Resources（原Adaro）、砂拉越能源和PT卡扬帕特里亚合资开发，2025年底—2026年初推进最终融资关闭，建成后主要为北加里曼丹绿色铝冶炼园（KIPI）提供清洁电力。","descEn":"A 1,375 MW run-of-river hydropower project on the Mentarang River in North Kalimantan, targeting financial close in 2026 to supply clean power to the KIPI green aluminium industrial park.","detailEn":"Located in Malinau Regency, North Kalimantan, MIHEP features a 235 m-high CFRD dam, ~200 km² reservoir, and ~9 TWh annual output. The developer is PT Kayan Hydropower Nusantara (KHN), a JV of AlamTri Resources (50%), Sarawak Energy (25%), and PT Kayan Patria Pratama (25%). Total investment is ~$2.7 billion. Financial close is targeted for Q1 2026; full EPC construction will accelerate thereafter, with commercial operation expected around 2029–2030. The project will primarily power the nearby KIPI green aluminium smelter.","progress":"2026年第一季度目标融资关闭，早期进场道路工程已启动"},
  {"id":4759,"name":"印尼北加里曼丹绿色铝冶炼厂（KIPI一期）","en":"KIPI Green Aluminium Smelter Phase 1 – PT Kalimantan Aluminium Industry","country":"印度尼西亚","region":"东南亚","cat":"ci","coord":[117.3,3.5],"cap":"年产50万吨铝锭（一期）","inv":20,"invText":"约20亿美元（一期）","status":"投运","year":2025,"updated":"2026-06","owner":"PT Kalimantan Aluminium Industry（PT KAI）、AlamTri Resources","flagship":false,"desc":"北加里曼丹年产50万吨铝冶炼厂，2025年底首批产出","detail":"位于北加里曼丹布隆干县担南宁卡里曼丹工业园（KIPI），一期规划年产50万吨铝锭，总产能规划150万吨/年（分三期）。PT KAI由AlamTri Resources（原Adaro）主导，一期投资约20亿美元，2025年9月电解槽首批通电，年底进入生产爬坡阶段，2026年初目标满产。目前暂由燃煤电力供电，第三期（预计2029年后）将切换由门塔朗水电清洁供能。","descEn":"Phase 1 of Indonesia's KIPI aluminium smelter in North Kalimantan, with 500,000 t/yr initial capacity; first pot operations commenced in late 2025, ramp-up to full production ongoing.","detailEn":"Located in Tanah Kuning, Bulungan Regency, North Kalimantan, within the Kalimantan Industrial Park Indonesia (KIPI). PT Kalimantan Aluminium Industry (KAI), majority-owned by AlamTri Resources (formerly Adaro Minerals), commenced first pot-line operations in September 2025 and is targeting full Phase 1 production by early 2026 at 500,000 t/yr of aluminium ingots. The Phase 1 investment is ~$2 billion (including power plant and port). Phases 2–3 will add further 500,000 t/yr each, with full renewable power from Mentarang hydropower from ~Phase 3 (~2029).","progress":"2025年9月首批电解槽通电，2026年初目标满产"},
  {"id":4760,"name":"越南北爱一期海上风电（La Gan，CIP）","en":"La Gan Offshore Wind Farm – CIP / Binh Thuan Province","country":"越南","region":"东南亚","cat":"renewable","coord":[108.5,10.8],"cap":"3,500 MW","inv":100,"invText":"约100亿美元","status":"规划","year":2030,"updated":"2026-06","owner":"Copenhagen Infrastructure Partners（CIP）、Asiapetro、Novasia Energy","flagship":true,"desc":"越南最大海上风电规划，3500MW，CIP主导","detail":"位于越南平顺省近海海域，距岸12—40公里，规划装机3,500 MW，占地约600平方公里，预计可为700万户家庭供电，总投资约100亿美元。由丹麦哥本哈根基础设施合作伙伴（CIP）联合越南本地企业开发，是越南PDP8规划中的重点海上风电项目之一，目标2030年竣工，并推动越南本土海上风电供应链建设。","descEn":"Vietnam's largest planned offshore wind farm at 3,500 MW off Binh Thuan Province, led by Copenhagen Infrastructure Partners (CIP) with a ~$10 billion investment, targeting 2030 commissioning.","detailEn":"Situated 12–40 km offshore in Binh Thuan Province's South China Sea waters, La Gan spans ~600 km² and is designed for 3,500 MW. Developed by CIP in partnership with Asiapetro and Novasia Energy, it represents one of Vietnam's flagship offshore wind projects under PDP8. It could power more than 7 million Vietnamese households. With an estimated cost of ~$10 billion, it is expected to catalyse a domestic offshore wind supply chain. Target commissioning: 2030.","progress":"已完成风资源测量，PDP8框架下审批推进中"},
  {"id":4761,"name":"菲律宾布哈文北吕宋2GW漂浮式海上风电","en":"BuhaWind Northern Luzon 2 GW Floating Offshore Wind Farm","country":"菲律宾","region":"东南亚","cat":"renewable","coord":[119.6,18.2],"cap":"2,000 MW","inv":60,"invText":"约60亿美元（估算）","status":"规划","year":2030,"updated":"2026-06","owner":"BuhaWind Energy Philippines（PetroGreen Energy + Copenhagen Energy）、明阳智能","flagship":true,"desc":"菲律宾最大漂浮式海上风电，北伊洛科斯省近海2GW","detail":"位于北伊洛科斯省近海，规划装机2,000 MW，是菲律宾最大漂浮式海上风电项目，由PetroGreen Energy和丹麦Copenhagen Energy合资的BuhaWind开发。2025年5月获菲律宾能源部颁发国家战略意义证书（CEPNS），同年8月取得电网接入批复，11月与中国明阳智能签署合作协议加速推进，目标2030年全容量投运。","descEn":"A 2,000 MW floating offshore wind project off Ilocos Norte, Philippines, developed by BuhaWind (PetroGreen + Copenhagen Energy), backed by government support and grid-connection approval in 2025.","detailEn":"Located offshore Ilocos Norte in northern Luzon, this 2,000 MW floating offshore wind farm is developed by BuhaWind Energy Philippines (a JV of PetroGreen Energy Corporation and Copenhagen Energy). It was awarded the Certificate of Energy of National Significance (CEPNS) by the Philippine DOE in May 2025, secured grid connection approval in August 2025, and signed a collaboration agreement with Mingyang Smart Energy of China in November 2025. Target: full commercial operation by 2030. Estimated investment is ~$6 billion.","progress":"2025年8月电网接入批准，11月与明阳签署合作协议"},
  {"id":4762,"name":"菲律宾马顿抽水蓄能水电站（2000MW）","en":"Maton Pumped Storage Hydropower Project – Apayao","country":"菲律宾","region":"东南亚","cat":"storage","coord":[121.1,18.1],"cap":"2,000 MW","inv":30,"invText":"约300亿比索（约53亿美元）","status":"规划","year":2033,"updated":"2026-06","owner":"Pan Pacific Renewable Power Philippines（PGPC旗下，SM投资集团）","flagship":true,"desc":"菲律宾最大抽水蓄能计划，2000MW，阿帕亚奥省","detail":"位于菲律宾吕宋岛阿帕亚奥省，规划装机2,000 MW，由SM投资集团旗下菲律宾地热生产公司（PGPC）子公司泛太平洋可再生能源菲律宾公司开发。项目已获能源部批准并入菲律宾电力开发计划，被视为应对大规模可再生能源间歇性的关键储能基础设施。菲律宾当局正推动加速抽水蓄能融资，形成合计超50亿美元的抽蓄建设浪潮。","descEn":"Philippines' largest planned pumped storage project at 2,000 MW in Apayao Province, Luzon, developed by Pan Pacific Renewable Power Philippines under SM Investments.","detailEn":"Located in Apayao Province, northern Luzon, the Maton Pumped Storage Hydropower Project is developed by Pan Pacific Renewable Power Philippines Corporation (PGPC subsidiary, an SM Investments group company). With 2,000 MW of capacity, it is the largest proposed pumped-storage project in the Philippines and is integral to balancing the country's growing renewable energy capacity. The Philippine government is fast-tracking pumped-hydro financing, mobilizing a total $5+ billion wave of storage investment.","progress":"已获能源部批准纳入国家电力开发计划，融资及环评推进中"},
  {"id":4763,"name":"菲律宾圣罗克西/圣罗克下东抽水蓄能项目","en":"San Roque West & Lower East Pumped Storage Projects – San Miguel Global Power","country":"菲律宾","region":"东南亚","cat":"storage","coord":[120.67,16.37],"cap":"800 MW × 2（合计1,600 MW）","inv":17,"invText":"约890亿比索（约15亿美元）","status":"规划","year":2032,"updated":"2026-06","owner":"San Roque Hydropower Inc.（San Miguel Global Power旗下）","flagship":false,"desc":"圣米格尔集团双800MW抽水蓄能，班盖特与邦阿西楠省","detail":"由圣米格尔全球电力旗下圣罗克水电公司开发，包含圣罗克西（San Roque West）和圣罗克下东（San Roque Lower East）两个各800 MW抽水蓄能项目，均位于吕宋岛班盖特省与邦阿西楠省交界地带。两个项目总投资约890亿比索（约15亿美元），已向菲律宾环境与自然资源部（DENR）提交申请，计划2032年投运。","descEn":"Two 800 MW pumped storage projects in Benguet and Pangasinan, Philippines, developed by San Roque Hydropower Inc. (San Miguel Global Power), totaling 1,600 MW at ~$1.5 billion investment.","detailEn":"San Roque Hydropower Inc. (SRHI), a unit of San Miguel Global Power, is developing twin 800 MW pumped storage hydropower projects: San Roque West (P46.29 billion) and San Roque Lower East (P42.37 billion), located across Benguet and Pangasinan provinces. Together they form 1,600 MW of pumped storage capacity supporting Philippines' renewable energy integration targets. Both have been submitted to the DENR for environmental review.","progress":"已向DENR提交环境评估，融资结构设计中"},
  {"id":4764,"name":"越南三星半导体测试工厂（太原省）","en":"Samsung Semiconductor Test Plant – Thai Nguyen, Vietnam","country":"越南","region":"东南亚","cat":"ci","coord":[105.87,21.6],"cap":"半导体测试产线，首期约15亿美元","inv":15,"invText":"约15亿美元（首期）","status":"在建","year":2027,"updated":"2026-06","owner":"三星电子（Samsung Electronics）","flagship":false,"desc":"三星越南首座芯片测试工厂，太原省，2027年投产","detail":"位于越南河内北约60公里的太原省工业园区，是三星在越南的首座半导体测试工厂，主要测试存储器芯片。2026年5月由路透社披露，越南当局已于2026年3月批准投资，总投资约15亿美元，并已有200余名三星工程师进驻施工现场，计划2027年11月投产，若效益达标可追加投资至约40亿美元建设第二工厂。","descEn":"Samsung's first semiconductor chip testing plant in Vietnam, located in Thai Nguyen Province, approved in March 2026 with a $1.5 billion initial investment and 2027 start-up target.","detailEn":"Located in an industrial park ~60 km north of Hanoi in Thai Nguyen Province, this is Samsung's first chip testing facility in Vietnam, focused on legacy memory chips. Vietnamese authorities approved the investment in March 2026; over 200 Samsung engineers and staff have been on-site since April 2026. Construction has already begun, with operations targeted for November 2027. Samsung may reinvest profits of up to $2.5 billion for a potential second facility, bringing the total commitment to ~$4 billion.","progress":"2026年3月获批，已开工，2027年11月目标投产"},
  {"id":4765,"name":"越南政府半导体研究与制造基地（河内）","en":"Vietnam National Semiconductor R&D and Fabrication Center – Hanoi","country":"越南","region":"东南亚","cat":"ci","coord":[105.8,21.1],"cap":"晶圆设计、封装测试全产业链","inv":5,"invText":"约5亿美元（政府投入）","status":"在建","year":2030,"updated":"2026-06","owner":"越南政府（国家出资）","flagship":false,"desc":"越南国家出资5亿美元建设半导体研发与量产基地","detail":"越南政府计划投入5亿美元在河内建设国家级半导体研究、设计、生产、封装和测试综合基地，工程于2026年1月正式开工，计划2030年投入运营，旨在培育本土半导体产业、配合三星等外资巨头投资，并推动越南成为东南亚半导体产业中心。","descEn":"A $500 million state-funded semiconductor research, design, production, packaging, and testing complex in Hanoi, breaking ground in January 2026 and targeting operations by 2030.","detailEn":"The Vietnamese government is investing $500 million to build a national semiconductor R&D and manufacturing complex in Hanoi to develop a domestic semiconductor industry base. Construction began in January 2026, with the facility slated to be operational by 2030. The initiative complements major foreign investments such as Samsung's new chip testing plant and Intel's existing assembly and test operations, and positions Vietnam as a regional semiconductor hub in Southeast Asia.","progress":"2026年1月正式开工，2030年目标投运"},
  {"id":4766,"name":"泰国AWS东部经济走廊云区域数据中心","en":"AWS Asia Pacific Thailand Region – EEC Data Center","country":"泰国","region":"东南亚","cat":"datacenter","coord":[101.35,13.15],"cap":"三可用区，规划算力超1 GW（2027年）","inv":50,"invText":"约500亿泰铢（约50亿美元，至2037年）","status":"投运","year":2025,"updated":"2026-06","owner":"亚马逊云科技（AWS）","flagship":true,"desc":"AWS泰国云区域2025年1月正式上线，50亿美元长期投资","detail":"AWS亚太（泰国）区域于2025年1月8日正式上线，设有三个可用区，主要位于泰国东部经济走廊（EEC）的乔武里府、罗勇府和恰春骚府。AWS承诺至2037年向泰国投入50亿美元，预计带动GDP增长100亿美元、每年支持1.1万个就业岗位，是2025年泰国吸引超160亿美元数据中心投资潮（同比增长20倍）的核心组成部分。","descEn":"AWS Asia Pacific (Thailand) Region launched January 8, 2025, with three Availability Zones in Thailand's Eastern Economic Corridor (EEC), backed by a $5 billion investment commitment through 2037.","detailEn":"AWS launched its Thailand cloud region on January 8, 2025, with three AZs strategically located in Chonburi, Rayong, and Chachoengsao within the EEC. The company has committed $5 billion through 2037, projected to contribute $10 billion to GDP and support 11,000 jobs annually. This is part of a broader 2025 data center investment wave in Thailand exceeding $16 billion (a 20-fold increase over 2024), alongside Google ($1 billion in Chonburi), TikTok/ByteDance ($8.8 billion), and Microsoft.","progress":"2025年1月正式上线，持续扩建中"},
  {"id":4767,"name":"泰国字节跳动·TikTok数据中心集群","en":"ByteDance / TikTok Thailand Data Center Complex – EEC","country":"泰国","region":"东南亚","cat":"datacenter","coord":[101.1,13],"cap":"多省大规模算力集群（含乔武里、罗勇、恰春骚）","inv":88,"invText":"约880亿泰铢（约88亿美元）","status":"在建","year":2026,"updated":"2026-06","owner":"字节跳动（ByteDance）/ TikTok新加坡运营主体","flagship":true,"desc":"字节跳动泰国数据中心集群，88亿美元为东南亚单笔最大","detail":"字节跳动旗下TikTok于2025年1月获泰国投资委员会批准首期38亿美元投资，同年2月进一步宣布5年累计投入88亿美元，在泰国东部经济走廊（EEC）乔武里、罗勇和恰春骚三府建设大规模数据中心集群，首批设施计划2026年投入运营，是东南亚迄今规模最大的数据中心单体投资。","descEn":"ByteDance/TikTok's $8.8 billion data center investment in Thailand's EEC (Chonburi, Rayong, Chachoengsao), the largest single data center commitment in Southeast Asia, approved in 2025.","detailEn":"ByteDance's Singapore unit received Thailand BOI approval for an initial $3.8 billion data hosting investment on January 29, 2025. On February 28, 2025, ByteDance expanded its commitment to $8.8 billion over five years across three EEC provinces. The first phase is expected to commence operations in 2026, making this the largest single data center investment in Southeast Asia by any company.","progress":"2025年1月首期获批，2026年首批设施投运"},
  {"id":4768,"name":"新加坡SLNG第二LNG接收终端（FSRU）","en":"Singapore Second LNG Terminal (SLNG 2) – FSRU-based","country":"新加坡","region":"东南亚","cat":"petro","coord":[103.7,1.27],"cap":"500万吨/年（合计与一期达1500万吨/年）","inv":20,"invText":"约20亿美元（估算）","status":"在建","year":2029,"updated":"2026-06","owner":"新加坡液化天然气公司（SLNG）、商船三井（MOL）、裕廊港","flagship":false,"desc":"新加坡第二LNG接收站，FSRU模式，2025年10月开工","detail":"由新加坡液化天然气公司（SLNG）主导，采用浮式储存和再气化装置（FSRU）模式，储存容量20万立方米、再气化能力500万吨/年，由韩国韩华海洋建造，商船三井（MOL）负责租赁运营，裕廊港提供码头，Wood承接FEED设计。FEED已于2025年中期完成，FSRU于2025年10月正式开工建造，计划本十年底前投入运营，届时SLNG总接收能力将提升至1,500万吨/年。","descEn":"Singapore's second LNG terminal using a 200,000 m³ FSRU with 5 MTPA regasification capacity, developed by SLNG in partnership with MOL and Jurong Port, construction started October 2025, operational by end of decade.","detailEn":"Singapore LNG Corp (SLNG) is developing a second LNG import terminal at Jurong Island using an FSRU (200,000 m³ storage, 5 MTPA regasification) built by Hanwha Ocean (South Korea) and chartered from a MOL subsidiary. FEED was completed mid-2025; FSRU construction commenced in October 2025. Together with the existing SLNG terminal, the combined throughput capacity will rise to 15 MTPA, enhancing Singapore's energy security.","progress":"2025年10月FSRU开工建造，预计本十年内竣工"},
  {"id":4769,"name":"马来西亚沙巴古达100MW风电（SEC，马来西亚首座）","en":"Sabah Kudat 100 MW Wind Energy Project – Malaysia's First","country":"马来西亚","region":"东南亚","cat":"renewable","coord":[116.85,6.88],"cap":"100 MW","inv":2,"invText":"约2亿美元（估算）","status":"规划","year":2028,"updated":"2026-06","owner":"沙巴能源公司（Sabah Energy Corporation，SEC）","flagship":false,"desc":"马来西亚首座商业风电，沙巴古达100MW，2026年启动建设","detail":"位于马来西亚沙巴州北部古达，规划装机100 MW，由沙巴能源公司（SEC）主导开发，是马来西亚有史以来首座商业规模风电项目，填补了马来西亚可再生能源组合的关键空白。2025年底前完成初步可行性研究，2026年启动详细工程和环境影响评估，预计2028年建成投运，将显著提升沙巴州电网清洁电比例。","descEn":"Malaysia's first utility-scale wind power project at 100 MW in Kudat, Sabah, developed by Sabah Energy Corporation (SEC); construction expected to begin in 2026, targeting commissioning in 2028.","detailEn":"Located in Kudat, northern Sabah, on the northeast coast of Borneo, this 100 MW wind project is developed by Sabah Energy Corporation and is Malaysia's first commercial-scale wind energy project. SEC completed preliminary feasibility assessments by late 2025 covering wind speed profiles and site conditions. Detailed engineering, environmental and social impact studies, and grid connection planning are set to begin in 2026, with commissioning targeted for 2028.","progress":"2025年底完成可行性研究，2026年启动详细设计"},
  {"id":4770,"name":"马来西亚Lumut第三LNG接收终端（RGT-3）","en":"Malaysia Third LNG Regasification Terminal (RGT-3) – Lumut, Perak","country":"马来西亚","region":"东南亚","cat":"petro","coord":[100.63,4.23],"cap":"500百万标准立方英尺/天 / 储存17万立方米","inv":10,"invText":"约10亿美元（估算）","status":"规划","year":2028,"updated":"2026-06","owner":"Petronas Gas、Tenaga Nasional Bhd（TNB）","flagship":false,"desc":"马来西亚第三LNG接收站，霹雳州鲁莫特，2028年投运","detail":"马来西亚国家石油公司（Petronas）宣布在霹雳州鲁莫特建设第三座液化天然气接收终端（RGT-3），采用浮式储存和再气化装置（FSRU）模式，储量17万立方米，日再气化能力达5亿标立英尺，以应对半岛马来西亚天然气需求增长。Petronas Gas与国家能源（TNB）于2026年6月签署项目合作意向协议，最终投资决定预计2025年底前作出，建设期约30个月，预计2028年投运。","descEn":"Malaysia's third LNG regasification terminal (RGT-3) in Lumut, Perak, using FSRU technology (170,000 m³ / 500 MMcfd), developed by Petronas Gas and TNB, FID expected end-2025, operations planned for 2028.","detailEn":"Petronas Gas Bhd and Tenaga Nasional Bhd (TNB) inked a heads of agreement for RGT-3 in June 2026, following the announcement by Petronas CEO at Energy Asia 2025 (June 17, 2025). The FSRU-based terminal will be located in Lumut, Perak, southwest peninsular Malaysia, with 170,000 m³ storage and 500 MMcfd send-out capacity. Final investment decision is expected by end-2025; a 30-month construction period would see operations commence in 2028.","progress":"2026年6月TNB-Petronas Gas签署合作意向，FID待确认"},
  {"id":4771,"name":"老挝琅勃拉邦湄公河干流水电站（1460MW）","en":"Luang Prabang Hydropower Dam – Mekong Mainstream, Laos","country":"老挝","region":"东南亚","cat":"renewable","coord":[102.15,19.85],"cap":"1,460 MW","inv":30,"invText":"约30亿美元","status":"在建","year":2027,"updated":"2026-06","owner":"老挝国家电力公司（EDL）、泰国EGCO集团及泰国合资联合体","flagship":true,"desc":"老挝湄公河干流第三座大坝1460MW，2027年投运","detail":"位于老挝琅勃拉邦省城北约25公里湄公河干流，装机1,460 MW（7×200 MW+60 MW辅机），坝高80米，总投资约30亿美元，由泰国EGCO集团及合作方联合开发，90%电力出口泰国。2025年4月工人拍摄视频显示大坝建设进展迅速，预计2027年首批机组投运，是湄公河下游段最具争议的大坝之一，因涉及对世界遗产城市琅勃拉邦周边生态的潜在影响受到国际关注。","descEn":"A 1,460 MW run-of-river dam on the Mekong mainstream north of Luang Prabang city, under rapid construction and targeting 2027 commissioning, with 90% of power exported to Thailand.","detailEn":"Located ~25 km north of Luang Prabang city on the lower Mekong mainstream, this project features a 80-metre-high, 275-metre-long dam with seven 200 MW generating units plus a 60 MW auxiliary unit. Developed primarily by a Thai consortium led by EGCO Group, it involves a $3 billion total investment. Construction has advanced rapidly since 2022, with rapid progress observed in April 2025. Most power will be sold to EGAT (Thailand) under a long-term PPA. Environmental groups have flagged risks to downstream ecosystems and the UNESCO World Heritage Zone.","progress":"2025年4月大坝建设进展明显加速，2027年目标首批投运"},
  {"id":4772,"name":"老挝北奔湄公河水电站（912MW，大唐）","en":"Pak Beng Hydropower Dam – Mekong Mainstream, Laos (Datang)","country":"老挝","region":"东南亚","cat":"renewable","coord":[101.1,20.22],"cap":"912 MW","inv":20,"invText":"约20亿美元","status":"规划","year":2029,"updated":"2026-06","owner":"大唐（老挝）北奔水电有限公司、泰国EGCO集团","flagship":false,"desc":"湄公河干流912MW北奔大坝，大唐主导，90%电出口泰国","detail":"位于老挝北部湄公河干流，与北奔市相邻，规划装机912 MW，年发电量约4,775 GWh。由大唐集团旗下大唐（老挝）北奔水电有限公司与泰国EGCO集团联合开发，90%电力通过长期购电协议出口泰国，电价协议已签署。需安置约4,700人、700余户。预计2029年前建成发电，是湄公河下游计划中的七座干流大坝之一。","descEn":"A 912 MW run-of-river dam on the Mekong mainstream in northern Laos, developed by Datang (Laos) and EGCO of Thailand; PPA signed, targeting 2029 commissioning, 90% power to Thailand.","detailEn":"Located on the Mekong mainstream adjacent to Pak Beng town in Oudomxay Province, northern Laos, this 912 MW dam (average annual generation: 4,775 GWh) is developed by Datang (Laos) Pak Beng Hydropower Co. and Thailand's EGCO Group. A PPA has been signed for 90% of the output to be sold to EGAT (Thailand). The project requires resettlement of ~4,700 people from over 700 households. One of seven planned mainstream Mekong dams in Laos, it is expected to be operational by 2029.","progress":"电力购售协议已签署，可研推进中，2029年目标投运"},
  {"id":4773,"name":"印尼伯他明那绿氢示范工厂（乌卢贝卢地热）","en":"Pertamina Geothermal Green Hydrogen Pilot Plant – Ulubelu, Lampung","country":"印度尼西亚","region":"东南亚","cat":"renewable","coord":[104.65,-5.4],"cap":"日产约80—100公斤绿氢","inv":0.3,"invText":"约300万美元","status":"在建","year":2026,"updated":"2026-06","owner":"PT Pertamina Geothermal Energy（PGE）","flagship":false,"desc":"全球首个地热驱动绿氢试验项目，楠榜省乌卢贝卢","detail":"位于苏门答腊楠榜省乌卢贝卢地热发电区，是全球首个利用地热电力驱动阴离子交换膜（AEM）电解槽制绿氢的商业验证项目，规划日产绿氢80—100公斤，约80%用于坦戎斯孔LPG码头的燃料电池低碳供能，约20公斤供丰田印尼采购。由Pertamina Geothermal Energy（PGE）投资约300万美元，2025年底奠基开工，计划2026年底投产，被印尼投资部誉为全球首例地热基绿氢项目。","descEn":"World's first geothermal-powered green hydrogen pilot using AEM electrolyser technology at Ulubelu, Lampung, Indonesia; $3 million investment, groundbreaking in late 2025, targeting operations by end-2026.","detailEn":"Located at the Ulubelu geothermal field in Lampung Province, Sumatra, this pilot plant is developed by Pertamina Geothermal Energy (PGE) at a $3 million investment. It uses Anion Exchange Membrane (AEM) electrolyser technology powered by geothermal electricity to produce 80–100 kg/day of green hydrogen. About 80% of output will serve the Tanjung Sekong LPG terminal via fuel cell, while ~20 kg/day is allocated to Toyota Indonesia. Groundbreaking was held in late 2025; target commissioning is end-2026.","progress":"2025年底奠基开工，2026年底目标投产"},
  {"id":4774,"name":"菲律宾PLDT VITRO圣罗沙AI超算数据中心（50MW）","en":"PLDT ePLDT VITRO Sta. Rosa AI-Ready Hyperscale Data Center","country":"菲律宾","region":"东南亚","cat":"datacenter","coord":[121.07,14.28],"cap":"50 MW IT负载（AI-ready）","inv":0.9,"invText":"约50亿比索（约9000万美元）","status":"投运","year":2025,"updated":"2026-06","owner":"ePLDT（PLDT旗下）","flagship":false,"desc":"菲律宾首座AI就绪型超大规模数据中心，圣罗沙50MW","detail":"位于菲律宾拉古纳省圣罗沙，是菲律宾首座也是首个GPU算力即服务（GPUaaS）的AI就绪超大规模数据中心，IT负载容量50 MW。由PLDT旗下ePLDT子公司建设，2024年7月正式投运，由ABB提供电力基础设施，以NVIDIA GPU服务器支撑AI推理与训练工作负载。ePLDT还计划2026年在甲米地省动工建设100 MW的第十二座数据中心（预计耗资约10亿美元），将算力规模提升一倍。","descEn":"Philippines' first AI-ready hyperscale data center at 50 MW in Sta. Rosa, Laguna, operated by ePLDT (PLDT subsidiary), featuring GPU-as-a-Service, launched July 2024; 100 MW VITRO Cavite expansion planned for 2026 groundbreaking.","detailEn":"Located in Sta. Rosa, Laguna, south of Metro Manila, VITRO Sta. Rosa is the Philippines' first AI-ready hyperscale data center with 50 MW IT load, powered by NVIDIA GPUs and featuring the country's first GPUaaS offering. Developed and operated by ePLDT, a subsidiary of PLDT, it commenced operations in July 2024. A $1 billion, 100 MW follow-on facility in Cavite (VITRO-12) is planned to break ground in 2026 with completion targeted for 2028.","progress":"2024年7月投运，VITRO-12（100MW/卡维特）2026年开工"},
  {"id":4775,"name":"马来西亚砂拉越H2ornbill绿氢出口项目","en":"Sarawak H2ornbill Green Hydrogen Export Project","country":"马来西亚","region":"东南亚","cat":"renewable","coord":[113.98,1.55],"cap":"目标年产9万吨绿氢（调整后）","inv":42,"invText":"约42亿美元","status":"规划","year":2030,"updated":"2026-06","owner":"SEDC Energy（砂拉越经发局能源）、ENEOS（日本）、住友商事","flagship":false,"desc":"砂拉越绿氢出口旗舰项目，2025年启动固态氢试验出口","detail":"由砂拉越经济发展局能源公司（SEDC Energy）联合日本ENEOS和住友商事开发，利用砂拉越丰富水电建设大规模绿氢生产与出口设施，原规划年产12万吨，受市场需求信号不足2026年下调规模，目标调整至约9万吨/年。2025年8月SEDC Energy与Hydrexia合作，以镁基固态金属氢化物技术向新加坡出口首批固态绿氢，成为砂拉越绿氢商业化首个里程碑。目标2030年规模出口。","descEn":"Sarawak's flagship green hydrogen export project, developed by SEDC Energy, ENEOS, and Sumitomo Corporation using Sarawak's hydropower; first solid-state green hydrogen exported to Singapore in August 2025.","detailEn":"H2ornbill, led by SEDC Energy (Sarawak Economic Development Corporation's energy arm) with Japan's ENEOS and Sumitomo Corporation, targets producing up to 90,000 t/yr of green hydrogen (scaled down from 120,000 t/yr due to weaker-than-expected demand signals in 2026). The project leverages Sarawak's abundant hydropower base. In August 2025, SEDC Energy exported the first batch of solid-state green hydrogen to Singapore using Hydrexia's magnesium hydride (MHX) technology, marking a commercial milestone. Full-scale operations are targeted for 2030.","progress":"2025年8月首批固态绿氢出口新加坡，规模化出口目标2030年"},
  {"id":4776,"name":"菲律宾GEA-5固定式海上风电计划（3300MW）","en":"Philippines GEA-5 Fixed-Bottom Offshore Wind Programme – 3,300 MW","country":"菲律宾","region":"东南亚","cat":"renewable","coord":[122.5,12.5],"cap":"3,300 MW（2028—2030年分批并网）","inv":140,"invText":"约800亿比索以上（约140亿美元，估算）","status":"规划","year":2030,"updated":"2026-06","owner":"菲律宾能源部（DOE）统筹，多家开发商","flagship":false,"desc":"菲律宾首批3300MW固定式海上风电，2025年6月启动招标","detail":"菲律宾能源部于2025年6月11日正式启动第五批绿色能源拍卖（GEA-5），专注固定桩基海上风电，安装目标3,300 MW，分批于2028—2030年并网。此前GEA-4（2025年11月）还授予了超4.1 GW地面光伏、2.2 GW陆上风电和超1 GW电池储能，合计123个项目10,195 MW可再生能源。GEA-5标志着菲律宾从近岸走向真正意义的海上风电规模化开发，预计总投资超140亿美元。","descEn":"Philippines' first utility-scale offshore wind auction (GEA-5), launched June 11, 2025, targeting 3,300 MW of fixed-bottom offshore wind capacity to be commissioned 2028–2030.","detailEn":"The Philippines DOE officially launched the Green Energy Auction 5 (GEA-5) on June 11, 2025, dedicated exclusively to fixed-bottom offshore wind with an installation target of 3,300 MW between 2028 and 2030. GEA-5 follows the GEA-4 auction (November 2025) which awarded 10,195 MW across 123 projects, including >4.1 GW ground-mounted solar, 2.3 GW floating solar, 2.2 GW onshore wind, and >1 GW BESS. GEA-5 marks the Philippines' entry into utility-scale offshore wind development, with total investment expected to exceed $14 billion.","progress":"2025年6月11日正式启动招标，2028—2030年并网"},
  {"id":4777,"name":"印尼伯他明那地热绿氢13站PLN计划","en":"PLN IP 13-Site Green Hydrogen Production Programme","country":"印度尼西亚","region":"东南亚","cat":"renewable","coord":[107,-7.2],"cap":"目标年产约80吨绿氢（13个分布式站点）","inv":0.5,"invText":"约500万美元（估算）","status":"在建","year":2026,"updated":"2026-06","owner":"PT PLN Indonesia Power（PLN IP）","flagship":false,"desc":"PLN旗下13座分布式绿氢生产站，爪哇苏门答腊多省","detail":"印尼国家电力公司旗下PLN Indonesia Power（PLN IP）正在多个省份同步开发13座分布式绿氢生产站，利用现有电力基础设施产制绿氢，目标年总产量约80吨，部分站点已投入试运行。绿氢将用于工业示范、交通和清洁能源展示，是印尼政府推动氢能示范的重要布局，与伯他明那地热绿氢试验项目形成互补。","descEn":"PLN Indonesia Power's programme to develop 13 distributed green hydrogen production sites across Indonesia, targeting ~80 tonnes/year of green hydrogen output, some sites already in trial operation.","detailEn":"PT PLN Indonesia Power (PLN IP), a subsidiary of state utility PLN, is developing 13 green hydrogen production sites across multiple provinces in Indonesia, leveraging existing power infrastructure to produce green hydrogen. The programme targets a combined annual output of ~80 tonnes. Several sites are already in trial operation as of early 2026. The initiative supports Indonesia's hydrogen demonstration roadmap and complements Pertamina Geothermal Energy's geothermal-based green hydrogen pilot at Ulubelu.","progress":"部分站点已试运行，目标2026年全部建成"},
  {"id":4778,"name":"越南和发荣橘二期钢铁基地","en":"Hoa Phat Dung Quat 2 Integrated Steel Complex – Quang Ngai","country":"越南","region":"东南亚","cat":"ci","coord":[108.8,15.35],"cap":"年产钢铁约850万吨（一二期合计）","inv":35,"invText":"约35亿美元（二期）","status":"在建","year":2025,"updated":"2026-06","owner":"和发集团（Hoa Phat Group）","flagship":false,"desc":"越南最大钢铁基地扩建，广义省荣橘工业区，35亿美元","detail":"位于越南广义省荣橘经济区，是越南最大的综合性钢铁联合体扩建工程。和发集团总投资约35亿美元建设荣橘二期（Dung Quat 2），规划年产粗钢约430万吨，与一期合计年产能达850万吨，以年耗电约40亿千瓦时的高载能特性成为越南最大工业用电户之一，配套自建燃气发电和余热回收系统。二期于2023年启动建设，2025年首座高炉点火，大规模量产阶段持续推进。","descEn":"Hoa Phat Group's Dung Quat 2 integrated steel complex in Quang Ngai, Vietnam, a $3.5 billion expansion adding ~4.3 million t/yr crude steel capacity; first blast furnace ignited in 2025.","detailEn":"Located within the Dung Quat Economic Zone in Quang Ngai Province, Hoa Phat Dung Quat 2 is Vietnam's most significant steel expansion in decades. The $3.5 billion Phase 2 investment adds ~4.3 million t/yr of crude steel capacity, bringing the total Dung Quat site output to ~8.5 million t/yr. The complex is one of Vietnam's largest industrial electricity consumers at ~4 billion kWh/yr and features in-house gas power generation and waste heat recovery. Construction started in 2023; the first blast furnace was fired in 2025.","progress":"2025年首座高炉点火，年产能持续爬坡中"},
  {"id":4779,"name":"泰国EGAT水库漂浮光伏计划（第三阶段140MW）","en":"EGAT Reservoir Floating Solar Phase 3 – 140 MW Srinagarind","country":"泰国","region":"东南亚","cat":"renewable","coord":[98.5,14.75],"cap":"140 MW（累计超过300 MW）","inv":0.58,"invText":"约20亿泰铢（约6000万美元）","status":"规划","year":2026,"updated":"2026-06","owner":"泰国发电局（EGAT）","flagship":false,"desc":"泰国EGAT水库漂浮光伏第三期，斯里纳加林水库140MW","detail":"位于北碧府斯里纳加林水库（Srinagarind Reservoir），泰国电力局（EGAT）计划建设140 MW漂浮太阳能，是其系列水库漂浮光伏项目中规模最大的单体。前期两个阶段合计已超过160 MW，本期2026年招标建设，推动EGAT漂浮光伏总规模超过300 MW。泰国政府计划在全国水库安装合计2,725 MW漂浮光伏，作为国家可再生能源战略的重要组成。","descEn":"EGAT's Phase 3 floating solar project on the Srinagarind Reservoir in Kanchanaburi, Thailand, at 140 MW, set for 2026 construction tender, part of a 2,725 MW national floating solar programme.","detailEn":"Located on Srinagarind Dam reservoir in Kanchanaburi Province, this 140 MW floating solar project is EGAT's third and largest phase of floating PV deployment on Thai reservoirs. Earlier phases combined exceed 160 MW. Thailand's national floating PV plan calls for 2,725 MW total across reservoirs, with EGAT and private contractors sharing the target. The Phase 3 auction is set for 2026. Regional and international floating solar developers are expected to participate, aligned with Thailand's 20 GW renewables target by 2037.","progress":"2026年招标，斯里纳加林水库已完成选址评估"},
  {"id":4780,"name":"印尼苏拉威西镍产能新增扩产2026（多HPAL）","en":"Indonesia Nickel HPAL Capacity Wave 2026 – Morowali & Weda Bay","country":"印度尼西亚","region":"东南亚","cat":"mining","coord":[121.85,-2.5],"cap":"新增产能合计超30万吨含镍MHP（2026年新投产）","inv":25,"invText":"约25亿美元（2026年新增产能相关投资合计）","status":"在建","year":2026,"updated":"2026-06","owner":"青山/Eramet/Ceria/默迪卡等多家参与方","flagship":false,"desc":"印尼2026年HPAL镍产能浪潮，苏拉威西镍供应再创高峰","detail":"2026年印尼进入新一波HPAL产能释放周期：Excelsior Nickel Cobalt（ENC，Tsingshan与Nickel Industries合资）120,000吨MHP产能完成调试；Ceria红白镍冶炼厂进入爬产；韦达湾Eramet镍矿扩产推进。与此同时，BSE（Battery Smelting Enterprise）于2026年4月首次产出达规格MHP，标志印尼镍湿法产业链成熟度持续提升。预计2026年印尼镍产量同比增长约11.9%，至290万吨，全球占比进一步提高。","descEn":"Indonesia's 2026 wave of new HPAL nickel production capacity: multiple plants commissioning at Morowali and Weda Bay, including ENC (120,000 t/yr MHP), Ceria, and BSE's first on-spec MHP output in April 2026, pushing Indonesia's nickel output up ~11.9% to 2.9 Mt.","detailEn":"Multiple HPAL nickel projects entered commissioning in late 2025 and 2026 at Indonesia's major nickel industrial parks. Excelsior Nickel Cobalt (ENC), a Tsingshan–Nickel Industries JV at IMIP Morowali, adds 120,000 t/yr of MHP capacity. Battery Smelting Enterprise (BSE) produced its first on-spec mixed hydroxide precipitate (MHP) output in April 2026. Ceria's red-white nickel smelter is ramping up, and Eramet is expanding at Weda Bay. Total Indonesian nickel output is projected to reach 2.9 Mt in 2026, up ~11.9% year-on-year, driven by this commissioning pipeline.","progress":"BSE 2026年4月首出达标MHP；ENC完成调试；Ceria爬产中"},
  {"id":4781,"name":"越南胡志明市地铁2号线延伸及新建","en":"Ho Chi Minh City Metro Line 2 – Ben Thanh to Tham Luong","country":"越南","region":"东南亚","cat":"transport","coord":[106.66,10.78],"cap":"全长11.3公里，11座车站，年旅客约1亿人次","inv":20,"invText":"约20亿美元","status":"在建","year":2027,"updated":"2026-06","owner":"胡志明市轨道交通管理局（MAUR）、中国中铁EPC","flagship":false,"desc":"胡志明市地铁2号线，中国中铁EPC，11站11公里","detail":"连接胡志明市一区奔成站至十二区探良站，全长11.3公里，设11座地下车站，总投资约20亿美元，由中国中铁承担EPC总承包。项目2024年重启全面施工，轨道铺设及机电安装持续推进，计划2027年通车运营，是胡志明市轨道交通网络扩展的核心工程，与1号线（2024年12月已通车）共同构成城市骨干公共交通体系。","descEn":"Ho Chi Minh City Metro Line 2 from Ben Thanh to Tham Luong, 11.3 km with 11 stations, ~$2 billion investment, EPC by China Railway, targeting 2027 operations.","detailEn":"Metro Line 2 runs 11.3 km underground from Ben Thanh station in District 1 to Tham Luong in District 12, with 11 underground stations. Total investment is ~$2 billion. China Railway (CREC) is the EPC contractor. Full construction resumed in 2024 after earlier delays; track laying and M&E installation are progressing, with a target opening of 2027. It complements Metro Line 1 (opened December 2024) to form HCMC's core rapid transit backbone.","progress":"2024年全面复工，轨道铺设推进中，2027年目标通车"},
  {"id":4782,"name":"马来西亚YTL-英伟达古来绿色AI数据中心园","en":"YTL–NVIDIA Kulai Green AI Data Center Campus – Johor","country":"马来西亚","region":"东南亚","cat":"datacenter","coord":[103.56,1.66],"cap":"超大规模AI算力，目标500MW+","inv":40,"invText":"约40亿美元（估算）","status":"在建","year":2026,"updated":"2026-06","owner":"YTL Power International、英伟达（NVIDIA）","flagship":true,"desc":"YTL与英伟达合作古来超大规模绿色AI数据中心，柔佛州","detail":"位于柔佛州古来，YTL Power International与NVIDIA深度合作，利用YTL在柔佛的可再生能源基础设施和园区资源，打造以NVIDIA AI算力为核心的超大规模绿色AI数据中心园，规划装机超500 MW，与英伟达签署GPU集群部署协议，是东南亚首批绿色AI数据中心旗舰项目之一，目前阶段性投产并快速扩张。","descEn":"YTL Power International and NVIDIA's joint green AI data center campus in Kulai, Johor, Malaysia, targeting 500+ MW with NVIDIA GPU clusters deployed on renewable energy, a Southeast Asia flagship AI infrastructure project.","detailEn":"Located in Kulai District, Johor, the YTL–NVIDIA collaboration leverages YTL Power's renewable energy assets and data center land bank to build a hyperscale green AI data center campus powered by clean energy. NVIDIA has signed agreements to deploy GPU clusters at the site as part of its Southeast Asia AI infrastructure push. The project is among the first in the region to market itself explicitly as a green AI data center, targeting >500 MW of IT load. Phased deployment is underway with rapid expansion planned through 2026–2028.","progress":"部分设施已阶段性投运，快速扩产中"},
  {"id":4783,"name":"柬埔寨德崇富南运河（水运基础设施）","en":"Decho-Funan Techo Canal – Phnom Penh to Kep, Cambodia","country":"柬埔寨","region":"东南亚","cat":"transport","coord":[104.5,11.2],"cap":"全长180公里，宽100米，通航1,000吨级船","inv":17,"invText":"约17亿美元","status":"在建","year":2028,"updated":"2026-06","owner":"柬埔寨政府、桥梁建设公司（中国路桥参与EPC）","flagship":true,"desc":"柬埔寨180公里运河直通海港，结束对越南湄公河依赖","detail":"从金边延伸至磅士卑省再至贡布出海，全长180公里，宽100米，深5.4米，可通行1,000吨级货船，总投资约17亿美元。工程于2024年8月由洪玛奈总理出席奠基，中国路桥承担EPC建设，计划2028年建成。运河建成后柬埔寨将拥有独立出海通道，摆脱对越南湄公河水道的依赖，同时带动沿线8万公顷农地灌溉，是柬埔寨独立以来最大基础设施工程。","descEn":"Cambodia's 180 km Funan Techo Canal from Phnom Penh to Kep sea outlet, $1.7 billion investment, EPC by China Road and Bridge, groundbreaking August 2024, targeting 2028 completion; eliminates Cambodia's dependence on Vietnam's Mekong waterway.","detailEn":"The Funan Techo Canal runs 180 km from Phnom Penh through Kandal and Kampot provinces to the coast at Kep, with a width of 100 m and depth of 5.4 m to accommodate 1,000-tonne vessels. Total investment is ~$1.7 billion. Groundbreaking was held on August 5, 2024, attended by PM Hun Manet; China Road and Bridge Corporation (CRBC) is the primary EPC contractor. Completion is targeted for 2028. The canal will give Cambodia an independent sea outlet, eliminating its reliance on Vietnam's Mekong River system, and enable irrigation of ~80,000 hectares of farmland along its banks.","progress":"2024年8月奠基开工，中国路桥EPC建设，2028年目标竣工","route":[[104.92,11.57],[104.7,11.35],[104.45,11.1],[104.15,10.7],[103.85,10.4]]},
  {"id":4784,"name":"印尼伯他明那地热公司卡里安温多-3地热扩建","en":"Pertamina Geothermal Energy – Kamojang Unit 6 Expansion (Karian Windoo 3)","country":"印度尼西亚","region":"东南亚","cat":"renewable","coord":[107.8,-7.1],"cap":"55 MW（第六机组）","inv":1.5,"invText":"约1.5亿美元","status":"规划","year":2027,"updated":"2026-06","owner":"PT Pertamina Geothermal Energy（PGE）","flagship":false,"desc":"西爪哇卡莫让地热区第六机组55MW，推进PGE达1GW目标","detail":"位于西爪哇省加鲁特县卡莫让地热区，是PGE在该地区的第六台发电机组，装机55 MW，预计投资约1.5亿美元。作为PGE实现1 GW总装机目标的阶段性工程，目前已完成地质勘探和初步工程设计，2025年启动融资和EPC招标，计划2027年建成投运，届时卡莫让区域总装机将达到约280 MW，是印尼地热最密集的单一区域。","descEn":"Pertamina Geothermal Energy's Unit 6 expansion at the Kamojang geothermal field in West Java, adding 55 MW toward PGE's 1 GW target, with 2027 completion planned.","detailEn":"Located in Garut Regency, West Java, the Kamojang geothermal field is Indonesia's most productive single geothermal site. PGE's planned Unit 6 (55 MW) is the next phase in the Kamojang development, following the operational Units 1–5. The $150 million project has completed geological surveys and preliminary engineering; financing and EPC tendering began in 2025. Target commissioning is 2027, which would bring Kamojang's total installed capacity to ~280 MW and help PGE approach its 1 GW installed target.","progress":"2025年启动EPC招标，2027年目标投产"},
  {"id":4785,"name":"缅甸达贡山镍业扩产（中色矿业）","en":"Tagaung Taung Nickel Project Expansion – Myanmar (CNMC)","country":"缅甸","region":"东南亚","cat":"mining","coord":[96,23.55],"cap":"年产镍矿石约150万吨，镍铁约10万吨（扩产后）","inv":3,"invText":"约3亿美元（扩产部分）","status":"在建","year":2026,"updated":"2026-06","owner":"中国有色矿业集团（CNMC）旗下达贡山镍业","flagship":false,"desc":"缅甸中色达贡山镍矿扩产，年产镍铁10万吨","detail":"位于缅甸马圭省达贡山，是中国有色矿业集团（CNMC）在缅甸最大的矿业投资项目，资源储量约1.06亿吨镍矿石。当前扩产计划投资约3亿美元，将选矿和冶炼产能提升至年产镍铁约10万吨，配套建设选矿厂、运输基础设施和供电系统。受缅甸政治局势影响，部分施工有所放缓，但核心生产设施持续推进，是中国在东南亚最重要的镍矿资源布局之一。","descEn":"CNMC's Tagaung Taung nickel mine expansion in Magway Region, Myanmar, targeting ~100,000 t/yr ferronickel output at a $300 million expansion investment, though progress is subject to Myanmar's political situation.","detailEn":"Located in Magway Region, Myanmar, Tagaung Taung holds ~106 million tonnes of nickel ore resources and is CNMC's largest mining investment in Myanmar. The current expansion phase (~$300 million) upgrades beneficiation and smelting to produce ~100,000 t/yr of ferronickel, with associated mineral processing, transport infrastructure, and captive power improvements. Construction progress has been affected by Myanmar's political situation since the 2021 coup, but core production facilities continue to be developed. It remains one of China's most significant nickel resource holdings in Southeast Asia.","progress":"核心设施持续建设，受缅甸局势影响进展有所放缓"},
  {"id":4786,"name":"老挝亚钾国际钾肥矿扩建（二期）","en":"Asia Potash International Laos Potash Mine Phase 2 Expansion","country":"老挝","region":"东南亚","cat":"mining","coord":[102.65,17.35],"cap":"年产氯化钾（MOP）100万吨（扩产后）","inv":8,"invText":"约8亿美元（二期）","status":"在建","year":2026,"updated":"2026-06","owner":"亚钾国际投资（老挝）有限公司（香港主板上市）","flagship":false,"desc":"老挝最大钾肥矿扩产至100万吨/年，解决国内钾肥进口依赖","detail":"位于老挝万象省，是老挝乃至东南亚规模最大的钾矿开发项目，已探明储量约2.1亿吨氯化钾。亚钾国际持续推进二期扩产工程，总投资约8亿美元，将年产能从初期约30万吨提升至100万吨MOP（氯化钾），产品主要供应中国和东南亚农业市场。2025—2026年产能爬升加速，是老挝农业资源开发的标志性大项目。","descEn":"Asia Potash International's Phase 2 expansion of its Laos potash mine in Vientiane Province, scaling output from ~300,000 t/yr to 1 million t/yr of MOP, targeting markets in China and Southeast Asia.","detailEn":"Located in Vientiane Province, the Asia Potash International mine is the largest potash development in Laos and Southeast Asia, with proven reserves of ~210 million tonnes of muriate of potash (MOP). Phase 2 of the ~$800 million expansion programme targets annual production of 1 million t/yr MOP, up from the initial ~300,000 t/yr nameplate capacity. Production ramp-up accelerated in 2025–2026, with output primarily destined for agricultural markets in China and Southeast Asia. The project is the flagship resource development in Laos and a key government revenue source.","progress":"2025—2026年产能爬升，目标100万吨/年MOP"},

  // ===== 南亚（4900-4919）=====
  {"id":4900,"name":"NTPC 卡夫达二期光伏电站","en":"NTPC Khavda-II Solar PV (1.2 GW)","country":"印度","region":"南亚","cat":"renewable","coord":[69.93,23.82],"cap":"1200 MW 光伏","inv":7.2,"invText":"约 7.2 亿美元（估）","status":"投运","year":2026,"updated":"2026-06","owner":"NTPC 绿色能源(NGEL/NREL)","flagship":false,"desc":"古吉拉特卡夫达 1200MW 光伏电站，2026 年 5 月全容量投运。","detail":"NTPC 绿色能源子公司 NREL 在古吉拉特卡奇县卡夫达园区建设 1200MW 光伏电站(Khavda-II)，分八批施工，2026 年 2 月投产 165MW+270MW，2026 年 5 月 28 日最后 105MW 建成，全容量 1200MW 商运，是 NTPC 集团在单一园区最大单期光伏工程，推动集团可再生总装机超 11GW。","descEn":"NTPC Khavda-II 1.2 GW solar fully commissioned in Gujarat in May 2026.","detailEn":"NTPC's renewable subsidiary NREL completed all 8 phases of the 1,200 MW Khavda-II Solar PV project at the Khavda RE Park in Gujarat's Kutch district. The final 105 MW tranche was commissioned on May 28, 2026, making it NTPC's largest single-park solar project. This brings NTPC's total renewable portfolio past 11 GW.","progress":"2026-05-28 最后 105MW 投产，全容量商运"},
  {"id":4901,"name":"AMPIN 能源法塔赫加尔 500MW 风光混合电站","en":"AMPIN Energy Fatehgarh 500 MWp Wind-Solar Hybrid (Barmer, Rajasthan)","country":"印度","region":"南亚","cat":"renewable","coord":[71.3,25.82],"cap":"约 500 MWp（400 MWp 光伏 + 100 MW 风电）","inv":3.5,"invText":"约 3.5 亿美元（估）","status":"投运","year":2026,"updated":"2026-06","owner":"AMPIN Energy Transition","flagship":false,"desc":"拉贾斯坦巴尔默 500MW 风光混合，AMPIN 首座大型一体化混合项目。","detail":"AMPIN 能源在拉贾斯坦巴尔默县法塔赫加尔开发约 500MWp ISTS 联网风光混合电站，400MWp 光伏与 100MW 风电同址共建，2026 年 5 月正式商运，向 SECI 第三、五批次 DISCOM 及三星电子、印度电信等工商业客户供绿电，年发约 12.5 亿度，减碳 115 万吨，获 2025 年 IJGlobal 南亚 ESG 基础设施年度大奖。","descEn":"AMPIN Energy's first large-scale integrated wind-solar hybrid (~500 MWp) at Fatehgarh, Barmer, Rajasthan — commissioned May 2026, supplying SECI Tranche III/V DISCOMs and Samsung/Airtel C&I customers.","detailEn":"AMPIN Energy Transition commissioned its ~500 MWp ISTS-connected wind-solar hybrid project at Fatehgarh-IV substation in Barmer, Rajasthan in May 2026. The co-located project combines ~400 MWp solar and ~100 MW wind. It supplies power under SECI Tranches III & V to DISCOMs and C&I customers including Samsung Electronics and Bharti Airtel, generating 1.25 billion units annually and saving 1.15 million tonnes of CO₂.","progress":"2026-05 全容量商运，获 2025 年 IJGlobal 南亚 ESG 年度奖"},
  {"id":4902,"name":"苏基克纳里水电站（巴基斯坦）","en":"Suki Kinari Hydropower Project","country":"巴基斯坦","region":"南亚","cat":"renewable","coord":[73.48,34.87],"cap":"884 MW 径流式水电","inv":18,"invText":"约 18 亿美元","status":"投运","year":2024,"updated":"2026-06","owner":"中国葛洲坝集团(Gezhouba) / CPEC","flagship":true,"desc":"CPEC 最大私营水电，2024 年 9 月全容量商运，年发 32.1 亿度。","detail":"苏基克纳里水电站位于开伯尔-普赫图赫瓦省曼西赫拉县昆哈尔河，中国葛洲坝集团作为 CPEC 早期收获项目建设，装机 884MW，总投资约 18 亿美元，中国进出口银行与工商银行联合融资 75%，2024 年 9 月 13 日正式商运，是 CPEC 迄今最大私营及水电项目，年发电约 32.1 亿度，供超 100 万户用电。","descEn":"CPEC's largest private-sector hydropower project, 884 MW on Kunhar River, fully commissioned September 2024, generating 3.21 billion kWh/year.","detailEn":"The Suki Kinari Hydropower Project (884 MW) is a run-of-river plant on the Kunhar River in KP's Mansehra. Developed by China Gezhouba Group under CPEC at ~$1.8B, financed 75% by Chinese banks. It achieved full commercial operations on September 13, 2024 — CPEC's largest private-sector and largest hydropower project — generating 3.21 billion kWh annually for 1 million+ households.","progress":"2024-09-13 全容量商运，标志 CPEC 最大水电投运"},
  {"id":4903,"name":"尼泊尔下阿伦水电站","en":"Lower Arun Hydroelectric Project (679 MW, Nepal)","country":"尼泊尔","region":"南亚","cat":"renewable","coord":[87.18,27.42],"cap":"679 MW 水电","inv":8.6,"invText":"约 8.6 亿美元（约 1000 亿尼泊尔卢比）","status":"在建","year":2029,"updated":"2026-06","owner":"SJVN(印度) / NEA(尼泊尔) BOOT 模式","flagship":false,"desc":"尼泊尔阿伦河第三级 679MW 水电，SJVN BOOT，2029 年投运。","detail":"下阿伦水电站位于尼泊尔桑胡瓦萨帕与博杰布尔县阿伦河，是阿伦三号(900MW)尾水利用项目，印度 SJVN 以 BOOT 模式开发，总投资约 1000 亿尼泊尔卢比(约 8.6 亿美元)，年发 2625GWh，尼泊尔免费获 21.9% 电量，其余向印度出售，2026 年 1 月签署项目开发协议(PDA)，属印尼水电合作约 11.2GW 组合。","descEn":"Lower Arun 679 MW run-of-river hydropower in Nepal (Sankhuwasabha/Bhojpur), SJVN BOOT model, $860M, PDA signed January 2026.","detailEn":"The Lower Arun Hydroelectric Project (679 MW) is a tailrace development of Arun-III on Nepal's Arun River. India's SJVN develops it under BOOT at ~NPR 100B ($860M). Nepal gets 21.9% free electricity; remainder exported to India. Project Development Agreement signed January 2026, part of India-Nepal's 11.2 GW hydro cooperation.","progress":"2026-01 签 PDA，SJVN 推进前期开发准备"},
  {"id":4904,"name":"尼泊尔阿伦四号水电站","en":"Arun-4 Hydroelectric Project (490 MW, Nepal)","country":"尼泊尔","region":"南亚","cat":"renewable","coord":[87.22,27.52],"cap":"490 MW 水电","inv":4.2,"invText":"约 4.2 亿美元（约 490 亿印度卢比）","status":"规划","year":2031,"updated":"2026-06","owner":"SJVN(51%) / 尼泊尔电力局 NEA(49%)","flagship":false,"desc":"尼泊尔桑胡瓦萨帕 490MW 水电，SJVN 与 NEA 合资，阿伦河第三阶梯。","detail":"阿伦四号水电站位于尼泊尔桑胡瓦萨帕县阿伦河，SJVN(51%)与尼泊尔电力局(49%)合资，总投资约 490 亿卢比，是 SJVN 在阿伦河流域第三个项目(继阿伦三号与下阿伦)，尼方免费获 21.9% 电量，其余出口印度，2022 年签 MoU，是印度对尼约 11.2GW 水电合作框架重要项目。","descEn":"Arun-4 490 MW hydropower in Sankhuwasabha, Nepal — SJVN(51%)/NEA(49%) JV, ~$420M, part of India-Nepal 11.2 GW hydro cooperation.","detailEn":"Arun-4 (490 MW) is on Nepal's Arun River in Sankhuwasabha district, a SJVN-NEA joint venture at ~INR 4,900 crore. Nepal receives 21.9% free electricity. It is SJVN's third project on the Arun River and part of the India-Nepal 11.2 GW hydro cooperation package.","progress":"2022 签 MoU，2026-01 纳入印尼水电合作框架推进前期"},
  {"id":4905,"name":"斯里兰卡锡亚姆巴兰杜瓦 100MW 光伏电站","en":"Siyambalanduwa Rividanavi 100 MW Solar Park (Sri Lanka)","country":"斯里兰卡","region":"南亚","cat":"renewable","coord":[81.53,6.87],"cap":"100 MW 光伏 + 12 MWh 储能","inv":1.4,"invText":"约 1.4 亿美元（ADB 融资支持）","status":"在建","year":2026,"updated":"2026-06","owner":"Rivi Danavi Pvt Co (Lakdhanavi + WindForce) / CEB","flagship":false,"desc":"斯里兰卡最大单体可再生项目，莫纳勒格勒 100MW 光伏+储能。","detail":"锡亚姆巴兰杜瓦光伏园区(Rividanavi)位于斯里兰卡莫纳勒格勒县约 500 英亩，Lakdhanavi 与 WindForce 合资开发，亚行融资支持，约 1.4 亿美元，配 12MWh 储能，年发 219GWh，经 220kV 线接阿帕拉网络节点，每年减少 6970 万美元进口柴油，2025 年 9 月正式破土，预计 2026 年建成，是斯里兰卡最大单体可再生能源项目。","descEn":"Sri Lanka's largest renewable project: 100 MW solar + 12 MWh storage in Monaragala, $140M ADB-backed, groundbreak September 2025, completion 2026.","detailEn":"The Rividanavi 100 MW Solar PV Park in Siyambalanduwa, Monaragala district is Sri Lanka's largest single renewable project. Developed by Rivi Danavi Pvt Co (Lakdhanavi + WindForce JV) with ADB financing at ~$140M, it features 12 MWh storage, generates 219 GWh/year, and saves $69.7M/year in diesel imports. Construction began September 2025.","progress":"2025-09 正式破土，预计 2026 年建成投运"},
  {"id":4906,"name":"NLC-NTPC 450MW 比卡内尔-布杰风光混合项目","en":"NLC India 450 MW Wind-Solar Hybrid (Bikaner + Bhuj) for NTPC","country":"印度","region":"南亚","cat":"renewable","coord":[73.32,27.98],"cap":"450 MW（300 MW 光伏/比卡内尔 + 150 MW 风电/布杰）","inv":3,"invText":"约 3 亿美元（估）","status":"在建","year":2027,"updated":"2026-06","owner":"NLC India Ltd（NTPC 下属项目）","flagship":false,"desc":"NLC India 获 NTPC 授标 450MW 风光混合，比卡内尔 300MW 光伏+布杰 150MW 风电。","detail":"NLC India 于 2025 年 6 月 27 日收到 NTPC 450MW ISTS 风光混合项目授标函，分两期执行：拉贾斯坦比卡内尔 300MW 光伏电站与古吉拉特布杰 150MW 风电场，25 年购电协议，电价 3.35 卢比/度，SCSD 为协议生效后 24 个月，是 NTPC 通过反向拍卖向央企采购可再生能源的重要安排。","descEn":"NLC India wins 450 MW wind-solar hybrid LoA from NTPC: 300 MW solar in Bikaner, Rajasthan + 150 MW wind in Bhuj, Gujarat, tariff Rs 3.35/kWh, 25-year PPA.","detailEn":"NLC India received a Letter of Award from NTPC in June 2025 for a 450 MW ISTS-connected wind-solar hybrid project: 300 MW solar in Bikaner, Rajasthan and 150 MW wind in Bhuj, Gujarat. The 25-year PPA is at Rs 3.35/kWh, with commissioning required within 24 months of PPA effective date.","progress":"2025-06-27 收到授标函，进入 PPA 签署与项目实施"},
  {"id":4907,"name":"NTPC 法塔赫加尔 800MW/3200MWh 电池储能","en":"NTPC Fatehgarh Solar Plant BESS (800 MW / 3,200 MWh)","country":"印度","region":"南亚","cat":"storage","coord":[71.98,27.08],"cap":"800 MW / 3200 MWh 电池储能","inv":7,"invText":"约 7 亿美元（估）","status":"规划","year":2028,"updated":"2026-06","owner":"NTPC 绿色能源(NGEL)","flagship":false,"desc":"拉贾斯坦法塔赫加尔光伏园区配套 800MW/3200MWh 大型 BESS。","detail":"NTPC 绿色能源于 2026 年 6 月为拉贾斯坦 NTPC REL 法塔赫加尔光伏园区发布 800MW/3200MWh 电池储能 EPC 招标，分 300MW/1200MWh×2 组及 200MW/800MWh 共三块，25 年设计寿命、15 年运维合同、99.8% 可用率要求，是 NTPC 绿色能源同期在古吉拉特与拉贾斯坦发布总计 17500MWh BESS 招标包的核心组成，推动 100GWh 国家储能战略落地。","descEn":"NTPC Green Energy tenders 800 MW / 3,200 MWh BESS EPC at Fatehgarh Solar Plant, Rajasthan, bid deadline June 25, 2026.","detailEn":"NTPC Green Energy issued an EPC tender in June 2026 for 800 MW / 3,200 MWh of battery energy storage at its Fatehgarh Solar Plant in Rajasthan, structured as three blocks (300+300+200 MW). The project has a 25-year design life and 15-year O&M requirement, forming part of NTPC's broader 17,500 MWh BESS rollout across Gujarat and Rajasthan plants.","progress":"2026年6月，NTPC绿能法塔赫加尔3200MWh储能招标全面推进：分三个标段（2×300MW/1200MWh＋200MW/800MWh），全部位于法塔赫加尔光伏园区内，被视为印度大型储能招标的技术与定价标杆。"},
  {"id":4908,"name":"格林科沙普尔抽水蓄能（中央邦尼穆奇）","en":"Greenko Shahpur Pumped Storage Project (Neemuch, Madhya Pradesh)","country":"印度","region":"南亚","cat":"storage","coord":[74.82,24.45],"cap":"1440 MW（可扩至 1920 MW）/ 11 GWh","inv":10,"invText":"约 10 亿美元（约 1000 亿卢比）","status":"在建","year":2029,"updated":"2026-06","owner":"格林科集团(Greenko Group)","flagship":false,"desc":"中央邦尼穆奇 1.44GW 抽蓄，格林科 3.3GW 组合旗舰，AFRY 工程设计。","detail":"格林科沙普尔抽水蓄能项目位于中央邦尼穆奇县凯姆拉区，初期 1.44GW、可扩 1.92GW，满放 11GWh，约 1000 亿卢比，AFRY 公司负责工程设计，已破土进入主体施工，是格林科在印度南方三省 3.3GW 抽蓄组合的旗舰。格林科目标建立逾 100GWh 云储能平台以供调度绿电给难减排工业。","descEn":"Greenko Shahpur PSP: 1.44 GW (expandable 1.92 GW) / 11 GWh in Neemuch, MP. AFRY-designed, ~$1B, construction underway — flagship of Greenko's 3.3 GW India pumped-storage portfolio.","detailEn":"Greenko's Shahpur Pumped Storage Project in Neemuch (Khemla block), MP features 1,440 MW (expandable to 1,920 MW) and 11 GWh storage. AFRY handles engineering design at ~INR 100 billion. Ground has been broken and construction is underway. It is the centerpiece of Greenko's 3.3 GW pumped storage portfolio and contributes to its goal of a 100+ GWh dispatchable cloud energy platform.","progress":"已破土，AFRY 设计，主体工程推进，2029 目标投运"},
  {"id":4909,"name":"卡夫达 KPS2—那格浦尔 ±800kV 6GW HVDC（1200km）","en":"Khavda KPS2–Nagpur ±800 kV 6 GW LCC-HVDC (1,200 km)","country":"印度","region":"南亚","cat":"grid","coord":[73.05,22.3],"cap":"±800 kV / 6000 MW LCC-HVDC / 约 1200 km","inv":30,"invText":"约 30 亿美元（约 24819 亿卢比）","status":"在建","year":2029,"updated":"2026-06","owner":"印度电网(POWERGRID) / BHEL-Hitachi Energy","flagship":true,"desc":"卡夫达绿电西电东送，±800kV 6GW 1200km 送马哈拉施特拉那格浦尔。","detail":"卡夫达 KPS2—那格浦尔 HVDC 由印度电网(POWERGRID)以 BOOT 模式承接，将卡夫达园区绿电经约 1200km ±800kV 双极直流送至马哈拉施特拉那格浦尔，额定 6GW，约 248.19 亿卢比，BHEL-Hitachi Energy 联合体负责换流站及交流配套，2029 年完工，是卡夫达五期 8GW 外送整体方案 Part A，配合 Khavda VSC(Part C)、765kV 网络(四期)构成 30GW 园区外送骨架。","descEn":"Khavda KPS2–Nagpur ±800 kV / 6 GW / 1,200 km LCC-HVDC — POWERGRID BOOT, BHEL-Hitachi Energy converters, ~$3B, completion 2029. Part A of Khavda Phase-V 8 GW evacuation.","detailEn":"POWERGRID (PGCIL) won the Khavda Phase-V Part A HVDC project to evacuate 8 GW of renewable energy from Khavda, Gujarat to Nagpur, Maharashtra (~1,200 km, ±800 kV, 6 GW). Estimated at INR 24,819 crore (~$3B). BHEL and Hitachi Energy India handle the converter stations. The project supports India's 500 GW by 2030 target and integrates with the Khavda Phase-V Part C VSC-HVDC and Phase-IV 765 kV network.","progress":"POWERGRID 中标，BHEL-Hitachi Energy 签换流站合同，2029 完工","route":[[70.15,23.45],[72.9,22.1],[79.08,21.15]]},
  {"id":4910,"name":"塔塔电子 Dholera 300mm 晶圆代工厂","en":"Tata Electronics Dholera 300 mm Semiconductor Fab","country":"印度","region":"南亚","cat":"ci","coord":[72.18,22.27],"cap":"5 万片/月（28-110nm DUV）","inv":110,"invText":"约 110 亿美元（约 91000 亿卢比）","status":"在建","year":2027,"updated":"2026-06","owner":"塔塔电子(Tata Electronics) / PSMC(台湾) / ASML","flagship":true,"desc":"印度首座 300mm 晶圆代工厂，多勒拉 SIR，28-110nm，2027 年投产。","detail":"塔塔电子在古吉拉特多勒拉特别投资区建印度首座 300mm 商业晶圆代工厂，初期月产能 5 万片，采用 28-110nm DUV 工艺，台湾 PSMC 授权技术，总投资约 910 亿卢比(含配套阿萨姆 OSAT 共约 110 亿美元)。2026 年 4 月获 SEZ 认定，5 月塔塔与 ASML 签 MoU 确认设备配套，目标 2027 年中期爬产，聚焦汽车、移动及 AI 芯片，是 ISM 2.0 旗舰。","descEn":"India's first commercial 300 mm wafer fab at Dholera SIR, Gujarat — 28-110 nm, 50,000 WSPM, ~$11B, Tata Electronics + PSMC tech + ASML tools, production 2027.","detailEn":"Tata Electronics is building India's first commercial 300 mm front-end semiconductor fab at Dholera SIR, Gujarat. It targets 50,000 wafer starts per month at 28-110 nm using ASML DUV lithography, licensed from Taiwan's PSMC. Investment is ~INR 91,000 crore ($11B including Assam OSAT). SEZ status granted April 2026; Tata–ASML partnership MoU signed May 2026. Production ramp targeted mid-2027.","progress":"2026-05 塔塔与 ASML 签 MoU，2026-04 SEZ 认定，2027 中期爬产"},
  {"id":4911,"name":"L&T 半导体科技高压功率器件平台","en":"L&T Semiconductor Technologies (LTSCT) Power Device Platform","country":"印度","region":"南亚","cat":"ci","coord":[72.85,19.2],"cap":"650V-3300V 功率晶圆，SiC/Si EV 及工业器件","inv":5,"invText":"约 5 亿美元（估）","status":"规划","year":2028,"updated":"2026-06","owner":"L&T 半导体科技(LTSCT) / 鸿扬半导体(HYS/Foxconn)","flagship":false,"desc":"L&T 与富士康旗下鸿扬合作，印度开发 650V-3300V 高压功率晶圆。","detail":"L&T 半导体科技(LTSCT)是 L&T 集团半导体部门，2025 年 10 月 14 日与富士康旗下鸿扬半导体(HYS)签长期合作协议，在印度开发 650V–3300V 高压功率晶圆(含碳化硅 SiC 与高压硅)，用于电动汽车牵引逆变器、车载充电机与工业变换器，借助 HYS 台湾产线快速验证后转移至印度批量生产，同年 LTSCT 还收购富士通功率模块业务，向高压功率全链覆盖。","descEn":"L&T Semiconductor Technologies and Foxconn's HYS signed Oct 2025 partnership for 650V–3,300V power wafers (SiC/Si) in India for EVs and industrial drives; LTSCT also acquired Fujitsu's power module business.","detailEn":"On October 14, 2025, L&T Semiconductor Technologies (LTSCT) and Foxconn subsidiary Hon Young Semiconductor (HYS) inked a long-term deal to develop 650V–3,300V power wafers (SiC/Si) in India for EV traction inverters and industrial converters. HYS's Taiwan fabs enable rapid prototyping before India-based volume production. LTSCT also acquired Fujitsu's power module business in 2025, creating an end-to-end high-voltage power semiconductor platform.","progress":"2025-10-14 签 HYS 合作协议，推进印度功率晶圆量产布局"},
  {"id":4912,"name":"孟买双机场黄金地铁线（Metro 8）","en":"Mumbai Metro Line 8 'Gold Line' Airport Link","country":"印度","region":"南亚","cat":"transport","coord":[72.92,19.1],"cap":"34 km / 20 站，双机场直连，30 分钟","inv":27.3,"invText":"约 27.3 亿美元（约 22862 亿卢比）","status":"规划","year":2029,"updated":"2026-06","owner":"马哈拉施特拉邦 / PPP 私营","flagship":true,"desc":"孟买 CSMIA—新孟买机场 34km 双机场 PPP 轨交，马邦 2025-01 批准。","detail":"孟买地铁 8 号线（黄金线）连接恰特拉帕蒂·希瓦吉国际机场(CSMIA)与新孟买国际机场(NMIA)，34km（25.8km 高架+8.2km 地下）共 20 站，行程从 90 分钟压缩至 30 分钟，投资约 22862 亿卢比，60% 私企出资、40% 政府缺口补贴，马哈拉施特拉邦内阁 2025 年 1 月 27 日正式批准，加速土地征收及 PPP 招标。","descEn":"Mumbai Metro Line 8 Gold Line: 34 km dual-airport PPP link (CSMIA–NMIA), 20 stations, 30-min journey, ~$2.73B, Maharashtra Cabinet approved January 2025.","detailEn":"Mumbai Metro Line 8 (Gold Line) connects CSMIA and the new Navi Mumbai International Airport (NMIA) over 34 km (25.8 km elevated + 8.2 km underground) with 20 stations, cutting travel time from 90 to 30 minutes. Investment is ~INR 22,862 crore, 60% private / 40% VGF. Maharashtra Cabinet formally approved the project in January 2025.","progress":"2025-01 马邦内阁批准，快速推进土地征收和 PPP 招标","route":[[72.87,19.09],[73.01,18.99]]},
  {"id":4913,"name":"德里—孟买高速公路（全线）","en":"Delhi–Mumbai Expressway (1,350 km Full Completion)","country":"印度","region":"南亚","cat":"transport","coord":[76.62,24.85],"cap":"1350 km 8 车道，旅行时间 24→12 小时","inv":131,"invText":"约 131 亿美元（约 96547 亿卢比）","status":"在建","year":2026,"updated":"2026-06","owner":"印度国家高速公路局(NHAI)","flagship":true,"desc":"印度最长高速公路 1350km，德里经拉贾斯坦、古吉拉特至孟买，2026 年基本通车。","detail":"德里—孟买高速公路全长 1350km、8 车道，经哈里亚纳、拉贾斯坦、中央邦、古吉拉特、马哈拉施特拉，将德孟旅行时间由 24 小时压缩至 12 小时，总批准投资约 96547 亿卢比，截至 2025 年底已支出 77558 亿卢比，929km 已通车。德里至瓦多达拉段(912km)计划 2026 年 6 月完成，古吉拉特三个标段因延误推至 2028 年 3 月，全线 2028 年通车。","descEn":"India's longest expressway: 1,350 km, 8-lane Delhi–Mumbai corridor, $13.1B, 929 km open by end-2025, Delhi–Vadodara section targeting June 2026 completion.","detailEn":"The Delhi–Mumbai Expressway (1,350 km, 8 lanes) runs through Haryana, Rajasthan, MP, Gujarat, and Maharashtra, cutting travel time from 24 to 12 hours. Total sanctioned cost is ~INR 96,547 crore ($13.1B); expenditure reached INR 77,558 crore by December 2025. Of 1,445 km (total project length including service roads), 929 km are now open. The Delhi–Vadodara (912 km) segment targets June 2026 completion; three Gujarat packages are delayed to March 2028.","progress":"2025 底 929km 通车，德里-瓦多达拉段 2026-06 目标完工","route":[[77.1,28.65],[75.8,27],[74.7,24.8],[73.2,22.3],[72.83,19.08]]},
  {"id":4914,"name":"谷歌维沙卡帕特南 AI 枢纽（阿达尼-谷歌）","en":"Google India AI Hub – Visakhapatnam (AdaniConnex)","country":"印度","region":"南亚","cat":"datacenter","coord":[83.3,17.73],"cap":"吉瓦级 AI 算力园（三大园区约 480 英亩）","inv":150,"invText":"约 150 亿美元（谷歌五年印度总投资）","status":"在建","year":2030,"updated":"2026-06","owner":"谷歌(Google) / AdaniConneX / Airtel","flagship":true,"desc":"谷歌 150 亿美元印度首座吉瓦级 AI 枢纽，维沙卡帕特南三大园区。","detail":"谷歌与阿达尼企业 2025 年 10 月宣布合作，在安得拉维沙卡帕特南建印度首座吉瓦级 AI 数据中心园区，涵盖 Adivivaram 120 英亩、Tarluvada 200 英亩和 Rambilli-Achyutapuram 160 英亩三处，AdaniConneX 与 Airtel 配套基础设施，2026 年 4 月 28 日正式破土，谷歌五年(2026–2030)150 亿美元印度整体投资的核心，含海底电缆新入口，是印度 AI 基础设施里程碑。","descEn":"Google India AI Hub in Visakhapatnam: GW-scale campus across three sites (480 acres), AdaniConnex + Airtel partnership, $15B 5-year India investment, ground broken April 28, 2026.","detailEn":"In October 2025, Adani Enterprises and Google announced India's largest AI data center campus in Visakhapatnam, AP — three linked campuses covering 480 acres. AdaniConnex and Airtel provide supporting infrastructure. Google broke ground on April 28, 2026, as the flagship of its $15B five-year India investment (2026–2030), also including a major new international subsea cable gateway.","progress":"2026-04-28 正式破土，三大园区并行推进"},
  {"id":4915,"name":"TCS HyperVault AI 数据中心（OpenAI Stargate 印度）","en":"TCS HyperVault AI Data Center Business (OpenAI Stargate India)","country":"印度","region":"南亚","cat":"datacenter","coord":[72.88,19.07],"cap":"目标 1 GW AI 算力（首期 100 MW for OpenAI）","inv":65,"invText":"约 65 亿美元（TPG 10 亿 + TCS 总建设）","status":"在建","year":2027,"updated":"2026-06","owner":"塔塔咨询服务(TCS) / TPG / OpenAI","flagship":true,"desc":"TCS HyperVault 获 TPG 10 亿美元，OpenAI 首客 100MW，目标 1GW。","detail":"TCS 2025 年 10 月宣布成立 HyperVault AI 数据中心业务，目标建设逾 1GW 的 AI 就绪数据中心，5-7 年投资约 65-70 亿美元，私募巨头 TPG 注资 10 亿美元加速。2026 年 2 月 OpenAI 宣布成为 HyperVault 首位客户，初租 100MW 并瞄准 1GW，是 Stargate 印度核心支柱，推动印度以主权 AI 算力跻身全球前列。","descEn":"TCS HyperVault: GW-scale AI data center business, $1B TPG investment, OpenAI as anchor customer (100 MW, eyes 1 GW), part of Stargate India initiative.","detailEn":"TCS launched HyperVault in October 2025, targeting 1+ GW of AI-ready data center capacity in India ($6-7B over 5-7 years). TPG committed $1B to accelerate the rollout. In February 2026, OpenAI signed as HyperVault's first customer with an initial 100 MW commitment and ambitions for 1 GW, making it a core pillar of the Stargate India initiative.","progress":"2026-02 OpenAI 签约 100MW，TPG 10 亿美元已到位，GW 级推进中"},
  {"id":4916,"name":"亚马逊 AWS 马哈拉施特拉云区 83 亿美元扩建","en":"AWS Asia-Pacific (Mumbai) Region – $8.3B Maharashtra Expansion","country":"印度","region":"南亚","cat":"datacenter","coord":[72.87,19.08],"cap":"多可用区扩建，孟买/马哈拉施特拉","inv":83,"invText":"约 83 亿美元（马哈拉施特拉区域专项投资）","status":"在建","year":2030,"updated":"2026-06","owner":"亚马逊 AWS","flagship":false,"desc":"AWS 向马哈拉施特拉孟买 AP 云区投资 83 亿美元，支撑印度 AI 算力需求。","detail":"AWS 宣布向马哈拉施特拉 AWS 亚太(孟买)区域投资 83 亿美元，到 2030 年贡献约 153 亿美元 GDP 并每年支撑约 8.13 万个供应链就业，已在孟买开设三个可用区，海得拉巴第二区域另有约 44 亿美元专项投资，合计 AWS 对印度约 127 亿美元总承诺，2025 年 12 月与微软($175 亿)合计印度超大规模云宣布逾 520 亿美元。","descEn":"AWS commits $8.3B to expand its Asia-Pacific (Mumbai) region in Maharashtra by 2030, part of a $12.7B total India pledge.","detailEn":"AWS announced $8.3B into its Asia-Pacific (Mumbai) cloud region in Maharashtra, supporting 81,300+ supply-chain jobs and contributing $15.3B to India's GDP by 2030. Combined with the $4.4B AWS AP Hyderabad region, total AWS India commitment is $12.7B. Alongside Microsoft's $17.5B, over $52B in Big Tech cloud investment was pledged within 24 hours in December 2025.","progress":"多可用区持续扩建，2030 年前 83 亿美元投入马哈拉施特拉区域"},
  {"id":4917,"name":"察拉 LNG 接收站（印度西海岸首座绿地站）","en":"Chhara LNG Terminal (HPCL Shapoorji Energy)","country":"印度","region":"南亚","cat":"petro","coord":[70.33,20.73],"cap":"500 万吨/年（可扩至 1000 万吨）","inv":7.5,"invText":"约 7.5 亿美元（估）","status":"投运","year":2025,"updated":"2026-06","owner":"HPCL Shapoorji Energy Ltd（HPCL + SP Infra 合资）","flagship":false,"desc":"印度西海岸察拉 500 万吨/年 LNG 站，2025 年 2 月商运。","detail":"察拉 LNG 接收站位于古吉拉特 Gir Somnath 县察拉港，HPCL 与 SP Infra 合资建设，首期 5 MTPA 可扩至 10 MTPA，2025 年 1 月 6 日首批货到港，2025 年 2 月正式商业运营，是继达摩拉之后印度西海岸新投运的重要绿地 LNG 站，弥补印度西部天然气供应缺口并配套绿氢制造走廊。","descEn":"Chhara LNG Terminal (5 MTPA, expandable to 10 MTPA) on Gujarat's west coast — India's newest greenfield LNG import terminal, commercial operations started February 2025.","detailEn":"The Chhara LNG Terminal in Gir Somnath, Gujarat was developed by HPCL Shapoorji Energy Ltd (HPCL + SP Infra JV). It received its commissioning cargo on January 6, 2025 and began commercial operations in February 2025 at 5 MTPA, expandable to 10 MTPA, plugging a gap in India's west coast gas supply infrastructure.","progress":"2025-01 首批货抵港，2025-02 商业运营启动"},
  {"id":4918,"name":"马塔巴里 1200MW 超超临界燃煤电站（孟加拉国）","en":"Matarbari Ultra Super-Critical Coal Power Plant (1,200 MW, Bangladesh)","country":"孟加拉国","region":"南亚","cat":"petro","coord":[91.88,21.65],"cap":"1200 MW 超超临界燃煤（2×600MW）","inv":24,"invText":"约 24 亿美元（日本 JICA 气候融资）","status":"在建","year":2026,"updated":"2026-06","owner":"孟加拉 CPGCBL / JICA（日本）/ 住友商事 EPC","flagship":false,"desc":"孟加拉最大电力项目，2×600MW 超超临界煤电，日本 JICA 融资，2026 年底投运。","detail":"马塔巴里燃煤电站位于孟加拉国科克斯巴扎尔县马塔巴里岛，2×600MW 超超临界机组，日本 JICA 提供逾 24 亿美元气候融资，住友商事 EPC，配套深水港码头年处理 11.2 万吨/日煤炭，原计划 2024 年投运延至 2026 年 12 月，是孟加拉投资最大单体电力项目，配套港口基础设施将带动马塔巴里岛工业区发展。","descEn":"Matarbari 2×600 MW ultra-supercritical coal plant in Cox's Bazar, Bangladesh — $2.4B+ JICA-financed, Sumitomo EPC, delayed to December 2026. Bangladesh's largest single power investment.","detailEn":"The Matarbari Ultra Super-Critical Coal Power Plant (1,200 MW / 2×600 MW) on Matarbari Island, Cox's Bazar, Bangladesh is financed by Japan's JICA at $2.4B+, with Sumitomo as EPC contractor. It includes an integrated deepwater coal terminal. Originally scheduled for 2024, commissioning is now delayed to December 2026. It is Bangladesh's single largest power project and anchors a planned industrial complex.","progress":"延至 2026-12 投运，配套深水港码头同步建设推进"},
  {"id":4919,"name":"印度斯坦铜业 Malanjkhand 地下铜矿扩产","en":"Hindustan Copper Malanjkhand Underground Mine Expansion (500 Mtpa)","country":"印度","region":"南亚","cat":"mining","coord":[80.71,22.01],"cap":"年产铜矿石 500 万吨（露天转地下）","inv":6,"invText":"约 6 亿美元（估）","status":"在建","year":2030,"updated":"2026-06","owner":"印度斯坦铜业(Hindustan Copper / HCL)","flagship":true,"desc":"印度最大贱金属矿露天转地下扩产，2030 年前铜矿石产能翻番至 500 万吨。","detail":"马兰杰坎德铜矿位于中央邦 Balaghat，是印度最大贱金属矿，印度斯坦铜业计划到 2030-31 财年将铜矿石产能由约 250 万吨提升至 500 万吨/年，已完成露天向地下开采转换，配套印度公共部门首座采矿充填站、新选矿厂，采用 BHEL 深穿孔钻机与现代地下装备，目标成印度最大地下铜矿并扶持铜自给率提升。","descEn":"Hindustan Copper's Malanjkhand mine in MP transitioning from open-pit to underground, targeting 5 Mtpa ore by 2030-31 — India's first PSU underground copper mine with paste filling, India's largest base metals mine.","detailEn":"Hindustan Copper's Malanjkhand Copper Mine in Balaghat, MP is India's largest base-metal mine. HCL plans to double ore capacity from ~2.5 Mtpa to 5 Mtpa by FY2030-31 by completing the open-pit-to-underground transition. The project installs India's first PSU mining paste fill plant, a new concentrator, and modern underground equipment. Malanjkhand aims to become India's largest underground copper mine.","progress":"2025 露天转地下完成，向 500 万吨/年产能爬坡中"},

  // ===== 中亚（5050-5063）=====
  {"id":5050,"name":"哈萨克斯坦热苏1GW风储项目（ACWA Power）","en":"Zhetysu 1GW Wind & 300MW BESS (ACWA Power)","country":"哈萨克斯坦","region":"中亚","cat":"renewable","coord":[79.5,44.8],"cap":"1 GW / 300 MW BESS","inv":15,"invText":"约 15 亿美元","status":"规划","year":2027,"updated":"2026-06","owner":"ACWA Power、Samruk-Kazyna","flagship":false,"desc":"沙特ACWA Power在哈萨克东部热苏州建1GW风电+300MW储能，最大沙特对哈能源投资","detail":"项目位于哈萨克斯坦热苏（Zhetysu）州，由沙特ACWA Power与国家主权基金Samruk-Kazyna合作，总投资约15亿美元，属沙特对哈萨克斯坦电力领域最大投资。拟建1 GW陆上风电配套300 MW/600 MWh BESS及约300千米输电线。协议于COP28（2023年）签署，目标2027年完工，支持哈萨克斯坦可再生能源占比目标。","descEn":"ACWA Power's $1.5B 1GW wind and 300MW BESS project in Zhetysu Region, eastern Kazakhstan — the largest Saudi energy investment in Kazakhstan.","detailEn":"Located in Zhetysu Region of eastern Kazakhstan, this $1.5B project by ACWA Power and Samruk-Kazyna involves 1 GW of onshore wind generation, a 300 MW/600 MWh BESS, and ~300 km of transmission lines. Signed at COP28 in December 2023, the project targets 2027 commissioning and will supply clean power under a long-term PPA, marking the largest Saudi energy investment in Kazakhstan to date.","progress":"AIIB已将该项目列入2026年拟议融资清单，结构性融资方案制定中"},
  {"id":5051,"name":"哈萨克斯坦乌尔肯核电站","en":"Ulken Nuclear Power Plant (Balkhash)","country":"哈萨克斯坦","region":"中亚","cat":"nuclear","coord":[74.02,45.61],"cap":"2.4 GW（2×VVER-1200）","inv":165,"invText":"约 165 亿美元","status":"规划","year":2034,"updated":"2026-06","owner":"Rosatom、哈萨克斯坦原子能委员会","flagship":true,"desc":"哈萨克斯坦首座核电站，巴尔喀什湖畔乌尔肯村，2×VVER-1200，俄Rosatom承建","detail":"选址于哈萨克斯坦江布尔州巴尔喀什湖畔乌尔肯村，计划建设2台VVER-1200（Gen III+）机组，总装机2400 MW。2024年10月全国公投超70%民众赞成；俄罗斯Rosatom于竞标中击败中核、法国EDF、韩国KHNP中标；2025年8月正式启动地质勘探，2026年5月双方签署165亿美元建设协议，规划2027年正式开工、2034年首堆投运，对哈萨克斯坦能源转型意义深远。","descEn":"Kazakhstan's first nuclear power plant at Ulken on Lake Balkhash — two VVER-1200 units built by Rosatom under a $16.5B deal signed in 2026.","detailEn":"Sited at Ulken village on the shores of Lake Balkhash (~350 km from Almaty), the plant will deploy two Rosatom VVER-1200 Generation III+ reactors totalling 2,400 MW. Kazakhstan's October 2024 referendum endorsed the project (>70% support); Rosatom was selected from four bidders including China, France, and South Korea. Geological surveys began August 2025; a $16.5B intergovernmental agreement was signed in May 2026; construction target: 2027 start, first reactor by 2034.","progress":"2026年5月28日俄哈签署巴尔喀什核电站（2×VVER-1200）建设政府间协定，场址工程勘察完成逾90%，计划2027年主体开工、2030年代中期投运。"},
  {"id":5052,"name":"乌兹别克斯坦巴什二期风电（Bash 2）","en":"Bash 2 Wind Power Plant (300MW, ACWA Power)","country":"乌兹别克斯坦","region":"中亚","cat":"renewable","coord":[64.25,39.88],"cap":"300 MW","inv":3.6,"invText":"约 3.6 亿美元","status":"规划","year":2027,"updated":"2026-06","owner":"ACWA Power","flagship":false,"desc":"布哈拉州吉贾万区300MW风电，L&T为EPC承包商，AIIB/ADB联合融资","detail":"项目位于乌兹别克斯坦布哈拉州吉贾万区，紧邻已投运的500 MW Bash 1风电场（2025年3月满容量投运），安装39台风机，并配套500 kV升压站和1.5千米送出线路，与现有Bash-卡拉库尔500 kV线连接。L&T为首选EPC承包商，合同额3.6亿美元。2026年ADB年会上ACWA签署2.26亿美元融资协议（ADB+AIIB+渣打银行），签有25年PPA，预计年发电943 GWh，减排47.5万吨CO₂。","descEn":"300 MW Bash 2 wind farm in Gijduvan, Bukhara Region — $360M project with L&T as EPC and $226M multilateral financing from ADB/AIIB.","detailEn":"Adjacent to the 500 MW Bash 1 plant (commissioned March 2025), Bash 2 will install 39 wind turbines in Gijduvan District. L&T was named preferred EPC contractor for $360M total investment. At the 2026 ADB Annual Meeting, ACWA Power signed $226M in financing from ADB, AIIB and Standard Chartered. A 25-year PPA with NEGU was signed November 2023. Expected annual output: 943 GWh, offsetting 475,000 t CO₂/yr.","progress":"2026年5月ADB年会上签署2.26亿美元融资协议，建设准备推进"},
  {"id":5053,"name":"乌兹别克斯坦独立储能项目（ACWA Power 2GWh）","en":"Uzbekistan Standalone BESS Portfolio (2GWh, ACWA Power)","country":"乌兹别克斯坦","region":"中亚","cat":"storage","coord":[69.24,41.29],"cap":"2000 MWh","inv":8,"invText":"约 8 亿美元（估）","status":"规划","year":2027,"updated":"2026-06","owner":"ACWA Power、乌兹别克斯坦能源部","flagship":false,"desc":"COP29签署独立储能实施协议，ACWA在乌兹别克全国部署2GWh电网级储能","detail":"2024年11月ACWA Power与乌兹别克斯坦能源部在COP29（巴库）签署2 GWh独立电池储能系统实施协议，ACWA获得合同优先权，协议有效期2年。具体选址将通过可行性研究确定。该协议是乌兹别克对ACWA Power 13 GW开发管道的延伸，旨在解决可再生能源并网灵活性不足问题。","descEn":"2 GWh of grid-scale standalone BESS across Uzbekistan — implementation agreement signed at COP29 in November 2024.","detailEn":"Signed at COP29 in Baku on November 16, 2024, the binding Implementation Agreement between ACWA Power and Uzbekistan's Ministry of Energy grants ACWA contractual priority for up to 2 GWh of new standalone BESS capacity. Sites will be identified through joint feasibility studies. The agreement is valid for two years and extends ACWA's dominant position in Uzbekistan's energy sector (13 GW pipeline under development).","progress":"COP29签署实施协议，可行性研究选址中，首批BESS筹备招标"},
  {"id":5054,"name":"乌兹别克斯坦锡达里亚CCGT二期（Syrdarya 2）","en":"Syrdarya II CCGT Power Plant (1500MW)","country":"乌兹别克斯坦","region":"中亚","cat":"petro","coord":[68.8,40.5],"cap":"1500 MW","inv":9.5,"invText":"约 9.5 亿美元","status":"在建","year":2026,"updated":"2026-06","owner":"Enersok（EDF 15%、Nebras 35%、Siemens Energy 25%、Sojitz/Kyuden 25%）","flagship":false,"desc":"乌兹别克锡达里亚州1500MW联合循环气电，三菱M701JAC燃气轮机，效率超60%","detail":"项目位于乌兹别克斯坦锡达里亚州希林市，由EDF、卡塔尔Nebras Power、西门子能源、日本住金/九电国际合资建设，合同于2021年完成，装机1500 MW（两台三菱M701JAC燃气轮机），效率逾60%，预计年发电120亿千瓦时。融资约8.05亿美元，包括JBIC 3.93亿美元、IFC及日欧商业银行联合贷款；2022年12月开工，2024年完成主机安装，2026年Q1目标投运。","descEn":"1,500 MW CCGT gas power plant in Shirin, Syrdarya Region — Mitsubishi M701JAC turbines, >60% efficiency, $950M investment.","detailEn":"Developed by Enersok (EDF, Nebras Power, Siemens Energy, Sojitz, Kyuden), the 1,500 MW Syrdarya II CCGT uses two Mitsubishi M701JAC gas turbines (>60% efficiency) and generates ~12 billion kWh annually. $950M total project cost funded partly by a $393M JBIC loan plus IFC co-financing. Construction broke ground December 2022; turbine installation completed in 2024; commissioning targeted for Q1 2026 under a 25-year PPA with NEGU.","progress":"主机安装完成，调试进行中，预计2026年投运"},
  {"id":5055,"name":"乌兹别克斯坦苏尔汉达里亚1560MW气电项目","en":"Surkhandarya 1,560MW CCGT Power Plant","country":"乌兹别克斯坦","region":"中亚","cat":"petro","coord":[67.28,37.85],"cap":"1560 MW","inv":13,"invText":"约 13 亿欧元（约14亿美元）","status":"在建","year":2027,"updated":"2026-06","owner":"SCE-Quvvat（石城能源25%、EDF15%、西门子能源25%、Nebras Power35%）","flagship":false,"desc":"乌兹别克南部苏尔汉达里亚州1560MW联合循环气电，德法卡塔尔联合建设","detail":"项目位于乌兹别克斯坦苏尔汉达里亚州安戈尔市，由Stone City Energy、EDF、西门子能源、卡塔尔Nebras Power合资建设1560 MW联合循环气电站（西门子SGT5-9000HL燃气轮机，基础负荷效率>60%）。2024年3月完成约12亿欧元融资（AIIB、EBRD、亚洲开发银行参与），首批资金2024年12月到位；2022年3月奠基开工，计划2027年1月投运，签有25年PPA。","descEn":"1,560 MW CCGT plant in Angor, Surkhandarya — Siemens SGT5-9000HL turbines, €1.2B financing closed March 2024, COD January 2027.","detailEn":"Located in Angor, Surkhandarya Region (southern Uzbekistan), the project is jointly owned by Stone City Energy (25%), EDF (15%), Siemens Energy (25%) and Nebras Power (35%), through project company SCE-Quvvat LLC. Siemens SGT5-9000HL turbines deliver >60% baseload efficiency. EUR 1.2B financing closed March 2024 (AIIB, EBRD, ADB, commercial banks); first disbursement December 2024. Construction started March 2022; COD targeted January 2027 under a 25-year PPA.","progress":"2024年3月欧元12亿融资关闭，建设进入设备安装阶段"},
  {"id":5056,"name":"乌兹别克阿尔马雷克铜厂3期（约什利克-1矿）","en":"AGMK Copper Processing Plant No.3 (Yoshlik-1)","country":"乌兹别克斯坦","region":"中亚","cat":"mining","coord":[69.6,40.85],"cap":"日产铜精矿 5000 吨","inv":27,"invText":"约 27 亿美元","status":"投运","year":2026,"updated":"2026-06","owner":"阿尔马雷克矿冶联合体（AGMK）","flagship":true,"desc":"乌兹别克最大工业项目之一，约什利克-1矿配套27亿美元铜精矿选厂三期投运","detail":"乌兹别克阿尔马雷克矿冶联合体（AGMK）在约什利克-1铜矿配套建设第三号铜精矿选厂，总投资27亿美元，占地196公顷，2026年正式投产。日处理铜精矿能力从2400吨提升至约5000吨，帮助AGMK推进150亿美元扩产计划（2030年前铜阳极产量翻倍至40万吨/年）。约什利克-1及卡尔莫吉尔矿区探明铜储量达4500万吨，金储量逾5000吨，预计可供百年开采。","descEn":"Uzbekistan's largest industrial project — AGMK Copper Processing Plant No.3 at Yoshlik-1 deposit commissioned 2026, $2.7B investment.","detailEn":"Almalyk Mining & Metallurgical Complex (AGMK) launched Copper Processing Plant No. 3 in early 2026, built on a 196-hectare site adjacent to the Yoshlik-1 open-pit mine. The $2.7B facility nearly doubles daily concentrate output from 2,400 t to ~5,000 t. This is the first tranche of AGMK's $15B long-term expansion plan targeting 400,000 t/yr of copper cathodes by 2030, backed by $2.55B in KfW IPEX-Bank arranged loans. Yoshlik-1 and Qalmoqqir together hold an estimated 45 Mt of copper and >5,000 t of gold.","progress":"2026年选厂三期正式投产，AGMK铜阳极扩产至24万吨/年阶段目标"},
  {"id":5057,"name":"哈萨克斯坦科克赛铜矿开发（Kazakhmys）","en":"Koksay Copper Mine Development (Kazakhmys)","country":"哈萨克斯坦","region":"中亚","cat":"mining","coord":[79,43.5],"cap":"年产铜精矿 8–8.5 万吨铜当量","inv":22,"invText":"约 22 亿美元（科克赛部分）","status":"在建","year":2026,"updated":"2026-06","owner":"Kazakhmys Corporation","flagship":false,"desc":"热苏州科克赛铜矿，哈萨克最大新建铜矿之一，含铜3.5百万吨，年处理5000万吨矿石","detail":"科克赛铜矿位于哈萨克斯坦热苏州，矿石储量8.24亿吨（含铜350万吨、金63.7吨、银865吨），平均铜品位0.42%，矿山寿命逾20年。Kazakhmys Corporation联合科克赛和艾达尔利（Aidarly）矿共投入约44亿美元，选厂年处理能力5000万吨矿石，目标2026年建成投产，届时哈萨克斯坦铜矿石年产量将翻倍至3亿吨，是中亚铜资源战略布局重大里程碑。","descEn":"Koksay copper mine in Zhetysu Region — 824Mt ore reserve at 0.42% Cu, 50Mtpa plant, part of Kazakhmys' $4B copper expansion.","detailEn":"Located in Zhetysu Region, the Koksay deposit holds 823.7 Mt of ore with 3.5 Mt of copper (0.42% average grade), plus 63.7 t of gold and 865 t of silver. Kazakhmys Corporation owns the project through Consolidated Construction Mining Company LLP. A new concentrator with 50 Mtpa capacity targets commissioning by 2026. Combined with the Aidarly project, total investment exceeds $4B (≈2.056 trillion KZT), enabling Kazakhstan to double its annual copper ore output to 300 Mt.","progress":"建设进行中，计划2026年建成选矿厂；Aidarly矿计划2027年投产"},
  {"id":5058,"name":"吉尔吉斯斯坦苏乌萨梅尔-科科梅伦水电梯级","en":"Suusamyr-Kokomeren HPP Cascade (1305MW)","country":"吉尔吉斯斯坦","region":"中亚","cat":"renewable","coord":[73.5,41.7],"cap":"1305 MW","inv":30,"invText":"约 30 亿美元（估）","status":"规划","year":2030,"updated":"2026-06","owner":"吉尔吉斯斯坦能源部、中国电力工程有限公司（CNEEC）","flagship":false,"desc":"吉尔吉斯科科梅伦河3座水电站梯级开发，总装机1305MW，CNEEC签署合作备忘录","detail":"苏乌萨梅尔-科科梅伦水电梯级位于吉尔吉斯斯坦纳伦州科科梅伦河，包括卡拉科尔（33 MW）、科科梅伦一期（360 MW）和科科梅伦二期（912 MW）三座电站，年发电量约33亿千瓦时。2024年1月吉尔吉斯能源部与中国电力工程有限公司（CNEEC）签署合作备忘录；2025年3月欧亚开发银行（EDB）与吉政府签署技术援助协议，开展预可研；2025年12月项目获国家重点投资项目地位。","descEn":"Three-dam 1,305 MW cascade on Kyrgyzstan's Kokomeren River — memorandum with China's CNEEC signed 2024, EDB pre-feasibility study launched 2025.","detailEn":"The cascade comprises Karakol (33 MW), Kokomeren HPP-1 (360 MW) and Kokomeren HPP-2 (912 MW), together generating ~3.3 billion kWh/yr. Kyrgyzstan's Ministry of Energy signed a cooperation MOU with CNEEC in January 2024 for this and the Kara-Keche coal plant. The EDB signed a technical assistance agreement in March 2025 to begin a pre-feasibility study; national investment project status was granted December 2025. Estimated cost ~$3B; schedule targets early 2030s commissioning.","progress":"2025年12月获国家重点投资项目地位，EDB完成预可研立项，融资结构制定中"},
  {"id":5059,"name":"吉尔吉斯斯坦托克托古尔水电站现代化改造","en":"Toktogul HPP Modernization (1440MW upgrade)","country":"吉尔吉斯斯坦","region":"中亚","cat":"renewable","coord":[72.9,41.79],"cap":"1440 MW（改造后）","inv":2,"invText":"约 2 亿美元","status":"投运","year":2025,"updated":"2026-06","owner":"吉尔吉斯斯坦国家电力公司（Elektricheskiye Stantsii）","flagship":false,"desc":"吉尔吉斯最大水电站托克托古尔4台机组全面改造，装机从1200MW升至1440MW","detail":"托克托古尔水电站坐落于吉尔吉斯斯坦纳伦河上，是全国最大电力设施。四台机组历经2021—2025年逐步改造（每台从300 MW升至360 MW），2025年11月最后一台机组改造完成，总装机容量升至1440 MW，年增发约5.25亿千瓦时，机组寿命延长25—30年。总改造投资约2亿美元，对缓解吉尔吉斯斯坦电力短缺具重要意义。","descEn":"Full modernization of Kyrgyzstan's largest 1,440 MW Toktogul HPP completed 2025 — all four units upgraded from 300MW to 360MW each.","detailEn":"Located on the Naryn River in Jalal-Abad Region, Toktogul HPP underwent a sequential upgrade of all four generating units between 2021 and 2025. Each unit was refurbished from 300 MW to 360 MW (total: 1,200 MW→1,440 MW), adding ~525 million kWh/yr and extending plant life by 25–30 years. The final Unit 4 modernization ran from March to November 2025. Total investment ~$200M. The plant remains the backbone of Kyrgyzstan's power system.","progress":"2025年11月四台机组全部改造完毕，总装机达1440MW"},
  {"id":5060,"name":"哈萨克斯坦YPP绿氢绿氨综合体","en":"YPP Kazakhstan Green Hydrogen & Ammonia Complex","country":"哈萨克斯坦","region":"中亚","cat":"renewable","coord":[51.8,43.7],"cap":"2 GW 电解槽","inv":31,"invText":"约 31 亿美元","status":"规划","year":2030,"updated":"2026-06","owner":"YPP Corporation（韩国）","flagship":false,"desc":"韩国YPP在哈萨克斯坦投资31亿美元建2GW电解槽绿氢绿氨综合体","detail":"韩国YPP Corporation宣布在哈萨克斯坦建设2 GW电解槽绿氢及绿氨生产综合体，总投资约31亿美元，初步规划选址于曼格斯套州（里海沿岸），利用当地丰富的风能和光照资源驱动电解。项目目标2030年前实现规模化生产，并将绿氢/绿氨出口至韩国及欧洲市场。该投资是哈萨克斯坦2040年氢能发展概念框架下吸引的重要外资之一。","descEn":"South Korea's YPP Corporation plans a $3.1B 2GW electrolyser green hydrogen and ammonia complex in Kazakhstan's Mangystau region.","detailEn":"YPP Corporation announced a $3.1B investment in a 2 GW electrolyser-based green hydrogen and green ammonia complex in Kazakhstan, tentatively sited in the Mangystau Region on the Caspian coast, leveraging strong regional wind and solar resources. The project falls under Kazakhstan's 2024 Hydrogen Development Concept (targeting 10 GW electrolyser capacity by 2040) and aims for green ammonia exports to South Korea and Europe. Milestone target: commercial production by 2030.","progress":"投资意向达成，前期可行性研究及选址工作推进"},
  {"id":5061,"name":"哈萨克斯坦东哈州锂矿开发（HMS Bergbau）","en":"East Kazakhstan Lithium Mining Projects (HMS Bergbau)","country":"哈萨克斯坦","region":"中亚","cat":"mining","coord":[82.6,49.7],"cap":"两座锂矿及加工厂（规模待定）","inv":5,"invText":"约 5 亿美元","status":"规划","year":2028,"updated":"2026-06","owner":"HMS Bergbau AG（德国）","flagship":false,"desc":"德国HMS Bergbau在哈萨克斯坦东哈州乌兰区投资5亿美元建两座锂矿及加工厂","detail":"2025年4月哈萨克斯坦东哈州（East Kazakhstan Region）地方当局披露，德国矿业公司HMS Bergbau AG将在乌兰区（Ulan District）投资约5亿美元建设两座锂矿开采和加工厂，利用当地锂矿资源满足新能源电池需求。哈萨克斯坦锂资源主要分布于曼格斯套含油盐水层和东哈地区，本项目是哈萨克斯坦 2024—2028年稀有金属综合开发计划下吸引的重要外资项目。","descEn":"Germany's HMS Bergbau AG to invest $500M in two lithium mining and processing plants in Ulan District, East Kazakhstan.","detailEn":"Announced in April 2025 by East Kazakhstan Region authorities, German miner HMS Bergbau AG plans a ~$500M investment in two lithium extraction and processing facilities in the Ulan District. The project taps Kazakhstan's significant lithium reserves and aligns with the country's 2024-2028 Rare Earth Metals Development Plan. Kazakhstan is positioning itself as a critical minerals supplier for EV batteries, with lithium concentrations also noted in the Mangystau-Ustyurt oil and gas province.","progress":"2025年4月投资意向披露，前期勘探及环评推进"},
  {"id":5062,"name":"哈萨克斯坦Kondybay天然气综合体（NurGas Energy）","en":"Kondybay Gas Processing Complex (NurGas Energy)","country":"哈萨克斯坦","region":"中亚","cat":"petro","coord":[53.6,47.7],"cap":"天然气处理能力 10 亿立方米/年","inv":8,"invText":"约 8 亿美元","status":"规划","year":2027,"updated":"2026-06","owner":"NurGas Energy、哈萨克斯坦国家油气公司","flagship":false,"desc":"哈萨克斯坦西部阿特劳州孔季拜气田天然气处理综合体，年处理10亿立方米","detail":"孔季拜（Kondybay）天然气综合体规划于哈萨克斯坦阿特劳州，为里海沿岸伴生气资源综合开发项目，年处理天然气约10亿立方米，生产商品天然气、LPG及凝析油，满足哈萨克斯坦国内能源需求并可部分出口。项目由NurGas Energy运营，总投资约8亿美元，与哈萨克斯坦推动天然气深加工和减少伴生气放空的政策目标高度契合。","descEn":"Kondybay gas processing complex in Atyrau Region — 1 bcm/yr capacity to capture associated gas and produce commercial gas and LPG.","detailEn":"Located in the Atyrau Region near Kazakhstan's Caspian coast, the Kondybay complex will process ~1 billion cubic metres of associated petroleum gas annually, producing commercial natural gas, LPG and condensate. Operated by NurGas Energy, the $800M project aligns with Kazakhstan's policy to eliminate gas flaring and develop domestic gas processing capacity. It is expected to enter operation in 2027, providing feedstock for downstream petrochemicals and reducing Kazakhstan's reliance on gas imports.","progress":"项目批复及前期工程推进，计划2027年投运"},
  {"id":5063,"name":"哈萨克斯坦东哈州稀土金属项目群（2024–2028）","en":"Kazakhstan Rare Earth & Critical Minerals Projects (2024–2028)","country":"哈萨克斯坦","region":"中亚","cat":"mining","coord":[82,49.8],"cap":"锂/稀土/钴多矿种","inv":3,"invText":"约 3 亿美元（2025年探矿及基础设施）","status":"规划","year":2028,"updated":"2026-06","owner":"哈萨克斯坦地质委员会、国际矿业企业","flagship":false,"desc":"哈萨克斯坦2024–2028稀有金属综合计划，东哈州多处锂稀土探矿及加工投资","detail":"哈萨克斯坦政府2024年发布2024—2028年稀有金属综合开发计划，在东哈萨克斯坦、卡拉干达等地区推进锂、钴、稀土氧化物、钨、铌、钽等战略矿产的勘探和开发。2025年3月宣布投入800万美元锂资源详查；加拿大Condor Energies于同年宣布开发科尔库杜克盐水锂矿；美国地质调查局（USGS）与哈方达成咸海地区锂资源初步勘探协议。哈已列为欧盟战略原料法下重点伙伴国，铜、锂、镍、钴、稀土开发多线并进。","descEn":"Kazakhstan's 2024–2028 Rare Earth Metal Plan — $800M lithium exploration, partnerships with USGS, Canadian and German firms across East Kazakhstan and Aral Sea regions.","detailEn":"Kazakhstan launched its 2024–2028 Rare Earth Metals Complex Plan targeting lithium, cobalt, rare earth oxides, tungsten, niobium and tantalum. March 2025: $8M allocated for detailed lithium survey. Canadian firm Condor Energies announced development of the Kolkuduk lithium brine deposit. USGS signed a preliminary agreement for Aral Sea region lithium exploration. Kazakhstan is designated a priority partner under the EU Critical Raw Materials Act, and is pursuing parallel tracks in copper, lithium, nickel and REEs to position as a critical minerals exporter.","progress":"2025年多份勘探协议签署，首批矿区详查进行中"},

  // ===== 中东（5150-5184）=====
  {"id":5150,"name":"卡哈法光伏电站（Al Kahfah）","en":"Al Kahfah Solar PV IPP","country":"沙特阿拉伯","region":"中东","cat":"renewable","coord":[43.48,27.42],"cap":"1425 MW","inv":14,"invText":"约 14 亿美元","status":"投运","year":2025,"updated":"2026-06","owner":"ACWA Power / Badeel","flagship":false,"desc":"沙特哈伊勒省1425MW独立光伏电站，2025年11月投运","detail":"卡哈法光伏电站位于沙特哈伊勒省，装机1425 MW，由ACWA Power与Badeel联合开发，2025年11月获得商业运营证书，是沙特当年单年最大光伏投运组合之一。电站采用35年PPA模式，向SPPC供电，可为约40万户家庭提供清洁电力。2026年初因沙特电网稳定问题出现限电，目前已部分恢复。","descEn":"Al Kahfah 1,425 MW solar IPP in Hail Province, Saudi Arabia, commenced commercial operations in November 2025.","detailEn":"Al Kahfah Solar PV IPP is located in Hail Province, Saudi Arabia, with 1,425 MW of capacity developed by ACWA Power and Badeel. It achieved commercial operation in November 2025 under a 35-year PPA with SPPC, becoming one of the largest single-year solar commissionings in the kingdom. It can power approximately 400,000 homes and forms part of Saudi Arabia's NREP rollout."},
  {"id":5151,"name":"阿尔-拉斯2号光伏电站（Ar Rass 2）","en":"Ar Rass 2 Solar PV IPP","country":"沙特阿拉伯","region":"中东","cat":"renewable","coord":[43.52,25.88],"cap":"2000 MW","inv":19,"invText":"约 19 亿美元","status":"投运","year":2025,"updated":"2026-06","owner":"ACWA Power","flagship":false,"desc":"沙特盖西姆省2GW光伏电站，2025年分批投运完毕","detail":"阿尔-拉斯2号光伏电站位于沙特盖西姆省阿尔-拉斯市附近，总装机2000 MW，由ACWA Power开发。首批1000 MW于2025年9月投运，第二批1000 MW随后完工，合计创下沙特单站最大光伏装机纪录之一。项目采用35年PPA，LCOE创历史新低，为沙特Vision 2030可再生能源目标贡献重要产能。","descEn":"Ar Rass 2 is a 2,000 MW solar PV IPP in Qassim Province, Saudi Arabia, commissioned in phases during 2025.","detailEn":"Ar Rass 2 Solar PV IPP is located near Ar Rass city in Saudi Arabia's Qassim Province with a total capacity of 2,000 MW developed by ACWA Power. The first 1,000 MW phase achieved commercial operation in September 2025, with the remaining capacity completed shortly after. The project operates under a 35-year PPA with SPPC and contributes significantly to Saudi Arabia's Vision 2030 renewable energy targets."},
  {"id":5152,"name":"沙特15GW光伏风电综合开发（ACWA-Badeel-SAPCO七站）","en":"Saudi 15 GW Renewable Portfolio (ACWA-Badeel-SAPCO 7 Projects)","country":"沙特阿拉伯","region":"中东","cat":"renewable","coord":[42.8,23.5],"cap":"15000 MW（12000 MW 光伏 + 3000 MW 风电）","inv":83,"invText":"约 83 亿美元","status":"规划","year":2028,"updated":"2026-06","owner":"ACWA Power / Badeel(PIF) / SAPCO(沙特阿美)","flagship":true,"desc":"沙特七站15GW光伏风电大包，创全球单批可再生能源投资纪录","detail":"2025年7月，ACWA Power、Badeel与SAPCO签署七座可再生能源电站PPA，总规模15 GW（比沙3 GW光伏、胡迈吉3 GW光伏、库利斯2 GW光伏、阿菲夫1号2 GW光伏、阿菲夫2号2 GW光伏、斯塔拉2 GW风电、沙格拉1 GW风电），总投资约83亿美元，分布于阿西尔、麦地那、麦加、利雅得各省。所有机组计划于2027年下半年至2028年上半年并网，支撑沙特2030年实现130 GW可再生装机目标。2025年12月完成融资关闭。","descEn":"Saudi Arabia's 15 GW renewable portfolio across seven plants (solar + wind) developed by ACWA Power, Badeel, and SAPCO with $8.3B investment, setting a global record for a single renewable energy tranche.","detailEn":"In July 2025, ACWA Power, Badeel (PIF subsidiary), and SAPCO signed PPAs for seven renewable energy plants totaling 15,000 MW: Bisha (3 GW PV, Asir), Humaij (3 GW PV, Madinah), Khulis (2 GW PV, Makkah), Afif 1 (2 GW PV, Riyadh), Afif 2 (2 GW PV, Riyadh), Starah (2 GW wind, Riyadh) and Shaqra (1 GW wind, Riyadh). Total investment is ~$8.3B; financing closed December 2025. All plants are set for commercial operation in H2 2027 – H1 2028."},
  {"id":5153,"name":"阿尔-萨达维2GW光伏电站","en":"Al Sadawi Solar PV IPP (2 GW)","country":"沙特阿拉伯","region":"中东","cat":"renewable","coord":[47.9,25.3],"cap":"2000 MW","inv":18,"invText":"约 18 亿美元","status":"在建","year":2027,"updated":"2026-06","owner":"Masdar / KEPCO / GD Power","flagship":false,"desc":"沙特东部省2GW大型光伏IPP，LCOE创全球新低1.29美分/kWh","detail":"阿尔-萨达维光伏电站位于沙特东部省，装机2000 MW，由阿布扎比Masdar、韩国电力KEPCO与国家电力GD Power组成的财团中标，LCOE仅1.2926美分/kWh创全球新低（NREP第五轮）。项目已于2024年底签署PPA，预计2027年第二季度投运，可为约60万户家庭供电。","descEn":"Al Sadawi 2,000 MW solar PV IPP in Saudi Arabia's Eastern Province, awarded to Masdar-KEPCO-GD Power consortium at a record-low LCOE of 1.29 cents/kWh.","detailEn":"Al Sadawi Solar PV IPP in Saudi Arabia's Eastern Province has 2,000 MW of capacity and was awarded to a consortium of Masdar, KEPCO, and GD Power under NREP Round 5 at a world record LCOE of 1.2926 cents/kWh. The PPA was signed in late 2024, with commercial operations targeted for Q2 2027. The project will power approximately 600,000 households."},
  {"id":5154,"name":"沙特NREP第七轮5.3GW光伏风电招标包","en":"Saudi NREP Round 7 – 5.3 GW Solar & Wind Tender","country":"沙特阿拉伯","region":"中东","cat":"renewable","coord":[38.5,26.5],"cap":"5300 MW（3100 MW 光伏 + 2200 MW 风电）","inv":50,"invText":"预计约 50 亿美元","status":"规划","year":2029,"updated":"2026-06","owner":"SPPC（沙特电力采购公司）/ 多家国际开发商","flagship":false,"desc":"沙特第七轮NREP招标：塔巴尔贾勒II 1.4GW、毛卡格600MW等六个项目","detail":"2025年9月，沙特电力采购公司（SPPC）发布第七轮NREP资格预审，总规模5300 MW，涵盖塔巴尔贾勒II光伏（1400 MW，焦夫省）、毛卡格光伏（600 MW，哈伊勒）、塔思利斯光伏（600 MW，阿西尔）、南乌拉光伏（500 MW，麦地那）、比尔加风电（1300 MW，麦地那）和沙格兰风电（900 MW，麦地那），2026年1月公布合格投标人。项目预计2028–2029年投运。","descEn":"Saudi Arabia's NREP Round 7 includes 5,300 MW across four solar and two wind projects, with prequalification launched in September 2025 and bids due in 2026.","detailEn":"Saudi Arabia's NREP Round 7, launched in September 2025, covers six projects totalling 5,300 MW: Tabarjal II PV (1,400 MW, Al Jouf), Mawqaq PV (600 MW, Hail), Tathleeth PV (600 MW, Aseer), South Al Ula PV (500 MW, Madinah), Bilghah Wind (1,300 MW, Madinah), and Shagran Wind (900 MW, Madinah). Qualified bidders were revealed in January 2026; commercial operations are targeted for 2028–2029."},
  {"id":5155,"name":"阿尔-盖特600MW风电场","en":"Al Ghat Wind Farm (600 MW)","country":"沙特阿拉伯","region":"中东","cat":"renewable","coord":[43.9,26],"cap":"600 MW","inv":6,"invText":"约 6 亿美元","status":"在建","year":2027,"updated":"2026-06","owner":"Marubeni / Abdul Aziz Al-Ajlan Sons","flagship":false,"desc":"沙特利雅得省600MW风电场，LCOE创全球风电最低纪录1.57美分/kWh","detail":"阿尔-盖特风电场位于沙特利雅得省，装机600 MW，由日本丸红（Marubeni）联合沙特本地伙伴开发，属NREP第四轮项目，LCOE仅1.56558美分/kWh创全球风电最低记录。2026年3月首台风机完成电网同步并网，全部80台风机预计2027年第二季度完工投运。","descEn":"Al Ghat 600 MW wind farm in Riyadh Province, Saudi Arabia, achieved a world-record LCOE of 1.57 cents/kWh; first turbine synchronized with the grid in March 2026.","detailEn":"Al Ghat Wind Farm (600 MW) is located in Riyadh Province, Saudi Arabia, and is developed by a consortium led by Japan's Marubeni with local partner Abdul Aziz Al-Ajlan Sons. Under NREP Round 4, it set a global wind LCOE record of 1.56558 cents/kWh. The first turbine was synchronized with the Saudi grid in March 2026 and all 80 turbines are expected to reach commercial operation by Q2 2027."},
  {"id":5156,"name":"鲁迈赫1号与奈里亚赫1号燃气联合循环电站","en":"Rumah 1 & Nairyah 1 CCGT Power Plants","country":"沙特阿拉伯","region":"中东","cat":"renewable","coord":[45.8,24.4],"cap":"3600 MW（各 1800 MW）","inv":60,"invText":"约 60 亿美元","status":"在建","year":2028,"updated":"2026-06","owner":"ACWA Power / 沙特电力 SEC / KEPCO","flagship":false,"desc":"沙特两座1800MW灵活天然气联合循环电站，含碳捕集，计划2028年投运","detail":"鲁迈赫1号（利雅得省以东80公里）与奈里亚赫1号（东部省）各1800 MW，采用灵活联合循环燃气轮机（CCGT）技术并配备碳捕集单元，由ACWA Power、沙特电力与韩国电力联合开发，2025年3月SEPCO3与斗山联合体签署EPC合同，计划2028年第二季度投运，合计向电网供应7200 MW（含另两台姊妹机组），是沙特电力系统灵活性改造的核心工程。","descEn":"Rumah 1 (1,800 MW) and Nairyah 1 (1,800 MW) CCGT power plants in Saudi Arabia equipped with carbon capture units, targeting Q2 2028 COD.","detailEn":"Rumah 1 is located ~80 km east of Riyadh and Nairyah 1 is in the Eastern Province; both are 1,800 MW flexible CCGT plants with carbon capture units. Developed by ACWA Power, SEC, and KEPCO, EPC contracts were signed with SEPCO3-Doosan consortium in March 2025. Both are scheduled for commercial operation in Q2 2028, together contributing 3,600 MW of dispatchable low-carbon capacity to Saudi Arabia's grid."},
  {"id":5157,"name":"阿布扎比阿尔-阿齐扎5.2GW光储项目","en":"Al Azeezah Solar PV + BESS (5.2 GW / 19 GWh)","country":"阿联酋","region":"中东","cat":"storage","coord":[53.9,22.8],"cap":"5200 MW / 19000 MWh","inv":59,"invText":"约 59 亿美元（AED 232 亿）","status":"在建","year":2027,"updated":"2026-06","owner":"Masdar / EWEC","flagship":true,"desc":"全球首个GW级24小时全可再生能源光储电站，1GW基荷持续供电","detail":"阿尔-阿齐扎项目位于阿布扎比南部，由Masdar与阿联酋水电公司（EWEC）共同开发，配置5.2 GW光伏与19 GWh电池储能（CATL Tener系统），可实现1 GW持续基荷供电，占地90平方公里，2025年1月在阿布扎比可持续发展周正式宣布并开工，预计2027年首批投运、2028年全容量完工。中国POWERCHINA和印度L&T担任EPC总承包，JA Solar与晶科提供光伏组件，创造逾万个就业岗位。","descEn":"Al Azeezah is the world's first and largest gigascale 24/7 solar-plus-storage project (5.2 GW PV + 19 GWh BESS) in southern Abu Dhabi, delivering 1 GW of continuous baseload power.","detailEn":"Located in southern Abu Dhabi, Al Azeezah is developed by Masdar and EWEC with 5.2 GW of solar PV and a 19 GWh BESS supplied by CATL, across 90 km². Ground was broken at Abu Dhabi Sustainability Week in January 2025. POWERCHINA and L&T serve as EPC contractors; JA Solar and Jinko Solar supply modules. The project delivers 1 GW of firm 24/7 renewable power and is targeted for first output in 2027 and full completion by April 2028, at a cost of ~$5.9B (AED 232B)."},
  {"id":5158,"name":"阿布扎比阿尔-扎拉夫1.5GW光伏电站","en":"Al Zarraf Solar PV IPP (1.5 GW)","country":"阿联酋","region":"中东","cat":"renewable","coord":[53.6,23.3],"cap":"1500 MW","inv":12,"invText":"约 12 亿美元","status":"规划","year":2028,"updated":"2026-06","owner":"EDF / KOWEPO / EWEC","flagship":false,"desc":"阿布扎比第五座大型光伏IPP，EDF与韩国西部电力联合开发","detail":"阿尔-扎拉夫光伏电站位于阿布扎比南部阿尔-阿齐扎项目以北约50公里处，装机1500 MW，由法国EDF与韩国西部电力（KOWEPO）联合体于2025年6月与EWEC签署联合开发协议（JDA），成为阿布扎比第五个大型光伏独立电站项目。项目计划于2028年投运，助力阿布扎比2035年实现60%清洁能源目标。","descEn":"Al Zarraf 1.5 GW solar PV IPP in Abu Dhabi, developed by EDF and KOWEPO under a JDA signed with EWEC in June 2025.","detailEn":"Al Zarraf Solar PV IPP is located ~50 km north of the Al Azeezah project in southern Abu Dhabi, with 1,500 MW of capacity. EDF and KOWEPO signed a Joint Development Agreement with EWEC in June 2025 to co-develop this fifth utility-scale solar project for Abu Dhabi. It is expected to be commercially operational by 2028, contributing to Abu Dhabi's target of 60% clean energy by 2035."},
  {"id":5159,"name":"Google-HUMAIN利雅得与达曼AI数据中心","en":"Google Cloud–HUMAIN AI Hub (Riyadh & Dammam)","country":"沙特阿拉伯","region":"中东","cat":"datacenter","coord":[46.72,24.69],"cap":"初期 200 MW，远期 6 GW（HUMAIN总规划）","inv":100,"invText":"约 100 亿美元（Google-PIF联合投资）","status":"在建","year":2026,"updated":"2026-06","owner":"Google Cloud / PIF / HUMAIN","flagship":true,"desc":"谷歌与PIF在沙特共投100亿美元打造全球AI枢纽，HUMAIN主导运营","detail":"2025年5月，谷歌云与沙特公共投资基金（PIF）宣布在沙特合作建设全球AI枢纽，联合投资100亿美元，依托HUMAIN（PIF旗下AI公司）在达曼与利雅得各建100 MW首期数据中心，预计2026年第二季度投产，配置超1.8万颗英伟达GB300 GPU。HUMAIN整体规划容量达6 GW，成为中东最大AI算力平台之一，经济贡献预计到2040年达350亿美元。","descEn":"Google Cloud and PIF announced a $10B joint investment to build a global AI hub in Saudi Arabia through HUMAIN, with initial 100 MW data centers in Riyadh and Dammam going live in Q2 2026.","detailEn":"In May 2025, Google Cloud and Saudi Arabia's Public Investment Fund announced a $10 billion partnership to develop a global AI hub through HUMAIN, PIF's AI entity. The initial facilities are 100 MW data centers in Riyadh and Dammam, expected to come online in Q2 2026 with over 18,000 NVIDIA GB300 NVL72 GPUs. HUMAIN's long-term roadmap targets 6 GW of data center capacity across Saudi Arabia, forming one of the Middle East's largest AI compute platforms."},
  {"id":5160,"name":"甲骨文沙特云与AI基础设施","en":"Oracle Saudi Arabia Cloud & AI Infrastructure ($14B)","country":"沙特阿拉伯","region":"中东","cat":"datacenter","coord":[46.77,24.71],"cap":"多云区域（利雅得、吉达、达曼）","inv":140,"invText":"约 140 亿美元（十年期）","status":"在建","year":2026,"updated":"2026-06","owner":"Oracle / 沙特政府","flagship":false,"desc":"甲骨文宣布未来十年向沙特投资140亿美元扩建云与AI数据中心","detail":"2025年5月，甲骨文宣布未来十年对沙特阿拉伯投资140亿美元，在利雅得、吉达现有云区域基础上，增设NEOM及达曼数据中心节点，打造覆盖全国的云与AI基础设施网络，并计划培训5万名沙特AI人才。此举与沙特政府将2026年定为「AI年」战略高度契合，是沙特数字经济转型的重要支柱。","descEn":"Oracle announced a $14 billion, 10-year investment plan to expand cloud and AI data center infrastructure across Saudi Arabia, including new nodes in NEOM and Dammam.","detailEn":"In May 2025, Oracle committed to invest $14 billion in Saudi Arabia over ten years, building on existing cloud regions in Riyadh and Jeddah while adding data center presence in NEOM and Dammam. The investment supports Saudi Arabia's 2026 Year of AI strategy and includes plans to train 50,000 Saudis in AI skills, in partnership with the Ministry of Communications and the National eLearning Center."},
  {"id":5161,"name":"科威特阿迪比达—沙加亚1100MW光伏项目（第三期一区）","en":"Kuwait Al Dibdibah–Al Shagaya Phase III Zone 1 Solar PV IPP (1,100 MW)","country":"科威特","region":"中东","cat":"renewable","coord":[46.5,29.5],"cap":"1100 MW","inv":10,"invText":"约 10 亿美元","status":"规划","year":2028,"updated":"2026-06","owner":"科威特KAPP / Masdar或EDF（待定）","flagship":false,"desc":"科威特贾赫拉省1100MW大型光伏IPP，30年PPA，2026年确定中标方","detail":"科威特合作项目管理局（KAPP）在贾赫拉省沙加亚可再生能源园区内招标1100 MW光伏项目（第三期一区），三家联合体（ACWA+科威特/Masdar+Fouad Alghanim/EDF+Al Sagar+KOWEPO）提交了技术方案，预计2026年第二季度公布中标方，并签署30年PPA，是科威特迄今最大单一光伏IPP。","descEn":"Kuwait's Al Dibdibah–Al Shagaya Phase III Zone 1 is a 1,100 MW solar PV IPP in Jahra Governorate, with three shortlisted bidder consortia and a winner expected in Q2 2026.","detailEn":"Kuwait Authority for Partnership Projects (KAPP) is procuring 1,100 MW of solar capacity at the Al Dibdibah/Shagaya Renewable Energy Park in Jahra Governorate. Three consortia submitted proposals: ACWA Power with a Kuwaiti partner, Masdar with Fouad Alghanim & Sons, and EDF with Al Sagar and KOWEPO. The winning bidder is expected to be announced in June 2026 under a 30-year PPA, making this Kuwait's largest solar IPP to date."},
  {"id":5162,"name":"科威特阿迪比达—沙加亚500MW光伏项目（第三期二区）","en":"Kuwait Al Dibdibah–Al Shagaya Phase III Zone 2 Solar PV IPP (500 MW)","country":"科威特","region":"中东","cat":"renewable","coord":[46.3,29.4],"cap":"500 MW","inv":5,"invText":"约 5 亿美元","status":"规划","year":2029,"updated":"2026-06","owner":"科威特KAPP / 待定","flagship":false,"desc":"科威特沙加亚园区500MW第二批光伏IPP，2026年开标","detail":"科威特阿迪比达—沙加亚第三期二区500 MW光伏IPP与一区同属沙加亚园区，由KAPP负责招标，原定2026年2月截标，后延至2026年4月30日，是科威特可再生能源规划的重要组成，与一区合计形成1600 MW光伏产能，推动科威特实现2030年可再生能源占比15%目标。","descEn":"Kuwait Al Dibdibah–Shagaya Phase III Zone 2 is a 500 MW solar PV IPP in Jahra Governorate, with bids submitted by April 2026.","detailEn":"The 500 MW Al Dibdibah–Al Shagaya Phase III Zone 2 solar PV project is being procured by Kuwait's KAPP in Jahra Governorate alongside the larger 1,100 MW Zone 1. The bid deadline was extended to April 30, 2026. Together the two zones will add 1,600 MW of solar capacity and help Kuwait meet its 15% renewables target by 2030."},
  {"id":5163,"name":"巴林阿勒杜尔100MW光伏电站","en":"Bahrain Al Dur 100 MW Solar PV Project","country":"巴林","region":"中东","cat":"renewable","coord":[50.61,25.98],"cap":"100 MW","inv":1.2,"invText":"约 1.2 亿美元","status":"在建","year":2026,"updated":"2026-06","owner":"巴林水电局（EWA）","flagship":false,"desc":"巴林首座百兆瓦级光伏电站，2026年第三季度完工，推动2035年可再生能源20%目标","detail":"阿勒杜尔100 MW光伏电站位于巴林南部省阿勒杜尔地区，由水电局（EWA）开发，共安装约135,000块光伏板，占地约83万平方米，2025年底开工，计划2026年第三季度并网。该项目是巴林国家可再生能源计划核心项目，将助力巴林2035年实现可再生能源占比20%，并推动2060年碳中和目标。","descEn":"Bahrain's Al Dur 100 MW solar PV plant in the Southern Governorate, built by EWA, targets completion in Q3 2026 and will support Bahrain's 2035 renewables target.","detailEn":"Al Dur 100 MW Solar PV is located in the Al Dur area of Bahrain's Southern Governorate, developed by the Electricity and Water Authority (EWA). Construction began in late 2025, with ~135,000 solar panels spread across 830,000 m². The plant is scheduled for grid connection in Q3 2026. It represents a key milestone in Bahrain's National Renewable Energy Plan to reach 20% renewables by 2035 and carbon neutrality by 2060."},
  {"id":5164,"name":"伊拉克巴士拉拉塔维1GW光伏电站（GGIP配套）","en":"Iraq Basra Ratawi 1 GW Solar Farm (GGIP)","country":"伊拉克","region":"中东","cat":"renewable","coord":[47.35,30.28],"cap":"1000 MW（1250 MWp）","inv":9,"invText":"约 9 亿美元","status":"在建","year":2027,"updated":"2026-06","owner":"TotalEnergies / QatarEnergy / 巴士拉石油公司","flagship":true,"desc":"伊拉克首座大型光伏电站，TotalEnergies主导，首批250MW已于2026年初投运","detail":"巴士拉拉塔维光伏电站是伊拉克首座大型商业光伏设施，装机1 GWac（1.25 GWp），位于拉塔维油田旁，采用200万块双面板+单轴跟踪，由TotalEnergies（45%）、巴士拉石油公司（30%）和卡塔尔能源（25%）组成的GGIP联合体开发，EPC由能源中国（CEEC）承建。首批250 MW已于2026年第一季度投运，全部四期预计2027年完工，每年减排CO₂约200万吨，向35万户家庭供电。","descEn":"Iraq's first utility-scale solar farm (1 GW) at the Ratawi oilfield near Basra, developed as part of TotalEnergies-led GGIP; first 250 MW phase came online in Q1 2026.","detailEn":"The Ratawi Solar Farm is Iraq's first large-scale solar project, with 1 GWac (1.25 GWp) capacity located at the Ratawi oilfield in Basra governorate. Developed by the GGIP consortium (TotalEnergies 45%, Basrah Oil 30%, QatarEnergy 25%) with CEEC as EPC contractor, the plant uses 2 million bifacial panels on single-axis trackers. The first 250 MW phase was energized in Q1 2026. The full 1 GW is expected by 2027, cutting 2 million tonnes of CO₂ per year and powering 350,000 homes."},
  {"id":5165,"name":"阿曼马胡特—杜库姆2.7GW风光储项目","en":"Oman Mahout–Duqm 2.7 GW Hybrid Wind-Solar-BESS (O-Green / Naqaa)","country":"阿曼","region":"中东","cat":"renewable","coord":[57.6,20.45],"cap":"2700 MW（含风电+光伏+储能，保证出力770 MW）","inv":35,"invText":"约 35 亿美元","status":"规划","year":2029,"updated":"2026-06","owner":"O-Green Energy（阿曼国家绿色能源公司）","flagship":true,"desc":"阿曼首个全天候2.7GW风光储大型项目，2026年5月签署PPA","detail":"2026年5月，阿曼电力采购公司（Nama PWP）与O-Green Energy签署2.7 GW风光储全天候可再生能源项目PPA，选址马胡特与杜库姆，可保证出力约770 MW，年容量因子超70%，媲美燃气发电可靠性。O-Green Energy由阿曼苏丹国于2025年成立，专注大规模清洁能源开发。该项目是阿曼迄今最大单一可再生能源合同，也是全球规模最大的全天候风光储项目之一，支持阿曼2030年7 GW可再生能源和3 GW储能目标。","descEn":"Oman's O-Green Energy (Naqaa) signed a PPA for a 2.7 GW hybrid wind-solar-BESS round-the-clock project in Mahout and Duqm in May 2026, guaranteeing 770 MW of firm power.","detailEn":"In May 2026, Nama Power and Water Procurement signed a PPA with O-Green Energy for a 2.7 GW hybrid renewable project at Mahout and Duqm in Oman. The integrated wind, solar PV, and BESS system guarantees around 770 MW of firm dispatchable capacity with an annual capacity factor exceeding 70%. O-Green Energy was established by Oman in 2025 to develop gigawatt-scale clean energy. This is the largest single renewable energy contract in Oman's history and supports its goal of 7 GW solar/wind and 3 GW BESS by 2030."},
  {"id":5166,"name":"萨拉拉绿氢绿氨项目（SalalaH2）","en":"SalalaH2 Green Hydrogen / Green Ammonia Project","country":"阿曼","region":"中东","cat":"renewable","coord":[54.05,17.02],"cap":"1 GW 风光制氢 / 年产绿氨 100 万吨","inv":50,"invText":"约 50 亿美元","status":"规划","year":2030,"updated":"2026-06","owner":"OQ Alternative Energy / Marubeni / Samsung C&T / Dutco","flagship":false,"desc":"阿曼萨拉拉自贸区出口导向绿氨项目，年产能100万吨，FID预计2026年","detail":"SalalaH2是位于阿曼萨拉拉自贸区的出口导向型绿氨项目，由OQ替代能源、日本丸红、三星物产及Dutco共同开发，利用约1 GW风光电力驱动400 MW碱性电解槽，接入OQ现有氨厂，设计年产绿氨达100万吨。项目成本约50亿美元，pre-FEED已于2025年完成，FID计划2026年，投产目标2030年，全部产量锁定欧洲市场。","descEn":"SalalaH2 is a $5 billion export-focused green ammonia project in Oman's Salalah Free Zone, targeting 1 million tonnes/year output, with FID expected in 2026.","detailEn":"SalalaH2 is being developed in Oman's Salalah Free Zone by OQ Alternative Energy, Marubeni, Samsung C&T, and Dutco. It will use ~1 GW of wind and solar power to run 400 MW of alkaline electrolysers, feeding into OQ's existing ammonia plant to produce up to 1 million tonnes per year of green ammonia for export to Europe. Pre-FEED was completed in 2025, with FID expected in 2026 and commercial operations targeted for 2030. Project cost is ~$5 billion."},
  {"id":5167,"name":"卡塔尔北方气田东区LNG扩能（NFE）","en":"Qatar North Field East (NFE) LNG Expansion – 32 MTPA","country":"卡塔尔","region":"中东","cat":"petro","coord":[51.56,25.75],"cap":"32 MTPA（四条8 MTPA列车）","inv":290,"invText":"约 290 亿美元","status":"在建","year":2027,"updated":"2026-06","owner":"QatarEnergy / TotalEnergies / ExxonMobil / Shell / ConocoPhillips","flagship":true,"desc":"卡塔尔LNG扩能核心工程，首列车2025年11月产出首批LNG","detail":"北方气田东区（NFE）扩能包括四条8 MTPA级LNG列车，将卡塔尔LNG产能从77 MTPA提升至109 MTPA，总投资约290亿美元。NFE Train 1于2025年11月生产出首批LNG，Train 2目标2026年中投产，Train 3计划2026年底至2027年初，Train 4预计2027年底，全部四列车完成时限2028年中。与配套的北方气田南区（NFS，+16 MTPA）合并后，卡塔尔2030年LNG总产能将达142 MTPA。","descEn":"Qatar's North Field East LNG expansion adds 32 MTPA across four 8-MTPA trains; Train 1 produced first LNG in November 2025 with Trains 2–4 commissioning through 2027.","detailEn":"North Field East (NFE) is a cornerstone of QatarEnergy's LNG expansion plan, adding four 8 MTPA trains to lift total Qatari LNG capacity from 77 to 109 MTPA with a ~$29B investment. Train 1 achieved first LNG in November 2025 and is ramping toward full nameplate capacity. Trains 2, 3, and 4 are scheduled for mid-2026, late-2026/early-2027, and late-2027 respectively. Together with the North Field South expansion, Qatar targets 142 MTPA by 2030."},
  {"id":5168,"name":"以色列利维坦气田扩产（Phase 1B）","en":"Leviathan Gas Field Expansion – Phase 1B","country":"以色列","region":"中东","cat":"petro","coord":[34.68,31.97],"cap":"21 BCM/年（扩产后）","inv":23.6,"invText":"约 23.6 亿美元","status":"在建","year":2029,"updated":"2026-06","owner":"Chevron（39.66%）/ NewMed Energy（45.34%）/ Ratio Energies（15%）","flagship":false,"desc":"利维坦气田获23.6亿美元FID扩产，年产能从12增至21 BCM","detail":"2026年1月，雪佛龙等合伙人通过利维坦气田Phase 1B最终投资决定（FID），总投资23.6亿美元，新钻3口海底井、扩建海底基础设施并升级生产平台处理能力，将年产能从12 BCM提升至约21 BCM，预计2029年下半年投产。利维坦气田位于以色列多尔市近海约10公里，2025年8月利维坦签下该国史上最大出口协议（约350亿美元，向埃及供气），是东地中海天然气格局的核心资产。","descEn":"Leviathan Phase 1B expansion ($2.36B FID in January 2026) will increase annual production capacity from 12 to 21 BCM, with operations starting in H2 2029.","detailEn":"In January 2026, Chevron and partners (NewMed Energy 45.34%, Ratio Energies 15%) approved a $2.36B Final Investment Decision for the Leviathan Phase 1B expansion. The project involves drilling three new subsea wells, additional subsea infrastructure, and processing enhancements on the production platform ~10 km offshore Dor, Israel. Annual production capacity will grow from 12 BCM to ~21 BCM, with first gas from the expansion targeted for H2 2029. In August 2025, Leviathan signed Israel's largest-ever export deal ($35B) to supply gas to Egypt."},
  {"id":5169,"name":"土耳其阿库尤核电站1号机组（即将并网）","en":"Akkuyu Nuclear Power Plant – Unit 1 Grid Connection","country":"土耳其","region":"中东","cat":"nuclear","coord":[33.54,36.14],"cap":"1200 MW（一期）","inv":200,"invText":"约 200 亿美元（全厂四台机组总投资）","status":"在建","year":2026,"updated":"2026-06","owner":"俄罗斯Rosatom / 土耳其阿库尤核电公司","flagship":true,"desc":"土耳其首座核电站，1号机组调试接近完成，2026年预计首次并网发电","detail":"阿库尤核电站位于土耳其梅尔辛省地中海沿岸，由俄罗斯Rosatom以BOO模式承建，总规模4台VVER-1200机组（共4800 MW），全厂总投资约200亿美元。1号机组已完成约99%建设，调试工作于2025年5月正式启动，GIS隔离开关已通电完成测试，2026年目标首次并网发电，后续机组拟每年增加一台（至2028年），届时将满足土耳其约10%用电需求。","descEn":"Turkey's Akkuyu Nuclear Power Plant Unit 1 (1,200 MW VVER-1200) is entering final commissioning in 2026, with grid connection targeted for 2026 — Turkey's first nuclear generation.","detailEn":"Akkuyu NPP is located on Turkey's Mediterranean coast in Mersin Province, built by Russia's Rosatom under a BOO contract. The plant will ultimately have four 1,200 MW VVER-1200 reactors for 4,800 MW total capacity, with total investment of ~$20 billion. Unit 1 is ~99% complete; commissioning activities began in May 2025 with the GIS switchgear energized and diesel generators tested. Grid connection is targeted for 2026, making it Turkey's first-ever nuclear power generation. Units 2, 3, and 4 are slated for 2026, 2027, and 2028 respectively."},
  {"id":5170,"name":"NEOM绿氢项目（NGHC，90%竣工）","en":"NEOM Green Hydrogen Company (NGHC) – Phase 1","country":"沙特阿拉伯","region":"中东","cat":"renewable","coord":[36.51,28.02],"cap":"4 GW 风光发电 / 日产绿氢 600 吨（氨形式）","inv":84,"invText":"约 84 亿美元","status":"在建","year":2027,"updated":"2026-06","owner":"ACWA Power / Air Products / NEOM","flagship":true,"desc":"全球最大绿氢项目，NEOM奥克萨贡，2026年初完成90%建设","detail":"NEOM绿氢项目（NGHC）位于NEOM奥克萨贡工业区，由ACWA Power、Air Products与NEOM三方各持1/3股权，2023年完成84亿美元融资关闭。该项目集成4 GW风光制氢、电网、电解槽，日产600吨绿氢并以液氨形式出口。截至2026年初建设完成约90%，风光发电区预计2026年中竣工，电解槽调试后2027年开始商业供货，供应欧洲（TotalEnergies、Edison、EnBW等为主要买家）。","descEn":"NGHC at NEOM's Oxagon is the world's largest green hydrogen facility (4 GW RE + 600 t/day H₂ as ammonia), 90% complete as of early 2026 with commercial output targeted for 2027.","detailEn":"The NEOM Green Hydrogen Company project at Oxagon, NEOM, integrates 4 GW of wind and solar capacity with electrolysers to produce 600 tonnes of green hydrogen daily, exported as liquid ammonia. The $8.4 billion project is an equal JV between ACWA Power, Air Products, and NEOM, with financial close in 2023. Construction was ~90% complete by early 2026, with renewable generation sites on track for mid-2026 completion and electrolyser commissioning targeting first commercial delivery in 2027 to offtakers TotalEnergies, Edison, and EnBW."},
  {"id":5171,"name":"伊拉克GGIP伴生气回收与气电工程","en":"Iraq GGIP Gas Midstream Project (GMP) – Gas Flaring Elimination & Power","country":"伊拉克","region":"中东","cat":"petro","coord":[47.48,30.44],"cap":"气体处理 300 Mcf/d / 输气发电 1500 MW","inv":15,"invText":"约 15 亿美元","status":"在建","year":2028,"updated":"2026-06","owner":"TotalEnergies / QatarEnergy / 巴士拉石油公司","flagship":false,"desc":"伊拉克拉塔维等三油田伴生气捕集处理，2028年投运后向电厂供气1500MW","detail":"GGIP气体中游项目（GMP）负责回收伊拉克拉塔维、马杰努恩、西古尔纳三座油田每天燃除的伴生气（160 Mcf/d），建设300 Mcf/d气体处理厂，处理后天然气送入国家电网，支撑1500 MW电厂发电，惠及150万家庭。TotalEnergies于2025年9月宣布启动GMP最后两个主体工程建设，早期生产设施（50 Mcf/d）预计2026年初投运，完整GMP设施2028年完工。","descEn":"Iraq's GGIP Gas Midstream Project will recover 300 Mcf/d of flared gas from three Basra oil fields, providing gas feedstock to power plants with 1,500 MW of generation capacity, with full operations by 2028.","detailEn":"The GGIP Gas Midstream Project (GMP) in southern Iraq's Basra region will recover associated gas currently flared at the Ratawi, Majnoon, and West Qurna fields. The 300 Mcf/d gas processing plant, once fully operational in 2028, will supply gas to power plants generating ~1,500 MW to benefit 1.5 million Iraqi households. TotalEnergies launched the final two major construction packages in September 2025. An early production unit (50 Mcf/d) is scheduled for early 2026 commissioning."},
  {"id":5172,"name":"阿曼萨拉拉绿氢ACME一期项目","en":"ACME Salalah Green Hydrogen & Ammonia Phase 1","country":"阿曼","region":"中东","cat":"renewable","coord":[54.09,17],"cap":"年产绿氨 10 万吨 / 绿氢 1.7 万吨","inv":5,"invText":"约 5 亿美元（一期）","status":"在建","year":2027,"updated":"2026-06","owner":"ACME集团（印度）","flagship":false,"desc":"阿曼杜库姆经济特区绿氢绿氨一期，全部产量出口欧洲，2027年起运营","detail":"ACME集团在阿曼杜库姆经济特区（SEZAD）开发绿氢绿氨项目，一期目标年产绿氨10万吨、绿氢1.7万吨，已进入建设阶段，全部一期产量已锁定欧洲市场，计划2027年初开始出口。该项目是阿曼最早进入实施阶段的绿氢项目之一，三期全部建成后年产能可达百万吨级。","descEn":"ACME Group's Duqm Phase 1 green hydrogen/ammonia project in Oman is under construction, targeting 100,000 tpa green ammonia output for European export starting early 2027.","detailEn":"ACME Group's green hydrogen and ammonia project at the Duqm Special Economic Zone (SEZAD) in Oman is in active construction. Phase 1 targets annual production of 100,000 tonnes of green ammonia and 17,000 tonnes of green hydrogen, with all Phase 1 output committed to European buyers. Commercial operations are expected to begin in early 2027. This is among the first green hydrogen projects in Oman to enter the implementation phase, with later phases targeting over 1 million tpa total."},
  {"id":5173,"name":"沙特NREP第五轮四大光伏项目群（马萨/亨纳基耶2/拉比格2）","en":"Saudi NREP Round 5 Solar Portfolio – Al Masaa, Al Henakiyah 2, Rabigh 2","country":"沙特阿拉伯","region":"中东","cat":"renewable","coord":[38.9,24.4],"cap":"1700 MW（1000+400+300 MW）","inv":16,"invText":"约 16 亿美元","status":"在建","year":2027,"updated":"2026-06","owner":"多家国际开发商 / SPPC","flagship":false,"desc":"沙特NREP第五轮三个光伏项目：哈伊勒1GW、麦地那400MW、麦加300MW","detail":"沙特电力采购公司（SPPC）第五轮NREP除旗舰阿尔-萨达维项目外，还包括哈伊勒省阿尔-马萨光伏（1000 MW）、麦地那亨纳基耶2号光伏（400 MW）及麦加省拉比格2号光伏（300 MW），合计1700 MW，PPA于2024年底相继签署，均计划2027年投运，持续推动沙特西部与北部地区可再生能源开发。","descEn":"Saudi NREP Round 5 includes three additional solar projects beyond Al Sadawi: Al Masaa (1,000 MW, Hail), Al Henakiyah 2 (400 MW, Madinah), and Rabigh 2 (300 MW, Makkah), all targeting 2027 COD.","detailEn":"Saudi Arabia's NREP Round 5 solar portfolio beyond the flagship Al Sadawi project includes: Al Masaa Solar IPP (1,000 MW in Hail), Al Henakiyah 2 Solar IPP (400 MW in Madinah), and Rabigh 2 Solar IPP (300 MW in Makkah Province). PPAs for all three were signed with SPPC in late 2024. All three are expected to reach commercial operation in 2027 as part of Saudi Arabia's accelerating renewable energy buildout."},
  {"id":5174,"name":"约旦ACWA Power里沙61MW光伏电站","en":"Jordan Risha Solar PV IPP – ACWA Power (61.3 MW)","country":"约旦","region":"中东","cat":"renewable","coord":[38.18,32.48],"cap":"61.3 MW","inv":0.6,"invText":"约 0.6 亿美元","status":"在建","year":2026,"updated":"2026-06","owner":"ACWA Power / NEPCO","flagship":false,"desc":"约旦里沙61MW光伏，ACWA Power与国家电力签署PPA","detail":"ACWA Power与约旦国家电力公司（NEPCO）签署PPA，在约旦里沙地区开发61.3 MW光伏电站，是约旦放开大型可再生能源限制后的重要新增项目，支持约旦电力需求年增6.5%下的绿色能源转型，项目预计2026年并网。约旦EBRD正规划每年约2亿欧元的可再生能源新投资，为当地项目注入额外资金支持。","descEn":"Jordan's Risha 61.3 MW solar PV IPP, developed by ACWA Power under PPA with NEPCO, is targeting 2026 grid connection.","detailEn":"ACWA Power signed a PPA with Jordan's National Electric Power Company (NEPCO) to develop a 61.3 MW photovoltaic plant at Risha in Jordan. The project is one of the first utility-scale solar developments following Jordan's decision to lift its moratorium on large renewable energy projects. It is expected to connect to the grid in 2026 and supports Jordan's energy transition as electricity demand grows at 6.5% annually. The EBRD plans to invest ~€200 million annually in Jordan's energy sector."},
  {"id":5175,"name":"阿联酋微软东部云区（沙迦/达曼）三可用区","en":"Microsoft Azure UAE East Cloud Region – Availability Zones (Sharjah area)","country":"阿联酋","region":"中东","cat":"datacenter","coord":[55.38,25.34],"cap":"三个可用区（数据中心园区）","inv":15,"invText":"约 15 亿美元","status":"在建","year":2026,"updated":"2026-06","owner":"Microsoft","flagship":false,"desc":"微软阿联酋三可用区数据中心，2026年投入运营，支持G42 AI合作","detail":"微软在阿联酋东部（沙迦-迪拜走廊）建设三座大型数据中心，形成Azure可用区（Availability Zones），计划2026年开放，以配合微软与G42的AI合作框架及阿联酋数字经济战略。微软此前已与G42签署15亿美元AI合作协议，本次数据中心投资进一步强化其中东AI基础设施布局。","descEn":"Microsoft is building three Azure Availability Zone data centers in the UAE East region (Sharjah area), set to open in 2026 as part of its AI partnership with G42.","detailEn":"Microsoft is constructing three data centers in the UAE East region to launch Azure Availability Zones in the UAE, expected to come online in 2026. The facilities complement Microsoft's $1.5 billion AI partnership with G42 announced in 2024 and strengthen Microsoft's Middle East AI infrastructure alongside its investments in Saudi Arabia's Eastern Province. The UAE data centers will support G42's AI deployments and UAE government digital services."},
  {"id":5176,"name":"伊朗国家新能源15GW建设计划（国家发展基金）","en":"Iran National Renewable Energy 15 GW Development Programme (NDF)","country":"伊朗","region":"中东","cat":"renewable","coord":[53.69,32.42],"cap":"15000 MW（光伏+风电）","inv":100,"invText":"约 100 亿美元","status":"规划","year":2027,"updated":"2026-06","owner":"伊朗国家发展基金（NDF）/ 多家私营与中国企业","flagship":false,"desc":"伊朗NDF主导15GW风光建设，同期与中国企业谈判扩大太阳能合作","detail":"伊朗国家发展基金（NDF）宣布投资建设15000 MW风光发电设施，配合总统政府2026年3月实现10 GW新能源目标（其中5.5 GW光伏）。2025年10月已举行250 MW新光伏电站投产仪式，还启动450 MW在建项目。伊朗正与多家中国企业谈判光伏及储能合作，2025年底已发放100 GW光伏项目许可证以吸引私人投资。2025年底已安装容量达3165 MW，较年初增长显著。","descEn":"Iran's National Development Fund is sponsoring a 15,000 MW wind and solar program, with 250 MW of new solar inaugurated in October 2025 and negotiations with Chinese firms for expanded cooperation.","detailEn":"Iran's National Development Fund (NDF) has announced investment in 15,000 MW of new wind and solar capacity, alongside a government target of 10 GW renewables by March 2026. In October 2025, Iran inaugurated 250 MW of new solar plants and launched 450 MW more under construction. Iran is in negotiations with several Chinese companies for solar and BESS cooperation, and has issued permits for 100 GW of solar projects to attract private investment. Installed renewable capacity reached 3,165 MW by end-2025, up sharply from 1,230 MW at the start of the year."},
  {"id":5177,"name":"HyPort Duqm绿氢项目（BP入股49%）","en":"HyPort Duqm Green Hydrogen Project (BP acquires 49%)","country":"阿曼","region":"中东","cat":"renewable","coord":[57.7,19.65],"cap":"1.3 GW 可再生能源 / 绿氨 33 万吨/年（一期）","inv":18,"invText":"约 18 亿美元（一期）","status":"规划","year":2030,"updated":"2026-06","owner":"BP（49%）/ OQ Alternative Energy（25.5%）/ DEME（25.5%）","flagship":false,"desc":"BP 2025年7月收购杜库姆绿氢项目49%股权，一期年产绿氨33万吨","detail":"HyPort Duqm绿氢项目位于阿曼杜库姆经济特区，2025年7月BP收购49%股权，OQ替代能源与DEME各保留25.5%。项目一期配置1.3 GW可再生能源驱动电解槽，年产绿氨33万吨，二期扩至65万吨/年，全部出口欧洲市场。项目FID预计2026–2027年，是BP可再生能源转型战略的旗舰布局，也是阿曼绿氢出口版图的重要项目。","descEn":"BP acquired a 49% stake in the HyPort Duqm green hydrogen project in Oman in July 2025; Phase 1 targets 330,000 tpa green ammonia output for European export.","detailEn":"HyPort Duqm is located in Oman's Duqm Special Economic Zone. In July 2025, BP acquired a 49% stake, with OQ Alternative Energy and DEME each retaining 25.5%. Phase 1 uses 1.3 GW of renewable energy to run electrolysers producing 330,000 tonnes per year of green ammonia for European export, with Phase 2 expanding to 650,000 tpa. FID is targeted for 2026–2027. The project is a flagship for BP's renewable transition strategy and a key component of Oman's green hydrogen export roadmap."},
  {"id":5178,"name":"土耳其YEKA 2025–2026年风光大规模招标（2+1.5 GW）","en":"Turkey YEKA 2025–2026 Wind & Solar Tenders (3.5 GW)","country":"土耳其","region":"中东","cat":"renewable","coord":[35.2,38.96],"cap":"3500 MW（2025年2GW + 2026年1.5GW风电）","inv":40,"invText":"约 40 亿美元","status":"规划","year":2027,"updated":"2026-06","owner":"土耳其能源自然资源部 / 多家开发商","flagship":false,"desc":"土耳其YEKA 2025年2GW风光+2026年1.5GW风电招标，年均新增6–8GW","detail":"土耳其可再生能源资源区（YEKA）计划2025年招标1150 MW风电（锡瓦斯等省）+850 MW光伏（埃拉泽等省），2026年再招标1500 MW风电，配合2035年风光总装机130 GW目标，每年需新增约8 GW。2025年土耳其实际新增6.5 GW创纪录，并正在筛选萨罗斯湾等四处离岸风电场址，为首个离岸风电YEKA招标铺路。","descEn":"Turkey's YEKA program launched 2 GW of wind and solar tenders in 2025 (1,150 MW wind + 850 MW solar), with 1,500 MW of additional wind tenders planned for 2026, targeting 130 GW by 2035.","detailEn":"Turkey's Renewable Energy Resource Zone (YEKA) program awarded tenders for 1,150 MW of wind (across Sivas, Balikesir, Aydin, Denizli, Kutahya) and 850 MW of solar (Elazig, Kahramanmaras, Erzurum, Bolu, Eskisehir, Mardin, Van) in 2025. An additional 1,500 MW of wind is planned for YEKA tenders in 2026. Turkey set a record of 6.5 GW in new installations in 2025 and is identifying four offshore wind sites (Saros Bay, Gokceada, Bozcaada, Edremit) ahead of Turkey's first offshore wind tender."},
  {"id":5179,"name":"沙特HUMAIN-xAI 500MW AI数据中心","en":"HUMAIN–xAI 500 MW AI Data Center, Saudi Arabia","country":"沙特阿拉伯","region":"中东","cat":"datacenter","coord":[46.71,24.7],"cap":"500 MW","inv":30,"invText":"约 30 亿美元","status":"规划","year":2027,"updated":"2026-06","owner":"HUMAIN（PIF）/ xAI（马斯克）","flagship":false,"desc":"HUMAIN与马斯克xAI合作在沙特建500MW超大规模AI数据中心","detail":"2025年11月，HUMAIN与马斯克旗下xAI宣布合作建设500 MW AI数据中心，部署xAI Grok模型并设计低成本大规模算力方案，是沙特吸引全球顶级AI公司落地的重要里程碑。该中心纳入HUMAIN 6 GW长期数据中心规划，选址利雅得，预计2026–2027年建成，推动沙特成为全球AI算力枢纽。","descEn":"HUMAIN and xAI (Elon Musk) announced a 500 MW AI data center in Saudi Arabia in November 2025, deploying Grok AI models as part of Saudi Arabia's AI infrastructure buildout.","detailEn":"In November 2025, HUMAIN (PIF's AI arm) and xAI announced a collaboration to design, build, and operate a 500 MW low-cost AI data center in Riyadh, Saudi Arabia, deploying xAI's Grok AI models. The facility is part of HUMAIN's 6 GW long-term data center roadmap and is a milestone in Saudi Arabia's goal to become a global AI hub. The project is expected to be operational by 2026–2027."},
  {"id":5180,"name":"伊拉克发展之路铁路（南部段Basra–Baghdad）","en":"Iraq Development Road Railway – South Section (Basra to Baghdad)","country":"伊拉克","region":"中东","cat":"transport","coord":[47,32],"cap":"约 1200 km（南段及全线）","inv":70,"invText":"约 70 亿美元（南段；全线规划约 170 亿美元）","status":"规划","year":2030,"updated":"2026-06","owner":"伊拉克政府 / 多国承建方","flagship":true,"desc":"连接法奥大港与土耳其边境的伊拉克发展之路铁路走廊，打造中东物流大通道","detail":"伊拉克「发展之路」计划以法奥大港为起点，经巴士拉、巴格达北上至土耳其边境，全长约1200公里，含铁路和高速公路双走廊，总投资约700亿美元，是伊拉克重建史上最大基础设施计划。南段铁路（巴士拉-巴格达）已进入详细设计阶段，伊拉克已分配15亿美元用于新巴士拉-费什哈布尔管段，中国企业参与其中。项目联通波斯湾与地中海，将使伊拉克成为地区物流枢纽。","descEn":"Iraq's Development Road is a 1,200 km rail and highway corridor from Al-Faw Grand Port to the Turkish border with ~$70B total investment, making Iraq a key regional logistics hub.","detailEn":"Iraq's Development Road initiative stretches from the Al-Faw Grand Port in Basra to the Turkish border via Baghdad, encompassing ~1,200 km of railway and expressway. Total investment is estimated at $70 billion. The southern rail section (Basra–Baghdad) is in detailed design; Iraq has allocated $1.5 billion for the Basra–Fishkhabour pipeline segment with Chinese infrastructure firms involved. The corridor aims to connect the Persian Gulf with the Mediterranean, positioning Iraq as a major regional transit hub by 2030."},
  {"id":5181,"name":"阿曼Al Kamil I光伏电站","en":"Oman Al Kamil I Solar PV IPP","country":"阿曼","region":"中东","cat":"renewable","coord":[58.17,22.21],"cap":"500 MW（预计）","inv":4,"invText":"约 4 亿美元","status":"规划","year":2028,"updated":"2026-06","owner":"阿曼Nama PWP / 待定","flagship":false,"desc":"阿曼内陆Al Kamil地区新光伏IPP，2026年授标，2028年投运","detail":"阿曼电力采购公司（Nama PWP）计划2026年向阿尔-卡米勒I号光伏IPP授标，项目规模预计约500 MW，是阿曼快速扩张可再生能源产能的重要组成，与多个风电项目同步推进，助力阿曼实现2030年装机目标。项目同时还包含Duqm（拉斯·马德拉卡）、马胡特、萨达赫三个风电IPP，正式采购工作于2026年启动。","descEn":"Oman's Al Kamil I Solar PV IPP (~500 MW) is being awarded in 2026 by Nama PWP as part of Oman's accelerated renewables rollout targeting 2028 operations.","detailEn":"Nama Power and Water Procurement Company planned to award the Al Kamil I Solar PV IPP in 2026, alongside three wind IPPs at Duqm (Ras Madrakah), Mahout, and Sadah. Estimated at around 500 MW, Al Kamil I is part of Oman's strategy to reach its 2030 clean energy goals. The procurement of these projects represents Oman's most active year of renewables tendering, aimed at transitioning at least 10% of its power mix to clean energy by 2025 (achieved) and scaling up rapidly through 2030."},
  {"id":5182,"name":"沙特东部省微软Azure三可用区数据中心","en":"Microsoft Azure Eastern Province Cloud Region – 3 Availability Zones","country":"沙特阿拉伯","region":"中东","cat":"datacenter","coord":[50.1,26.43],"cap":"三可用区云数据中心","inv":20,"invText":"约 20 亿美元","status":"在建","year":2026,"updated":"2026-06","owner":"Microsoft","flagship":false,"desc":"微软在沙特东部省建设三可用区Azure数据中心，2026年开放服务","detail":"微软在沙特阿拉伯东部省（达曼地区）建设三座大型数据中心，组成Azure可用区（Availability Zones），计划2026年向客户开放。这是微软配合HUMAIN AI战略在沙特的重要基础设施投入，提供高可用云服务并支持沙特数字主权。与此同时，微软是HUMAIN生态的关键合作伙伴，协同AWS、Google Cloud共同奠定沙特AI计算底座。","descEn":"Microsoft is building three Azure data centers in Saudi Arabia's Eastern Province (Dammam area) to create Availability Zones, opening to customers in 2026.","detailEn":"Microsoft is constructing three large-scale data centers in Saudi Arabia's Eastern Province (Dammam region) to establish Azure Availability Zones, expected to open in 2026. The facilities complement Microsoft's AI partnership with HUMAIN and support Saudi Arabia's data sovereignty goals. Together with AWS's $5B commitment and Google Cloud's $10B AI hub, Microsoft's Eastern Province investment forms a pillar of Saudi Arabia's rapidly expanding cloud and AI infrastructure ecosystem."},
  {"id":5183,"name":"沙特AWS-HUMAIN达曼AI基础设施（50亿美元）","en":"AWS–HUMAIN Dammam AI Infrastructure ($5B)","country":"沙特阿拉伯","region":"中东","cat":"datacenter","coord":[50.11,26.44],"cap":"大规模AI云算力（达曼云区域）","inv":50,"invText":"约 50 亿美元","status":"在建","year":2026,"updated":"2026-06","owner":"Amazon Web Services / HUMAIN（PIF）","flagship":false,"desc":"AWS承诺50亿美元在沙特部署AI基础设施，与HUMAIN深度合作","detail":"亚马逊云服务（AWS）向HUMAIN承诺部署50亿美元AI基础设施，在达曼AWS云区域基础上扩展算力，提供大规模AI训练与推理服务。AWS是HUMAIN首批战略合作伙伴之一，合作涵盖算力、数据服务及AI模型部署，配合沙特2026年「AI年」战略。项目将在现有达曼区域基础上大幅扩建，是全球超大规模云厂商在中东最大单笔AI承诺之一。","descEn":"AWS committed $5 billion in AI infrastructure to Saudi Arabia through HUMAIN, expanding on the Dammam AWS cloud region to support large-scale AI training and inference.","detailEn":"Amazon Web Services (AWS) committed $5 billion in AI infrastructure through its partnership with HUMAIN, Saudi Arabia's state-backed AI entity. The investment expands AWS's existing Dammam cloud region with large-scale AI compute for training and inference, supporting Saudi Arabia's 2026 Year of AI strategy. AWS is among HUMAIN's earliest strategic partners alongside Google Cloud, Microsoft, and NVIDIA, together underpinning the $77B HUMAIN AI infrastructure roadmap targeting 1.9 GW of data center capacity by 2030."},
  {"id":5184,"name":"阿联酋Abu Dhabi Masdar与TA'ZIZ低碳氨甲醇项目","en":"Abu Dhabi TA'ZIZ Low-Carbon Ammonia & Methanol Complex","country":"阿联酋","region":"中东","cat":"ci","coord":[52.73,24.09],"cap":"低碳氨 100 万吨/年 + 甲醇 45 万吨/年","inv":66,"invText":"约 66 亿美元","status":"在建","year":2026,"updated":"2026-06","owner":"ADNOC / ADQ / OCI（TA'ZIZ联合体）","flagship":false,"desc":"阿布扎比鲁维斯TA'ZIZ工业区低碳氨与甲醇综合体，2026年投运","detail":"TA'ZIZ低碳氨与甲醇项目位于阿布扎比鲁维斯工业区（KIZAD），由ADNOC、ADQ与OCI联合开发，年产低碳氨100万吨及甲醇45万吨。其中OCI Fertiglobe低碳氨装置为全球最大单体低碳氨工厂之一，使用碳捕集技术生产蓝氨，计划2026年投运，产品出口欧洲、亚洲，配合全球去碳化对清洁氢载体的强劲需求。","descEn":"TA'ZIZ Low-Carbon Ammonia & Methanol Complex at Abu Dhabi's Ruwais KIZAD zone targets 1 million tpa blue ammonia and 450,000 tpa methanol, commissioning in 2026.","detailEn":"The TA'ZIZ Low-Carbon Ammonia and Methanol Complex is located in the Ruwais Industrial Zone (KIZAD) in Abu Dhabi, developed by ADNOC, ADQ, and OCI. The project produces 1 million tpa of low-carbon (blue) ammonia using carbon capture technology and 450,000 tpa of methanol. OCI Fertiglobe's blue ammonia unit is among the world's largest single-train low-carbon ammonia plants. Commercial operations are targeted for 2026, with output earmarked for European and Asian markets seeking clean hydrogen carriers."},

  // ===== 欧洲（5300-5325）=====
  {"id":5300,"name":"荷兰海岸西6号海上风电（Ecowende）","en":"Ecowende Hollandse Kust West VI Offshore Wind Farm","country":"荷兰","region":"欧洲","cat":"renewable","coord":[4.05,52.55],"cap":"760 MW","inv":22,"invText":"约 22 亿欧元","status":"在建","year":2026,"updated":"2026-06","owner":"Shell、Eneco、Chubu","flagship":false,"desc":"荷兰760MW零补贴海上风电，52台15MW机组，2026年投运","detail":"Ecowende是Shell、Eneco和Chubu的合资项目，位于荷兰IJmuiden以西约53公里北海海域，装机760 MW，共52台Vestas V236-15.0 MW机组。项目为零补贴中标，海上施工已于2025年9月启动；2026年4月所有单桩基础安装完成，预计2026年底全面投运，约满足荷兰3%的电力需求。","descEn":"760 MW subsidy-free Dutch offshore wind, 52×15 MW Vestas turbines, commissioning end-2026.","detailEn":"Ecowende (Shell/Eneco/Chubu JV) is located ~53 km off IJmuiden in the Dutch North Sea with 760 MW capacity from 52 Vestas V236-15.0 MW turbines. The project was awarded without subsidy; offshore construction started September 2025, all monopiles were installed by April 2026, and full commissioning is targeted for end-2026, supplying ~3% of Dutch electricity demand.","progress":"2026年4月所有单桩基础安装完成，2026年Q2开始吊装机组"},
  {"id":5301,"name":"德国北海N-9.4 TotalEnergies海上风电","en":"German North Sea N-9.4 Offshore Wind Concession (TotalEnergies)","country":"德国","region":"欧洲","cat":"renewable","coord":[6.2,55.3],"cap":"1 GW","inv":40,"invText":"约 40 亿欧元","status":"规划","year":2030,"updated":"2026-06","owner":"TotalEnergies","flagship":false,"desc":"TotalEnergies赢得德国北海1GW风电海上特许权，距赫尔戈兰岛150公里","detail":"2025年6月，德国联邦网络局将北海N-9.4地块（约141平方公里）授予TotalEnergies旗下North Sea OFW One GmbH，可开发约1 GW离岸风电，特许期25年。该地块毗邻TotalEnergies与RWE合资的N-9.1/N-9.2地块，可实现集群协同开发。受德国TSO并网时间表延迟影响，开发方案仍在战略评估中，预计2030年前后并网。","descEn":"TotalEnergies awarded the N-9.4 North Sea offshore wind concession (1 GW) in June 2025, adjacent to its N-9.1/N-9.2 cluster.","detailEn":"In June 2025, Germany's Federal Network Agency awarded TotalEnergies the N-9.4 concession (~141 km², ~1 GW) in the North Sea, ~150 km northwest of Heligoland, for a 25-year term. It is adjacent to the TotalEnergies–RWE N-9.1/N-9.2 cluster, enabling synergistic development. Grid connection delays have triggered a strategic review; commissioning is expected around 2030."},
  {"id":5302,"name":"狮链英荷离岸混合互联（LionLink）","en":"LionLink UK–Netherlands Hybrid Interconnector","country":"英国—荷兰","region":"欧洲","cat":"grid","coord":[3.5,52.9],"cap":"2 GW","inv":45,"invText":"约 45 亿欧元","status":"规划","year":2032,"updated":"2026-06","owner":"National Grid Ventures、TenneT","flagship":false,"desc":"英荷2GW混合互联，通过Nederwiek3海上风电平台实现","detail":"LionLink是英国与荷兰之间首条融合互联与海上风电接入的混合HVDC连接线，容量2 GW，通过TenneT规划中的Nederwiek 3海上平台连接两国电网。2026年4月TenneT与National Grid签署联合开发协议，英国侧预计2026年提交开发许可申请，2027年获批，力争2032年投运。","descEn":"2 GW UK–Netherlands hybrid HVDC interconnector via the Nederwiek 3 offshore platform, targeting commissioning in 2032.","detailEn":"LionLink is a pioneering 'Offshore Hybrid Asset' combining interconnection with offshore wind integration, linking the UK and Netherlands via TenneT's planned Nederwiek 3 platform. Capacity is 2 GW; TenneT and National Grid Ventures signed a Joint Development Agreement in April 2026. The UK DCO application is expected in 2026 with an approval target of 2027 and commissioning in the early 2030s.","route":[[-0.5,51.5],[1.5,52.2],[3.5,52.9],[4.6,52.5]]},
  {"id":5303,"name":"南欧氢气走廊（SoutH2 Corridor）","en":"SoutH2 Corridor Hydrogen Pipeline","country":"意大利—奥地利—德国","region":"欧洲","cat":"grid","coord":[13.5,46.5],"cap":"4 Mtpa / 3300 km","inv":140,"invText":"约140亿欧元（Snam 2026–2030规划）","status":"规划","year":2030,"updated":"2026-06","owner":"Snam、TAG、GCA、bayernets","flagship":true,"desc":"3300公里氢气管道走廊，连接北非-意大利-奥地利-德国，2030年全线贯通","detail":"SoutH2走廊由Snam、TAG、GCA和bayernets联合推进，全线约3300公里，利用现有天然气管道改造，从北非输送可再生氢至欧洲核心工业区，目标年输氢能力4 Mtpa（>40%的REPowerEU进口目标）。2025年1月意大利、奥地利、德国、突尼斯和阿尔及利亚签署政治声明；2026年首段15公里在巴伐利亚化工三角区投入运营；2026年欧盟CINEA授予2400万欧元可行性研究共同资助。","descEn":"3,300 km green hydrogen pipeline corridor from North Africa via Italy, Austria to Germany, targeting 4 Mtpa capacity by 2030.","detailEn":"The SoutH2 Corridor (Snam/TAG/GCA/bayernets) repurposes ~3,300 km of existing gas infrastructure to transport renewable hydrogen from North Africa to Central Europe, with 4 Mtpa capacity covering >40% of the REPowerEU hydrogen import target. Five nations signed a Joint Declaration in January 2025; a 15 km pilot section in Bavaria was commissioned in 2026; EU CINEA granted €24 million for feasibility studies.","route":[[10.2,36.8],[12.5,40],[13.5,42],[14.5,46],[13.5,47.5],[11.5,48.1]]},
  {"id":5304,"name":"威尔法 SMR 核电站（英国首批小堆）","en":"Wylfa SMR Nuclear Power Station","country":"英国","region":"欧洲","cat":"nuclear","coord":[-4.47,53.41],"cap":"1.4 GW（3台SMR各470MW）","inv":25,"invText":"£2.6 亿英镑政府分配（全期成本待公布）","status":"规划","year":2035,"updated":"2026-06","owner":"Rolls-Royce SMR、Great British Energy","flagship":true,"desc":"英国首批SMR，安格尔西岛3台470MW Rolls-Royce小堆，2035年中期首发","detail":"威尔法（Wylfa）位于威尔士安格尔西岛，系英国政府选定的第一个SMR建设地点，部署3台Rolls-Royce 470 MW小型模块化反应堆，总装机1.4 GW。2025年11月宣布选址，2026年4月英国政府与Rolls-Royce SMR签署合同并提供最高5.99亿英镑国家财富基金贷款，政府2025年财政审查中分配26亿英镑支持全期实施。目标在2030年代中期投入商业运营，届时将成为欧洲第一批实际运营的SMR机队。","descEn":"UK's first SMR fleet: 3×470 MW Rolls-Royce units at Wylfa, Anglesey, Wales; contract signed April 2026, targeting first power in the mid-2030s.","detailEn":"Wylfa on Anglesey was confirmed in November 2025 as the UK's first SMR site. Three Rolls-Royce 470 MW units (1.4 GW total) will be built at the former Magnox plant site. The UK government signed the development contract in April 2026, backed by up to £599 million from the National Wealth Fund and £2.6 billion in Spending Review allocation. First power is targeted for the mid-2030s, making it the first commercial SMR fleet in Europe.","progress":"2026年4月合同签署，设计活动正式启动，选址环评程序推进中"},
  {"id":5305,"name":"欣克利角C核电站","en":"Hinkley Point C Nuclear Power Station","country":"英国","region":"欧洲","cat":"nuclear","coord":[-3.13,51.21],"cap":"3.2 GW（2台EPR）","inv":610,"invText":"约 490 亿英镑（2015年价格约 350 亿英镑）","status":"在建","year":2030,"updated":"2026-06","owner":"EDF、中广核","flagship":true,"desc":"英国首座新建大型核电站，两台EPR机组，Unit1预计2030年首发","detail":"欣克利角C位于英格兰萨默塞特郡，建设2台EPR机组（各1.6 GW），总装机3.2 GW，是英国近30年来首座新建核电站。2026年2月EDF宣布因机电安装进度滞后，Unit 1首发时间从2029年推迟至2030年，项目总成本（按2015年价格）已升至350亿英镑，折合今日价格约490亿英镑。2025年7月世界最大起重机完成Unit 2反应堆穹顶吊装，2026年1月Unit 2压力容器到货。","descEn":"UK's first new large nuclear station in 30 years; 2×EPR (3.2 GW); Unit 1 first power now targeted for 2030; cost ~£35bn (2015 prices).","detailEn":"Hinkley Point C in Somerset is the UK's first new large nuclear station in nearly 30 years, with two 1.6 GW EPR units (3.2 GW total) developed by EDF and CGN. In February 2026 EDF confirmed Unit 1 first power is now 2030 (delayed from 2029) due to slow electromechanical installation. Total cost has reached £35 bn in 2015 prices (~£49 bn in today's money). Key milestones: reactor dome placed July 2025, Unit 2 reactor pressure vessel delivered January 2026.","progress":"2026年2月确认Unit 1首发推迟至2030年，机电安装效率已于2025年下半年改善"},
  {"id":5306,"name":"法国彭利 EPR2 核电站","en":"Penly EPR2 Nuclear Power Plant","country":"法国","region":"欧洲","cat":"nuclear","coord":[1.22,49.97],"cap":"3 GW（2台EPR2）","inv":240,"invText":"约 240 亿欧元（六堆总计728亿欧元）","status":"在建","year":2038,"updated":"2026-06","owner":"EDF","flagship":true,"desc":"法国EPR2新建核电首站，彭利2台机组，2024年场地工程已动工","detail":"彭利（Penly）位于塞纳-滨海省，计划新建2台EPR2机组（各约1500 MW），是法国2023年核能振兴法案确定的六堆新建计划中的首批两台。EDF于2024年7月启动场地准备工程（土建非核工程），首台机组计划2027年浇筑第一罐混凝土，预计2038年并网；EDF估算六堆总投资约728亿欧元，彭利合同仅土建即达40亿欧元（由Eiffage承建）。欧盟委员会正在审核法国国家援助方案。","descEn":"France's first new EPR2 nuclear plant at Penly, Normandy; site works started July 2024, first concrete targeted 2027, grid connection ~2038.","detailEn":"Penly in Seine-Maritime will host two EPR2 units (~1,500 MW each), the first of France's six-reactor new-build programme under the 2023 Nuclear Renaissance Act. EDF commenced non-nuclear civil preparatory works in July 2024; first concrete is targeted for 2027 and commissioning for 2038. The €4 bn civil engineering contract was awarded to Eiffage. EDF's total six-unit cost estimate is €72.8 billion; the EU state-aid framework is under review.","progress":"2026年政府间核能授权令（DAC）审查进行中，ASN已对土壤承载设计提出意见"},
  {"id":5307,"name":"捷克杜科万尼5&6号核电机组","en":"Dukovany 5 & 6 Nuclear Power Units","country":"捷克","region":"欧洲","cat":"nuclear","coord":[16.15,49.09],"cap":"2.5 GW（2台APR-1400）","inv":180,"invText":"约 160–170 亿欧元","status":"规划","year":2037,"updated":"2026-06","owner":"ČEZ、KHNP","flagship":true,"desc":"捷克最大能源投资，韩国KHNP建设2台APR-1400，2037–2038年投运","detail":"捷克政府选定韩国水电与核电公司（KHNP）承建杜科万尼核电站5和6号机组，各容量约1250 MW（APR-1400型），总装机约2.5 GW，合同价值超过4000亿克朗（约160亿欧元），为捷克有史以来最大能源投资。2025年4月EDF与西屋的申诉被驳回后合同正式确立；2025年8月场地勘探动工；2026年2月成立捷克-韩国部长级指导委员会；首台机组预计2037年商运，第二台2038年。","descEn":"Czech Republic's largest energy investment: 2×APR-1400 units at Dukovany by KHNP, contract finalised 2025, commissioning 2037–2038.","detailEn":"KHNP (South Korea) won the contract for Dukovany 5&6 after Westinghouse and EDF appeals were rejected in April 2025. Each 1,250 MW APR-1400 unit will bring total new capacity to ~2.5 GW at a cost exceeding €16 billion (Czech history's largest energy investment). Site survey work began August 2025; a Czech-Korean ministerial steering committee was established February 2026; Unit 5 commercial operation is expected in 2037, Unit 6 in 2038.","progress":"2025年8月启动场地勘探，2026年2月签署涡轮设备合同（Doosan Enerbility）"},
  {"id":5308,"name":"波兰卢比亚托沃核电站","en":"Poland Lubiatowo-Kopalino Nuclear Power Plant","country":"波兰","region":"欧洲","cat":"nuclear","coord":[17.73,54.87],"cap":"3.75 GW（3台AP1000）","inv":490,"invText":"约 420 亿欧元","status":"规划","year":2036,"updated":"2026-06","owner":"Polskie Elektrownie Jądrowe（PEJ）、Westinghouse、Bechtel","flagship":true,"desc":"波兰首座核电站，3台西屋AP1000机组，2028年开工，2036年首台投运","detail":"卢比亚托沃-科帕利诺（Lubiatowo-Kopalino）位于波美拉尼亚省滨海地带，拟建3台Westinghouse AP1000机组（各1250 MW），总装机3.75 GW，总投资约420亿欧元，为波兰能源转型核心工程。2025年3月波兰国会通过法案，政府向PEJ提供2025–2030年约150亿美元公共融资；2025年8月场地平整许可获批；2026年3月PEJ提交建造许可申请；EPC合同预计2026年中与Westinghouse-Bechtel联合体签订，首台机组目标2036年商运。","descEn":"Poland's first nuclear power plant: 3×AP1000 at Lubiatowo-Kopalino, construction license submitted March 2026, first unit targeting 2036.","detailEn":"PEJ (state utility) is developing three Westinghouse AP1000 units (1,250 MW each, 3,750 MW total) at Lubiatowo-Kopalino on the Baltic coast. The €42 billion project received Polish parliamentary funding approval ($15 billion public financing 2025–2030) in March 2025 and EU state-aid approval in December 2025. Site clearance permits were issued in August 2025; the construction licence was applied for in March 2026; the EPC contract is expected mid-2026. First unit commercial operation is targeted for 2036.","progress":"2026年3月提交建造许可申请，获欧盟委员会国家援助批准，场地平整已启动"},
  {"id":5309,"name":"英国特拉福德特大型电池储能站","en":"Trafford BESS (Carlton Power)","country":"英国","region":"欧洲","cat":"storage","coord":[-2.34,53.45],"cap":"1040 MW / 2080 MWh","inv":9.5,"invText":"约 7.5 亿英镑","status":"在建","year":2025,"updated":"2026-06","owner":"Carlton Power","flagship":false,"desc":"英国曼彻斯特1GW特大型电池储能，前燃煤电厂址改造","detail":"特拉福德BESS位于大曼彻斯特特拉福德低碳能源园区（前燃煤电厂旧址），由Carlton Power开发，装机1040 MW / 2080 MWh，投资约7.5亿英镑，为欧洲规划中规模最大的电网级电池储能项目之一。2024年初开工建设，目标2025年底投入商业运营，将显著提升英格兰西北部电网调峰能力。","descEn":"UK's 1,040 MW / 2,080 MWh grid-scale BESS at former Trafford coal site, ~£750m investment, commissioning targeted late 2025.","detailEn":"The Trafford BESS at Trafford Low Carbon Energy Park (former coal-fired power station site) is developed by Carlton Power with 1,040 MW / 2,080 MWh capacity at ~£750 million investment. Construction commenced in early 2024 following FID, targeting commercial operation in Q4 2025. It is one of the largest planned grid-scale battery projects in Europe and will enhance peaking capacity in northwest England."},
  {"id":5310,"name":"英国彭布罗克电池储能站（RWE）","en":"Pembroke Battery Storage (RWE)","country":"英国","region":"欧洲","cat":"storage","coord":[-4.94,51.68],"cap":"350 MW / 700 MWh","inv":2.5,"invText":"约 2 亿英镑","status":"规划","year":2028,"updated":"2026-06","owner":"RWE","flagship":false,"desc":"RWE在威尔士彭布罗克建设350MW/700MWh电池储能，2026年开工","detail":"彭布罗克电池储能站是RWE在英国规模最大的储能项目，位于威尔士彭布罗克电力站南侧，装机350 MW / 700 MWh，由212台锂离子电池集装箱构成，占地5.1公顷。RWE于2025年12月作出最终投资决定，投资约2亿英镑，已取得规划许可并在容量市场中标。建设计划于2026年上半年启动，预计2028年下半年投入运营。","descEn":"RWE's largest UK battery project: 350 MW / 700 MWh at Pembroke Net Zero Centre, Wales; FID December 2025, construction 2026, commissioning 2028.","detailEn":"Pembroke Battery Storage is RWE's largest UK BESS, sited at the Pembroke Net Zero Centre in South Wales with 350 MW / 700 MWh capacity (212 lithium-ion containers over 5.1 ha). RWE took FID in December 2025 with ~£200 million investment, having secured planning consent and a Capacity Market contract. Construction begins H1 2026, commissioning targeted H2 2028."},
  {"id":5311,"name":"瑞典谢莱夫特奥 Lyten 工业中枢（原 Northvolt）","en":"Lyten Industrial Hub Skellefteå (former Northvolt)","country":"瑞典","region":"欧洲","cat":"ci","coord":[21.07,64.75],"cap":"16 GWh 电池产能（近期）","inv":50,"invText":"约 50 亿美元（收购及重启）","status":"在建","year":2026,"updated":"2026-06","owner":"Lyten","flagship":true,"desc":"Lyten以约50亿美元收购Northvolt瑞典资产，重启16GWh电池产能并配套数据中心","detail":"美国锂硫电池公司Lyten于2026年2月完成对Northvolt瑞典资产（Northvolt Ett及扩建设施、Northvolt Labs）的全部收购，包含16 GWh现有电池产能及超160公顷土地，收购价值近50亿美元。Lyten计划2026年下半年恢复电池商业化出货，并在园区内引入数据中心——EQT旗下EdgeConneX宣布收购园区部分用地，规划最高1 GW数据中心容量，成为欧洲最大数据中心项目之一。此举将谢莱夫特奥打造为电池制造与AI算力协同发展的新型工业中枢。","descEn":"Lyten acquires Northvolt Sweden assets for ~$5 billion, restarting 16 GWh battery capacity in Skellefteå and co-locating a planned 1 GW data center campus.","detailEn":"US-based Lyten completed acquisition of Northvolt Ett (Skellefteå) and Labs (Västerås) in February 2026, securing 16 GWh of existing Li-ion capacity and 160+ ha of land at ~$5 billion total value. Commercial cell shipments are planned for H2 2026. EQT-backed EdgeConneX simultaneously announced plans to acquire a portion of the site for a data center campus with up to 1 GW potential capacity — potentially Europe's largest — powered by regional hydropower.","progress":"2026年2月收购完成，重新招募600+员工，Q2开始为BESS客户恢复产线"},
  {"id":5312,"name":"ESMC 德累斯顿晶圆厂（台积电合资）","en":"ESMC Dresden Semiconductor Fab (TSMC JV)","country":"德国","region":"欧洲","cat":"ci","coord":[13.74,51.05],"cap":"41700 片/月（12英寸等效）","inv":100,"invText":"超过 100 亿欧元","status":"在建","year":2027,"updated":"2026-06","owner":"TSMC、Bosch、Infineon、NXP","flagship":true,"desc":"欧洲首座台积电合资晶圆厂，月产4.17万片，28–12nm，2027年量产","detail":"欧洲半导体制造公司（ESMC）由台积电（持股约35%）、博世、英飞凌、恩智浦联合组建，总投资超过100亿欧元（德国政府补贴约50亿欧元），在德累斯顿建设先进晶圆厂，专注28–12nm汽车及工业芯片，设计月产能约41700片12英寸晶圆。2024年8月正式破土动工；2025年底主体结构封顶；2026年进入设备搬入阶段，预计2027年实现量产，将大幅提升欧洲汽车与工业芯片本地供给能力。","descEn":"TSMC-led €10 bn+ semiconductor fab in Dresden (ESMC JV with Bosch/Infineon/NXP); 28–12 nm automotive chips; groundbreak August 2024, production 2027.","detailEn":"ESMC (TSMC ~35%, Bosch/Infineon/NXP ~5% each) is building a €10+ billion fab in Dresden, Germany focusing on 28–12 nm processes for automotive and industrial customers, with full capacity of ~41,700 12-inch wafers/month. Groundbreaking was in August 2024; structural build completed late 2025; equipment move-in began H1 2026; volume production is targeted for 2027. The German government is contributing ~€5 billion in subsidies.","progress":"2025年底主体结构完工，2026年上半年开始设备进场，目标2027年量产"},
  {"id":5313,"name":"挪威纳尔维克 Stargate Norway AI算力中心","en":"Stargate Norway AI Gigafactory, Narvik","country":"挪威","region":"欧洲","cat":"datacenter","coord":[17.43,68.44],"cap":"100000 NVIDIA GPU / 230 MW","inv":10,"invText":"初期约 10 亿美元（20MW首期）","status":"在建","year":2026,"updated":"2026-06","owner":"Nscale、Aker、OpenAI","flagship":true,"desc":"OpenAI欧洲首个AI超算中心，100000枚GPU，纯水电绿电供电","detail":"Stargate Norway是OpenAI与Nscale、Aker合作在挪威纳尔维克建设的AI算力基础设施，目标2026年底实现10万枚NVIDIA GPU上线，设计IT容量230 MW（远期可扩至520 MW）。Nscale与Aker各50%出资，初期20 MW阶段双方合计承诺约10亿美元投资（含2.5亿美元权益）。设施100%采用当地水电清洁能源，余热供周边低碳产业使用，纳尔维克低廉电价与寒冷气候提供天然优势，将成为欧洲最大主权AI算力平台之一。","descEn":"OpenAI's first European AI data center at Narvik, Norway: 100,000 NVIDIA GPUs, 230 MW, 100% hydro power, targeting commissioning end-2026.","detailEn":"Stargate Norway, developed by Nscale and Aker (50/50 JV) with OpenAI, targets 100,000 NVIDIA GPUs online by end-2026, representing 230 MW of IT capacity expandable to 520 MW. The initial ~$1 billion commitment (~$250 million equity) funds the 20 MW first phase in Narvik, Norway, leveraging low-cost hydropower, a cool climate, and robust industrial infrastructure. Excess heat will benefit local low-carbon industries. It will be one of Europe's largest sovereign AI computing platforms.","progress":"2026年首期GPU机柜部署进行中，一期设施建设按计划推进"},
  {"id":5314,"name":"瑞典谢莱夫特奥 EdgeConneX 超大规模数据中心园区","en":"EdgeConneX Skellefteå Hyperscale Data Center Campus","country":"瑞典","region":"欧洲","cat":"datacenter","coord":[21.07,64.74],"cap":"1 GW（最大规划容量）","inv":80,"invText":"约 80 亿美元（规划总投资估计）","status":"规划","year":2030,"updated":"2026-06","owner":"EdgeConneX（EQT旗下）","flagship":true,"desc":"EQT旗下EdgeConneX规划欧洲最大数据中心之一，1GW容量，在Lyten工业园内","detail":"EQT旗下EdgeConneX于2026年2月宣布从Lyten手中收购瑞典谢莱夫特奥（Skellefteå）部分地块，拟开发最高1 GW容量的数据中心园区，依托Northvolt旧址的完善基础设施和当地充足的水电资源。该规模若实现，将跻身欧洲最大数据中心设施之列，服务AI训练及云计算工作负载。项目尚在监管审批程序中，实际容量将分阶段实现。","descEn":"EdgeConneX (EQT-backed) plans up to 1 GW data center campus in Skellefteå on ex-Northvolt land, announced February 2026, powered by renewable hydro.","detailEn":"EQT-backed EdgeConneX announced in February 2026 that it intends to acquire a portion of Lyten's Skellefteå site (formerly Northvolt Ett) to develop a data center campus with potential capacity of up to 1 GW, powered by regional renewable hydropower. The campus would be co-located with Lyten's battery manufacturing operations, creating a unique industrial-AI hub. Development is subject to regulatory approvals and will proceed in phases targeting AI and cloud workloads.","progress":"2026年2月宣布，正推进行政和监管审批程序"},
  {"id":5315,"name":"芬兰 Keliber 锂矿与锂电池材料联合体","en":"Keliber Lithium Mine and Hydroxide Refinery, Finland","country":"芬兰","region":"欧洲","cat":"mining","coord":[23.89,63.59],"cap":"年产 1.5 万吨氢氧化锂","inv":8,"invText":"约 7.83 亿欧元","status":"在建","year":2026,"updated":"2026-06","owner":"Sibanye-Stillwater（80%）、芬兰矿业集团（20%）","flagship":false,"desc":"欧洲首条锂矿到电池材料全链条项目，芬兰，2026年建成投产","detail":"Keliber项目是欧洲首个完整锂矿–选矿–精炼全产业链项目，由Sibanye-Stillwater（80%）和芬兰国家矿业集团（20%）共同开发，总投资约7.83亿欧元。矿山和选矿厂位于芬兰科克奥拉/考斯蒂宁地区，锂辉石精矿在科科拉工业园精炼为电池级氢氧化锂。2026年Q1主体工程竣工，2026年Q2开始热调试，满产后年产约1.5万吨氢氧化锂（约占欧洲现有需求10%），供应至少18年。","descEn":"Europe's first full-cycle lithium project (mine-to-refinery) in Finland; €783 m investment; construction completed Q1 2026, production ramp-up from Q2 2026.","detailEn":"The Keliber project (Sibanye-Stillwater 80%, Finnish Minerals Group 20%) is Europe's first integrated spodumene mine-to-lithium-hydroxide value chain, totalling €783 million. Mining operations and a concentrator are in Kaustinen/Kokkola area, with the refinery at Kokkola Industrial Park. Construction completed Q1 2026; hot commissioning and production ramp-up began Q2 2026. At full capacity (~2028), Keliber will produce ~15,000 t/year of battery-grade LiOH, covering ~10% of Europe's current demand for at least 18 years.","progress":"2026年Q1建设竣工，Q2开始热调试，芬兰国家注资4000万欧元助力达产"},
  {"id":5316,"name":"芬兰萨卡蒂铜镍钴多金属矿（Anglo American）","en":"Sakatti Copper-Nickel-Cobalt Mine, Finnish Lapland","country":"芬兰","region":"欧洲","cat":"mining","coord":[26.72,67.82],"cap":"年产约10万吨铜当量","inv":40,"invText":"超过 40 亿欧元（估计）","status":"规划","year":2032,"updated":"2026-06","owner":"Anglo American","flagship":false,"desc":"欧盟战略项目，芬兰拉普兰铜镍钴矿，2032年前后投产","detail":"萨卡蒂（Sakatti）是Anglo American位于芬兰拉普兰索丹屈莱北约15公里的铜镍钴多金属矿床，伴生铂族金属、金、银，是欧洲规模最大的未开发铜矿之一。2025年3月获欧盟委员会《关键原材料法》战略项目认定，可享受加快审批通道。按设计年产约10万吨铜当量，目标2030年代初投产；2023年完成环评，目前正在推进Natura 2000保护区相关补充研究。","descEn":"Anglo American's Sakatti polymetallic project in Finnish Lapland; EU Strategic Project (CRMA) since March 2025; targeting ~100,000 t copper-equivalent per year from early 2030s.","detailEn":"Sakatti, located 15 km north of Sodankylä in Finnish Lapland, is Anglo American's next-generation greenfield mine project containing copper, nickel, cobalt and PGMs. Designated an EU Strategic Project under the Critical Raw Materials Act in March 2025, enabling accelerated permitting. EIA was approved in 2023; supplemental Natura 2000 studies are ongoing. At full design capacity, the highly automated underground operation will produce ~100,000 tonnes of copper-equivalent annually from the early 2030s.","progress":"2025年3月获欧盟CRMA战略项目认定，Natura 2000补充研究进行中"},
  {"id":5317,"name":"葡萄牙巴罗索锂矿（Savannah Resources）","en":"Barroso Lithium Project, Portugal","country":"葡萄牙","region":"欧洲","cat":"mining","coord":[-7.55,41.73],"cap":"年产锂辉石精矿（资源量3900万吨@1.05% Li2O）","inv":6,"invText":"约 6 亿欧元（预计资本支出）","status":"规划","year":2028,"updated":"2026-06","owner":"Savannah Resources","flagship":false,"desc":"欧洲最大已知锂辉石矿床，葡萄牙博蒂卡斯，获1.1亿欧元国家补助","detail":"巴罗索（Barroso）锂矿位于葡萄牙米尼奥大区博蒂卡斯附近，是欧洲已探明最大锂辉石矿床，JORC资源量3900万吨（Li2O品位1.05%）。2026年1月葡萄牙政府向Savannah Resources授予最高1.1亿欧元不可偿还国家补助，支持矿山及选矿厂建设；目标2028年开始产出锂辉石精矿。项目所在的巴罗索农业景观系联合国粮农组织世界重要农业遗产，面临一定环保争议。","descEn":"Europe's largest known spodumene deposit at Barroso, Portugal; Savannah Resources secured a €110 million state grant in January 2026; production targeted 2028.","detailEn":"The Barroso Lithium Project near Boticas in northern Portugal holds Europe's largest known spodumene lithium deposit (39 Mt at 1.05% Li2O, containing ~411,900 t Li2O across five orebodies). In January 2026, the Portuguese government awarded Savannah Resources a non-reimbursable grant of up to €110 million to fund construction. The project targets spodumene concentrate production from 2028 and is designated a strategic project under the EU Critical Raw Materials Act. The site's location within a globally recognised agricultural heritage area has prompted some local opposition.","progress":"2026年1月获葡萄牙政府1.1亿欧元国家补助，可行性研究持续完善中"},
  {"id":5318,"name":"罗马尼亚黑海深水气田（Neptun Deep）","en":"Neptun Deep Black Sea Gas Field, Romania","country":"罗马尼亚","region":"欧洲","cat":"petro","coord":[30.5,44.4],"cap":"约 80 亿立方米/年（高峰产量）","inv":40,"invText":"约 40 亿欧元","status":"在建","year":2027,"updated":"2026-06","owner":"OMV Petrom、Romgaz","flagship":true,"desc":"罗马尼亚最大气田开发，将使罗马尼亚成为欧盟最大天然气生产国","detail":"Neptun Deep位于罗马尼亚黑海深水区，距海岸约160公里，由OMV Petrom（运营商）与Romgaz各50%合作开发，总投资约40亿欧元。可采资源量约1000亿立方米天然气，高峰年产约80亿立方米（占罗马尼亚当前年产量近80%）。2025年3月开始钻井（10口生产井，2026年底前完钻），生产平台正在印度尼西亚制造并将于2026年运抵安装，160公里海底管道已于2026年4月开始铺设，预计2027年首批天然气上岸。","descEn":"Romania's largest gas development: ~100 bcm recoverable in the Black Sea; €4 bn investment by OMV Petrom & Romgaz; first gas expected 2027.","detailEn":"Neptun Deep is the largest natural gas project in Romania and the first deep-water project in the Black Sea, located ~160 km offshore at ~100 m water depth. OMV Petrom (operator) and Romgaz each hold 50%, investing up to €4 billion total. Recoverable resources are ~100 billion cubic metres; plateau production of ~8 billion m³/year would make Romania the EU's largest gas producer. Drilling of 10 production wells commenced March 2025; the production platform is being fabricated and will be installed in 2026; 160 km offshore pipeline construction started April 2026; first gas is targeted for 2027.","progress":"2025年3月开始钻井，2026年4月启动160公里海底管道铺设，平台2026年运抵安装"},
  {"id":5319,"name":"德国威廉港2号 LNG 接收站","en":"Wilhelmshaven 2 LNG Terminal, Germany","country":"德国","region":"欧洲","cat":"petro","coord":[8.12,53.52],"cap":"4.6 bcm/年","inv":4,"invText":"约 4 亿欧元","status":"投运","year":2025,"updated":"2026-06","owner":"Deutsche Energy Terminal（DET）","flagship":false,"desc":"德国第二座大型LNG浮式接收站，2025年8月商业投运，年处理46亿立方米","detail":"威廉港2号（Wilhelmshaven 2）LNG接收站由Deutsche Energy Terminal运营，以277米长FSRU「Excelsior」号为核心，2025年8月正式进入商业运营，地点位于威廉港港口约1.5公里处，毗邻威廉港1号。2025年年内向德国天然气管网注气约19亿立方米，预计2026–2027年扩容至全设计能力46亿立方米/年，可供约370万户家庭使用，进一步强化德国天然气供应安全。","descEn":"Germany's second major LNG FSRU terminal at Wilhelmshaven commenced commercial operations August 2025; 4.6 bcm/year capacity at full ramp.","detailEn":"Wilhelmshaven 2 LNG terminal (Deutsche Energy Terminal) uses the 277 m FSRU 'Excelsior' moored ~1.5 km offshore in the Port of Wilhelmshaven, next to the existing Wilhelmshaven 1 terminal. It entered commercial service in August 2025, feeding up to 1.9 bcm into the German gas grid in 2025, scaling to 4.6 bcm/year by 2026–2027 (enough to power ~3.7 million homes), meaningfully reinforcing Germany's gas supply security.","progress":"2025年8月投入商业运营，2025年已向管网注气约19亿立方米"},
  {"id":5320,"name":"荷兰 Nederwiek 3 海上风电（LionLink 互联节点）","en":"Nederwiek 3 Offshore Wind Farm (LionLink Hub)","country":"荷兰","region":"欧洲","cat":"renewable","coord":[4.3,53.7],"cap":"约 2 GW","inv":30,"invText":"约 30 亿欧元","status":"规划","year":2031,"updated":"2026-06","owner":"TenneT","flagship":false,"desc":"荷兰北海约2GW海上风电，兼作LionLink英荷互联枢纽平台","detail":"Nederwiek 3是TenneT规划在荷兰北海开发的约2 GW离岸风电项目，也是LionLink英荷混合直流互联的关键离岸节点。风电特许招标计划于2026年启动，项目采用「混合互联资产」模式，同时承担向荷兰电网和英国电网输电的双重功能。预计2031年前后投运，届时将成为欧洲首批真正实现离岸风电与跨境互联深度融合的示范工程之一。","descEn":"TenneT's ~2 GW Nederwiek 3 offshore wind site in the Dutch North Sea, doubling as the LionLink UK–Netherlands interconnector offshore hub; tender launch 2026.","detailEn":"Nederwiek 3 is TenneT's planned ~2 GW offshore wind site in the Dutch North Sea, selected as the offshore hub for the LionLink hybrid HVDC interconnector. Its offshore converter platform will route power simultaneously to the Dutch onshore grid and, via LionLink, to the UK grid. The offshore wind tender is expected to launch in 2026; the combined wind-plus-interconnector project targets commissioning around 2031."},
  {"id":5321,"name":"英德 NeuConnect 直流海缆互联","en":"NeuConnect UK–Germany HVDC Interconnector","country":"英国—德国","region":"欧洲","cat":"grid","coord":[5.5,52.8],"cap":"1.4 GW / 725 km","inv":23,"invText":"约 18 亿英镑","status":"在建","year":2028,"updated":"2026-06","owner":"Meridian Energy（Allianz/Hermes/Kansai Electric）","flagship":false,"desc":"英德首条直流互联，1.4GW/725km，经荷兰海域，2028年投运","detail":"NeuConnect是英国与德国之间有史以来第一条直接电力互联，全长约725公里（含海底和陆上段），额定容量1.4 GW，由Allianz、安联旗下Meridian Energy公司主导，联合日本关西电力参与。线路经荷兰海域，连接英国肯特郡比尔斯通变电站与德国威廉港。项目已获必要审批并启动建设，目标2028年投运，可满足约150万户家庭用电，并显著提升英德两国可再生能源交换能力。","descEn":"First direct UK–Germany power link: 1.4 GW, 725 km HVDC cable via Netherlands sea; commissioning targeted 2028.","detailEn":"NeuConnect (Meridian Energy/Allianz/Hermes/Kansai Electric) is the first-ever direct electricity link between the UK and Germany, running ~725 km of HVDC land and subsea cables through British, Dutch and German waters. Rated at 1.4 GW, it connects Birchington in Kent (UK) to Wilhelmshaven (Germany). Construction has commenced following regulatory approvals; commissioning is targeted for 2028, enabling bi-directional trade of up to 1.4 GW and supporting the integration of renewable energy in both markets.","progress":"建设阶段，海缆制造和路由勘察均已推进","route":[[-1,51.4],[1.5,51.8],[4,52.5],[5.5,52.8],[7,53],[8.1,53.5]]},
  {"id":5322,"name":"英国塞兹韦尔C核电站（规划）","en":"Sizewell C Nuclear Power Station, UK","country":"英国","region":"欧洲","cat":"nuclear","coord":[1.62,52.21],"cap":"3.2 GW（2台EPR）","inv":445,"invText":"约 200–350 亿英镑","status":"规划","year":2040,"updated":"2026-06","owner":"EDF、英国政府（大英能源）","flagship":true,"desc":"英国后续旗舰核电计划，萨福克郡2台EPR，政府已批准142亿英镑投资计划","detail":"塞兹韦尔C（Sizewell C）位于英格兰萨福克郡，规划建设2台EPR反应堆（各约1600 MW），总装机3.2 GW，紧邻已运营的塞兹韦尔B站。英国政府于近期批准142亿英镑投资决定以推进项目，设计基本参考欣克利角C，但力求降本提效。由于欣克利角C成本超支，塞兹韦尔C目前仍处于规划及融资框架确立阶段，预期2040年前后实现首台机组并网，可为约六百万家庭供电。","descEn":"UK's planned second new EPR nuclear station at Sizewell, Suffolk; government approved £14.2 bn investment; 2×EPR (3.2 GW), targeting commissioning ~2040.","detailEn":"Sizewell C in Suffolk will replicate Hinkley Point C's twin-EPR design (2×1,600 MW, 3.2 GW total) adjacent to the existing Sizewell B station. The UK government approved a £14.2 billion investment decision for the project. It remains in planning and financing-framework stages, drawing on Hinkley Point C engineering learnings to reduce cost and schedule risk. First power is targeted around 2040, with the station eventually supplying electricity for ~6 million homes.","progress":"规划及融资框架确立阶段，政府批准142亿英镑投资决定"},
  {"id":5323,"name":"英特尔爱尔兰莱克斯利普 Fab 34","en":"Intel Fab 34, Leixlip, Ireland","country":"爱尔兰","region":"欧洲","cat":"ci","coord":[-6.49,53.37],"cap":"Intel 4（7nm级EUV）高端晶圆","inv":170,"invText":"约 170 亿欧元","status":"投运","year":2023,"updated":"2026-06","owner":"Intel","flagship":true,"desc":"欧洲首条EUV量产线，爱尔兰莱克斯利普，2023年投产，总投资170亿欧元","detail":"英特尔爱尔兰Fab 34位于都柏林西郊莱克斯利普园区，总投资约170亿欧元，是欧洲首座实现极紫外光刻（EUV）大规模量产的晶圆厂，采用Intel 4工艺（约相当于7nm级别），于2023年9月正式量产。2024年阿波罗全球管理公司以114亿美元收购49%股权形成合资，2025年英特尔以142亿美元回购该股权，恢复100%控股。Fab 34可为1600名全职员工提供岗位，目前承接AI加速芯片及高性能计算产品的先进制程订单。","descEn":"Europe's first high-volume EUV fab at Leixlip, Ireland; Intel 4 process; €17 bn investment; production since September 2023.","detailEn":"Intel Fab 34 at Leixlip, Ireland is Europe's first fab running high-volume EUV lithography (Intel 4 process node, ~7 nm equivalent), operational since September 2023 at a total cost of ~€17 billion. Apollo Global Management acquired 49% in a $11 billion JV in 2024 to help fund ongoing expansion; Intel repurchased that 49% stake for $14.2 billion in 2025, restoring full ownership. The facility employs 1,600+ new full-time staff and produces chips for AI and high-performance computing.","progress":"2025年英特尔斥资142亿美元回购阿波罗49%股权，恢复独资运营"},
  {"id":5324,"name":"欧盟 EuroHPC AI 超级工厂（多站点）","en":"EuroHPC AI Factory Initiative (Multi-site)","country":"欧盟多国","region":"欧洲","cat":"datacenter","coord":[10,50],"cap":"每站点约 10 万枚 AI 芯片级","inv":200,"invText":"约 200 亿欧元（InvestAI 计划总规模）","status":"规划","year":2027,"updated":"2026-06","owner":"欧盟委员会、EuroHPC JU、各成员国","flagship":true,"desc":"欧盟200亿欧元InvestAI计划，在成员国建4–5座AI超级工厂，抢先AI主权","detail":"欧盟委员会于2025年2月宣布200亿欧元InvestAI计划，在欧盟内建设4–5座AI超级工厂，每座配备约10万枚最先进AI加速芯片（约为当前一代数据中心的4倍）。EuroHPC JU第一批已选定奥地利、保加利亚、法国、德国、波兰、斯洛文尼亚6处AI工厂，并于2025年10月宣布第二批6处（捷克、立陶宛、荷兰、罗马尼亚、西班牙、波兰）；正式招标预计2026年Q2发布，全面运营目标2027年。此举是欧盟人工智能主权战略的核心基础设施部署。","descEn":"EU's €20 bn InvestAI programme: 4–5 AI gigafactories across member states, each with ~100,000 advanced AI processors; 12 sites selected by EuroHPC, formal tender expected Q2 2026.","detailEn":"The European Commission's InvestAI initiative (February 2025) commits €20 billion to build 4–5 AI gigafactories in the EU, each equipped with ~100,000 state-of-the-art AI accelerators — four times more computing power than current data centers. EuroHPC JU selected six AI Factory sites in March 2025 (Austria, Bulgaria, France, Germany, Poland, Slovenia) and six more in October 2025 (Czech Republic, Lithuania, Netherlands, Romania, Spain, Poland). The formal call for proposals is expected Q2 2026; full operation is targeted by 2027.","progress":"2025年3月选定首批6站点，10月选定第二批6站点，正式招标待2026年Q2发布"},
  {"id":5325,"name":"波兰SMR核电站（弗沃茨瓦韦克）","en":"Poland Włocławek SMR Nuclear Plant","country":"波兰","region":"欧洲","cat":"nuclear","coord":[19.06,52.65],"cap":"约 1.2 GW（3台SMR）","inv":40,"invText":"约 40 亿美元","status":"规划","year":2035,"updated":"2026-06","owner":"ORLEN、Synthos Green Energy、Rolls-Royce SMR","flagship":false,"desc":"波兰首批SMR落地弗沃茨瓦韦克，ORLEN与Synthos合作，Rolls-Royce技术","detail":"波兰计划在弗沃茨瓦韦克（Włocławek）建设该国首个SMR核电站，由ORLEN能源公司与Synthos Green Energy合作，采用Rolls-Royce SMR技术，部署约3台机组（总容量约1.2 GW）。波兰已批准建设6台SMR，该项目为其中优先推进的代表性工程，同时辅以西屋AP1000传统机组计划（卢比亚托沃-科帕利诺）。项目目标在2035年左右实现首台机组商运，是波兰脱煤转型的关键支柱之一。","descEn":"Poland's first SMR plant at Włocławek: ORLEN & Synthos Green Energy with Rolls-Royce SMR technology, ~1.2 GW (3 units), targeting 2035.","detailEn":"Poland's Włocławek SMR project, developed by ORLEN and Synthos Green Energy using Rolls-Royce SMR technology, will deploy approximately three units (~1.2 GW total) at the Włocławek industrial cluster. Poland has approved construction of six SMRs nationally; Włocławek is the lead site. The project is part of Poland's coal-exit strategy alongside the Lubiatowo-Kopalino AP1000 conventional nuclear plant, with a target of first SMR operation around 2035.","progress":"选址与前期开发协议阶段，依托Rolls-Royce SMR与英国合作框架"},

  // ===== 北美（5450-5465）=====
  {"id":5450,"name":"皮克顿AI超级数据中心（SoftBank×Stargate）","en":"Piketon AI Mega Data Center (SoftBank × Stargate)","country":"美国","region":"北美","cat":"datacenter","coord":[-83.018,38.856],"cap":"10 GW（第一期 800 MW）","inv":1000,"invText":"约 1000 亿美元（远期 10GW 全面建成；含配套燃气电厂约 330 亿美元）","status":"在建","year":2028,"updated":"2026-06","owner":"SoftBank / SB Energy / OpenAI / Oracle","flagship":true,"desc":"俄亥俄皮克顿旧铀浓缩厂址建设全球规模最大AI数据中心集群","detail":"位于俄亥俄州派克县前朴次茅斯铀扩散厂旧址，SoftBank联合OpenAI、Oracle规划总容量10 GW的AI数据中心群，配套9.2 GW天然气发电与42亿美元AEP新输电基础设施；第一期800 MW预计2028年初投运，Masayoshi Son称总投资规模500亿美元起步；2026年3月破土动工，是迄今全球最大AI算力基础设施声明，开创「数据中心×能源一体化园区」新范式。","descEn":"World's largest AI data center cluster at Ohio's former Portsmouth uranium enrichment site, SoftBank × Stargate","detailEn":"Located at Pike County, Ohio on the former Portsmouth Gaseous Diffusion Plant site, SoftBank with OpenAI and Oracle plans a 10 GW AI data center complex supported by 9.2 GW of natural gas generation and $4.2 billion in new AEP transmission. Phase 1 (800 MW) targets early 2028; Masayoshi Son quoted a $500 billion program; groundbreaking March 2026 is the largest AI infrastructure commitment globally, pioneering the integrated data center-energy campus model.","progress":"2026年3月正式破土，配套输电工程同步启动，第一期预计2028年初通电"},
  {"id":5451,"name":"GW Ranch德州超大离网数据中心能源园区","en":"GW Ranch Off-Grid Data Center Power Campus, Pecos County, Texas","country":"美国","region":"北美","cat":"datacenter","coord":[-102.887,30.953],"cap":"7.65 GW（含1.8 GW储能）","inv":100,"invText":"约 100 亿美元（电力园区：7.65GW 燃气 + 1.8GW 储能 + 750MW 光伏）","status":"规划","year":2027,"updated":"2026-06","owner":"Pacifico Energy","flagship":true,"desc":"德州培科斯县全美最大获批离网天然气+储能数据中心能源园区","detail":"位于德克萨斯州培科斯县福特斯托克顿北17英里，Pacifico Energy获美国史上最大发电环境许可证（7.65 GW），园区含高效天然气机组与1.8 GW电池储能，完全离网供电；首批电力预计2027年第一季度交付，8000英亩园区采用模块化设计，可无需额外许可扩展至5 GW以上，服务超大规模数据中心租户；是「二叠盆地天然气+AI」模式标杆项目。","descEn":"Largest permitted off-grid gas-plus-storage data center power campus in the US, Pecos County, Texas","detailEn":"Pacifico Energy secured the largest single power-generation air permit in US history (7.65 GW) for the GW Ranch campus 17 miles north of Fort Stockton, Pecos County, Texas. The campus combines high-efficiency gas turbines with 1.8 GW of battery storage, fully off-grid, targeting first power in Q1 2027. The 8,000+ acre modular campus can scale to 5+ GW to serve hyperscale data center tenants without further environmental approvals.","progress":"2026年1月获德州TCEQ批准；规划Q1 2026开工建设"},
  {"id":5452,"name":"NextEra德州+宾州天然气枢纽（AI数据中心专供）","en":"NextEra Texas + Pennsylvania Natural Gas Hubs for AI Data Centers","country":"美国","region":"北美","cat":"petro","coord":[-96.359,31.988],"cap":"9.5 GW（德州5.2 GW + 宾州4.3 GW）","inv":250,"invText":"约250亿美元","status":"规划","year":2029,"updated":"2026-06","owner":"NextEra Energy Resources","flagship":true,"desc":"NextEra获总统批准在德州和宾州各建天然气枢纽，专供AI数据中心","detail":"NextEra Energy于2026年3月获得特朗普政府批准，在德克萨斯州安德森县建设5.2 GW天然气发电枢纽，在宾夕法尼亚州西南部建设4.3 GW枢纽，总计9.5 GW，专门服务超大规模AI数据中心；项目依托日本550亿美元对美投资协议框架推进，由NextEra建设运营，是全美最大单一企业天然气新建项目之一，将显著增强美国东部与德州电力供应弹性。","descEn":"NextEra received presidential approval March 2026 for 9.5 GW of new gas generation in Texas and Pennsylvania dedicated to AI data centers","detailEn":"Announced March 2026, NextEra Energy Resources received US presidential approval to develop a 5.2 GW natural gas hub in Anderson County, Texas, and a 4.3 GW hub in southwest Pennsylvania totaling 9.5 GW. Tied to Japan's $550 billion US investment commitment and dedicated to hyperscale AI facilities, this is among the largest single-company gas generation approvals in US history.","progress":"2026年3月获总统批准，土地已锁定，工程推进中"},
  {"id":5453,"name":"Applied Digital Polaris Forge 2 AI工厂（北达科他）","en":"Applied Digital Polaris Forge 2 AI Factory, Harwood, North Dakota","country":"美国","region":"北美","cat":"datacenter","coord":[-96.898,46.978],"cap":"1 GW（首期200 MW）","inv":30,"invText":"约30亿美元","status":"在建","year":2026,"updated":"2026-06","owner":"Applied Digital / Macquarie Asset Management","flagship":false,"desc":"北达科他哈伍德镇1 GW AI工厂园区，已签50亿美元超算租约","detail":"位于北达科他州哈伍德镇（法戈以北），Applied Digital规划建设900英亩、1 GW总容量AI工厂园区，首期200 MW于2025年9月破土，并与美国投资级超大规模计算租户签订约50亿美元、15年超算租约；Macquarie提供融资，巴布科克-威尔科克斯提供1.2 GW天然气配套电力；首期预计2026年上线，液冷基础设施领先，是北达科他州最大AI算力投资。","descEn":"1 GW AI factory campus in Harwood, North Dakota with a $5 billion hyperscaler lease, groundbreaking September 2025","detailEn":"Applied Digital broke ground September 2025 on a 900-acre, 1 GW AI factory campus near Harwood, ND. A ~$5 billion, 15-year hyperscaler lease covers 200 MW initially with first-right-of-refusal for 800 MW more. Macquarie provides project financing; Babcock & Wilcox supplies 1.2 GW of gas-fired capacity. First buildings target 2026 online using proprietary liquid-cooling infrastructure.","progress":"2025年9月破土，首期200 MW预计2026年上线，融资已到位"},
  {"id":5454,"name":"Galaxy Digital Helios AI数据中心（西德州迪肯斯县）","en":"Galaxy Digital Helios AI Data Center Campus, West Texas","country":"美国","region":"北美","cat":"datacenter","coord":[-100.837,33.612],"cap":"1.6 GW（终期规划3.5 GW）","inv":75,"invText":"约75亿美元（CoreWeave租约合同价值）","status":"在建","year":2026,"updated":"2026-06","owner":"Galaxy Digital / CoreWeave","flagship":false,"desc":"西德州旧比特币矿场改建全球最大AI数据中心之一，ERCOT批准1.6 GW","detail":"位于德克萨斯州迪肯斯县，Galaxy Digital将160英亩前Argo Blockchain比特币矿场改建为AI数据中心；2025年获ERCOT新增批准830 MW，累计获批超1.6 GW；CoreWeave租用首批800 MW（合同价值逾75亿美元），2026年初供电启动；园区终期可扩至3.5 GW，是美国将比特币算力基础设施转型为AI基础设施的最大案例。","descEn":"Former bitcoin mining campus in Dickens County, Texas converted to 1.6 GW AI data center leased by CoreWeave","detailEn":"Galaxy Digital converted its 160-acre Helios campus in Dickens County, TX from bitcoin mining to AI infrastructure. ERCOT approved a total of 1.6 GW (adding 830 MW in 2025); CoreWeave leased the first 800 MW for $7.5+ billion with power starting early 2026. Full buildout targets 3.5 GW, the largest bitcoin-to-AI infrastructure conversion in the US.","progress":"首期800 MW于2026年初向CoreWeave供电，ERCOT二期批准已到位"},
  {"id":5455,"name":"Tehuacana Creek 1太阳能+储能（德州纳瓦罗县）","en":"Tehuacana Creek 1 Solar + BESS, Navarro County, Texas","country":"美国","region":"北美","cat":"storage","coord":[-96.471,31.984],"cap":"837 MW太阳能 + 418 MW / 1674 MWh储能","inv":16,"invText":"约16亿美元","status":"在建","year":2026,"updated":"2026-06","owner":"Solar Proponent","flagship":false,"desc":"2026年全美最大单体光伏项目，德州纳瓦罗县837 MW配418 MW储能","detail":"位于达拉斯西南65英里的纳瓦罗县，Solar Proponent开发，占地6700英亩，安装约150万块光伏组件，装机837 MW，另配418 MW/1674 MWh电池储能；光伏部分投资约11亿美元，储能约5亿美元；预计2026年10月投运，是2026年全美投运最大单体光伏项目，也是同期最大光储一体化项目之一。","descEn":"Largest single US solar project to come online in 2026, 837 MW solar with 418 MW BESS in Navarro County, Texas","detailEn":"Located in Navarro County, Texas, 65 miles southwest of Dallas, Solar Proponent's 6,700-acre farm with ~1.5 million modules delivers 837 MW solar and 418 MW/1,674 MWh battery storage. The combined ~$1.6 billion project targets commercial operation in October 2026, making it the largest single solar installation to come online in the US in 2026.","progress":"在建中，预计2026年10月完工投运"},
  {"id":5456,"name":"Dominion弗吉尼亚525 kV地下骨干输电线","en":"Dominion Energy Virginia 525 kV Underground HVDC Backbone","country":"美国","region":"北美","cat":"grid","coord":[-77.446,37.541],"cap":"525 kV HVDC / 185英里（298公里）","inv":23,"invText":"约23亿美元","status":"规划","year":2030,"updated":"2026-06","owner":"Dominion Energy Virginia","flagship":false,"desc":"弗吉尼亚185英里525 kV地下HVDC骨干线，应对数据中心爆发需求","detail":"Dominion Energy Virginia规划建设185英里525 kV地下HVDC骨干输电线，投资约23亿美元；2026年2月PJM批准包含该线路在内共计48亿美元弗吉尼亚输电扩建计划，将南部电力输送至北弗吉尼亚数据中心走廊，缓解全美数据中心密度最高地区的输电瓶颈；是应对AI数据中心用电潮的美国东部最重要输电新建项目之一。","descEn":"185-mile 525 kV underground HVDC backbone in Virginia approved February 2026 to relieve the world's densest data center corridor","detailEn":"Dominion Energy Virginia's $2.3 billion, 185-mile 525 kV underground HVDC backbone was approved as part of PJM's February 2026 $4.8 billion Virginia transmission expansion plan. The line will transfer generation capacity from southern PJM into data-center-dense Northern Virginia, addressing the most acute transmission bottleneck in the US amid surging AI demand.","progress":"2026年2月PJM批准，进入详细工程设计阶段","route":[[-79.8,36.7],[-77.4,37.5],[-77,38.8]]},
  {"id":5457,"name":"McIlvenna Bay铜锌矿（萨斯喀彻温）","en":"McIlvenna Bay Copper-Zinc-Gold-Silver Mine, Saskatchewan","country":"加拿大","region":"北美","cat":"mining","coord":[-101.912,54.423],"cap":"4900吨/日选矿，年产铜4100万磅+锌5400万磅","inv":7.3,"invText":"约10亿加元（约7.3亿美元）","status":"在建","year":2026,"updated":"2026-06","owner":"Foran Mining / Eldorado Gold","flagship":false,"desc":"萨斯喀彻温省首座全新铜锌矿，2026年三季度商业投产","detail":"位于萨斯喀彻温省克雷顿以西，Foran Mining开发地下铜锌金银矿与地面选矿厂，日处理矿石4900吨，矿山寿命18年，总投资逾10亿加元；2025年底建设完成率72%，2026年2月建设91%完工并开始试车，Q3 2026目标商业投产，产出铜锌精矿；萨省关键矿产投资激励计划及联邦战略创新基金均已拨款，是萨省重要新建金属矿。","descEn":"Saskatchewan's first new copper-zinc mine, 91% complete by February 2026 targeting Q3 2026 commercial production","detailEn":"Foran Mining's McIlvenna Bay, west of Creighton, Saskatchewan, is an underground Cu-Zn-Au-Ag mine with a 4,900 tpd mill and 18-year mine life. Capital exceeds C$1 billion; 91% complete by February 2026 with commissioning underway. Q3 2026 commercial production of copper and zinc concentrate targeted; supported by Saskatchewan's CMPII incentive and federal Strategic Innovation Fund grants.","progress":"2026年2月建设完成91%，试车启动，Q3 2026商业投产"},
  {"id":5458,"name":"Thompson镍矿带复兴（曼尼托巴）","en":"Thompson Nickel Belt Revival, Thompson, Manitoba","country":"加拿大","region":"北美","cat":"mining","coord":[-97.855,55.743],"cap":"年产精镍1.2万吨以上（含冶炼厂）","inv":2,"invText":"约2亿美元（新注入资本）","status":"规划","year":2027,"updated":"2026-06","owner":"Exiro Nickel（Vale / Orion / Canada Growth Fund）","flagship":false,"desc":"加拿大历史镍矿曼尼托巴Thompson获2亿美元新资本注入延续并扩展运营","detail":"曼尼托巴省汤普森历史镍矿区面临关闭，Exiro Minerals、Orion Resource Partners与加拿大增长基金组建Exiro Nickel新公司，与Vale合组投入高达2亿美元维持并扩展Thompson矿带运营，CGF承诺最多8500万美元；2026年2月政府宣布支持，交易2026年底完成；Thompson矿2025年产精镍1.2万吨，是加拿大战略镍供给的核心节点，对西方EV电池供应链意义重大。","descEn":"US$200M investment to preserve Manitoba's historic Thompson Nickel Belt, Canada Growth Fund backing critical nickel supply","detailEn":"Thompson Nickel Belt in Manitoba was saved from closure when Exiro Minerals, Orion Resource Partners, and Canada Growth Fund formed Exiro Nickel Co. with up to US$200 million (CGF up to US$85 million). Government support announced February 2026; transaction closes by end-2026. Thompson produced 12,000 tonnes of refined nickel in 2025, a critical North American nickel source for EV battery supply chains.","progress":"2026年2月政府宣布支持，交易预计2026年底完成"},
  {"id":5459,"name":"Tanbreez稀土矿（格陵兰卡科尔托克）","en":"Tanbreez Rare Earth Project, Qaqortoq, Greenland","country":"格陵兰","region":"北美","cat":"mining","coord":[-46.034,60.72],"cap":"年产稀土氧化物约8.5万吨（初期），扩建后42.5万吨","inv":3,"invText":"约3亿美元（含EXIM Bank 1.2亿美元融资意向）","status":"规划","year":2029,"updated":"2026-06","owner":"Critical Metals Corp (Nasdaq: CRML)","flagship":false,"desc":"格陵兰全球最大稀土矿床之一，试验厂2026年启动，获EXIM Bank支持","detail":"位于格陵兰岛卡科尔托克附近，Tanbreez矿床估计稀土氧化物资源量2820万吨，为全球最重要稀土资源之一；Critical Metals Corp已于2026年初开始建设多功能仓储与试验工厂，美国进出口银行提供1.2亿美元融资意向书；初期规模8.5万吨/年稀土氧化物，后模块化扩至42.5万吨/年；预计2028年底至2029年初开始矿石生产，净现值约30亿美元，是支撑西方稀土供应链的战略资源。","descEn":"Potentially the world's largest REE deposit in Greenland, Critical Metals Corp building pilot plant in 2026 backed by US EXIM Bank $120M LoI","detailEn":"The Tanbreez deposit near Qaqortoq, Greenland holds 28.2 million metric tonnes of REOs — potentially the world's largest. Critical Metals Corp commenced construction of a multi-use storage and pilot plant early 2026, backed by a US EXIM Bank $120 million letter of interest. Initial production targets late 2028/early 2029 at 85,000 tonnes/year REO, scaling modularly to 425,000 tonnes; NPV ~$3 billion.","progress":"2026年初开始建设试验厂及基础设施，目标8月完成第一期"},
  {"id":5460,"name":"Amitsoq石墨矿（格陵兰南部）","en":"Amitsoq Graphite Mine, South Greenland","country":"格陵兰","region":"北美","cat":"mining","coord":[-45.593,60.183],"cap":"JORC资源量2300万吨，品位20.41%石墨碳","inv":1,"invText":"约1亿美元（初期开发阶段）","status":"规划","year":2028,"updated":"2026-06","owner":"GreenRoc Strategic Materials (AIM: GROC)","flagship":false,"desc":"格陵兰南部世界级高品位石墨矿，2025年12月获30年开采许可，EU战略项目","detail":"位于格陵兰南部纳诺尔塔利克地区，Amitsoq石墨矿床品位20.41%，JORC资源量2300万吨，含石墨471万吨，是世界上品位最高的石墨矿床之一；2025年12月获格陵兰政府30年开采许可，同年获EU关键原材料法案战略项目认定；GreenRoc已与挪威Morrow Batteries建立合作，预可研计划2026年底启动；丹麦EIFO提供520万欧元贷款支持初期发展。","descEn":"World-class high-grade graphite deposit in South Greenland with 30-year exploitation licence December 2025 and EU Strategic Project status","detailEn":"GreenRoc's Amitsoq deposit in Greenland's Nanortalik region holds 23 million tonnes at 20.41% graphitic carbon — one of the world's highest-grade graphite deposits. A 30-year exploitation licence was granted December 2025; the EU Critical Raw Materials Act designated it a Strategic Project. Pre-feasibility study planned by end-2026; GreenRoc partnered with Norway's Morrow Batteries; Denmark's EIFO provided EUR 5.2 million in financing.","progress":"2025年12月获30年开采许可，预可研计划2026年底启动"},
  {"id":5461,"name":"Sarfartoq钕镨稀土项目（格陵兰西南）","en":"Sarfartoq Rare Earth Project, Southwest Greenland","country":"格陵兰","region":"北美","cat":"mining","coord":[-51.234,67.021],"cap":"Nd₂O₃约2700万公斤、Pr₆O₁₁约800万公斤（历史NI 43-101资源）","inv":0.35,"invText":"3500万美元（收购价，含股权对价）","status":"规划","year":2030,"updated":"2026-06","owner":"Greenland Mines Ltd (Nasdaq: GRML) / Neo Performance Materials","flagship":false,"desc":"格陵兰Nd-Pr碳酸盐稀土矿，全球Nd-Pr比例最高之一，2026年5月易主","detail":"位于格陵兰西南部深水fjord沿岸，Sarfartoq碳酸盐稀土矿床Nd-Pr占总稀土氧化物25-40%，是全球最高比例之一；Greenland Mines于2026年5月以3500万美元从Neo Performance Materials收购（含股份），Neo保留股权及60%矿石包销权；矿床具备深水港口物流优势及超15年钻探数据，是支撑西方磁铁级稀土供应链的战略资源节点。","descEn":"Greenland's Sarfartoq Nd-Pr carbonatite acquired for $35M in May 2026, Neo Performance retaining 60% offtake right","detailEn":"The Sarfartoq Carbonatite Complex in southwest Greenland is one of the world's highest Nd-Pr ratio rare earth deposits (25-40% of TREO). Greenland Mines acquired it from Neo Performance Materials in May 2026 for $35 million; Neo retains equity and a 60% offtake right. The deep-fjord tidewater location provides logistics advantages; over 15 years of drilling and metallurgical data support a feasibility study pathway.","progress":"2026年5月收购完成，开始推进可研工作及融资安排"},
  {"id":5462,"name":"Micron爱达荷博伊西晶圆厂群（ID1+ID2）","en":"Micron Idaho Boise Fab Complex (ID1 + ID2)","country":"美国","region":"北美","cat":"ci","coord":[-116.215,43.614],"cap":"2座旗舰级DRAM/HBM晶圆厂（先进制程+HBM封装）","inv":150,"invText":"约150亿美元（含CHIPS法案64亿美元拨款）","status":"在建","year":2027,"updated":"2026-06","owner":"Micron Technology","flagship":true,"desc":"美光博伊西新建ID1+ID2旗舰DRAM/HBM晶圆厂，2025年6月关键里程碑","detail":"美光科技在爱达荷州博伊西现有园区旁新建ID1和ID2两座旗舰级DRAM晶圆厂，专注最先进制程及高带宽存储器HBM（AI算力核心部件）；ID1于2025年6月完成关键建设里程碑，预计2027年下半年开始产晶圆；ID2毗邻ID1建设，预计先于纽约厂投产；两厂合计投资约150亿美元，获64亿美元CHIPS法案支持，另有先进HBM封装产线，将使美国本土AI存储芯片供给大幅提升。","descEn":"Micron's two new flagship DRAM/HBM fabs in Boise, Idaho with $6.4B CHIPS Act backing, ID1 construction milestone June 2025","detailEn":"Micron is constructing two leading-edge memory fabs (ID1 and ID2) in Boise, Idaho adjacent to its R&D campus. ID1 hit a key milestone in June 2025 with wafer output targeting H2 2027; ID2 enters production before the New York fabs. Combined investment ~$15 billion in Idaho, sharing $6.4 billion in CHIPS Act direct funding. Co-located HBM advanced packaging will make the US a major global supplier of AI memory chips.","progress":"ID1于2025年6月达成关键建设里程碑，预计2027年下半年产晶圆"},
  {"id":5463,"name":"TSMC亚利桑那Fab 21三期（N2/A16制程）","en":"TSMC Arizona Fab 21 Phase 3 (2nm / A16 Process)","country":"美国","region":"北美","cat":"ci","coord":[-112.013,33.677],"cap":"N2/A16先进制程晶圆厂（2nm/1.6nm节点）","inv":500,"invText":"约500亿美元（三期为1650亿美元总投资重要组成）","status":"在建","year":2028,"updated":"2026-06","owner":"TSMC Arizona Corporation / TSMC","flagship":true,"desc":"TSMC亚利桑那三期Fab 21 Phase 3于2025年4月开建，在美量产2nm/1.6nm芯片","detail":"TSMC于2025年4月在亚利桑那州菲尼克斯开始建设Fab 21三期，制程节点N2/A16（2nm及1.6nm级），是继一期（4nm已投产）和二期（3nm/2nm，2026年Q3装设备、2027年产出）之后第三座厂；TSMC将美国总投资扩至1650亿美元，是美国历史上最大单笔外商直接投资；三期力争在北美最先量产全球顶尖芯片，为AI芯片本土化供应提供关键基础。","descEn":"TSMC Arizona Fab 21 Phase 3 for 2nm/A16 chips broke ground April 2025 as part of TSMC's expanded $165B US commitment","detailEn":"TSMC began Fab 21 Phase 3 construction in Phoenix, Arizona in April 2025 for N2/A16 (2nm/1.6nm) chips. Phase 1 (4nm) is operational; Phase 2 (3nm/2nm) begins equipment installation Q3 2026 targeting production in 2027. Phase 3 is part of TSMC's $165 billion US commitment — the largest single FDI in US history — with three fabs, two packaging facilities and an R&D center targeting leading-edge chip production in North America.","progress":"2025年4月三期开工，二期同步推进设备安装，三期目标2028年前后产出"},
  {"id":5464,"name":"Mangrove锂精炼厂（不列颠哥伦比亚德尔塔）","en":"Mangrove Lithium Electrochemical Refinery, Delta, BC","country":"加拿大","region":"北美","cat":"mining","coord":[-122.955,49.085],"cap":"电池级锂（一期供约2.5万辆EV/年）","inv":0.5,"invText":"约5000万加元","status":"投运","year":2026,"updated":"2026-06","owner":"Mangrove Lithium","flagship":false,"desc":"北美首座商业化电化学锂精炼厂，2026年4月在BC省德尔塔市投运","detail":"位于不列颠哥伦比亚省德尔塔市工业区，Mangrove Lithium于2026年4月正式投运北美首座商业化电化学锂精炼设施，利用专有电化学工艺将提取的锂转化为电池级材料，消除传统化学品使用；加拿大政府通过CMRDD计划批准最高2190万加元支持；一期规模可供约2.5万辆EV年用量，公司另规划东加拿大大型工厂，年产量可供50万辆EV，是北美锂供应链的重要突破。","descEn":"North America's first commercial electrochemical lithium refinery opened April 2026 in Delta, BC using Mangrove's proprietary process","detailEn":"Mangrove Lithium opened North America's first commercial electrochemical lithium refinery in Delta, BC in April 2026. The proprietary process uses electricity instead of chemicals to produce battery-grade lithium, eliminating chemical waste. Current capacity supports ~25,000 EVs per year; Canada conditionally approved up to C$21.9 million via CMRDD. A larger Eastern Canada facility targeting 500,000 EV supply annually is in development.","progress":"2026年4月正式投运，北美首座同类商业化设施"},
  {"id":5465,"name":"墨西哥私营可再生能源项目群（2025年12月批准）","en":"Mexico 20 Private Renewable Energy Projects (December 2025 Batch)","country":"墨西哥","region":"北美","cat":"renewable","coord":[-102.553,23.634],"cap":"3320 MW（光伏2471 MW+风电849 MW）+ 1488 MW储能","inv":47.5,"invText":"约47.5亿美元","status":"规划","year":2028,"updated":"2026-06","owner":"CFE及11个州私营投资方","flagship":false,"desc":"墨西哥2025年12月批准20个私营可再生能源项目，总投资约47.5亿美元","detail":"墨西哥能源部长冈萨雷斯2025年12月宣布，20个私营项目共投资约47.5亿美元，分布于11个州，包括15座光伏电站（2471 MW）和5座风电场（849 MW），另配1488 MW储能；CFE同期自建3座太阳能电站，另规划20亿美元电网扩建；多数项目预计2026年开工，2027-2028年投运，是墨西哥新政府能源改革以来最大批私营可再生能源项目。","descEn":"Mexico's December 2025 batch of 20 private renewable projects: 3,320 MW solar/wind + 1,488 MW storage across 11 states, $4.75B total","detailEn":"Mexico's Energy Minister González announced $4.75 billion in private investment across 20 projects in 11 Mexican states in December 2025: 15 solar plants (2,471 MW) and 5 wind farms (849 MW) plus 1,488 MW of storage. CFE also building 3 solar plants and planning ~$2 billion in grid expansion. Most projects begin construction 2026 with CODs 2027-2028, the largest private renewable batch under Mexico's new energy policy.","progress":"2025年12月批准，2026年完成工程设计与许可，建设2026-2027启动"},

  // ===== 南美（5600-5634）=====
  {"id":5600,"name":"科帕亚索光储混合项目（智利）","en":"Copiapó Solar + BESS Project (Atlas Renewable Energy)","country":"智利","region":"南美","cat":"storage","coord":[-70.35,-27.37],"cap":"357 MW / 320 MW / 1.28 GWh","inv":4.8,"invText":"约 4.75 亿美元","status":"在建","year":2027,"updated":"2026-06","owner":"Atlas Renewable Energy","flagship":false,"desc":"智利阿塔卡马区规模最大光储混合项目之一，服务矿业客户。","detail":"项目位于智利科金博和阿塔卡马大区北部，包含357 MW光伏与320 MW/1.28 GWh电池储能系统。2025年10月完成4.75亿美元多边融资（BBVA、法农信贷等），2025年底开工，计划2027年一季度投运。通过两份15年PPA向CAP集团钢铁及矿业运营供应24×7清洁电力，年发电约750 GWh。","descEn":"One of Chile's largest solar-plus-storage hybrid projects in Atacama, serving mining clients.","detailEn":"Located in Chile's Coquimbo and Atacama regions, the Copiapó Solar project combines 357 MW of PV with a 320 MW/1.28 GWh BESS. Atlas Renewable Energy closed US$475M financing in October 2025 (BBVA, Crédit Agricole, Natixis, SMBC, SocGen). Construction began late 2025; COD target Q1 2027. Two 15-year PPAs supply CAP Group's iron-ore and mining operations with 750 GWh/year of 24/7 clean power.","progress":"2025年10月融资交割完成，土建施工启动；2027年一季度预期并网。"},
  {"id":5601,"name":"阿根廷LNG浮式出口项目（YPF/ENI/XRG）","en":"Argentina LNG – FLNG Export Project (YPF / Eni / XRG)","country":"阿根廷","region":"南美","cat":"petro","coord":[-62.08,-38.72],"cap":"12 MTPA（两台6 MTPA FLNG）","inv":200,"invText":"约 200 亿美元","status":"规划","year":2030,"updated":"2026-06","owner":"YPF、Eni、ADNOC XRG","flagship":true,"desc":"阿根廷首个大规模浮式LNG出口项目，依托瓦卡穆埃尔塔气源，FID目标2026年中。","detail":"项目整合瓦卡穆埃尔塔页岩气上游生产与海上浮式液化，规划两台FLNG船各6 MTPA，总能力12 MTPA。2026年2月YPF、Eni、XRG签署具约束力JDA，启动FEED及工程、融资活动；YPF委托摩根大通组建最高160亿美元项目融资包，创阿根廷史上最大私人项目贷款记录；2030—2031年启动出口。若实现，将彻底改变阿根廷油气出口格局，推动年创汇超百亿美元。","descEn":"Argentina's first large-scale FLNG export project, fed by Vaca Muerta shale gas, targeting FID mid-2026.","detailEn":"An integrated project linking Vaca Muerta shale gas production with two 6 MTPA FLNG vessels offshore Argentina. Partners YPF, Eni and XRG signed a binding JDA in February 2026 and are advancing FEED. YPF tapped JP Morgan to raise up to US$16 billion in project financing. First LNG exports are targeted for 2030–2031, potentially transforming Argentina into a top-10 LNG exporter.","progress":"2026年2月JDA签署，FEED启动；FID目标2026年中；融资谈判进行中。"},
  {"id":5602,"name":"里约廷科里孔锂DLE扩产项目（阿根廷）","en":"Rio Tinto Rincon Lithium DLE Expansion, Argentina","country":"阿根廷","region":"南美","cat":"mining","coord":[-66.85,-23.73],"cap":"年产 6 万吨碳酸锂（LCE）","inv":25,"invText":"约 25 亿美元","status":"在建","year":2028,"updated":"2026-06","owner":"Rio Tinto","flagship":false,"desc":"阿根廷盐湖DLE提锂扩产，从3000吨/年跃升至6万吨/年，采用直接锂提取技术。","detail":"项目位于萨尔塔省里孔盐湖，是里约廷科旗下最大锂资产。3000吨/年试验厂于2024年已验证技术路线，2025年中启动全规模扩产工程，采用DLE（直接锂提取）大幅降低耗水量。总投资25亿美元，已获11.75亿美元四家国际银行融资包支持；设计产能6万吨/年电池级碳酸锂，2028年首批产出、三年爬坡达产，是里约廷科在阿根廷锂三角的旗舰项目。","descEn":"Rio Tinto's flagship DLE lithium expansion in Argentina's Salta province, scaling from 3,000 t/y to 60,000 t/y LCE.","detailEn":"Located at Rincon salt flat in Salta province, this US$2.5 billion project uses direct lithium extraction (DLE) technology to scale from the validated 3,000 t/y starter plant to 60,000 t/y of battery-grade lithium carbonate. Full-scale construction started mid-2025, backed by a US$1.175 billion multi-bank financing package. First production is targeted for 2028, with a three-year ramp to full capacity.","progress":"2025年中全规模工程启动，融资完成11.75亿美元；2028年首产目标。"},
  {"id":5603,"name":"甘峰/锂阿根廷PPG锂盐湖项目（波苏埃洛斯-帕斯托斯格兰德斯）","en":"Ganfeng / Lithium Argentina Pozuelos-Pastos Grandes (PPG) Lithium Project","country":"阿根廷","region":"南美","cat":"mining","coord":[-66.54,-24.08],"cap":"年产 15 万吨碳酸锂（三期各5万吨）","inv":30,"invText":"约 30 亿美元（含收购）","status":"规划","year":2028,"updated":"2026-06","owner":"赣锋锂业（67%）、Lithium Argentina（33%）","flagship":false,"desc":"阿根廷史上最大单笔锂投资申请，三期合计产能15万吨/年，已提交RIGI。","detail":"项目整合赣锋锂业独资的波苏埃洛斯-帕斯托斯格兰德斯矿权与Lithium Argentina的帕斯托斯格兰德斯及萨尔德拉普纳项目，覆盖萨尔塔省核心锂三角资源。2025年8月签署框架协议，赣锋持股67%、锂阿根廷33%；2025年11月萨尔塔省环评批准一期。2026年3月赣锋向锂阿根廷提供1.3亿美元贷款支持开发。三期产能目标合计15万吨/年，可行性研究进行中；系阿根廷史上最大单笔锂投资提案。","descEn":"The largest single lithium investment proposal in Argentine history, integrating Ganfeng and Lithium Argentina assets for 150,000 t/y LCE in Salta province.","detailEn":"The PPG project consolidates Ganfeng Lithium's solely-owned Pozuelos-Pastos Grandes brine assets with Lithium Argentina's Pastos Grandes and Sal de la Puna projects. A framework agreement was signed in August 2025 (Ganfeng 67%, Lithium Argentina 33%). Salta province issued the environmental approval for Phase 1 in November 2025; Ganfeng extended a US$130 million loan in March 2026. Target: 3 × 50,000 t/y phases to reach 150,000 t/y LCE—Argentina's largest-ever lithium investment proposal.","progress":"2025年11月一期环评批准，2026年3月1.3亿美元贷款落地；可研进行中。"},
  {"id":5604,"name":"维库尼亚铜金矿联合体（菲洛-德尔索尔/何塞玛利亚，BHP/Lundin）","en":"Vicuña Copper-Gold District (Filo del Sol / Josemaria, BHP & Lundin JV)","country":"阿根廷","region":"南美","cat":"mining","coord":[-69.45,-28.15],"cap":"年产铜30余万吨（规划）","inv":150,"invText":"超过 150 亿美元（综合开发）","status":"规划","year":2030,"updated":"2026-06","owner":"Vicuña Corp（BHP 50% + Lundin Mining 50%）","flagship":true,"desc":"近30年全球最大新发现铜金矿区，BHP与Lundin各持50%，总投资料超150亿美元。","detail":"BHP和Lundin Mining于2025年1月完成对Filo Corp的22亿美元收购，成立Vicuña Corp联营公司，合并运营圣胡安省菲洛-德尔索尔与何塞玛利亚相邻矿权。2025年Lundin公布初始资源量，被称为「近三十年全球最大绿地铜发现」；综合技术报告定于2026年一季度完成，指引超170亿美元开发，初始建设预计2026年启动，何塞玛利亚单独可行性研究所需投资约27亿美元。萨尔塔与圣胡安两省已启动RIGI申请。","descEn":"BHP and Lundin Mining's 50/50 JV in Argentina's San Juan province, described as the largest greenfield copper discovery in 30 years, with combined development cost potentially exceeding US$15 billion.","detailEn":"BHP Canada and Lundin Mining completed the acquisition of Filo Corp for US$2 billion in January 2025 and formed Vicuña Corp to jointly develop the adjacent Filo del Sol and Josemaria copper-gold projects. Lundin declared Filo del Sol 'one of the world's largest copper-gold-silver resources.' The integrated technical report is due Q1 2026; the Josemaria standalone feasibility study targets a 2026 construction start, with total district development potentially exceeding US$15–17 billion.","progress":"2025年1月收购完成；资源量估算完成；综合技术报告2026年一季度发布；RIGI申请进行中。"},
  {"id":5605,"name":"洛斯阿苏莱斯铜矿（McEwen，阿根廷圣胡安）","en":"Los Azules Copper Project (McEwen Copper, San Juan, Argentina)","country":"阿根廷","region":"南美","cat":"mining","coord":[-70.58,-29.92],"cap":"年产约12.5万吨铜阴极","inv":26.72,"invText":"约 26.72 亿美元","status":"规划","year":2029,"updated":"2026-06","owner":"McEwen Copper（McEwen Inc. 46.4%）","flagship":false,"desc":"阿根廷圣胡安省大型铜矿，RIGI获批26.72亿美元投资，2025年完成可行性研究。","detail":"项目位于圣胡安省安第斯山区，采用堆浸+溶剂萃取/电积工艺生产高纯铜阴极，全程依托可再生能源运营，目标2038年碳中和。2025年9月获RIGI批准，同年10月发布可行性研究报告，确认低成本、长寿命生产特性。建设总投资约27亿美元（含2.27亿美元前期工程），矿山寿命逾20年，年均产铜约12.5万吨。建设启动预计2026年，首产2029年。","descEn":"A long-life, low-cost copper cathode project in San Juan, Argentina, RIGI-approved with US$2.67 billion committed investment.","detailEn":"Los Azules uses run-of-mine heap leach, SX-EW technology and 100% renewable power to produce high-purity copper cathodes. The RIGI approval (September 2025) and Feasibility Study (October 2025) confirm strong economics. Total capex is ~US$2.7 billion; annual production ~125,000 t copper over a 20+ year mine life. Construction start is targeted for early 2026, with first production in 2029.","progress":"2025年9月RIGI获批，2025年10月可研发布；2026年初建设启动准备中。"},
  {"id":5606,"name":"科德科-SQM诺瓦安迪诺锂业合资公司（阿塔卡马）","en":"Nova Andino Litio (Codelco-SQM Atacama Lithium JV)","country":"智利","region":"南美","cat":"mining","coord":[-68.15,-23.5],"cap":"年产 28–30 万吨碳酸锂（LCE）","inv":50,"invText":"估计超过 50 亿美元（长期资本投入）","status":"在建","year":2025,"updated":"2026-06","owner":"Codelco（51%以上）、SQM","flagship":true,"desc":"智利国家铜矿公司与SQM合并阿塔卡马盐湖锂业，合资运营至2060年，全球最大锂产能合并。","detail":"2025年12月，智利监管机构批准科德科子公司Minera Tarar与SQM Salar合并，成立Nova Andino Litio SpA，国家控股超50%，合约运营至2060年。合并目标将阿塔卡马盐湖锂产能提升至年产28–30万吨LCE，国家将获得2025—2030年经营利润约70%、2031年起85%。这是全球单盐湖最大锂产能整合，也是智利锂国有化战略的核心里程碑。","descEn":"Chile's state miner Codelco and SQM merged their Atacama salt flat operations into Nova Andino Litio (>50% state-controlled), targeting 280,000–300,000 t/y LCE output through 2060.","detailEn":"In December 2025, Chilean regulators approved the merger of Codelco's Minera Tarar and SQM Salar into Nova Andino Litio SpA, with Codelco holding over 50%. The JV targets 280,000–300,000 t/y LCE by integrating operations at the Atacama salt flat, the world's premier lithium brine deposit. The Chilean state will receive ~70% of operating margin through 2030 and 85% from 2031. This is the world's largest single-brine lithium capacity consolidation.","progress":"2025年12月监管批准，诺瓦安迪诺锂业正式成立并进入实施阶段。"},
  {"id":5607,"name":"洛斯布隆塞斯-安蒂那铜矿联合采矿计划（安格美/科德科）","en":"Los Bronces–Andina Joint Mine Plan (Anglo American & Codelco)","country":"智利","region":"南美","cat":"mining","coord":[-70.32,-33.15],"cap":"新增约 12 万吨/年铜产量","inv":50,"invText":"产生超50亿美元税前净现值增量","status":"规划","year":2030,"updated":"2026-06","owner":"Anglo American Sur（50%）、Codelco（50%）","flagship":false,"desc":"安格美与科德科联合矿山规划，21年新增270万吨铜产量，世界级铜矿区整合。","detail":"2025年2月签署MOU，2025年9月达成最终协议，2026年3月获竞争监管批准。两家公司将成立合营运营公司，整合相邻洛斯布隆塞斯矿（安格美）与安蒂那矿（科德科）的矿山规划，协同利用选矿产能，21年期间新增铜产量约270万吨（年均约12万吨），税前净现值增量不低于50亿美元，双方各半。预计正式许可证约于2030年到位，是全球规模最大铜矿区整合之一。","descEn":"Anglo American and Codelco finalized a joint mine plan for adjacent Los Bronces and Andina copper mines in Chile, unlocking at least US$5 billion of pre-tax value over 21 years.","detailEn":"The definitive agreement was signed in September 2025, with competition regulatory clearance received in March 2026. A new jointly-controlled operating company will optimize the combined processing capacity of both mines, delivering ~2.7 million additional tonnes of copper over 21 years (roughly 120,000 t/y incremental) and at least US$5 billion pre-tax NPV uplift for each party. Full permits are expected around 2030.","progress":"2026年3月竞争监管批准；合营运营公司设立中，许可证申请预计2030年落地。"},
  {"id":5608,"name":"埃斯孔迪达新选矿厂（BHP，智利）","en":"Escondida New Concentrator Project (BHP, Chile)","country":"智利","region":"南美","cat":"mining","coord":[-69.25,-24.27],"cap":"220–260 万吨/年铜（替换老旧产能）","inv":52,"invText":"44亿–59亿美元","status":"规划","year":2031,"updated":"2026-06","owner":"BHP（57.5%）、Rio Tinto（30%）、三菱（12.5%）","flagship":false,"desc":"全球最大铜矿埃斯孔迪达新建选矿厂，替换老龙科洛拉多斯厂，投资最高59亿美元。","detail":"2026年3月BHP向智利环保主管机构提交新选矿厂环评申请（DIA），项目投资44亿至59亿美元，设计年处理硫化矿石4.6亿吨，年产铜22万至26万吨，替换接近寿命终止的老龙科洛拉多斯厂并维持矿山总产能。工程高峰期用工约6000人。若获批，建设约于2028年启动，2031至2032年首产，延续世界最大铜矿主导地位。","descEn":"BHP's US$4.4–5.9 billion new concentrator at the world's largest copper mine, Escondida, replacing the aging Los Colorados plant and sustaining 460,000 t/d throughput.","detailEn":"In March 2026, BHP submitted the Environmental Impact Declaration for the Escondida New Concentrator to Chilean regulators. The plant will process 220,000–260,000 t/y of copper equivalent from sulphide ore, replacing the Los Colorados plant nearing end of life. Capital cost is estimated at US$4.4–5.9 billion. If approved on schedule, construction begins ~2028, with first production 2031–32.","progress":"2026年3月EIA（DIA）提交，审批进行中；建设目标2028年启动。"},
  {"id":5609,"name":"圭亚那海锤头油田（ExxonMobil第七项目，斯塔布鲁克区块）","en":"Hammerhead Oil Development – Stabroek Block Project 7 (ExxonMobil / Hess / CNOOC)","country":"圭亚那","region":"南美","cat":"petro","coord":[-58.15,7.1],"cap":"15 万桶/日","inv":68,"invText":"约 68 亿美元","status":"在建","year":2029,"updated":"2026-06","owner":"ExxonMobil（45%）、Chevron/Hess（30%）、CNOOC（25%）","flagship":false,"desc":"圭亚那斯塔布鲁克第七个油田开发，FID已批，FPSO在建，产能15万桶/日，2029年首油。","detail":"2025年9月ExxonMobil宣布对锤头鱼项目做出最终投资决定并获政府批准，这是斯塔布鲁克区块第七个开发项目，投资68亿美元。Chevron（原Hess权益）以25%股份首次加入。FPSO由MODEC设计，18口生产和注入井，2029年首油，届时圭亚那斯塔布鲁克区块总装机产能将达150万桶/日，跻身全球前五大产油区。","descEn":"ExxonMobil's seventh Stabroek block development offshore Guyana. FID in September 2025; US$6.8 billion project with 150,000 bopd FPSO capacity, first oil 2029.","detailEn":"ExxonMobil received government and regulatory approvals and made the FID for Hammerhead in September 2025. The US$6.8 billion development—the first with Chevron (via its Hess acquisition) as a partner—will use an FPSO designed by MODEC for ~150,000 bopd with 18 wells. First oil is expected in 2029, pushing total Stabroek block installed capacity to 1.5 million bopd.","progress":"2025年9月FID完成，FPSO FEED启动；2029年首油目标。"},
  {"id":5610,"name":"圭亚那乌阿鲁FPSO油田开发（斯塔布鲁克第五项目）","en":"Uaru FPSO Development – Stabroek Block Project 5 (ExxonMobil)","country":"圭亚那","region":"南美","cat":"petro","coord":[-58.45,7.55],"cap":"25 万桶/日","inv":100,"invText":"约 100 亿美元（Uaru+Whiptail合并估算）","status":"在建","year":2026,"updated":"2026-06","owner":"ExxonMobil（45%）、Hess（30%）、CNOOC（25%）","flagship":false,"desc":"圭亚那斯塔布鲁克第五项目，2026年产出首油，产能25万桶/日，是全球产量增量最快海上区块之一。","detail":"Uaru项目（Errea Wittu FPSO）是斯塔布鲁克区块第五个开发项目。2025年11月圭亚那斯塔布鲁克区块日产油达90万桶历史高位，Uaru预计2026年投产，届时产能将再增25万桶/日，推动圭亚那成为全球成长最快的原油生产国之一。该项目最多20个钻井中心，92口生产注入井合并于Uaru与第六项目Whiptail统一管理。","descEn":"The fifth Stabroek block development offshore Guyana; FPSO Errea Wittu targeting first oil in 2026 to add 250,000 bopd.","detailEn":"Uaru is the fifth development on ExxonMobil's prolific Stabroek block. The Errea Wittu FPSO targets first oil in 2026, adding 250,000 bopd. In November 2025, cumulative Stabroek daily output hit 900,000 bopd with Yellowtail at full capacity. Uaru and the concurrent Whiptail project (6th, startup 2027) share up to 20 drill centers and 92 production/injection wells, collectively adding 500,000 bopd by end-2027.","progress":"2025年11月区块日产90万桶新高，Uaru FPSO最终调试阶段；2026年首油预期。"},
  {"id":5611,"name":"科尔科万达风储混合项目（巴西，奥亚西斯阿塔卡马续建）","en":"Dom Inocêncio Wind Complex – Casa dos Ventos / Vestas (Brazil, Piauí)","country":"巴西","region":"南美","cat":"renewable","coord":[-41.9,-9],"cap":"828 MW","inv":10,"invText":"约 50 亿雷亚尔（约 10 亿美元）","status":"规划","year":2028,"updated":"2026-06","owner":"Casa dos Ventos","flagship":false,"desc":"巴西皮奥伊州828 MW陆上风电综合体，Vestas供货184台4.5 MW风机，2026年开工。","detail":"Casa dos Ventos与Vestas宣布828 MW多姆伊诺森西奥风电综合体订单，项目位于皮奥伊州中南部高风速区，部署184台V150-4.5 MW风机，总投资逾50亿雷亚尔（约10亿美元）。2026年启动建设，2028年分阶段并网，预计可为约200万户家庭供电。这是2023年以来巴西陆上风电最大新建项目，Vestas同时负责25年运维服务（AOM 5000协议）。","descEn":"Brazil's largest onshore wind project since 2023: 828 MW Dom Inocêncio wind complex in Piauí state, ordered by Casa dos Ventos from Vestas (184 × V150-4.5 MW turbines).","detailEn":"Casa dos Ventos selected Vestas to supply and manage construction of the 828 MW Dom Inocêncio Wind Complex in south-central Piauí, Brazil. With 184 V150-4.5 MW turbines and total investment exceeding BRL 5 billion (~US$1 billion), construction starts in 2026 and commissioning is targeted for 2028. The project will power ~2 million homes and includes a 25-year AOM 5000 service agreement.","progress":"2025年订单公告，2026年施工计划中，2028年并网目标。"},
  {"id":5612,"name":"YPF光伏园El Quemado（门多萨，阿根廷首个RIGI项目）","en":"El Quemado Solar Park – YPF Luz (Mendoza, Argentina)","country":"阿根廷","region":"南美","cat":"renewable","coord":[-68.8,-32.85],"cap":"305 MW","inv":2.11,"invText":"约 2.11 亿美元","status":"投运","year":2026,"updated":"2026-06","owner":"YPF Luz","flagship":false,"desc":"阿根廷最大光伏园，首个RIGI投资项目，2026年5月满功率投运。","detail":"El Quemado光伏园位于门多萨省拉斯埃拉斯县，占地约620公顷，部署51.1万块双面光伏组件，装机305 MW。总投资2.11亿美元，是阿根廷首个在RIGI（大型投资激励制度）框架下建成运营的能源项目。2025年1月开工，历经18个月建设；2025年12月首期200 MW并网，2026年5月满功率投运，YPF可再生能源装机突破1 GW大关。","descEn":"Argentina's largest solar park (305 MW, US$211M), the country's first RIGI-approved energy project, commissioned at full capacity in May 2026 in Mendoza.","detailEn":"El Quemado Solar Park in Las Heras, Mendoza, spans ~620 ha and features 511,000 bifacial PV panels. It is YPF Luz's flagship renewable asset and the first RIGI project to enter commercial operation in Argentina. Construction ran from January 2025 to May 2026; the first 200 MW grid-connected in December 2025, with full 305 MW commissioning in May 2026, pushing YPF's renewable capacity past 1 GW.","progress":"2026年5月满功率投运，阿根廷首个RIGI能源项目。"},
  {"id":5613,"name":"科隆比亚加雅坡I&II光伏综合体（埃内尔，大西洋省）","en":"Guayepo I & II Solar Park – Enel Colombia (Atlántico, Colombia)","country":"哥伦比亚","region":"南美","cat":"renewable","coord":[-74.83,10.73],"cap":"370 MW","inv":3.4,"invText":"约 3.4 亿美元","status":"投运","year":2024,"updated":"2026-06","owner":"Enel Colombia（Enel Green Power）","flagship":false,"desc":"哥伦比亚迄今最大集中式光伏电站，370 MW，已于2024年底投运，欧洲投资银行参贷。","detail":"加雅坡I&II光伏综合体位于大西洋省波内德拉和萨瓦纳拉加市，部署逾82万块太阳能板，装机370 MW，年发电约820 GWh，可服务约60万用户。总投资逾3.4亿美元，欧洲投资银行提供3亿美元融资。2024年底正式投运，成为哥伦比亚迄今最大集中式光伏电站。埃内尔同步推进加雅坡III（与大西洋省其他项目），进一步扩大哥伦比亚可再生能源枢纽规模。","descEn":"Colombia's largest centralized solar PV plant (370 MW) in Atlántico department, commissioned end-2024 with EIB financing, operated by Enel Green Power.","detailEn":"Guayepo I & II Solar Park in Ponedera and Sabanalarga, Atlántico, houses 820,000+ solar panels with 370 MW capacity and annual output of ~820 GWh. Investment exceeded US$340 million, supported by a US$300 million EIB loan. Commercial operations began at end-2024, making it Colombia's largest centralized solar plant. Enel Colombia is simultaneously advancing Guayepo III and other Atlantic-area projects.","progress":"2024年底投运，加雅坡III已获欧洲投资银行2亿美元融资，续建进行中。"},
  {"id":5614,"name":"卡斯卡贝尔铜金矿（厄瓜多尔，江西铜业收购SolGold）","en":"Cascabel Copper-Gold Mine (Jiangxi Copper / SolGold, Ecuador)","country":"厄瓜多尔","region":"南美","cat":"mining","coord":[-78.2,0.45],"cap":"约 29 万吨/年铜当量（28年矿山寿命）","inv":42,"invText":"约 42 亿美元","status":"规划","year":2028,"updated":"2026-06","owner":"江西铜业（通过SolGold收购）","flagship":true,"desc":"厄瓜多尔超大型铜金斑岩矿，江西铜业12亿美元收购SolGold，2026年起早期工程。","detail":"卡斯卡贝尔项目位于因巴布拉省利塔地区，核心为阿尔帕拉斑岩铜金矿，矿山寿命28年，铜储量约290万吨、黄金694万盎司、白银1840万盎司。江西铜业于2025年12月以8.67亿欧元（约12亿美元）完成收购SolGold，取得控股。2026年早期工程启动（坦达亚马-美洲露采），2027年全规模建设，2028年首批产出，总资本开支约42亿美元，是厄瓜多尔迄今最大矿业项目。","descEn":"Ecuador's largest-ever mining project: Jiangxi Copper acquired SolGold for ~€867 million in March 2026, taking control of the Cascabel copper-gold porphyry project with US$4.2 billion capex and first ore targeted for 2028.","detailEn":"Cascabel's Alpala porphyry deposit in northern Ecuador holds ~2.9 Mt copper, 6.9 Moz gold and 18.4 Moz silver over a 28-year mine life. Jiangxi Copper completed the SolGold acquisition in March 2026. Early works at the Tandayama-América open pit start in 2026, followed by underground portal construction in 2027 and first production in 2028. Total initial capex is US$4.2 billion, including a US$750 million silver stream pre-paid by Wheaton Precious Metals.","progress":"2026年3月江西铜业完成SolGold收购，卡斯卡贝尔早期工程2026年启动。"},
  {"id":5615,"name":"库里帕姆巴-埃尔多莫铜金矿（厄瓜多尔，Silvercorp/Salazar）","en":"Curipamba-El Domo Copper-Gold Mine (Silvercorp & Salazar Resources, Ecuador)","country":"厄瓜多尔","region":"南美","cat":"mining","coord":[-79.3,-1.62],"cap":"年产约 4.7 万吨铜当量（约 4.69 万盎司金当量/年）","inv":9.25,"invText":"约 9.25 亿美元","status":"在建","year":2026,"updated":"2026-06","owner":"Silvercorp Metals（75%）、Salazar Resources（25%）","flagship":false,"desc":"厄瓜多尔首个VMS型铜金银矿，2025年全面建设启动，2026年下半年首产目标。","detail":"库里帕姆巴项目位于博利瓦尔省，是块状硫化物（VMS）型铜金银矿，资源量约469万盎司金当量/年，矿山寿命26年。2024年底获环境许可证及法院批准，2024年末启动早期建设，2025年Q2全面建设推进。总资本开支约9.25亿美元，预计2026年下半年首批铜金精矿产出，是厄瓜多尔第二大矿业开发项目，也是近年首个进入建设阶段的大型铜矿。","descEn":"Ecuador's first VMS copper-gold-silver mine in Bolívar province; full-scale construction started Q2 2025, targeting first concentrate production in H2 2026.","detailEn":"Curipamba-El Domo received its environmental license in January 2024 and court clearance in late 2024, enabling full-scale construction in Q2 2025. Total initial capex is US$925 million. The deposit's 26-year mine life yields ~469,000 oz AuEq/year. First copper-gold concentrate production is targeted for H2 2026, making it Ecuador's second-largest mine in development and the first large copper project to reach construction in recent years.","progress":"2025年Q2全面建设启动；2026年下半年首产目标。"},
  {"id":5616,"name":"苏里南格兰莫尔古深海油田（TotalEnergies，58区块）","en":"GranMorgu Deep-Offshore Oil Development (TotalEnergies / Staatsolie / APA Corp, Block 58, Suriname)","country":"苏里南","region":"南美","cat":"petro","coord":[-55.5,6.25],"cap":"约 22 万桶/日（FPSO）","inv":122,"invText":"约 122 亿美元","status":"在建","year":2028,"updated":"2026-06","owner":"TotalEnergies（运营商）、APA Corp、Staatsolie","flagship":true,"desc":"苏里南近海旗舰深水油田，TotalEnergies主导，FPSO建造中，2028年首油，储量近7.6亿桶。","detail":"格兰莫尔古项目开发58区块萨帕卡拉和克拉布达古两个油田，可采储量约7.6亿桶，位于苏里南海岸约150公里处。运营商TotalEnergies与APA Corp合作，2026年5月苏里南国家石油公司（Staatsolie）宣布完成融资协议。SBM Offshore负责FPSO建造，水下基础设施安装计划2027年启动，2028年首油。总投资约122亿美元，是苏里南史上最大单笔能源项目，将彻底改变该国财政与出口结构。","descEn":"Suriname's flagship deepwater oil project in Block 58: TotalEnergies (operator), APA Corp and Staatsolie are developing ~760 million recoverable barrels via FPSO; first oil targeted 2028, total investment ~US$12.2 billion.","detailEn":"GranMorgu develops the Sapakara and Krabdagu deepwater fields in Block 58, ~150 km offshore Suriname. Recoverable reserves are estimated at nearly 760 million barrels. In May 2026, Staatsolie announced the financing deal was closed. SBM Offshore is building the FPSO; subsea infrastructure installation is planned for 2027, with first oil in 2028. Total project cost is ~US$12.2 billion—Suriname's largest-ever investment.","progress":"2026年5月融资协议完成；FPSO建造中；2027年水下安装，2028年首油。"},
  {"id":5617,"name":"玻利维亚CBC（宁德时代子公司）乌尤尼锂DLE工厂","en":"Bolivia Uyuni Lithium DLE Plants – CBC Consortium (CATL subsidiary)","country":"玻利维亚","region":"南美","cat":"mining","coord":[-67.5,-20.15],"cap":"年产 3.5 万吨碳酸锂（两厂合计）","inv":10,"invText":"约 10 亿美元","status":"规划","year":2027,"updated":"2026-06","owner":"CBC投资（宁德时代子公司）、YLB（玻利维亚国家锂业公司，51%）","flagship":false,"desc":"玻利维亚国家锂业与宁德时代子公司CBC签约10亿美元DLE提锂工厂，两厂合计年产3.5万吨碳酸锂。","detail":"2024年12月，玻利维亚国家锂业公司（YLB）与CBC联合体（宁德时代旗下）签署约10亿美元协议，在乌尤尼盐滩建设两座直接锂提取（DLE）工厂：一厂1万吨/年、二厂2.5万吨/年，两厂合计年产3.5万吨电池级碳酸锂。玻方持51%股权，CB持49%。项目面临法律挑战（原住民咨询程序争议），但预计2025—2026年启动建设，2027—2028年首批产出，是玻利维亚锂国有化战略最大外资合作。","descEn":"Bolivia's YLB and CATL's CBC subsidiary signed a US$1 billion deal in December 2024 to build two DLE lithium plants at Uyuni salt flat, combined capacity 35,000 t/y of battery-grade lithium carbonate.","detailEn":"Two DLE plants—10,000 t/y and 25,000 t/y—will be built at Salar de Uyuni, with YLB holding 51% and CBC 49%. The deal, signed December 2024, represents the largest foreign investment in Bolivia's lithium sector. Legal challenges from indigenous groups seeking prior consultation rights have created delays, but construction is expected to begin in 2025–2026 with first production targeted for 2027–2028.","progress":"2024年12月签约，2025—2026年建设启动预期；原住民法律程序审议中。"},
  {"id":5618,"name":"TH2 马加拉内斯绿氢绿氨项目（TotalEnergies，智利）","en":"H2 Magallanes Green Hydrogen & Ammonia Project (TotalEnergies H2, Chile)","country":"智利","region":"南美","cat":"renewable","coord":[-69.5,-52.8],"cap":"5 GW风电 / 年产约 190 万吨绿氨","inv":160,"invText":"约 160 亿美元","status":"规划","year":2032,"updated":"2026-06","owner":"TotalEnergies H2","flagship":true,"desc":"智利麦哲伦大区160亿美元绿氢绿氨巨型项目，5 GW风电，2025年5月提交环评。","detail":"TotalEnergies H2于2025年5月以160亿美元投资额向智利环境影响评估系统（SEIA）提交环评，项目位于麦哲伦大区圣格雷戈里奥公社。规划安装5000 MW风机，年产约190万吨绿氨出口至欧洲及亚洲市场。巴伊亚波塞西翁港口海洋特许权已获批。项目寿命25年，建设高峰期约1万人就业，运营期约1000人。是全球最大规划中绿氢绿氨出口项目之一，也是智利迄今最大单体工业投资。","descEn":"TotalEnergies H2's US$16 billion mega-project in Chile's Magallanes region: 5 GW of wind power producing 1.9 Mt/y of green ammonia for export, EIA submitted May 2025.","detailEn":"H2 Magallanes filed its Environmental Impact Assessment with Chile's SEIA in May 2025. The project in San Gregorio commune will install 5,000 MW of wind capacity and produce ~1.9 million tonnes of green ammonia annually for export. Maritime concession for the port at Bahía Posesión has been approved. At US$16 billion investment, it is Chile's largest-ever planned industrial project with a 25-year operational life.","progress":"2025年5月EIA提交，审查阶段；港口海洋特许权已获批。"},
  {"id":5619,"name":"瓦莱索塞戈铜矿扩建（巴西帕拉州）","en":"Vale Sossego Copper Mine Expansion (Pará, Brazil)","country":"巴西","region":"南美","cat":"mining","coord":[-50.6,-6.32],"cap":"新增约 5 万吨/年铜（8年矿山寿命延长）","inv":2.9,"invText":"约 2.9 亿美元","status":"规划","year":2027,"updated":"2026-06","owner":"Vale S.A.","flagship":false,"desc":"淡水河谷索塞戈铜矿扩建，延寿8年，新增5万吨/年铜产能，总投资2.9亿美元。","detail":"项目位于巴西帕拉州卡纳斯矿区，是淡水河谷铜金属事业的重要资产。扩建工程将使索塞戈选矿综合体延寿约8年，新增铜产能约5万吨/年，总计划资本开支2.9亿美元。2025年四季度索塞戈创季度铜产量历史新高18600吨；2026年铜产量持续达产后，扩建工程投资决策时间表为2026年。这是淡水河谷在巴西铜矿板块的核心有机增长项目，也是瓦莱基本金属版块能力提升重要一环。","descEn":"Vale's Sossego copper mine expansion in Pará, Brazil: US$290 million capex to extend mine life by 8 years and add ~50,000 t/y copper capacity.","detailEn":"Vale's Sossego Mining Complex expansion will extend its life by about 8 years and add ~50,000 t/y of copper production, with total planned capex of US$290 million. Q4 2025 saw Sossego's all-time-high quarterly output of 18,600 t copper. The investment decision is scheduled for 2026, with construction following. This is a core organic growth project within Vale Base Metals.","progress":"2025年Q4创产量历史新高；投资决策预计2026年；建设启动后约两年达产。"},
  {"id":5620,"name":"秘鲁扎夫拉纳尔铜矿（Teck/三菱，阿雷基帕）","en":"Zafranal Copper Project (Teck 80% / Mitsubishi Materials 20%, Arequipa, Peru)","country":"秘鲁","region":"南美","cat":"mining","coord":[-72.47,-16.28],"cap":"年产约 12.6 万吨铜精矿","inv":20,"invText":"逾 20 亿美元","status":"在建","year":2028,"updated":"2026-06","owner":"Teck Resources（80%）、三菱材料（20%）","flagship":false,"desc":"秘鲁阿雷基帕省大型铜矿，2025年Q3开工，设计年产铜12.6万吨，矿山寿命19年。","detail":"扎夫拉纳尔项目位于秘鲁阿雷基帕省，是安第斯铜矿带重要新资产。环保局SENACE已授予环评批准。采用露天开采+传统浮选工艺，设计日处理量8万吨，年产铜精矿铜金属量约12.6万吨（前五年平均），矿山寿命19年。原始预算12.6亿美元因通胀及工程更新已上调至逾20亿美元。2025年Q3启动建设，预计2028—2029年首产，是2025—2026年秘鲁进入建设阶段的11个矿业项目之一。","descEn":"Teck's Zafranal copper project in Arequipa, Peru: >US$2 billion capex, construction started Q3 2025, targeting 126,000 t/y copper in concentrate over a 19-year mine life with first production 2028–29.","detailEn":"Zafranal is a conventional open-pit, milling and flotation operation with an 80,000 t/d plant throughput and a 19-year mine life in Arequipa region. SENACE's environmental approval is in place. Teck (80%) and Mitsubishi Materials (20%) began construction in Q3 2025; capex has risen above US$2 billion. First production of copper-gold concentrate is targeted 2028–2029.","progress":"2025年Q3建设启动，预计2028—2029年首产。"},
  {"id":5621,"name":"钱凯港二期扩建（秘鲁，COSCO-秘鲁港口）","en":"Chancay Port Phase 2 Expansion (COSCO Shipping / Peru)","country":"秘鲁","region":"南美","cat":"transport","coord":[-77.27,-11.57],"cap":"最终 15 个泊位 / 150 万 TEU/年","inv":35,"invText":"总投资约 35 亿美元（累计）","status":"在建","year":2032,"updated":"2026-06","owner":"COSCO Shipping Ports（60%）、Volcán Compañía Minera（40%）","flagship":true,"desc":"2024年11月首期投运，二期扩建至15个泊位，总投资35亿美元，重塑南太平洋贸易格局。","detail":"钱凯港2024年11月14日正式开港，由COSCO Shipping主导，首期4个泊位投运，年处理能力150万TEU；全面扩建至15个泊位后将成为南美洲最大综合港。2025年创汇约3.08亿美元，预计2026年通过19000辆中国汽车。工程计划2032年完成，届时将成为连接中国与南美洲最高效的太平洋枢纽港，对秘鲁GDP年贡献约45亿美元。","descEn":"Phase 1 opened November 2024 (4 berths, 1.5 M TEU/y); the full expansion to 15 berths by 2032 will make Chancay South America's largest multi-purpose port, anchoring the China–South America Pacific trade corridor.","detailEn":"Chancay multipurpose port terminal, inaugurated November 14, 2024, is operated by COSCO Shipping Ports (60%) and Volcán (40%). Phase 1's 4 berths handle 1.5 million TEU/year. Full expansion to 15 berths by 2032 will unlock 14.5 Mt/year of bulk and container capacity. In 2025, customs revenue reached US$308 million; COSCO targets 19,000 Chinese car shipments in 2026. The port could contribute US$4.5 billion/year to Peru's GDP.","progress":"2024年11月首期投运，2025年正式商业运营，二期扩建持续至2032年。"},
  {"id":5622,"name":"哥伦比亚科莱克托拉500千伏输电（加勒比海风光能源疏散）","en":"Colectora 500 kV Transmission Line (La Guajira–Cesar, Colombia)","country":"哥伦比亚","region":"南美","cat":"grid","coord":[-73.22,11.35],"cap":"500 kV / 475 km（La Guajira–La Loma）","inv":17,"invText":"约 17 亿美元","status":"在建","year":2026,"updated":"2026-06","owner":"Grupo Energía de Bogotá（GEB）","flagship":false,"desc":"哥伦比亚加勒比海地区500千伏骨干线，打通拉瓜希拉-塞萨尔风光电外送通道，开通后释放900 MW可再生容量。","detail":"科莱克托拉输电线全长475公里，穿越拉瓜希拉省和塞萨尔省14个市镇，是接入哥伦比亚加勒比海风光资源（拉瓜希拉省太阳辐射和风速全国最优）的关键基础设施。由波哥大能源集团（GEB）承建，南段（夸埃斯特西塔斯-拉洛马）2025年中完工，北段（科莱克托拉-夸埃斯特西塔斯）预计2026至2027年完工。并网后可解锁约900 MW风电容量，哥伦比亚政府投入约17亿美元进行加勒比海电网升级。","descEn":"Colombia's 475 km, 500 kV Colectora transmission backbone in La Guajira and Cesar departments to evacuate up to 6 GW of future renewable capacity; southern section completed mid-2025, northern section 2026–27.","detailEn":"The Colectora project is the critical transmission spine for Colombia's Caribbean renewable energy hub. The 500 kV line runs 475 km through 14 municipalities, enabling wind and solar power from La Guajira and Cesar to reach the national grid. Grupo Energía de Bogotá built the southern section (Cuestecitas–La Loma), completed mid-2025; the northern section is due 2026–27. Commissioning unlocks ~900 MW of previously constrained wind capacity.","progress":"南段2025年中投运，北段2026—2027年计划完工。","route":[[-73.1,11.5],[-73.2,10.95],[-73.3,10.55],[-73.22,9.9]]},
  {"id":5623,"name":"瓦莱铜矿萨洛博三期扩能评估（巴西帕拉州）","en":"Vale Salobo Copper Mine Phase 3 Expansion Study (Pará, Brazil)","country":"巴西","region":"南美","cat":"mining","coord":[-50.28,-6],"cap":"新增约 2–3 万吨/年铜","inv":6,"invText":"评估阶段，预计约 6 亿美元","status":"规划","year":2028,"updated":"2026-06","owner":"Vale S.A.","flagship":false,"desc":"淡水河谷萨洛博铜矿三期扩能处于FEL3阶段，2026年做出投资决策，年增产2–3万吨铜。","detail":"萨洛博铜矿位于巴西帕拉州，是淡水河谷铜业旗舰资产。2025年Q4萨洛博创季度历史最高产量62900吨铜。三期扩能方案目前处于FEL3（详细前端工程）阶段，新增产能约2–3万吨/年，2026年做出投资决策。若获批，建设约需两年，首产约在2028—2029年。配合索塞戈扩建，将进一步巩固淡水河谷在全球铜市的战略地位。","descEn":"Vale's Salobo copper mine in Pará, Brazil is evaluating a Phase 3 expansion (FEL3 stage) adding 20,000–30,000 t/y copper; investment decision scheduled for 2026.","detailEn":"Salobo hit its all-time-high quarterly copper output of 62,900 t in Q4 2025. The Phase 3 expansion study at FEL3 stage targets an incremental 20,000–30,000 t/y, with the investment decision planned for 2026 and potential first production by 2028–29. Combined with the Sossego expansion, this would add ~80,000 t/y to Vale's Brazilian copper portfolio.","progress":"2025年Q4产量历史新高；FEL3研究进行中，投资决策2026年预计。"},
  {"id":5624,"name":"科德科丘基卡马塔-部长阿莱斯-拉多米罗托米奇北部矿山联合重组","en":"Codelco Northern Mining Hub Integration (Chuquicamata / Ministro Hales / Radomiro Tomic)","country":"智利","region":"南美","cat":"mining","coord":[-68.9,-22.31],"cap":"整合后年产约 100 万吨铜","inv":20,"invText":"整合带来约 20 亿美元成本节省与增收（4年计划）","status":"在建","year":2027,"updated":"2026-06","owner":"Codelco","flagship":false,"desc":"科德科推进北方三大铜矿深度整合，共享选矿产能，四年期目标节省20亿美元并提升产量。","detail":"科德科管理层正推动丘基卡马塔、部长阿莱斯和拉多米罗托米奇三矿运营深度整合，共享选矿厂和统一运营计划，目标在2027年前通过协同效应实现20亿美元节支增收。三矿合并已是全球排名前五的铜矿区，整合完成后年产铜可超100万吨。该计划是科德科应对产量压力、优化资产组合的核心战略，也是智利巩固全球最大铜出口国地位的关键举措。","descEn":"Codelco's structural integration of three northern Chilean copper mines (Chuquicamata, Ministro Hales, Radomiro Tomic) targeting US$2 billion in combined cost savings and revenue gains by 2027.","detailEn":"Codelco is pursuing deep operational integration of its three largest northern copper operations, sharing processing plants and unifying mine plans. The four-year program targets US$2 billion in synergies by 2027. Together the three mines already rank among the world's top 5 copper-producing districts; full integration could push annual output above 1 million tonnes of copper. The plan is critical to Codelco's financial recovery after years of underperformance.","progress":"整合计划推进中，2027年为关键节点目标年份。"},
  {"id":5625,"name":"巴西北部海上风电先导工程（里约格兰德杜诺尔特州）","en":"Brazil Offshore Wind Pilot Project (Rio Grande do Norte, Atlantic Coast)","country":"巴西","region":"南美","cat":"renewable","coord":[-37.06,-4.95],"cap":"24.5 MW（两台风机，试验阶段）","inv":0.5,"invText":"约 4200 万雷亚尔（约 0.5 亿美元，一期工程）","status":"规划","year":2028,"updated":"2026-06","owner":"SENAI CIMATEC（巴西国家工业研究机构）","flagship":false,"desc":"巴西首个获IBAMA预许可的海上风电先导项目，里约格兰德杜诺尔特海岸4.5公里外，2025年启动工程分析。","detail":"该先导项目已获IBAMA（巴西环境与可再生资源研究院）颁发预许可证，是巴西首个海上风电开发里程碑。安装位置距里约格兰德杜诺尔特州阿雷亚布兰卡港岛约4.5公里海域，装设两台总功率24.5 MW的风机。一期投资约4200万雷亚尔，用于工程分析和可行性研究，合同签署计划2025年底，施工预计2026年4月启动，三年后正式并网。项目为巴西百吉瓦规模海上风电产业开拓商业路径，配套2026年首次海上风电拍卖政策框架。","descEn":"Brazil's first offshore wind project to receive IBAMA preliminary licensing—a 24.5 MW pilot off Rio Grande do Norte; Phase 1 engineering investment ~BRL 42 million, construction start targeted April 2026.","detailEn":"This pilot project 4.5 km off Areia Branca's port-island received Brazil's first IBAMA preliminary license for offshore wind and involves two turbines totaling 24.5 MW. Phase 1 (BRL 42 million) covers engineering and feasibility studies, with contractor contracts planned for late 2025 and construction commencing April 2026. It paves the commercial pathway for Brazil's broader 100+ GW offshore wind pipeline ahead of the government's first offshore auction in 2026.","progress":"2025年获IBAMA预许可，工程分析阶段，2026年4月计划开工。"},
  {"id":5626,"name":"秘鲁克利亚韦科铜矿扩能（Anglo American，莫克瓜省）","en":"Quellaveco Copper Throughput Expansion (Anglo American, Moquegua, Peru)","country":"秘鲁","region":"南美","cat":"mining","coord":[-70.58,-16.69],"cap":"增至约 14.2 万吨/日（一期）","inv":1,"invText":"约 1 亿美元（一期，初步估算）","status":"在建","year":2026,"updated":"2026-06","owner":"Anglo American（60%）、三菱商事（40%）","flagship":false,"desc":"秘鲁克利亚韦科铜矿增产改造，安装第二破碎机和浮选槽，2026年底达14.2万吨/日。","detail":"克利亚韦科铜矿由Anglo American运营，自2022年投产以来表现持续超预期，2025年上半年实现铜产量156600吨。2025年7月Anglo American宣布一期扩能方案：安装第二台砾石破碎机及附加浮选槽，将日处理量从12.75万吨提升至约14.2万吨，预计2026年底完成，初步资本投入约1亿美元；长期二期扩能（达15万吨/日）研究同步推进。这是秘鲁最大外资铜矿的首次有机扩能。","descEn":"Anglo American's Stage 1 throughput expansion at Quellaveco copper mine in Peru: installing a second pebble crusher and flotation cells to boost daily capacity to ~142,000 t/d by late 2026.","detailEn":"Anglo American announced Phase 1 debottlenecking at Quellaveco in July 2025, adding a second pebble crusher and flotation capacity to raise throughput from 127,500 t/d to ~142,000 t/d by late 2026, with preliminary capex of ~US$100 million. In H1 2025, Quellaveco produced 156,600 t copper. A longer-term Phase 2 (up to 150,000 t/d) is under early study. This is Quellaveco's first organic expansion since its 2022 start-up.","progress":"2025年7月扩能方案公告，工程进行中，2026年底达产目标。"},
  {"id":5627,"name":"巴西多姆伊诺森西奥风光储混合基地（皮奥伊/巴伊亚，Statkraft等）","en":"Piauí / Bahia Large-Scale Renewable Hub – Sol de Brotas & New Wind Complexes (Brazil NE)","country":"巴西","region":"南美","cat":"renewable","coord":[-42.7,-10.5],"cap":"500 MW+（综合基地规划）","inv":8,"invText":"约 8 亿美元（综合投资）","status":"规划","year":2027,"updated":"2026-06","owner":"Statkraft巴西、多家开发商","flagship":false,"desc":"巴西东北部皮奥伊-巴伊亚州际可再生能源基地群，Statkraft Sol de Brotas光储风混合体为代表项目。","detail":"2025—2026年，巴西东北部皮奥伊和巴伊亚两州新获许可或开工的可再生能源项目超过5000 MW，代表项目包括Statkraft巴西Sol de Brotas光储风混合复合体（巴伊亚州，约500 MW），以及多个500 MW以上的风光储联合开发项目。得益于该地区全国最优的风速（7—10 m/s）和日照条件，容量因数超国际平均水平。巴西2026年预计新增约9 GW太阳能，东北部是最主要布局区，已成为全球最具竞争力的可再生能源投资目的地之一。","descEn":"Brazil's Northeast (Piauí/Bahia) new renewable energy hubs 2025–2026: Statkraft's Sol de Brotas wind-solar-storage hybrid and multiple 500 MW+ greenfield projects capitalising on the region's best-in-class wind and solar resources.","detailEn":"Brazil added 7.4 GW of large-scale power in 2025, with the Northeast leading in wind and solar. Piauí and Bahia are home to some of the world's highest wind capacity factors (7–10 m/s, >40% CF). New projects in this hub, including Statkraft's Sol de Brotas hybrid complex, are driving the 2026 pipeline of ~9 GW solar additions. The region's renewable buildout is attracting global capital ahead of Brazil's first offshore wind auction in 2026.","progress":"2025—2026年多个项目开工；Sol de Brotas等复合体规划与融资进行中。"},
  {"id":5628,"name":"阿根廷瓦卡穆埃尔塔北部输油管道（Oldelval杜普利卡尔诺尔特扩建）","en":"Vaca Muerta Duplicar Norte Oil Pipeline Expansion (Oldelval, Argentina)","country":"阿根廷","region":"南美","cat":"petro","coord":[-69,-39],"cap":"新增 22 万桶/日（至2027年3月达 30 万桶/日）","inv":4,"invText":"约 4 亿美元","status":"在建","year":2026,"updated":"2026-06","owner":"Oldelval（YPF、Pan American Energy、Shell 等股东）","flagship":false,"desc":"阿根廷瓦卡穆埃尔塔北部新增输油管道，2026年底投运，增加22万桶/日外输能力，支持原油出口创汇。","detail":"Oldelval于2025年初将主管道扩能至54万桶/日后，再投资4亿美元建设「杜普利卡尔诺尔特」新支线，专门接入瓦卡穆埃尔塔北部油田产能。该管线2026年底投运，初始运力22万桶/日，后续追加泵站扩能最高可达30万桶/日（2027年3月）。配合瓦卡穆埃尔塔南部管道（VMOS），阿根廷原油外输瓶颈将大幅缓解，为年创汇目标提供基础设施支撑。","descEn":"Oldelval's Duplicar Norte feeder pipeline in northern Vaca Muerta: US$400 million investment, starting operations end-2026 at 220,000 bopd and scaling to 300,000 bopd by March 2027.","detailEn":"After doubling the main Oldelval pipeline to 540,000 bopd in early 2025, the company is investing US$400 million in the Duplicar Norte feeder for northern Vaca Muerta fields. Commercial operations are targeted for end-2026 at 220,000 bopd, ramping to 300,000 bopd by March 2027 with additional pumping investment. Combined with the Vaca Muerta Sur (VMOS) pipeline, this eliminates Argentina's crude oil takeaway bottleneck.","progress":"2025年启动建设，2026年底投运，配套瓦卡穆埃尔塔南部管道共同支持出口增长。","route":[[-69.5,-38.5],[-68.8,-39.2],[-68.5,-40.1]]},
  {"id":5629,"name":"圭亚那朗泰尔天然气综合开发（ExxonMobil，斯塔布鲁克八期）","en":"Longtail Gas Development – Stabroek Block Project 8 (ExxonMobil, Guyana)","country":"圭亚那","region":"南美","cat":"petro","coord":[-57.5,7.35],"cap":"100—150 亿立方英尺/日天然气 + 20—29 万桶/日凝析油","inv":125,"invText":"约 125 亿美元","status":"规划","year":2030,"updated":"2026-06","owner":"ExxonMobil（45%）、Chevron/Hess（30%）、CNOOC（25%）","flagship":false,"desc":"斯塔布鲁克区块第八个开发项目，整合朗泰尔、三重尾、图博特三气田，2026年FID预期，首产2030年。","detail":"朗泰尔开发项目整合斯塔布鲁克区块中三个重叠气田（朗泰尔、三重尾、图博特，2017—2019年发现），是ExxonMobil在圭亚那迄今最大单体项目，估算总投资约125亿美元。项目将生产10—15亿立方英尺/日天然气及20—29万桶/日凝析油，彻底改变圭亚那以石油为主的开发格局，开启天然气货币化进程。FID预计2026年做出，首产2030年，届时斯塔布鲁克区块累计产能将突破150万桶油当量/日。","descEn":"ExxonMobil's US$12.5 billion eighth Stabroek block development—the Longtail, Tripletail and Turbot gas fields combined—targeting FID 2026 and first gas 2030; 1–1.5 bcf/d gas plus 200,000–290,000 bopd condensate.","detailEn":"The Longtail development will tap three overlapping gas discoveries (Longtail, Tripletail, Turbot) 150+ km offshore Guyana. Estimated at US$12.5 billion, it is ExxonMobil's most capital-intensive single Stabroek project. FID is expected in 2026 with first gas in 2030. The project marks Guyana's transition from purely oil extraction to integrated gas monetisation, alongside the Gas-to-Energy initiative.","progress":"FID预计2026年；FEED/EIA工作推进中；首产目标2030年。"},
  {"id":5630,"name":"BHP科洛萨20+铜矿产能提升（科利亚瓦西，智利）","en":"Collahuasi C20+ Infrastructure Productivity Project (Anglo American / Glencore / Mitsui)","country":"智利","region":"南美","cat":"mining","coord":[-68.72,-20.98],"cap":"年产约 40 万吨铜（扩能后）","inv":13,"invText":"约 13 亿美元","status":"在建","year":2028,"updated":"2026-06","owner":"Anglo American（44%）、Glencore（44%）、三井（12%）","flagship":false,"desc":"智利科利亚瓦西铜矿C20+基础设施升级，延寿20年，投资约13亿美元，2026年为关键里程碑年。","detail":"科利亚瓦西铜矿是智利第二大铜矿，2025年产铜40.41万吨，由Anglo American和Glencore各持44%权益。C20+项目是矿山关键基础设施与选矿生产力提升计划，旨在将矿山寿命延长20年。项目包括新增选矿设备和尾矿管理设施，总投资约13亿美元，2026年多项关键施工节点推进。2025年因回收率问题影响部分季度产量，C20+预计将持续改善运营稳定性，是全球前五大铜矿之一维持产能的战略核心。","descEn":"Collahuasi C20+ productivity and infrastructure project (Anglo American 44% / Glencore 44% / Mitsui 12%): ~US$1.3 billion to extend mine life by 20 years, with 2026 as a key construction milestone year.","detailEn":"Collahuasi is Chile's second-largest copper mine (404,100 t produced in 2025). The C20+ project adds concentrator equipment and tailings management infrastructure to extend mine life by 20 years. Total investment is ~US$1.3 billion. 2026 is a key milestone year for multiple construction workstreams. Recovery issues in parts of 2025 underscore the strategic importance of C20+ for operational stability at one of the world's top 5 copper mines.","progress":"C20+建设2025—2026年推进，2028年预计主要工程完工。"},
  {"id":5631,"name":"哥伦比亚图尔皮亚莱斯光伏园（TW Solar，塞萨尔省）","en":"Turpiales Solar PV Park (TW Solar, Cesar Department, Colombia)","country":"哥伦比亚","region":"南美","cat":"renewable","coord":[-73.28,8.58],"cap":"279 MW","inv":2.2,"invText":"约 2.2 亿美元","status":"规划","year":2027,"updated":"2026-06","owner":"TW Solar SAS","flagship":false,"desc":"哥伦比亚塞萨尔省279 MW大型光伏园，配套500千伏输电基础设施，2026年开工。","detail":"图尔皮亚莱斯光伏园由TW Solar开发，位于哥伦比亚塞萨尔省里约德奥罗市，装机279 MW，配套500千伏输电接入基础设施。总投资约2.2亿美元，是哥伦比亚可再生能源扩能浪潮中六个2026年上半年开工、合计1144 MW的标志性项目之一，也是TW Solar在哥伦比亚能源转型进程中的旗舰资产。预计2026年启动建设，支持哥伦比亚实现6 GW可再生能源目标。","descEn":"TW Solar's 279 MW Turpiales photovoltaic park in Cesar, Colombia, with 500 kV transmission infrastructure; US$220 million investment, construction starting in 2026.","detailEn":"The Turpiales project in Rio de Oro, Cesar, is one of six major Colombian renewable projects (totalling 1,144 MW) scheduled to begin construction in H1 2026. TW Solar is investing US$220 million in 279 MW of PV capacity and associated 500 kV transmission works. The project contributes to Colombia's push towards 6 GW of installed non-conventional renewables, backed by a growing renewable energy auction pipeline.","progress":"2026年上半年开工计划，预计2027年投运。"},
  {"id":5632,"name":"巴西多姆伊诺森西奥光伏复合体（皮奥伊索拉蒂奥基地）","en":"Piauí Solatio 4 GW Solar Energy Base (Solatio Energia, Piauí, Brazil)","country":"巴西","region":"南美","cat":"renewable","coord":[-41.8,-8.35],"cap":"4 GW（分阶段开发）","inv":40,"invText":"约 40 亿美元","status":"规划","year":2028,"updated":"2026-06","owner":"Solatio Energia","flagship":false,"desc":"巴西皮奥伊州规划中的4 GW超大型光伏基地，是南美最大在规划单体光伏项目之一。","detail":"Solatio Energia正在巴西皮奥伊州规划约4 GW超大型光伏综合基地，分阶段开发，总投资约40亿美元。项目充分利用皮奥伊州高辐照和低土地成本优势，是巴西电力扩容计划的重要组成部分。预计2025—2026年完成许可证申请和电网接入协议，2027—2028年分批开工，与巴西东北部可再生能源产业链协同。皮奥伊州已成为巴西光伏装机增长最快的州之一，该项目将进一步巩固这一地位。","descEn":"Solatio Energia's ~4 GW phased solar energy mega-base in Piauí, Brazil: one of South America's largest planned single-site PV developments, ~US$4 billion investment.","detailEn":"Located in Piauí—one of Brazil's fastest-growing solar states thanks to high irradiation and competitive land costs—Solatio Energia's 4 GW phased PV development targets phased construction from 2027–28 after completing environmental licensing and grid connection agreements in 2025–26. The project represents one of the largest planned single-site solar investments in South America.","progress":"规划及许可证申请阶段，2027—2028年分批建设目标。"},
  {"id":5633,"name":"阿根廷亨努斯绿氨（Fortescue，里奥内格罗省）","en":"Fortescue Cerro Policía Green Hydrogen – Orkeke / Patagonia Project (Río Negro, Argentina)","country":"阿根廷","region":"南美","cat":"renewable","coord":[-65.5,-40.8],"cap":"300 MW风电 / 绿氢出口","inv":10,"invText":"约 10 亿美元（一期估计）","status":"规划","year":2027,"updated":"2026-06","owner":"Fortescue Future Industries","flagship":false,"desc":"澳大利亚富铁矿公司在阿根廷巴塔哥尼亚开发300 MW风电驱动绿氢项目，RIGI获批，2026年环评听证。","detail":"Fortescue Future Industries（FFI）在里奥内格罗省塞罗波利西亚开发绿氢项目，利用巴塔哥尼亚丰富风能资源，安装约300 MW风机，生产绿氢用于出口，并计划为后续阿根廷工业脱碳提供清洁燃料。项目已获RIGI批准，2026年3月举行环评公众听证，计划2026年底前启动并网供电，绿氢生产于2027—2028年实现。是阿根廷RIGI获批的少数可再生能源大型项目之一。","descEn":"Fortescue's Cerro Policía green hydrogen project in Patagonia (Río Negro): ~300 MW wind power for green hydrogen export, RIGI-approved in 2025, environmental hearing March 2026.","detailEn":"FFI's Cerro Policía project harnesses Patagonia's world-class wind resource for green hydrogen production. RIGI approval was secured in 2025, and the environmental public hearing was held in March 2026. Dispatch to the Argentine grid is planned by end-2026; full green hydrogen production is targeted for 2027–28. The project is one of the few RIGI-approved large renewable energy projects in Argentina alongside lithium and copper mining.","progress":"2026年3月环评公众听证；RIGI获批；2026年底并网、2027—2028年绿氢生产目标。"},
  {"id":5634,"name":"巴西安格拉3号核电站（工程重启）","en":"Angra 3 Nuclear Power Plant – Construction Resumption (Brazil)","country":"巴西","region":"南美","cat":"nuclear","coord":[-44.46,-23.01],"cap":"1405 MW","inv":48,"invText":"约 239 亿雷亚尔（约 48 亿美元）完工投资","status":"在建","year":2033,"updated":"2026-06","owner":"Eletronuclear（巴西核电）","flagship":false,"desc":"巴西第三座核电机组，2022年11月复工，商运预期2033年，完工估算239亿雷亚尔。","detail":"安格拉3号核电机组装机1405 MW，由Eletronuclear运营，位于里约热内卢州伊塔奥纳市。2015年因腐败调查和资金问题停工，2022年11月重新启动施工。BNDES研究显示放弃项目损失高达220—260亿雷亚尔，而完工仅需约239亿雷亚尔，经济压力下持续推进。2025年2月能源政策委员会推迟决策，商运目标调整为2033年。该项目对巴西电力安全和低碳基荷供应具有重要意义。","descEn":"Brazil's Angra 3 nuclear plant (1,405 MW) resumed construction in November 2022 after a 2015 halt; completion cost ~BRL 23.9 billion (~US$4.8 billion), commercial operation target 2033.","detailEn":"Angra 3 is a PWR unit in Itaorna, Rio de Janeiro state, with 1,405 MW installed capacity. Construction was suspended in 2015 due to Lava Jato corruption investigations and funding shortfalls but restarted in November 2022. A BNDES study found abandonment costs of BRL 22–26 billion vs. BRL 23.9 billion to complete. The CNPE postponed a decision in February 2025; commercial operation is now targeted for 2033. The project provides critical low-carbon baseload for Brazil's grid.","progress":"BNDES新研究显示弃建成本（220-260亿雷亚尔）或高于约240亿雷亚尔的续建成本，矿能部已将报告提交CNPE待决，拟以EPC招标+最高90%私人资本复工。"},

  // ===== 非洲（5750-5783）=====
  {"id":5750,"name":"Scatec 方尖碑光储混合电站（埃及）","en":"Scatec Obelisk Solar-Plus-Storage Project","country":"埃及","region":"非洲","cat":"renewable","coord":[31.22,26.08],"cap":"1.1 GW / 200 MWh BESS","inv":5.9,"invText":"约 5.9 亿美元","status":"投运","year":2026,"updated":"2026-06","owner":"Scatec ASA / Norfund / EDF Power Solutions","flagship":true,"desc":"非洲最大光储一体项目，一期2026年2月投运","detail":"位于埃及纳加哈马迪（Nagaa Hammadi），总规模1.1 GW光伏配200 MWh储能，分两期建设，一期561 MW光伏+100 MW/200 MWh BESS已于2026年2月实现商业运营，二期564 MW光伏预计2026年夏完成。总投资约5.9亿美元，获EBRD、非洲开发银行、英国BII联合融资4.79亿美元，是非洲规模最大的单体光储一体项目。","descEn":"Africa's largest solar-plus-storage project; Phase 1 commissioned February 2026.","detailEn":"Located in Nagaa Hammadi, Egypt, the 1.1 GW solar + 200 MWh BESS Obelisk project reached Phase 1 commercial operation in February 2026 with 561 MW PV and 100 MW/200 MWh storage. Phase 2 (564 MW) expected mid-2026. Total capex ~$590M, financed by EBRD, AfDB and British International Investment. Africa's largest integrated solar-BESS facility.","progress":"2026年2月一期商运，二期在建，预计2026年夏并网"},
  {"id":5751,"name":"Scatec 能源谷超大光储项目（埃及米尼亚）","en":"Scatec Valley for Sustainable Energy – 1.95 GW Solar + 3.9 GWh BESS","country":"埃及","region":"非洲","cat":"renewable","coord":[30.75,28.1],"cap":"1.95 GW / 3.9 GWh BESS","inv":25,"invText":"约 25 亿美元（估）","status":"规划","year":2028,"updated":"2026-06","owner":"Scatec ASA","flagship":true,"desc":"非洲最大光储投资，米尼亚省全天候可再生基荷电站","detail":"项目名「能源谷」（Valley for Sustainable Energy），位于埃及米尼亚省，2026年1月与埃及电力输电公司签署25年PPA，规模1.95 GW太阳能+3.9 GWh电池储能，年发电量约6000 GWh，为非洲迄今最大单体光储投资。财务关闭预计2026年下半年，是Scatec公司历史最大项目。","descEn":"Africa's largest-ever solar+BESS investment signed in Egypt's Minya Governorate, January 2026.","detailEn":"The 'Valley for Sustainable Energy' project in Minya Governorate, Egypt signed a 25-year PPA with EETC in January 2026 for 1.95 GW solar and 3.9 GWh BESS, delivering ~6,000 GWh/year of around-the-clock baseload renewable power. Financial close expected H2 2026; largest project in Scatec's history and Africa's biggest solar-BESS investment.","progress":"2026年1月签PPA，财务关闭目标2026年下半年"},
  {"id":5752,"name":"ACWA Power 胡尔加达2GW风电场（埃及）","en":"ACWA Power South Hurghada 2 GW Wind Farm","country":"埃及","region":"非洲","cat":"renewable","coord":[33.85,27.25],"cap":"2 GW","inv":23,"invText":"约 23 亿美元","status":"规划","year":2028,"updated":"2026-06","owner":"ACWA Power","flagship":true,"desc":"埃及最大单体风电项目，2025年2月签约","detail":"ACWA Power于2025年2月与埃及电力输电公司签署25年PPA，投资约23亿美元（86亿里亚尔），在南胡尔加达建设2 GW陆上风电项目，为埃及最大单体IPP风电资产，年减碳350万吨。预计2026年达财务关闭后开工，2028年投产。","descEn":"Egypt's largest single-asset wind IPP: 2 GW at South Hurghada signed Feb 2025 for $2.3B.","detailEn":"ACWA Power signed a $2.3 billion (SAR 8.6 billion), 25-year PPA with EETC in February 2025 for a 2 GW onshore wind farm at South Hurghada, Egypt's Red Sea coast. It will be Egypt's largest single-asset IPP. Financial close targeted 2026, commissioning ~2028, cutting 3.5 Mt CO₂ per year.","progress":"2025年2月签署协议，2026年完成融资后开工"},
  {"id":5753,"name":"Infinity Power & Hassan Allam 米尼亚1GW光储（埃及）","en":"Infinity Power – Hassan Allam Minya 1 GW Solar + 600 MWh BESS","country":"埃及","region":"非洲","cat":"renewable","coord":[30.73,28.07],"cap":"1 GW / 600 MWh BESS","inv":9,"invText":"约 9 亿美元","status":"规划","year":2027,"updated":"2026-06","owner":"Infinity Power / Hassan Allam Utilities","flagship":false,"desc":"埃及米尼亚1GW光伏+600MWh储能，2027年投产","detail":"由埃及Infinity Power（Masdar合资）与Hassan Allam Utilities联合开发，位于米尼亚省，规模1 GW光伏+600 MWh电池储能，预计2027年第三季度商业运营；与之配套的本班200 MW光伏+120 MWh BESS一期项目预计2026年Q3并网。总组合投资约20亿美元，支持埃及2030年可再生能源占比42%目标。","descEn":"1 GW solar + 600 MWh BESS in Egypt's Minya; part of a 1.2 GW, $2B portfolio with Hassan Allam.","detailEn":"Infinity Power (Masdar JV) and Hassan Allam Utilities signed PPAs with Egypt's Ministry of Electricity for a 1 GW solar + 600 MWh BESS facility in Minya Governorate, commissioning Q3 2027, alongside a 200 MW Benban Phase 1 (Q3 2026). Combined portfolio is ~1.2 GW / 720 MWh, total investment ~$2 billion.","progress":"已签PPA，2025年开展工程设计，2027年Q3目标投运"},
  {"id":5754,"name":"ACWA Power 努尔米德尔特II/III光储（摩洛哥）","en":"ACWA Power Noor Midelt II & III Solar PV + BESS","country":"摩洛哥","region":"非洲","cat":"renewable","coord":[-4.73,32.68],"cap":"800 MW / 1200 MWh BESS","inv":10,"invText":"超 10 亿美元","status":"在建","year":2027,"updated":"2026-06","owner":"ACWA Power / Nareva","flagship":false,"desc":"摩洛哥努尔二三期各400MW光伏配储能，2027年并网","detail":"ACWA Power于2025年8月中标摩洛哥MASEN努尔米德尔特II和III项目，各400 MW光伏配600 MWh电池储能，采用BOO+30年PPA模式，与纳雷瓦（Nareva）联合开发。2026年初开工，目标2027年7月并网，合计投资逾10亿美元。ACWA本年度在非洲累计签约35亿美元。","descEn":"ACWA Power wins Morocco's 800 MW Noor Midelt II & III PV+BESS under 30-year BOO contracts, construction starting 2026.","detailEn":"ACWA Power (with Nareva) was awarded Noor Midelt II and III contracts in August 2025 under Morocco's MASEN, each 400 MW PV + 600 MWh BESS (230 MW discharge), BOO + 30-year PPA. Construction started early 2026, grid connection target July 2027. Combined capex exceeds $1 billion.","progress":"2025年8月中标，2026年初开工，2027年7月目标并网"},
  {"id":5755,"name":"Chbika绿氢绿氨项目（摩洛哥）","en":"Chbika Green Hydrogen and Green Ammonia Project","country":"摩洛哥","region":"非洲","cat":"renewable","coord":[-12.6,28.8],"cap":"1 GW 风光 / 年产20万吨绿氨","inv":45,"invText":"估约 45 亿美元（一期）","status":"规划","year":2030,"updated":"2026-06","owner":"TotalEnergies TE H2 / CIP / A.P. Møller Capital","flagship":false,"desc":"摩洛哥大西洋海岸1GW风光绿氢绿氨项目","detail":"由TotalEnergies TE H2、丹麦CIP及A.P. Møller Capital组成的联合体开发，选址摩洛哥盖勒明-乌埃德努地区大西洋沿岸，规划1 GW陆上风光驱动绿氢电解，海水淡化后制氢，再转化为每年20万吨绿氨出口欧洲。2024年10月签署土地预留协议，2025年完成选址和环评准备，预计2030年前后投产。","descEn":"1 GW wind/solar green hydrogen project in Morocco's Guelmim-Oued Noun region, targeting 200 kt/yr green ammonia for Europe.","detailEn":"Developed by TE H2 (TotalEnergies+EREN), Copenhagen Infrastructure Partners and A.P. Møller Capital, the Chbika project plans 1 GW of onshore renewables to power electrolysis of desalinated seawater, producing 200,000 t/yr of green ammonia for European markets. Land reservation signed Oct 2024; feasibility and permitting ongoing through 2026.","progress":"2024年10月签土地预留协议，2025年7月完成选址，工程前期进行中"},
  {"id":5756,"name":"TAQA-摩维摩洛哥绿氨与电子燃料项目","en":"TAQA Morocco – Moeve Green Ammonia & e-Fuels Project (Dakhla)","country":"摩洛哥","region":"非洲","cat":"renewable","coord":[-16,23.7],"cap":"6 GW 风光 / 年产10万吨氢·56万吨氨","inv":45,"invText":"约 45 亿美元（一期）","status":"规划","year":2031,"updated":"2026-06","owner":"TAQA Morocco / Moeve（原Cepsa）","flagship":false,"desc":"摩洛哥达赫拉6GW风光制绿氢氨，供欧洲e-Fuels","detail":"阿联酋TAQA Morocco与西班牙Moeve（原Cepsa）于2025年3月获摩洛哥绿氢项目许可，在达赫拉-乌季达建设约6 GW可再生能源，年产约10万吨绿氢转化为约56万吨绿氨和e-Fuels，经霍尔费斯法尔港出口欧洲。一期投资约45亿美元，为摩洛哥总价值320亿美元绿氢项目群之一。","descEn":"TAQA Morocco and Moeve (Cepsa) selected in March 2025 for a 6 GW renewable green hydrogen-to-ammonia project in the Dakhla region.","detailEn":"UAE's TAQA Morocco and Spain's Moeve (formerly Cepsa) were selected in Morocco's first green hydrogen offer round (March 2025) to develop ~6 GW of renewables at Dakhla, producing ~100 kt/yr green hydrogen converted to ~560 kt/yr green ammonia and e-fuels for export through Jorf Lasfar port. Initial capex ~$4.5 billion, part of Morocco's $32.5B green hydrogen portfolio.","progress":"2025年3月获批，签署土地预留协议，可行性研究阶段"},
  {"id":5757,"name":"南非REIPPPP第7轮Infinity Power太阳能集群","en":"Infinity Power – Pele Green Energy REIPPPP BW7 Solar Cluster (South Africa)","country":"南非","region":"非洲","cat":"renewable","coord":[29.4,-25.1],"cap":"1280 MW","inv":5.2,"invText":"约 95 亿兰特（约 5.2 亿美元）","status":"规划","year":2028,"updated":"2026-06","owner":"Infinity Power / Pele Green Energy","flagship":false,"desc":"南非REIPPPP七期最大得标商，六座光伏电站1280MW","detail":"Infinity Power（Masdar/Infinity合资）与Pele Green Energy（51%/49%）在2024年12月南非第七轮REIPPPP中标六座太阳能电站，合计1280 MW，分布于姆普马兰加（Highveld 240MW）、林波波（Palladium 240MW、Copper 240MW、Vanadium 150MW）及西北省（Onderstepoort 1 220MW、Onderstepoort 2 190MW），是本轮总容量1760 MW的73%，总投资约95亿兰特。","descEn":"Six solar projects totalling 1,280 MW across Mpumalanga, Limpopo and North West; largest winner in REIPPPP Bid Window 7 (December 2024).","detailEn":"Infinity Power and Pele Green Energy won six of the eight solar projects awarded in South Africa's REIPPPP Bid Window 7 (December 2024): Highveld 240 MW (Mpumalanga), Palladium 240 MW, Copper 240 MW, Vanadium 150 MW (all Limpopo), Onderstepoort 1 220 MW and Onderstepoort 2 190 MW (North West). Combined 1,280 MW = 73% of the 1,760 MW awarded, total investment ~R9.5 billion (~$520M).","progress":"2024年12月获优先竞标方资格，拟向商业关闭推进"},
  {"id":5758,"name":"南非BESIPPPP第二轮电池储能集群（2024）","en":"South Africa BESIPPPP Bid Window 2 Battery Storage Projects","country":"南非","region":"非洲","cat":"storage","coord":[26.2,-28.9],"cap":"615 MW / 约 2460 MWh","inv":7,"invText":"约 128 亿兰特（约 7 亿美元）","status":"规划","year":2027,"updated":"2026-06","owner":"CIP / EDF / Scatec等多开发商","flagship":false,"desc":"南非第二轮BESS独立储能招标8个项目615MW","detail":"南非能源部于2024年12月宣布电池储能IPP采购计划（BESIPPPP）第二轮8个优先竞标方，合计615 MW容量，分布于自由省（4个）、西北省（2个）和豪登省（2个），总投资128亿兰特，比一期均价下降35%。CIP/EDF牵头的Oasis集群（257 MW/1028 MWh，获BESIPPPP BW1）已进入商业关闭，BW2项目预计2027年建成。","descEn":"8 BESS projects totalling 615 MW announced as preferred bidders under South Africa's BESIPPPP Bid Window 2 in December 2024.","detailEn":"South Africa's Department of Electricity & Energy announced eight preferred bidders for BESIPPPP Bid Window 2 in December 2024, totalling 615 MW across Free State, North West and Gauteng provinces, with total investment of R12.8 billion (~$700M). Average tariff was 35% lower than BW1. Projects are expected to reach commercial close and begin construction in 2025–2026.","progress":"2024年12月公布优先竞标方，融资关闭准备中"},
  {"id":5759,"name":"Barrick Lumwana铜矿超级坑扩建（赞比亚）","en":"Barrick Lumwana Super Pit Expansion","country":"赞比亚","region":"非洲","cat":"mining","coord":[25.82,-12.47],"cap":"年产铜 24 万吨（满产）","inv":20,"invText":"约 20 亿美元","status":"在建","year":2028,"updated":"2026-06","owner":"Barrick Mining Corporation","flagship":true,"desc":"赞比亚20亿美元铜矿超级坑扩建，产能翻倍","detail":"巴里克矿业（Barrick）斥资20亿美元在赞比亚卢万瓦纳（Lumwana）铜矿实施超级坑扩建，于2024年10月由赞比亚总统主持启动，2025年全面开工建设。扩建后年均采矿量从1.5亿吨增至2.9亿吨，年铜产量从12万吨翻倍至24万吨，成为全球前25大铜矿。预计2028年达峰值产能，每年出口约11亿美元。","descEn":"Barrick's $2B Super Pit expansion at Lumwana, Zambia to double copper output to 240 kt/yr by 2028.","detailEn":"Barrick Mining's $2 billion Super Pit Expansion at Lumwana copper mine in Zambia's North-Western Province was officially launched in October 2024 by President Hichilema and moved into full construction in 2025. Annual mining volumes will grow from 150 Mt to 290 Mt, doubling copper production to 240 kt/yr and making it a Tier One asset. Expected peak production 2028, contributing $1.1B/yr in exports.","progress":"2024年10月启动，2025年全面开工，预计2028年达满产"},
  {"id":5761,"name":"壳牌邦加北深水油田（尼日利亚）","en":"Shell Bonga North Deepwater Oil Project – Nigeria","country":"尼日利亚","region":"非洲","cat":"petro","coord":[5.2,4.15],"cap":"峰值产量 11 万桶/日","inv":50,"invText":"约 50 亿美元","status":"在建","year":2030,"updated":"2026-06","owner":"Shell SNEPCo（55% 运营方）/ NNPC / ExxonMobil / TotalEnergies / Eni","flagship":true,"desc":"尼日利亚邦加北50亿美元深水油田，2024年底FID","detail":"壳牌尼日利亚深水勘探公司（SNEPCo）于2024年12月对邦加北深水油田作出最终投资决定，投资约50亿美元，将钻16口井（8口生产、8口注水），并回接至现有邦加FPSO，预计峰值产量11万桶/日，可采储量约3.3亿桶。首油目标2030年。伙伴方包括NNPC、ExxonMobil（20%）、TotalEnergies（12.5%）、Eni（12.5%）。","descEn":"Shell Nigeria's $5B Bonga North deepwater FID taken December 2024; peak production 110 kbpd targeted 2030.","detailEn":"Shell Nigeria Exploration and Production Company (SNEPCo) took FID on the Bonga North deepwater oil project in December 2024, investing ~$5 billion to drill 16 wells tied back to the existing Bonga FPSO. Recoverable reserves ~330 MMboe, peak production 110,000 bpd, first oil expected 2030. Partners: NNPC, ExxonMobil (20%), TotalEnergies (12.5%), Eni (12.5%). Shell's interest increased to 67.5% in May 2025.","progress":"2024年12月FID，2025年开始工程采购，2030年首油"},
  {"id":5762,"name":"Azule Energy Agogo深水油田综合西枢纽（安哥拉）","en":"Azule Energy Agogo Integrated West Hub – Angola","country":"安哥拉","region":"非洲","cat":"petro","coord":[11.1,-6.8],"cap":"峰值产量 18 万桶/日（Agogo+Ndungu）","inv":78,"invText":"约 78 亿美元","status":"投运","year":2025,"updated":"2026-06","owner":"Azule Energy（bp+Eni）/ Sonangol / Sinopec","flagship":true,"desc":"安哥拉Agogo FPSO 2025年7月投产，创深水速度纪录","detail":"由bp与Eni合资的Azule Energy于2023年2月作出FID，78亿美元开发安哥拉15/06区块Agogo与Ndungu油田，包括一艘FPSO及配套水下设施。Agogo FPSO于2025年7月29日实现首油，距FID仅29个月，创同类项目最快纪录，且为安哥拉首座配备碳捕集装置的FPSO。设计峰值产量17.5万桶/日，Ndungu已于2026年2月全面投产。","descEn":"Agogo FPSO achieved first oil July 2025, just 29 months from FID; Angola's first FPSO with CCS; $7.8B project.","detailEn":"Azule Energy (bp-Eni JV) reached first oil from the Agogo FPSO on July 29, 2025, only 29 months after the February 2023 FID—record speed for a deepwater project of this size. The $7.8 billion Agogo Integrated West Hub on Block 15/06 encompasses Agogo and Ndungu fields with combined reserves of ~450 MMbbl, peak production ~175 kbpd, and is the first Angolan FPSO with a CCS pilot unit. Ndungu reached full production February 2026. Partners: Sonangol (36.84%), Sinopec (26.32%).","progress":"2025年7月Agogo投产，2026年2月Ndungu全面投产"},
  {"id":5763,"name":"TotalEnergies Kaminho深水FPSO项目（安哥拉）","en":"TotalEnergies Kaminho Deepwater FPSO – Angola Block 20/11","country":"安哥拉","region":"非洲","cat":"petro","coord":[10,-8.5],"cap":"7万桶/日","inv":60,"invText":"约 60 亿美元","status":"在建","year":2028,"updated":"2026-06","owner":"TotalEnergies（40%）/ Petronas Angola（40%）/ Sonangol（20%）","flagship":false,"desc":"安哥拉宽扎盆地首个深水开发项目，2024年5月FID","detail":"TotalEnergies与Petronas、Sonangol于2024年5月联合对安哥拉20/11区块Kaminho项目（Cameia和Golfinho油田）作出FID，投资约60亿美元，设计产量7万桶/日，全电动FPSO并实现伴生气全回注，消除例行燃除。FPSO已完工30%，安比日斯（Ambriz）码头海底构件建造中，2026–2027年安装，2028年投产。","descEn":"TotalEnergies' $6B Kaminho FPSO on Angola Block 20/11 (FID May 2024); first oil 2028, 70 kbpd.","detailEn":"In May 2024, TotalEnergies (40%, operator), Petronas Angola (40%) and Sonangol (20%) took FID on the $6 billion Kaminho project on Block 20/11 in Angola's Kwanza Basin, developing the Cameia and Golfinho fields. The all-electric FPSO (no routine flaring, full gas reinjection) is 30% complete. Subsea fabrication at Ambriz yard; installation 2026–2027; startup 2028 at 70,000 bpd.","progress":"2024年5月FID，FPSO完工30%，2026–2027年海底安装"},
  {"id":5764,"name":"刚果（金）英加三期世界银行开发计划","en":"DRC Inga 3 Development Program – World Bank $1B","country":"刚果（金）","region":"非洲","cat":"renewable","coord":[13.58,-5.53],"cap":"4800–11000 MW（长期）","inv":10,"invText":"世界银行首期 10 亿美元（总额估 100–250 亿美元）","status":"规划","year":2035,"updated":"2026-06","owner":"刚果（金）政府 / 世界银行 IDA","flagship":true,"desc":"世行2025年6月批准10亿美元为英加三期奠基","detail":"世界银行董事会于2025年6月3日批准向刚果（金）提供2.5亿美元IDA信贷，作为英加三期开发计划首期的10亿美元融资框架中的第一笔，目标是启动非洲最大水电潜力地点（全站最终容量约4.2万MW）的可持续开发。英加三期设计容量4800–11000 MW，总建设费用预估100亿美元以上，预计建设周期约十年。首期聚焦孔果中省10万户社区基础设施和能力建设。","descEn":"World Bank approved $250M IDA credit in June 2025 as first phase of a $1B program to restart Inga 3 (4,800–11,000 MW potential) in DRC.","detailEn":"The World Bank Board approved a $250 million IDA credit in June 2025 as Phase 1 of a $1 billion Inga 3 Development Program for the DRC. Inga 3 could generate 4,800–11,000 MW from the Congo River, with overall construction costs estimated at ~$10 billion and a 10-year construction timeline. Initial investment focuses on 100 communities (1.2 million people) in Kongo Central with water, power and road access. The full Grand Inga system could eventually reach 42,000 MW.","progress":"2025年6月世行批准首期2.5亿美元，社区前期投资启动"},
  {"id":5765,"name":"坦桑尼亚尼雷尔水电站全面投运","en":"Julius Nyerere Hydropower Station – Full Commissioning","country":"坦桑尼亚","region":"非洲","cat":"renewable","coord":[37.62,-7.75],"cap":"2115 MW / 年发电 5920 GWh","inv":30,"invText":"约 30 亿美元","status":"投运","year":2025,"updated":"2026-06","owner":"TANESCO / 中国电建（EPC）","flagship":true,"desc":"东非最大水电站，2025年3月九台机组全部投运","detail":"位于坦桑尼亚Stiegler峡谷的尼雷尔水电站（JNHPP）于2025年3月完成第九台机组移交，全部2115 MW装机投入商业运营，为非洲第四大、东非最大水电站，使坦桑尼亚发电能力翻倍。中国电建（葛洲坝）承建，总投资约30亿美元。全年发电量约5920 GWh，坦桑国家电网覆盖率及区域出口能力大幅提升。","descEn":"All 9 generating units (2,115 MW total) of the Julius Nyerere Hydropower Station commissioned March 2025, doubling Tanzania's generation capacity.","detailEn":"The Julius Nyerere Hydropower Station at Stiegler's Gorge, Tanzania reached full 2,115 MW capacity in March 2025 with the commissioning of its ninth and final 235 MW unit, becoming East Africa's largest power plant and Africa's fourth largest dam. Built by PowerChina (Gezhouba), total investment ~$3 billion, annual generation ~5,920 GWh. The project doubles Tanzania's installed generation and underpins regional power exports.","progress":"2025年3月全部九台机组完成商业运营"},
  {"id":5766,"name":"赞比亚-坦桑尼亚330kV输电互联（ZTK走廊）","en":"Zambia-Tanzania-Kenya (ZTK) Power Interconnector","country":"赞比亚—坦桑尼亚","region":"非洲","cat":"grid","coord":[31.85,-9.5],"cap":"330/400 kV，905+620 km","inv":4.3,"invText":"总 4.25 亿美元（赞比亚-坦桑尼亚段）","status":"在建","year":2027,"updated":"2026-06","owner":"ZESCO（赞比亚）/ TANESCO（坦桑尼亚）/ 世界银行 / EU / FCDO","flagship":false,"desc":"连接SAPP与EAPP的跨境互联干线，2025年4月启动","detail":"赞比亚-坦桑尼亚-肯尼亚（ZTK）跨境输电互联于2025年4月正式启动融资实施，总投资12亿美元，首段赞-坦段4.25亿美元，由世界银行IDA（2.45亿美元）、欧盟（0.3亿）和英国FCDO（0.17亿）提供补贴。赞比亚段建设905公里330 kV单回路（卡布韦至纳孔德），坦桑尼亚段620公里400 kV双回路（伊林加至赞坦边境）。2026年1月开工，目标2026年5月坦段完成，2027年全段贯通，连接南部非洲电力池与东非电力池。","descEn":"ZTK interconnector launched April 2025: 905 km (Zambia) + 620 km (Tanzania) 330/400 kV line linking SAPP and EAPP power pools.","detailEn":"The Zambia-Tanzania-Kenya (ZTK) Power Interconnector implementation was launched in April 2025 with $292 million in grants (World Bank $245M, EU $30M, UK FCDO $17M) for the Zambia-Tanzania section worth $425M. The project builds 905 km of 330 kV line in Zambia (Kabwe to Nakonde) and 620 km of 400 kV line in Tanzania (Iringa to border). Construction began January 2026; Tanzania section targets commissioning May 2026; full interconnection by 2027, linking SAPP and EAPP.","progress":"2025年4月启动融资，2026年1月开工，目标2027年贯通","route":[[28.45,-14.45],[30,-12],[31.85,-9.5],[33.5,-7.8],[35,-7]]},
  {"id":5767,"name":"卢济济三期跨境水电站（刚果金-卢旺达-布隆迪）","en":"Ruzizi III Regional Hydropower Project – DRC / Rwanda / Burundi","country":"刚果（金）—卢旺达—布隆迪","region":"非洲","cat":"renewable","coord":[28.9,-2.6],"cap":"206 MW","inv":8,"invText":"约 8 亿美元","status":"规划","year":2030,"updated":"2026-06","owner":"Ruzizi III Energy Limited（三国政府PPP）/ Anzana Electric（美国，少数股权）","flagship":false,"desc":"刚果金-卢旺达-布隆迪三国共建206MW跨境水电","detail":"卢济济三期水电项目（206 MW）将建于卢旺达-刚果（金）-布隆迪交界的卢济济河，是三国联合推进的区域共建项目。2025年6月在安哥拉卢安达举办的美非峰会期间，美国能源公司Anzana Electric签署意向合作协议拟注入股权。三国各持10%股权，开发联合体持70%，工程预计2025年12月开工，总投资8亿美元，建成后为三国电力市场一体化提供关键支撑。","descEn":"206 MW tri-national hydropower on the Ruzizi River; US investor Anzana Electric signed partnership intent June 2025; construction starting December 2025.","detailEn":"The Ruzizi III Regional Hydropower Project (206 MW) on the Ruzizi River at the DRC-Rwanda-Burundi border is a tripartite PPP with three governments each holding 10% equity. In June 2025 at the US-Africa Business Summit, US firm Anzana Electric signed an invitation-to-partner agreement for a minority stake. Construction was targeted to start December 2025, with completion around 2030. Total investment ~$800 million.","progress":"2025年6月美非峰会签合作意向，12月目标开工"},
  {"id":5768,"name":"GTA大托图阿麦姆二期LNG扩建（毛里塔尼亚-塞内加尔）","en":"Greater Tortue Ahmeyim (GTA) Phase 2 LNG Expansion","country":"毛里塔尼亚—塞内加尔","region":"非洲","cat":"petro","coord":[-17.05,17.85],"cap":"年产250–300万吨LNG（二期）","inv":50,"invText":"约 50 亿美元","status":"规划","year":2028,"updated":"2026-06","owner":"BP（运营方）/ Kosmos Energy / SMH（毛里塔尼亚）/ PETROSEN（塞内加尔）","flagship":false,"desc":"GTA一期投产后，BP主导二期250-300万吨LNG扩建","detail":"GTA一期FLNG（约250万吨/年）已进入生产阶段，BP及合作方已开展二期扩建概念设计，拟以重力基础结构（GBS）形式再建250–300万吨/年产能，并考虑用电力驱动液化以降低运营排放。毛里塔尼亚能源部表示二期2025年启动，2027年完工，总投资约50亿美元，新增井口及水下设备将依托现有GTA基础设施。","descEn":"BP and partners reveal GTA Phase 2 concept: 2.5–3 Mt/yr additional LNG via GBS; ~$5B investment targeting 2027–2028.","detailEn":"Following GTA Phase 1's startup, BP (operator), Kosmos Energy, SMH (Mauritania) and PETROSEN (Senegal) are advancing Phase 2 concept design based on a gravity-based structure (GBS) with 2.5–3 Mt/yr of additional LNG capacity. Power-driven liquefaction is being considered to lower operational emissions. Mauritania targets Phase 2 start in 2025, completion 2027. Total capex ~$5 billion.","progress":"一期已投产，二期概念设计推进中，2025年目标启动"},
  {"id":5769,"name":"莫桑比克LNG重启（TotalEnergies Rovuma Area 1）","en":"Mozambique LNG Full Restart – TotalEnergies Rovuma Area 1","country":"莫桑比克","region":"非洲","cat":"petro","coord":[40.55,-12.2],"cap":"年产1300万吨LNG（两列）","inv":200,"invText":"200 亿美元（总 FID，2019年）","status":"在建","year":2029,"updated":"2026-06","owner":"TotalEnergies（26.5%，运营方）/ Mitsui / ENH / ONGC / BPRL / PTTEP","flagship":true,"desc":"2026年1月宣布全面重启，预计2029年首LNG","detail":"TotalEnergies于2025年11月决定解除2021年因安全形势宣布的不可抗力，并于2026年1月29日在阿丰吉基地与莫桑比克总统联合宣布莫桑比克LNG（Rovuma Area 1）全面重启陆上和海上活动。目前已动员超4000名工人（其中3000名莫桑比克人），整体进度约40%，首LNG预计2029年。总FID投资200亿美元，项目包含两列年产650万吨LNG及相关基础设施。","descEn":"TotalEnergies and Mozambique president announced full restart of the $20B Mozambique LNG project in January 2026; first LNG expected 2029.","detailEn":"In November 2025, the Mozambique LNG consortium lifted the force majeure declared in April 2021 due to security concerns. On January 29, 2026, TotalEnergies CEO Pouyanné and President Chapo officially announced the full resumption of onshore/offshore construction at the Afungi site. Over 4,000 workers are mobilised; project is ~40% complete; first LNG targeted 2029. Original FID (2019) was $20 billion for 13 Mt/yr capacity across two LNG trains.","progress":"2025年11月解除不可抗力，2026年1月全面重启建设"},
  {"id":5770,"name":"塞内加尔桑戈马尔深水油田（首批产油）","en":"Senegal Sangomar Deepwater Oil Field – First Oil","country":"塞内加尔","region":"非洲","cat":"petro","coord":[-17.75,13.3],"cap":"峰值产量 10万桶/日","inv":50,"invText":"约 50 亿美元","status":"投运","year":2024,"updated":"2026-06","owner":"Woodside Energy（82%，运营方）/ Petrosen","flagship":false,"desc":"塞内加尔首个海上油田，2024年6月实现首油","detail":"澳大利亚伍德赛德能源主导的桑戈马尔（Sangomar）深水油田于2024年6月实现首油，是塞内加尔历史上第一个海上石油项目，总投资约50亿美元，FPSO设计日产能10万桶，可采储量约2.3亿桶。伍德赛德持股82%，塞内加尔国家石油公司（Petrosen）持18%。项目投产标志非洲大西洋沿岸新油区正式开启。","descEn":"Woodside Energy's Sangomar FPSO achieved first oil June 2024: Senegal's first offshore oil production, 100 kbpd peak, $5B capex.","detailEn":"The Sangomar deepwater oil project, operated by Woodside Energy (82%) with Petrosen (18%), achieved first oil in June 2024, marking Senegal's entry into oil production. The FPSO has a processing capacity of 100,000 bpd and ~230 MMbbl of recoverable reserves. Total capital cost ~$5 billion. Sangomar Phase 2 drilling and further development are under review.","progress":"2024年6月首油，2025年持续爬产"},
  {"id":5771,"name":"Seplat ANOH天然气处理厂（尼日利亚）","en":"Seplat ANOH Gas Processing Plant – Nigeria","country":"尼日利亚","region":"非洲","cat":"petro","coord":[6.8,5.5],"cap":"日处理天然气 3 亿标方（满产）","inv":4.2,"invText":"约 4.2 亿美元","status":"投运","year":2026,"updated":"2026-06","owner":"ANOH Gas Processing Co（Seplat 50% / 尼日利亚 NGC 50%）","flagship":false,"desc":"尼日利亚ANOH气厂2026年1月正式商业投产","detail":"Seplat Energy与尼日利亚天然气公司（NGC/NNPC）各持50%股权的Assa North-Ohaji South（ANOH）天然气处理项目于2026年1月获尼日利亚上游监管机构批准，正式启动商业生产，日处理湿气4000–5200万标方，初期向印多拉玛石化供气，远期满产日处理3亿标方。总投资4.2亿美元（双方各出资2.1亿美元）。","descEn":"Seplat's ANOH gas plant in Nigeria achieved commercial start-up January 2026; capacity 300 MMscf/day, $420M investment.","detailEn":"The Assa North-Ohaji South (ANOH) Gas Processing Plant, owned 50/50 by Seplat Energy and NNPC's NGC subsidiary, received regulatory clearance from Nigeria's NUPRC in January 2026. Initial output is 40–52 MMscfd of wet gas (rising to 300 MMscfd at full capacity), with initial supplies feeding Indorama's petrochemicals complex. Total investment: $420 million, with each partner contributing $210 million.","progress":"2026年1月取得商业生产许可，正在爬产阶段"},
  {"id":5772,"name":"阿尔及利亚Sonelgaz 3GW太阳能项目群","en":"Algeria Sonelgaz 3 GW Solar Portfolio","country":"阿尔及利亚","region":"非洲","cat":"renewable","coord":[3,30],"cap":"3 GW（20 个光伏电站）","inv":20,"invText":"约 18 亿欧元（约 20 亿美元）","status":"在建","year":2026,"updated":"2026-06","owner":"Sonelgaz及国内外承包商联合体","flagship":false,"desc":"阿尔及利亚Sonelgaz签约20座光伏，总容量3GW","detail":"阿尔及利亚国家电力公司Sonelgaz于2024年3月签署20个太阳能项目合同，总容量3 GW，分布于全国12个省，单站规模50–300 MW，总投资约18亿欧元，是阿尔及利亚2035年前部署15 GW光伏目标的首批落地项目。其中旗舰项目哈西德拉阿（362 MW+82 MW，拉格瓦特省）由土耳其Özgün İnşaat建设，使用龙基Hi-MO 7组件，2024年3月开工，2025–2026年完工。","descEn":"Sonelgaz signed 20 solar contracts (3 GW total, 12 provinces) in March 2024, invest ~€1.8B; first phase of Algeria's 15 GW by 2035 target.","detailEn":"Algeria's state utility Sonelgaz signed 19+1 contracts in March 2024 for 20 solar projects totalling 3 GW (80–220 MW each) across 12 provinces, part of a 1 GW and 2 GW tender programme launched in 2021 and 2023. Total investment ~€1.8 billion (~$2B). Flagship Hassi Delaa project (362 MW + 82 MW Guerrara, Laghouat Province, EPC Özgün İnşaat / LONGi Hi-MO 7 modules) broke ground March 2024, expected completion late 2025 to early 2026.","progress":"2024年3月签约，多个电站2025年陆续竣工并网"},
  {"id":5773,"name":"Scatec/TotalEnergies 拉斯舒凯尔900MW风电（埃及）","en":"Scatec Ras Shukeir 900 MW Onshore Wind Project – Egypt","country":"埃及","region":"非洲","cat":"renewable","coord":[33.1,27.65],"cap":"900 MW","inv":10,"invText":"约 10 亿美元（估）","status":"规划","year":2027,"updated":"2026-06","owner":"Scatec ASA","flagship":false,"desc":"Scatec与EETC签署埃及900MW红海风电25年PPA","detail":"挪威可再生能源开发商Scatec与埃及电力输电公司（EETC）签署25年PPA，在拉斯舒凯尔（红海岸）开发900 MW陆上风电项目，是继Obelisk光储项目外Scatec在埃及的又一大型布局。项目位置毗邻已有丰富风电运营经验的苏伊士湾区域，融资及工程准备进行中，预计2027年建成。","descEn":"Scatec signed 25-year PPA with EETC for a 900 MW onshore wind farm at Ras Shukeir on Egypt's Red Sea coast.","detailEn":"Scatec signed a 25-year Power Purchase Agreement with Egypt's Electricity Transmission Company (EETC) for a 900 MW onshore wind farm at Ras Shukeir on the Red Sea coast. The project complements Scatec's operational 400 MW Suez wind farm and the Obelisk solar-BESS project. Financing and engineering are being advanced for a target completion date of ~2027.","progress":"PPA已签，融资结构设计中，预计2027年投产"},
  {"id":5774,"name":"肯尼亚麦南盖地热OrPower22电站","en":"OrPower 22 Menengai Geothermal Power Plant – Kenya","country":"肯尼亚","region":"非洲","cat":"renewable","coord":[35.96,-0.33],"cap":"35 MW","inv":1.2,"invText":"约 1.17 亿美元","status":"在建","year":2026,"updated":"2026-06","owner":"OrPower Twenty-Two Ltd / GDC（蒸汽方）","flagship":false,"desc":"肯尼亚麦南盖地热园区第二座35MW电站，2026年Q1并网","detail":"OrPower Twenty-Two（OTTL）是肯尼亚地热开发公司（GDC）在麦南盖（Menengai）地热园区供蒸汽的第二座独立电厂，装机35 MW，由非洲开发银行批准1650万美元贷款支持，总投资约1.17亿美元。预计2026年3月实现首次发电，将与已并网的Sosian Energy（35 MW）及Globeleq（35 MW，2026年4月FCOD）共同构成麦南盖105 MW地热集群。","descEn":"35 MW OrPower22 geothermal plant at Kenya's Menengai field expected online March 2026; AfDB approved $16.5M loan.","detailEn":"OrPower Twenty-Two Ltd is developing a 35 MW geothermal power plant at Kenya's Menengai Caldera, the second of three planned IPP plants utilising steam supplied by the Geothermal Development Company (GDC). The African Development Bank approved a $16.5 million loan in January 2026; total project cost ~$117 million. Grid connection targeted March 2026, completing the three-plant Menengai cluster totalling 105 MW.","progress":"非洲开发银行2026年1月批贷，2026年3月目标发电"},
  {"id":5775,"name":"南非REIPPPP七期Scatec奥斯拉赫特光伏集群","en":"Scatec Oslaagte / Leeuwspruit Solar Cluster – South Africa REIPPPP BW7","country":"南非","region":"非洲","cat":"renewable","coord":[27.65,-27.65],"cap":"700 MW","inv":7.4,"invText":"约 13.5 亿兰特（约 7.4 亿美元）","status":"规划","year":2028,"updated":"2026-06","owner":"Scatec ASA / Atlantic Renewable Energy Partners","flagship":false,"desc":"Scatec在南非自由省克鲁恩斯塔德700MW光伏集群中标","detail":"挪威Scatec ASA通过Atlantic Renewable Energy Partners在南非REIPPPP第七轮中获授权700 MW太阳能，包括奥斯拉赫特太阳能2（240 MW）、奥斯拉赫特太阳能3（240 MW）及利乌斯普鲁伊特（220 MW），三项目共选址于自由省克鲁恩斯塔德（Kroonstad）。总估算投资约7.4亿美元（Scatec公布约7.4亿美元），预计向商业关闭推进。","descEn":"Scatec's 700 MW (three projects) in Kroonstad, Free State, awarded preferred bidder status in REIPPPP BW7 December 2024; ~$740M capex.","detailEn":"Scatec ASA, acting through Atlantic Renewable Energy Partners (Pty) Ltd, was awarded preferred bidder status in December 2024 for three co-located solar PV projects in Kroonstad, Free State Province: Oslaagte Solar 2 (240 MW), Oslaagte Solar 3 (240 MW) and Leeuwspruit Solar (220 MW). Combined capacity 700 MW; estimated total project cost ~$740 million. Projects will move toward commercial and financial close.","progress":"2024年12月获优先竞标资格，融资与商业关闭准备中"},
  {"id":5776,"name":"坦桑尼亚标准轨铁路伊萨卡-万扎段（Lot5）","en":"Tanzania Standard Gauge Railway Lot 5 – Isaka to Mwanza","country":"坦桑尼亚","region":"非洲","cat":"transport","coord":[32.9,-2.52],"cap":"249 km 标准轨铁路","inv":13.2,"invText":"约 13.2 亿美元","status":"在建","year":2026,"updated":"2026-06","owner":"CCECC / CRCC（EPC）/ 坦桑尼亚政府","flagship":false,"desc":"坦桑标轨铁路伊萨卡至万扎249km，2025年2月进度63%","detail":"由中国土木工程集团公司（CCECC）和中国铁道建筑（CRCC）承建的坦桑尼亚标准轨铁路Lot5（伊萨卡至万扎，249公里）合同额约13.2亿美元，以Sinosure保险覆盖的5.59亿美元融资支持，2025年2月完工63%，路基完工89%、桥梁超70%。整体标准轨项目获标准渣打银行安排23.3亿美元银团融资，预计2026年完工。","descEn":"249 km Isaka–Mwanza SGR (Lot 5) by CCECC/CRCC: 63% complete as of February 2025; $1.32B contract, targeted completion 2026.","detailEn":"China Civil Engineering Construction Corporation (CCECC) and China Railway Construction Company (CRCC) are building Tanzania's SGR Lot 5 (Isaka–Mwanza, 249 km) under a $1.32 billion contract. As of February 2025 construction reached 63% completion, with embankment 89% done and bridges 70%+. A $559M Sinosure ECA facility was drawn in 2025 to fund the works. Standard Chartered arranged $2.33 billion in financing for the broader three-lot SGR expansion. Expected completion 2026.","progress":"2025年2月完工63%，路基89%完成，预计2026年全线通车","route":[[32.97,-4],[32.91,-3.37],[32.9,-2.52]]},
  {"id":5777,"name":"刚果（金）Raxio数据中心扩建","en":"Raxio DRC Data Center – Kinshasa Expansion","country":"刚果（金）","region":"非洲","cat":"datacenter","coord":[15.27,-4.32],"cap":"数十 MW IT负荷（二期扩建）","inv":1,"invText":"约 1 亿美元（估）","status":"在建","year":2025,"updated":"2026-06","owner":"Raxio Group / Roha Group","flagship":false,"desc":"Raxio扩建金沙萨数据中心，服务刚果及中非市场","detail":"Raxio Group在刚果（金）首都金沙萨运营的Raxio DRC数据中心持续扩建，为非洲大陆中部最具规模的Tier III数据中心，由印度Roha集团背书，服务刚果DRC及周边中非市场日益增长的云计算和企业IT需求。Raxio在非洲多国（乌干达、坦桑尼亚、赞比亚、莫桑比克等）同步扩张，其总体投资计划超过3亿美元。","descEn":"Raxio Group expanding its Kinshasa Tier III data center, the main digital hub in Central Africa, as part of its pan-African expansion.","detailEn":"Raxio Group is expanding its Raxio DRC data center in Kinshasa, the largest Tier III facility in Central Africa. Backed by India's Roha Group, the facility serves the DRC's growing enterprise IT and cloud demand. Raxio operates across Uganda, Tanzania, Zambia, Mozambique and DRC as part of a pan-African growth strategy with over $300M total investment across all markets.","progress":"持续扩建中，为中非最大Tier III数据中心运营商"},
  {"id":5778,"name":"纳米比亚Hyphen绿氢绿氨项目（非洲开发银行贷款）","en":"Hyphen Green Hydrogen & Ammonia Project – Namibia (AfDB Loan 2025)","country":"纳米比亚","region":"非洲","cat":"renewable","coord":[15.16,-27],"cap":"3 GW 电解槽 / 年产30万吨绿氢（200万吨绿氨）","inv":100,"invText":"超 100 亿美元","status":"规划","year":2030,"updated":"2026-06","owner":"Hyphen Hydrogen Energy / 纳米比亚政府（24%）/ Climate Fund Managers / Invest International","flagship":true,"desc":"2025年12月AfDB批准1000万美元贷款助推百亿绿氢项目","detail":"Hyphen Hydrogen Energy在纳米比亚吕德里茨附近茨奥卡布（Tsau Khaeb）国家公园约4000平方公里内开发，规划7 GW可再生能源（风光组合）驱动3 GW电解槽，年产约30万吨绿氢转化为逾200万吨绿氨出口。2025年12月非洲开发银行批准1000万美元贷款以催化推进，项目总投资预估超100亿美元，纳米比亚政府通过SDG Namibia One持24%股权。","descEn":"Hyphen's Tsau Khaeb project: 3 GW electrolyser, 300 kt/yr green H₂, 2 Mt/yr green ammonia; AfDB approved $10M catalytic loan December 2025.","detailEn":"Hyphen Hydrogen Energy's flagship $10B+ green hydrogen and ammonia project near Lüderitz, Namibia covers ~4,000 km² of Tsau Khaeb National Park. It plans 7 GW of wind and solar powering 3 GW of electrolysers to produce ~300 kt/yr green hydrogen, converted to >2 Mt/yr green ammonia for export. In December 2025 the African Development Bank approved a $10 million catalytic loan. Namibia's government holds 24% through SDG Namibia One (structured with Climate Fund Managers and Invest International).","progress":"2025年12月AfDB批准贷款，FEED与环评持续推进"},
  {"id":5779,"name":"尼日利亚邦加北后续Shell $20亿天然气开发（海上）","en":"Shell Nigeria $2B Offshore Gas Development – Bonga Area","country":"尼日利亚","region":"非洲","cat":"petro","coord":[4.8,4.05],"cap":"待定（供气 NLNG Train 7）","inv":20,"invText":"约 20 亿美元","status":"规划","year":2028,"updated":"2026-06","owner":"Shell Nigeria（SNEPCo）/ NNPC","flagship":false,"desc":"Shell尼日利亚2025年10月批准20亿美元近海天然气项目","detail":"壳牌尼日利亚于2025年10月作出最终投资决定，追加20亿美元用于邦加近海天然气开发，以增加天然气输往尼日利亚液化天然气（NLNG）Seven号列车的供应。这是继2024年12月邦加北石油FID后Shell在尼日利亚的第二个重大投资决策，标志国际油气公司在尼日利亚深水区增资的信心回升。","descEn":"Shell Nigeria greenlit a $2B offshore gas project in October 2025 to boost gas supply for NLNG Train 7.","detailEn":"Shell Nigeria Exploration and Production Company (SNEPCo) approved a $2 billion offshore gas development in October 2025, targeting increased natural gas volumes to feed Nigeria LNG's Train 7 expansion. This is the second major FID Shell took in Nigeria within 12 months (following Bonga North oil FID in December 2024), signalling renewed confidence in Nigeria deepwater investment.","progress":"2025年10月FID，工程准备启动"},
  {"id":5780,"name":"毛里塔尼亚CWP全球AMAN绿氢30GW配套风光工程","en":"CWP Global AMAN Green Hydrogen Project – Mauritania (30 GW Renewables)","country":"毛里塔尼亚","region":"非洲","cat":"renewable","coord":[-14,21],"cap":"30 GW 风光 / 年产逾 800 万吨绿氢","inv":400,"invText":"数百亿美元（分期）","status":"规划","year":2035,"updated":"2026-06","owner":"CWP Global","flagship":true,"desc":"毛里塔尼亚30GW风光驱动全球最大绿氢项目规划中","detail":"CWP Global主导的AMAN项目规划在毛里塔尼亚境内建设约30 GW陆上风电及光伏，驱动大规模电解槽年产逾800万吨绿氢，为全球体量最大的绿氢规划项目之一。毛里塔尼亚于2024年成为全球首个颁布专项氢能法典的国家，2035年目标氢产量1250万吨，AMAN提供主要产能基础。项目将分多期逐步推进，目前处于可行性评估及前期工程阶段。","descEn":"CWP Global's AMAN: 30 GW wind/solar in Mauritania to produce 8+ Mt/yr green hydrogen; world's largest planned green hydrogen project.","detailEn":"CWP Global's AMAN project plans ~30 GW of onshore wind and solar in Mauritania to power electrolysers producing more than 8 million tonnes per year of green hydrogen—one of the world's largest planned hydrogen projects. Mauritania became the first country with a dedicated hydrogen code in 2024 and targets 12.5 Mt/yr of green hydrogen by 2035, with AMAN forming its central pillar. The project is in pre-feasibility and permitting phases; delivery will span multiple phases across the 2030s.","progress":"前期工程与可行性评估阶段，2024年氢能法典助力推进"},
  {"id":5781,"name":"肯尼亚奇佩托风电扩建（双倍产能）","en":"Kipeto Wind Farm Phase 2 Expansion – Kenya","country":"肯尼亚","region":"非洲","cat":"renewable","coord":[36.58,-1.92],"cap":"约 200 MW（扩建后，原100MW）","inv":1.5,"invText":"约 1.5 亿美元（扩建估）","status":"规划","year":2027,"updated":"2026-06","owner":"Meridiam / Kipeto Energy / Proparco","flagship":false,"desc":"肯尼亚奇佩托100MW风电拟翻倍扩建至约200MW","detail":"由法国Meridiam开发的肯尼亚奇佩托（Kipeto）100 MW陆上风电场（卡贾多县，60台1.7MW风机）于2025年11月宣布扩建计划，拟新增约18台风机，容量接近翻倍至约200 MW，有待肯尼亚电力公司PPA谈判及监管审批。法国发展融资机构Proparco已完成对Meridiam旗舰奇佩托项目的股权共投，显示融资信心。","descEn":"Kipeto Energy plans to add ~18 turbines to double output from 100 MW to ~200 MW; regulatory approvals and PPA negotiations underway.","detailEn":"Meridiam's Kipeto wind farm (100 MW, 60×1.7 MW turbines, Kajiado County) announced plans to double capacity with an additional 18 turbines (~100 MW) in November 2025, which would bring total capacity to ~200 MW. The expansion is subject to regulatory approvals and renegotiated PPA terms with Kenya Power. Proparco (French DFI) completed an equity co-investment in Meridiam's Kipeto flagship in 2025.","progress":"2025年11月宣布扩建计划，监管审批与PPA谈判中"},
  {"id":5782,"name":"南非图卢莫耶地热电站一期（埃塞俄比亚）","en":"Tulu Moye Geothermal Power Plant – Ethiopia (Phase 1, 150 MW)","country":"埃塞俄比亚","region":"非洲","cat":"renewable","coord":[39.05,8.25],"cap":"150 MW（分两期）","inv":9,"invText":"约 9 亿美元","status":"在建","year":2026,"updated":"2026-06","owner":"Meridiam / Reykjavik Geothermal / MIGA（世界银行担保）","flagship":false,"desc":"埃塞俄比亚图卢莫耶150MW地热电站建设中","detail":"由法国Meridiam与冰岛Reykjavik Geothermal联合开发的图卢莫耶地热电站位于亚的斯亚贝巴东南约100公里，分两期建设合计150 MW，获世界银行多边投资担保机构（MIGA）政治风险担保。电站将为埃塞俄比亚多水能依赖的电网提供地热基荷，增强全年供电稳定性，总投资约9亿美元，为埃塞俄比亚首个商业规模IPP地热项目。","descEn":"Ethiopia's first commercial-scale geothermal IPP: 150 MW at Tulu Moye, 100 km SE of Addis Ababa; $900M investment by Meridiam and Reykjavik Geothermal.","detailEn":"The Tulu Moye geothermal power plant (150 MW in two phases) is located ~100 km south-east of Addis Ababa, Ethiopia. Co-developed by France's Meridiam and Iceland's Reykjavik Geothermal, the project is backed by World Bank MIGA political risk guarantees. Total investment ~$900 million. It will be Ethiopia's first commercial-scale IPP geothermal project, providing baseload power to diversify the nation's hydro-dominated grid.","progress":"钻井及地面设施建设中，一期目标2026年发电"},
  {"id":5783,"name":"南非Crossover数据中心园区（开普敦/约堡）","en":"Equinix South Africa Data Center Expansion – Johannesburg & Cape Town","country":"南非","region":"非洲","cat":"datacenter","coord":[28.05,-26.2],"cap":"多园区扩建，总计数十MW","inv":3.9,"invText":"3.9 亿美元（5年非洲投资计划）","status":"在建","year":2026,"updated":"2026-06","owner":"Equinix","flagship":false,"desc":"Equinix承诺5年3.9亿美元扩建南非及非洲数据中心","detail":"美国Equinix宣布在未来五年向非洲数据中心投入3.9亿美元，重点扩建约翰内斯堡和开普敦园区（已有JB1-JB7及CT数据中心），应对南非云计算、AI及企业数字化爆发式需求。南非是撒哈拉以南非洲最大数据中心市场，现有装机容量约70 MW，预计2031年达94 MW，是外资超大规模算力部署的首选锚点。","descEn":"Equinix committed $390M over five years to expand Africa data centers, led by South Africa campuses in Johannesburg and Cape Town.","detailEn":"Equinix announced a commitment of US$390 million across Africa over five years, led by expansion at its South Africa campuses in Johannesburg (JB series) and Cape Town (CT series). South Africa dominates sub-Saharan Africa's data center market with ~70 MW of installed IT capacity (forecast ~94 MW by 2031), driven by cloud, AI and enterprise digitalisation demand. Equinix's expansion underpins growing hyperscale interest across the continent.","progress":"5年投资计划启动，约堡和开普敦园区持续扩建"},

  // ===== 大洋洲（5900-5920）=====
  {"id":5900,"name":"央科三角洲风电场","en":"Yanco Delta Wind Farm","country":"澳大利亚","region":"大洋洲","cat":"renewable","coord":[145.72,-35.35],"cap":"1,500 MW / 800 MWh","inv":26,"invText":"约 40 亿澳元（Origin 收购款含里程碑奖金最高 3 亿澳元）","status":"规划","year":2031,"updated":"2026-06","owner":"Origin Energy","flagship":true,"desc":"新南威尔士里弗里纳地区，澳大利亚最大在建风电项目之一，规划 1.5 GW","detail":"央科三角洲风电场位于新州杰里尔达里西北 10 公里里弗里纳地区，规划 208 台风机、装机 1.5 GW，配套 800 MWh 电池。Origin Energy 2024 年以最高 3 亿澳元完成收购，已获新州和联邦开发审批，预计 2027 年开工，2031 年建成。建成后可为约 75 万户家庭供电，是澳大利亚南西部可再生能源区旗舰工程。","epc":"EPC未招标","epcStatus":"未招标","descEn":"1.5 GW wind farm near Jerilderie in New South Wales Riverina district; Australia's largest wind project in planning stage.","detailEn":"Located 10 km northwest of Jerilderie in the South West Renewable Energy Zone, Yanco Delta proposes 208 turbines totalling 1,500 MW plus an 800 MWh battery. Origin Energy acquired the development in 2024 for up to A$300 million. NSW and Federal development approvals secured; FID targeted mid-2027 and construction expected to take four years from then. When built, it will power approximately 750,000 homes.","progress":"2026年5月以1.45GW容量成为联邦CIS第七轮招标（共授出7.8GW）最大中标项目，锁定长期收入保障协议。"},
  {"id":5901,"name":"西奥多风电场","en":"Theodore Wind Farm","country":"澳大利亚","region":"大洋洲","cat":"renewable","coord":[150.07,-24.93],"cap":"1,100 MW","inv":19.5,"invText":"约 30 亿澳元","status":"规划","year":2029,"updated":"2026-06","owner":"RWE Renewables Australia","flagship":false,"desc":"昆士兰中部 Banana Shire，1.1 GW 大型陆上风电，2026 年获 CIS 合同","detail":"西奥多风电场位于昆士兰州西奥多镇以东 22 公里，规划约 170 台风机、装机 1.1 GW，配套电池储能。2025 年 6 月获昆州规划审批，2026 年 5 月获联邦容量投资计划（CIS）合同，总投资约 30 亿澳元，由 RWE Renewables Australia 全资开发。预计 2026 年底启动建设，2029 年全面投运，可为约 50 万户昆州家庭供电。","epc":"EPC未招标","epcStatus":"未招标","descEn":"1.1 GW onshore wind farm in Banana Shire, Central Queensland; awarded CIS Tender 7 contract May 2026; construction expected to start late 2026.","detailEn":"Located about 22 km east of Theodore in Central Queensland, the project proposes ~170 turbines and a battery storage component. Queensland state approval was granted in June 2025, and federal CIS Tender 7 contract awarded May 2026. Total investment ~A$3 billion, fully owned by RWE Renewables Australia. Construction expected late 2026 subject to EPBC approval, with full operations targeted for 2029.","progress":"2026 年 5 月获 CIS 合同；州级审批 2025 年 6 月通过，待联邦环评"},
  {"id":5902,"name":"本加班可再生能源项目","en":"Bungaban Renewable Energy Project","country":"澳大利亚","region":"大洋洲","cat":"renewable","coord":[149.97,-26.5],"cap":"1,400 MW 风电 / 350 MW·1,400 MWh 储能","inv":23,"invText":"约 35 亿澳元（估算）","status":"规划","year":2030,"updated":"2026-06","owner":"Windlab","flagship":false,"desc":"昆士兰南部 Wandoan 附近超大风储混合项目，力拓 PPA 覆盖 80% 电量","detail":"本加班项目位于昆士兰沃达安和塔鲁姆之间，规划 1.4 GW 风机配套 350 MW/1,400 MWh 电池储能，是澳大利亚最大可再生能源 PPA 项目之一——力拓签署 25 年购电协议，覆盖项目 80% 电量，支撑其昆州铝业脱碳目标。2026 年 3 月完成联邦环评预提交，是 Windlab 南昆士兰可再生能源中心最成熟项目，计划 2030 年投运。","epc":"EPC未招标","epcStatus":"未招标","descEn":"1.4 GW wind farm plus 350 MW/1,400 MWh BESS near Wandoan, Queensland; 80% of output under 25-year PPA with Rio Tinto.","detailEn":"Bungaban is located in Western Downs and Banana Shire, ~40 km northeast of Wandoan. The project proposes 1,400 MW of wind and a colocated 350 MW/1,400 MWh battery. Rio Tinto has signed Australia's largest renewable PPA covering 80% of output for 25 years to decarbonise its Queensland aluminium smelters. EPBC referral documents published March 2026; operational target 2030.","progress":"2026 年 3 月完成环评预提交，Rio Tinto 25 年 PPA 锁定 80% 电量"},
  {"id":5903,"name":"比尔里瓦光储项目","en":"Birriwa Solar and Battery Project","country":"澳大利亚","region":"大洋洲","cat":"renewable","coord":[149.38,-32.02],"cap":"600 MW 光伏 / 900 MW·2,800 MWh 储能","inv":6.5,"invText":"约 10 亿澳元","status":"规划","year":2028,"updated":"2026-06","owner":"ACEN Australia","flagship":false,"desc":"新州中西部奥拉纳 REZ 内，600 MW 光伏配套近 3 GWh 大型电池，2024 年获批","detail":"比尔里瓦光储项目位于新南威尔士中西部奥拉纳可再生能源区（REZ）达尼度以东 19 公里，规划 600 MW 光伏与最高 900 MW/2,800 MWh 电池储能系统。项目于 2024 年 8 月获新州独立规划委员会批准，投资估算约 10 亿澳元，建设预计 2026 年底或 2027 年初启动，2028 年实现发电。由菲律宾 ACEN 旗下澳大利亚子公司主导开发。","epc":"EPC未招标","epcStatus":"未招标","descEn":"600 MW solar farm plus up to 900 MW/2,800 MWh BESS in the NSW Central-West Orana REZ; approved August 2024, construction from late 2026.","detailEn":"Birriwa is located ~19 km southeast of Dunedoo in the Central-West Orana Renewable Energy Zone. The project pairs 600 MW of photovoltaic capacity with up to 900 MW/2,800 MWh of battery storage. NSW Independent Planning Commission approved the project in August 2024. Investment estimated ~A$1 billion. ACEN Australia expects construction to commence late 2026 or early 2027 with generation by 2028.","progress":"2024 年 8 月获新州 IPC 批准，建设目标 2026 年底启动"},
  {"id":5904,"name":"贡达里光储混合电站","en":"Gundary Solar and Battery Hybrid","country":"澳大利亚","region":"大洋洲","cat":"renewable","coord":[149.56,-34.9],"cap":"320 MW 光伏 / 1,391 MWh 储能","inv":3.5,"invText":"约 5.4 亿澳元","status":"规划","year":2028,"updated":"2026-06","owner":"Lightsource bp","flagship":false,"desc":"新州高尔本南 13 公里，320 MW 光伏配 1,391 MWh 电池，2026 年获 CIS 合同","detail":"贡达里项目位于新南威尔士高尔本南约 13 公里，规划 400 MW 直流（320 MW 交流）光伏农场配套 1,391 MWh 电池储能。2026 年 5 月在 CIS Tender 7 中成功入选，总投资约 5.4 亿澳元，由 Lightsource bp（bp 旗下可再生能源平台）开发。该项目是澳大利亚南部高原首批光储混合枢纽之一，计划 2028 年前投运。","epc":"EPC未招标","epcStatus":"未招标","descEn":"320 MW solar (400 MWdc) plus 1,391 MWh BESS near Goulburn, NSW; selected in CIS Tender 7 in May 2026.","detailEn":"Gundary is located ~13 km south of Goulburn in the NSW Southern Tablelands. The project comprises a 400 MW DC (320 MW AC) solar farm paired with a 1,391 MWh battery energy storage system. Awarded a CIS Tender 7 contract in May 2026. Total investment ~A$540 million. Developed by Lightsource bp, an independent solar developer majority owned by BP. Target commissioning before 2028.","progress":"2026 年 5 月获 CIS Tender 7 合同，规划联邦环评提交"},
  {"id":5905,"name":"斯坦维尔电池储能电站（昆士兰）","en":"Stanwell Battery Energy Storage System","country":"澳大利亚","region":"大洋洲","cat":"storage","coord":[150.41,-23.45],"cap":"300 MW / 1,200 MWh","inv":4.9,"invText":"约 7.47 亿澳元","status":"在建","year":2027,"updated":"2026-06","owner":"Stanwell Corporation（昆州国有）","flagship":false,"desc":"昆士兰斯坦维尔电站旁大型 BESS，324 台特斯拉 Megapack 2XL，2025 年开工","detail":"斯坦维尔 BESS 位于昆士兰中部罗克汉普顿附近斯坦维尔电站园区，规划 300 MW/1,200 MWh，由 324 台特斯拉 Megapack 2XL 组成。昆州国有能源公司斯坦维尔以 7.47 亿澳元全资投建，2025 年启动建设，计划 2025 年底开始调试、2027 年中全面商业运营，是清洁能源枢纽战略的核心项目。","epc":"电池 Tesla Megapack 2XL(324台)；安装总包 Yurika","epcStatus":"已授标","descEn":"300 MW/1,200 MWh BESS at Stanwell Power Station site near Rockhampton, Queensland; 324 Tesla Megapack 2XL units; commercial operations mid-2027.","detailEn":"Located at the Stanwell Power Station site in Central Queensland, this state-owned BESS project uses 324 Tesla Megapack 2XL units to deliver 300 MW of power for four hours. Developed by Stanwell Corporation at a cost of A$747 million. Construction commenced in 2025 with commissioning to begin late 2025 and full commercial operations targeted mid-2027. The project will provide grid services including frequency control and capacity firming.","progress":"2025 年建设已过半，调试目标 2025 年底，商运 2027 年中"},
  {"id":5906,"name":"塔朗电池储能电站","en":"Tarong Battery Energy Storage System","country":"澳大利亚","region":"大洋洲","cat":"storage","coord":[151.91,-26.78],"cap":"300 MW / 600 MWh","inv":3.3,"invText":"约 5.14 亿澳元","status":"投运","year":2025,"updated":"2026-06","owner":"Stanwell Corporation（昆州国有）","flagship":false,"desc":"昆州南柏内特地区塔朗电站旁首个全资 BESS，2025 年正式商业运营","detail":"塔朗电池储能电站位于昆士兰州南柏内特地区塔朗电站旁，规划容量 300 MW/600 MWh（2 小时储能）。由昆州国有斯坦维尔公司以 5.14 亿澳元投建，2025 年正式启动商业运营，主动参与国家电力市场 NEM，是斯坦维尔首个自有调度储能项目，也是昆州煤电转型清洁能源枢纽计划的里程碑工程。","epc":"电池 Tesla Megapack 2XL(164台)；安装总包 Yurika(昆州国有)","epcStatus":"已授标","descEn":"300 MW/600 MWh BESS at Tarong Power Station site, South Burnett Queensland; Stanwell Corporation's first wholly-owned dispatchable storage, commissioned 2025.","detailEn":"Tarong BESS is located adjacent to the 1.4 GW Tarong coal-fired power station in the South Burnett region of Queensland. The 300 MW/600 MWh facility represents Stanwell Corporation's first wholly-owned dispatchable energy storage project, with a total investment of A$514 million. It commenced commercial operations in 2025 and actively participates in the National Electricity Market, providing frequency control and energy arbitrage services.","progress":"2025 年完成建设并正式商业运营，主动参与 NEM 调度"},
  {"id":5907,"name":"通基洛电池储能电站","en":"Tungkillo Battery Energy Storage System","country":"澳大利亚","region":"大洋洲","cat":"storage","coord":[139.08,-34.73],"cap":"270 MW / 1,080 MWh","inv":3,"invText":"约 2.75 亿欧元（约 4.9 亿澳元）","status":"规划","year":2028,"updated":"2026-06","owner":"Iberdrola Australia","flagship":false,"desc":"南澳通基洛镇附近 270 MW/1,080 MWh 电池，2025 年 Iberdrola 以 2.75 亿欧元收购","detail":"通基洛 BESS 位于南澳大利亚通基洛镇以南约 6 公里，规划 270 MW/1,080 MWh（4 小时）锂电储能系统。西班牙能源巨头 Iberdrola 于 2025 年 10 月以 2.75 亿欧元从 RES Australia 手中收购该项目，南澳规划委员会已于 2024 年 12 月完成审批。预计 2026 年底启动建设、2028 年投运，是 Iberdrola 在澳 10 亿欧元储能投资计划的重要组成部分。","epc":"EPC未招标","epcStatus":"未招标","descEn":"270 MW/1,080 MWh battery storage project in South Australia; acquired by Iberdrola for €275 million in October 2025; operational target 2028.","detailEn":"Located ~6 km south of Tungkillo township in South Australia's Mid-Murray region, the project will deliver 270 MW of power for four hours (1,080 MWh). Iberdrola Australia acquired it from RES Australia in October 2025 for €275 million as part of its A$1 billion+ Australian battery storage strategy. Planning approval was granted in December 2024. Construction expected to commence late 2026 with operations in 2028.","progress":"2025 年 10 月 Iberdrola 完成收购，规划批准已就绪，2026 年底开工"},
  {"id":5908,"name":"凤凰抽水蓄能电站（新州）","en":"Phoenix Pumped Hydro Energy Storage","country":"澳大利亚","region":"大洋洲","cat":"storage","coord":[149.5,-32.4],"cap":"800 MW / 9,600 MWh（12 小时）","inv":23,"invText":"约 36 亿澳元","status":"规划","year":2032,"updated":"2026-06","owner":"ACEN Australia","flagship":false,"desc":"新州马吉附近抽蓄，800 MW/12 小时，2025 年获 LTESA 并获 CSSI 认定","detail":"凤凰抽水蓄能位于新南威尔士马吉以西 35 公里、中西部奥拉纳 REZ 内，规划装机 800 MW、储能 9,600 MWh（12 小时），最大持续时长 15 小时。2025 年 2 月获新州政府长期能源服务协议（LTESA），同年获新州关键重大基础设施（CSSI）认定，投资估算 36 亿澳元。EIS 环评报告准备提交，建设预计 2028 年启动，2032 年投运。","epc":"EPC未授标(前期)","epcStatus":"未招标","descEn":"800 MW/12-hour pumped hydro project near Mudgee in NSW Central-West Orana REZ; awarded LTESA in Feb 2025 and declared Critical State Significant Infrastructure.","detailEn":"The Phoenix project sits 35 km west of Mudgee within the NSW Central-West Orana Renewable Energy Zone. It proposes 800 MW of generating/pumping capacity with 9,600 MWh (12-hour) storage. Awarded a Long-Term Energy Service Agreement in February 2025 and declared Critical State Significant Infrastructure by the NSW Government. Estimated cost ~A$3.6 billion. Environmental Impact Statement preparation underway; construction expected 2028, operations 2032.","progress":"2025 年 2 月获 LTESA；已获 CSSI 认定；EIS 环评报告准备阶段"},
  {"id":5909,"name":"西悉尼抽水蓄能电站","en":"Western Sydney Pumped Hydro Project","country":"澳大利亚","region":"大洋洲","cat":"storage","coord":[150.3,-33.95],"cap":"2,000 MW / 16,000 MWh（8 小时）","inv":23,"invText":"约 35 亿澳元","status":"规划","year":2031,"updated":"2026-06","owner":"ZEN Energy","flagship":false,"desc":"新州沃拉甘巴水库旁利用废弃煤矿，2,000 MW/8 小时抽蓄，2026 年获 CSSI 认定","detail":"西悉尼抽水蓄能位于沃拉甘巴大坝上游约 24 公里布拉戈湖东岸，利用废弃煤洗厂坑作为下水库、结合上水库形成封闭式抽蓄系统，规划容量 2,000 MW/16,000 MWh（8 小时）。由 ZEN Energy 与 Dunbier 家族合作开发，投资估算 35 亿澳元，2026 年 2 月获新州 CSSI 认定。计划 2027 年启动建设、2031 年投运，是大悉尼地区最大长时储能项目。","epc":"EPC未授标(前期)","epcStatus":"未招标","descEn":"2,000 MW/16,000 MWh closed-loop pumped hydro at Lake Burragorang, western Sydney; declared Critical State Significant Infrastructure February 2026.","detailEn":"Located ~24 km upstream from Warragamba Dam, Western Sydney Pumped Hydro uses a disused coal washery site on the eastern shore of Lake Burragorang as the lower reservoir. Developed by ZEN Energy in partnership with the Dunbier family, the project proposes 2,000 MW/16,000 MWh (8-hour) pumped hydro. Declared Critical State Significant Infrastructure by the NSW Government in February 2026. Investment ~A$3.5 billion; construction to begin 2027, operations by 2031.","progress":"2026 年 2 月获新州 CSSI 认定，计划 2027 年启动建设"},
  {"id":5910,"name":"马斯韦尔布鲁克抽水蓄能电站","en":"Muswellbrook Pumped Hydro Energy Storage","country":"澳大利亚","region":"大洋洲","cat":"storage","coord":[150.9,-32.27],"cap":"500 MW / 4,000 MWh（8 小时）","inv":4.6,"invText":"约 6.5–7 亿澳元","status":"规划","year":2029,"updated":"2026-06","owner":"AGL Energy / Idemitsu Australia（JV）","flagship":false,"desc":"新州马斯韦尔布鲁克利用废弃煤矿坑作下水库的 500 MW 抽蓄，2024 年获 CSSI","detail":"马斯韦尔布鲁克抽蓄利用 Idemitsu 公司煤矿废坑作为下水库、贝尔斯山为上水库，规划装机 500 MW，储能 4,000 MWh（8 小时），由 AGL 与 Idemitsu Australia 合资开发，投资估算 6.5–7 亿澳元。2024 年 7 月被新州政府认定为关键重大基础设施（CSSI），建设预计 2026 年启动、2029 年竣工，将在猎人河谷煤炭资产转型中扮演关键角色。","epc":"EPC未授标(前期)","epcStatus":"未招标","descEn":"500 MW/4,000 MWh pumped hydro using a coal mine void as lower reservoir near Muswellbrook NSW; declared CSSI July 2024.","detailEn":"Muswellbrook Pumped Hydro uses an existing mine void at Idemitsu's Muswellbrook coal mine site as the lower reservoir, with Bells Mountain as the upper reservoir. The project proposes 500 MW / 8-hour storage capacity. Developed as a 50:50 JV by AGL Energy and Idemitsu Australia, with an estimated investment of A$650–700 million. Declared Critical State Significant Infrastructure by NSW in July 2024. Construction expected to start 2026 and complete by 2029.","progress":"2024 年 7 月获新州 CSSI 认定，预计 2026 年开工建设"},
  {"id":5911,"name":"锡拉丘斯风电场（塔斯马尼亚）","en":"Cellars Hill Wind Farm","country":"澳大利亚","region":"大洋洲","cat":"renewable","coord":[146.9,-42.15],"cap":"341 MW / 2,400 MWh 储能","inv":6.5,"invText":"约 10 亿澳元（估算）","status":"规划","year":2030,"updated":"2026-06","owner":"Gamuda Renewables / Alternate Path","flagship":false,"desc":"塔斯马尼亚博斯韦尔附近 56 台风机+600 MW/2,400 MWh 大型配套电池，2026 年获 CIS","detail":"锡拉丘斯（Cellars Hill）风电场位于塔斯马尼亚州博斯韦尔附近，规划 56 台风机、装机 341 MW，并配套 600 MW/2,400 MWh 电池储能——是澳大利亚单个配套储能规模最大的风电项目之一。由马来西亚 Gamuda Renewables 与 Alternate Path 联合开发，2026 年 5 月获 CIS Tender 7 合同，已获塔州重大项目认定，计划 2027 年开工、2030 年投运。","epc":"EPC未招标(开发方Gamuda自身具承建能力)","epcStatus":"未招标","descEn":"341 MW wind farm plus 600 MW/2,400 MWh battery near Bothwell, Tasmania; awarded CIS Tender 7 contract May 2026; construction from 2027.","detailEn":"Located near Bothwell in Tasmania's Central Highlands, Cellars Hill proposes 56 turbines (341 MW) alongside one of Australia's largest co-located battery systems at 600 MW/2,400 MWh. Developed by Gamuda Renewables and Alternate Path, the project received Tasmania's Major Project Declaration and was selected in CIS Tender 7 in May 2026. Estimated investment ~A$1 billion. Construction planned 2027 with operations by 2030.","progress":"2026 年 5 月获 CIS Tender 7 合同，已获塔州重大项目认定"},
  {"id":5912,"name":"威拉图克风电场（维州）","en":"Willatook Wind Farm","country":"澳大利亚","region":"大洋洲","cat":"renewable","coord":[142.37,-38.1],"cap":"338 MW / 400 MWh 储能","inv":5.2,"invText":"约 8 亿澳元（估算）","status":"规划","year":2029,"updated":"2026-06","owner":"ENGIE Australia","flagship":false,"desc":"维州沃恩巴尔以北 22 公里，338 MW 风电配 200 MW/400 MWh 电池，2026 年获 CIS","detail":"威拉图克风电场位于维多利亚州沃恩巴尔以北 22 公里、沃南布尔西北 32 公里，规划 338 MW 风电配套 200 MW/400 MWh 电池储能，由法国能源巨头 ENGIE 澳大利亚子公司开发，2026 年 5 月在 CIS Tender 7 成功入选，预计 2029 年前投运，贡献维州西南地区脱碳目标。","epc":"EPC未招标(开发审批阶段)","epcStatus":"未招标","descEn":"338 MW wind farm plus 200 MW/400 MWh BESS near Port Fairy, south-west Victoria; developed by ENGIE; CIS Tender 7 selected May 2026.","detailEn":"Willatook Wind Farm is located 22 km north of Port Fairy and 32 km northwest of Warrnambool in south-west Victoria. It proposes 338 MW of wind generation paired with a 200 MW/400 MWh battery. Developed by ENGIE Australia; awarded CIS Tender 7 support in May 2026. Expected investment ~A$800 million. Targeted for commissioning before 2029, contributing to Victoria's renewable energy targets.","progress":"2026 年 5 月获 CIS Tender 7 合同"},
  {"id":5913,"name":"怀特亚克维风电场（南澳）","en":"Whyte Yarcowie Wind Farm","country":"澳大利亚","region":"大洋洲","cat":"renewable","coord":[139.05,-33.5],"cap":"289 MW","inv":3.9,"invText":"约 6 亿澳元（估算）","status":"规划","year":2029,"updated":"2026-06","owner":"EDF Renewables Australia","flagship":false,"desc":"南澳怀特亚克维 289 MW 陆上风电，2026 年获 CIS 合同，EDF 主导","detail":"怀特亚克维风电场位于南澳大利亚怀特亚克维地区，规划装机 289 MW，由法国 EDF 旗下澳大利亚可再生能源公司 EDF Power Solutions 开发，2026 年 5 月成功入选 CIS Tender 7 合同，预计 2029 年前完成建设，支撑南澳清洁能源过渡。","epc":"EPC未招标","epcStatus":"未招标","descEn":"289 MW onshore wind farm at Whyte Yarcowie in South Australia; developed by EDF Renewables Australia; CIS Tender 7 contract awarded May 2026.","detailEn":"Located in the Whyte Yarcowie area of South Australia, the project proposes 289 MW of onshore wind capacity. Developed by EDF Power Solutions (a subsidiary of EDF Renewables), the project received a CIS Tender 7 contract in May 2026. Estimated investment ~A$600 million. Targeted for commissioning before 2029, supporting South Australia's high-renewables grid.","progress":"2026 年 5 月获 CIS Tender 7 合同"},
  {"id":5914,"name":"必和必拓奥林匹克坝地下扩建","en":"BHP Olympic Dam Underground Infrastructure Expansion","country":"澳大利亚","region":"大洋洲","cat":"mining","coord":[136.88,-30.44],"cap":"铜精矿处理能力提升约 6%，新增地下电铁约 80 km","inv":5.5,"invText":"约 8.4 亿澳元","status":"在建","year":2027,"updated":"2026-06","owner":"BHP","flagship":false,"desc":"必和必拓奥林匹克坝 8.4 亿澳元地下采矿扩建，新增斜井、充填系统与冶炼氧气厂","detail":"必和必拓于 2025 年宣布向南澳奥林匹克坝铜铀金银矿注入逾 8.4 亿澳元，建设南矿区地下通道斜井、新型充填系统、扩建矿石溜井及地下电动铁路，同时新增氧气厂提升冶炼产能。改造完成后铜精矿处理量可从 80 吨/小时提升至 85 吨/小时，为将全球铜产能从 170 万吨/年提升至 250 万吨/年奠定基础。","epc":"业主自管+框架承包商，无单一EPC","epcStatus":"不适用","descEn":"BHP investing over A$840M in underground mining infrastructure at Olympic Dam, South Australia; new decline, backfill system, ore-pass expansion, and oxygen plant.","detailEn":"BHP announced in late 2025 an A$840 million investment package at Olympic Dam, encompassing an underground access decline into the Southern Mine Area, a new paste backfill system, expanded ore-pass capacity with new electric locomotives, and a new oxygen plant to boost smelter performance. These projects increase copper concentrate processing capacity by ~6% and underpin BHP's strategy to grow global copper output from 1.7 million to 2.5 million tonnes per annum.","progress":"2025 年宣布，项目建设中，目标 2027 年主要工程完工"},
  {"id":5915,"name":"利纳斯卡尔古利稀土精炼厂","en":"Lynas Kalgoorlie Rare Earths Processing Facility","country":"澳大利亚","region":"大洋洲","cat":"mining","coord":[121.47,-30.75],"cap":"年处理 Mt Weld 稀土精矿，生产多类稀土氧化物产品","inv":4.9,"invText":"约 7.5 亿澳元","status":"投运","year":2024,"updated":"2026-06","owner":"Lynas Rare Earths","flagship":false,"desc":"西澳卡尔古利澳大利亚本土首座稀土加工厂，2024 年全面整合至 Lynas 全球运营","detail":"利纳斯卡尔古利稀土精炼厂是澳大利亚首座本土稀土分离加工设施，处理来自 Mt Weld 矿山的稀土精矿，生成多类稀土氧化物产品，需持续 20–25 MW 电力。2025 年 8 月 Lynas 完成 7.5 亿澳元股权融资以支撑 Mt Weld 扩建工程，配套太阳能+电池应急电源在 2025 年 11 月停电事故后加快落地。Mt Weld 扩建处理厂于 2025 年底调试接近完成。","epc":"业主自管多包交付(无单一EPC)；参建 Delonix Solutions 等","epcStatus":"不适用","descEn":"Australia's first domestic rare earths separation facility at Kalgoorlie, WA; fully integrated in 2024; A$750M equity raising in 2025 to fund Mt Weld expansion.","detailEn":"The Kalgoorlie Rare Earths Processing Facility is Australia's first rare earth separation plant, processing Mt Weld ore concentrate (from the world's richest rare earth deposit) into refined products. Lynas completed a A$750 million equity raising in August 2025 to fund the Mt Weld Expansion programme. Construction of the Mt Weld expansion processing plant was completed and commissioning nearly finalised by end-2025. The facility requires 20–25 MW continuous power and is integrating solar and battery backup.","progress":"2024 年全面整合运营，2025 年 8 月完成 7.5 亿澳元融资支持 Mt Weld 扩产"},
  {"id":5916,"name":"凯瓦卡维风电场（新西兰）","en":"Kaiwaikawe Wind Farm","country":"新西兰","region":"大洋洲","cat":"renewable","coord":[173.78,-36.12],"cap":"77 MW","inv":1.7,"invText":"约 2.87 亿新西兰元","status":"在建","year":2027,"updated":"2026-06","owner":"Mercury Energy","flagship":false,"desc":"新西兰北地大区达尔加维尔附近首座大型风电，12 台风机，2026 年开始发电","detail":"凯瓦卡维风电场位于新西兰北地达尔加维尔附近奥马里农场，由水银能源（Mercury Energy）投资 2.87 亿新西兰元建造，是北地首座大型风电项目。规划 12 台 Vestas V162-6.4 MW 风机、装机 77 MW，叶尖高度 206 米，年发电 221 GWh，可覆盖约 2.7 万户家庭。2025 年 3 月破土动工，风机 2026 年 2 月到港，预计 2026 年中开始发电、2027 年全面建成。","descEn":"77 MW wind farm near Dargaville, Northland NZ; Mercury Energy's NZ$287M project; groundbreaking March 2025, first generation mid-2026.","detailEn":"The Kaiwaikawe Wind Farm is located on Pāmu (Landcorp) farmland near Dargaville in New Zealand's Northland region, marking Northland's first large-scale wind energy project. Mercury Energy is investing NZ$287 million for 12 Vestas V162-6.4 MW turbines (77 MW total). Ground was broken in March 2025, turbines arrived in February 2026. First generation is expected mid-2026 with full completion by late 2026/mid-2027.","progress":"2025 年 3 月破土，风机 2026 年 2 月到港，预计 2026 年中开始发电"},
  {"id":5917,"name":"南地大型风电场（新西兰）","en":"Southland Wind Farm","country":"新西兰","region":"大洋洲","cat":"renewable","coord":[169.3,-46],"cap":"380 MW","inv":6,"invText":"约 10 亿新西兰元（估算）","status":"规划","year":2029,"updated":"2026-06","owner":"Contact Energy","flagship":false,"desc":"新西兰有史以来最大风电项目，南地区 55 台风机 380 MW，2026 年 4 月获快速审批","detail":"南地风电场位于新西兰南岛南地大区戈尔东南约 30 公里 58 平方公里私有土地上，由接触能源（Contact Energy）开发，规划 55 台约 7 MW 风机，装机 380 MW，可为约 15 万户家庭供电，注入当地经济 1,350 万新西兰元并创造最多 300 个建设期岗位。2025 年 8 月提交快速审批申请，2026 年 4 月 2 日正式获批，是新西兰有史以来最大单体风电工程。","descEn":"380 MW wind farm in eastern Southland NZ; New Zealand's largest ever wind project; fast-track consented April 2026.","detailEn":"Located across 58 km² of privately owned land ~30 km southeast of Gore in eastern Southland, Contact Energy's Southland Wind Farm proposes 55 turbines at up to ~7 MW each, totalling 380 MW. Submitted for fast-track consent in August 2025 and formally approved on 2 April 2026—New Zealand's largest ever wind farm by capacity. The project will inject NZ$13.5 million into the local economy and create up to 300 construction jobs.","progress":"2026 年 4 月 2 日通过新西兰快速审批，准备推进详细设计与 FID"},
  {"id":5918,"name":"奥兹洛湖抽水蓄能（新西兰私人复活版）","en":"Lake Onslow Pumped Hydro Scheme","country":"新西兰","region":"大洋洲","cat":"storage","coord":[169.72,-45.75],"cap":"1,000 MW / 5 TWh","inv":95,"invText":"约 157 亿新西兰元（约 95 亿美元）","status":"规划","year":2036,"updated":"2026-06","owner":"Clutha Pumped Hydro Consortium（私人联合体）","flagship":true,"desc":"新西兰奥塔哥奥兹洛湖 5 TWh 抽蓄，政府搁置后私人联合体 2026 年申请快速审批","detail":"奥兹洛湖抽水蓄能曾是新西兰工党政府的旗舰长时储能计划，2023 年被现政府叫停。2026 年 3 月，由前 Transpower 主席基思·特纳领衔的私人联合体（Clutha Pumped Hydro Consortium）重启该计划，提交快速审批申请，基础设施部长已将其转介审批委员会。项目规划 1,000 MW 发电/抽水、储能 5 TWh，若建成将是全球最大抽蓄项目之一，估算费用约 157 亿新西兰元，建设周期 10 年以上。","descEn":"Proposed 1,000 MW/5 TWh pumped hydro at Lake Onslow, NZ Otago; revived by private consortium with fast-track consent referral in March 2026; potential world's largest pumped storage.","detailEn":"Originally a New Zealand Labour Government initiative, the Lake Onslow scheme was cancelled in 2023. In March 2026, a private consortium led by former Meridian CEO/Transpower chair Dr Keith Turner submitted a fast-track consent application, which was referred to an expert panel by the Minister of Infrastructure. The project proposes 1,000 MW of generating/pumping capacity with 5 TWh of storage—potentially the world's largest pumped storage scheme. Estimated cost ~NZ$15.7 billion; build time 10+ years.","progress":"2026 年 3 月提交快速审批申请，基础设施部长已转介专家组；项目处早期阶段"},
  {"id":5919,"name":"拉穆二期水电站（巴新）","en":"Ramu 2 Hydropower Station","country":"巴布亚新几内亚","region":"大洋洲","cat":"renewable","coord":[145.9,-5.85],"cap":"180 MW","inv":9.4,"invText":"约 9.4 亿美元（约 32 亿基纳）","status":"在建","year":2028,"updated":"2026-06","owner":"深圳能源集团 / 中国水利水电建设集团（BOOT 模式）","flagship":false,"desc":"巴新拉穆河流域 180 MW 水电站，中资 BOOT 模式，2025 年 6 月开展现场前期工作","detail":"拉穆二期水电站规划在巴新拉穆河流域建设 180 MW 水力发电机组，由深圳能源集团与中国水电（Sinohydro）联合体以建设-运营-移交（BOOT）模式开发，特许期 25 年后移交巴新政府，总投资约 9.4 亿美元（32 亿基纳）。2025 年 6 月中方团队抵达永基（Yonki）开展现场勘察和营地选址，项目将使巴新总装机增加约 36%，是巴新近年最大电力基础设施工程。","descEn":"180 MW hydropower station on the Ramu River, Papua New Guinea; US$940M BOOT project by Shenzhen Energy/Sinohydro; site survey commenced June 2025.","detailEn":"The Ramu 2 hydropower station is planned on the Ramu River in the Eastern Highlands of Papua New Guinea. A consortium of Shenzhen Energy Group and Sinohydro will build, own and operate the plant for 25 years before transferring ownership to the PNG state. Total investment US$940 million. Chinese teams commenced preliminary site surveys at Yonki in June 2025. Once operational, it will increase PNG's total electricity generation capacity by approximately 36%.","progress":"2025 年 6 月中方团队完成首轮现场踏勘，准备前进营地建设方案"},
  {"id":5920,"name":"新西兰塔拉纳基 LNG 进口接收站","en":"New Zealand Taranaki LNG Import Terminal","country":"新西兰","region":"大洋洲","cat":"petro","coord":[174.08,-39.5],"cap":"覆盖全国天然气峰值与工业安全气源需求","inv":6,"invText":"逾 10 亿新西兰元","status":"规划","year":2028,"updated":"2026-06","owner":"待定（政府公开遴选）","flagship":false,"desc":"新西兰政府招标 LNG 进口设施，塔拉纳基选址，目标 2027–2028 年投运","detail":"为应对国内天然气产量下滑引发的能源安全危机，新西兰政府决定在塔拉纳基地区建设 LNG 进口接收站。已于 2025–2026 年完成提案征集并遴选出 6 家候选方案，目标 2026 年中签署合同，2027 年底或 2028 年初投入运营。终端成本逾 10 亿新西兰元，通过电力行业征收 NZ$2–4/MWh 附加费回收，将为工业和电力部门提供峰值气源保障。","descEn":"New Zealand government-procured LNG import terminal in Taranaki; contract signing target mid-2026; operational target 2027–2028; NZ$1B+ investment.","detailEn":"With New Zealand's domestic natural gas production declining, the government is procuring an LNG import terminal in the Taranaki region to secure energy supply and lower electricity prices. Six shortlisted proposals were evaluated in 2025–2026. The government aims to sign a contract by mid-2026 with the terminal operational by late 2027 or early 2028. Infrastructure costs exceed NZ$1 billion, recovered via a NZ$2–4/MWh levy on electricity. It will provide peak and backup gas supply for industry and power generation.","progress":"6 家候选方案已入围，目标 2026 年中签约，2027–2028 年投运"},
]);
